BODY_TEXT:
// mx.preTrade.completion.COM.Pricing.FInit

/*
MXpress
COM Field Initialization and Pricing rules

Used algorithm
Loop over components
	Get registration
	If Registration is COM Swap or COM Capacity
		Then set he same quotation and quotation unit
	If Registration is COM Capacity or COM transport
		Depending on LUT results, initialize the Delivery Settlement, Index, Product & Counterpart and Cap UDFs accordingly
		Complete the pricing by:
			- forcing margin 0 on physical legs for Transport
			- assigning the price/margin2 the right value if UDF CAP_PREM was set by user for Capacity
	End if
End loop

Version 1.4
Initialize the fields (date, physical, index) for "Unpriced Average COM" pattern (floating/floating physical forward for base & precious metals)

Version 1.3
Replaced the UDF CAP_PREM_T by the pretrade field pf_cap_prem. This field holds the previous value of the capacity premium.
Used for technical reasons to dientify when the user changes the premium value.

Version 1.2
Made compatible with multi-component trades
Added the quotation check on Swaptions
Added, for Power & Gas Capacity & Transport:
- based on a LUT result based on Route criteria, complete the relevant field: Index, product, counterpart...
- complete pricing using UDF CAP_PREM

Version 1.1
COM Cleared Swap and COM transport registrations are no longer impacted

Version 1.0
The purpose of this rule is to initialize fields for COM products:
- for swap products, force the same quotation and quotation unit between the legs

This rule uses a Look-Up Table ( LUT ):
- ( MX.COM.Capacity,ALL ) provides assignment details for indices, counterparts, mandatory and overridable settings for COM Capacity and COM transport registrations
*/

{
	// Field initialization / reset
	pLeg := This,
	sYes := "Yes",
	sNo := "No",
	sCustomOTC := "Custom",
	sDefaultIndex := "__SPOT24 USD/MWH",
	sUseCapacity := "Capacity",
	sNoUseCapacity := "Free of Capacity",
	iNbComponents := 0,
	iComponent := 0,
	sRegistration := "",
	sRoute := "",
	sUseCap := sYes,
	sDeliveryModeManualAllowed := "",
	sAsset := "",
	sCapType := "",
	sCapProduct := "",
	sExpectedIndex := "",
	sIndex := "",
	fQuantity := 0.0,
	fCapPrem := 0.0,
	fCapPremCopy := 0.0,
	fNominal := 0.0,
	fPrice := 0.0,
	// For Contract/Package execution
    sLegRegistration := legGetRegistration( pLeg ),


	// loop on all components
	iNbComponents := legGetNumberOfComponents( pLeg ),
	iComponent := 0,
	WHILE ( iComponent < iNbComponents ) DO
	{
		pComponent := legGetComponentAt( pLeg,iComponent ),
		IF ( legIsInitialized( pComponent ) ) THEN
		{
			sRegistration := legGetRegistration( pComponent ),

			// Force the same quotation and quotation unit between the legs
			IF ( ( sRegistration == "COM Swap" ) OR ( sRegistration == "COM Capacity" ) OR ( sRegistration == "COM Swaption" ) ) THEN
			{
				sQuotation := legGetString( pComponent,"Quotation1" ),
				legSetString( pComponent,"Quotation2",sQuotation ),

				sQuotationUnit := legGetString( pComponent,"QuotationUnit1" ),
				legSetString( pComponent,"QuotationUnit2",sQuotationUnit )
			},

			// Force a zero margin on physical legs
			IF ( ( sRegistration == "COM Swap" )
			OR ( sRegistration == "COM Capacity" )
			OR ( sRegistration == "COM transport" ) ) THEN
			{
				sExercise1 := legGetString( pComponent, "Exercise1" ),
				IF ( sExercise1 == "Physical delivery" ) THEN
					legOverwrite( pComponent,"Price_Margin1",0.0 ),

				sExercise2 := legGetString( pComponent, "Exercise2" ),
				IF ( sExercise2 == "Physical delivery" ) THEN
					legOverwrite( pComponent,"Price_Margin2",0.0 ),

				// In addition, for Transport ( one-leg-swap ), we must force the NPV as implied because there is no other variable available to imply if the user dedices to set an NPV
				IF ( sRegistration == "COM transport" ) THEN
					legSetLocalImplied( pComponent,"Npv" )
			},

			// Block: Capacity index/route lookup, capacity product assignment, pricing
			IF ( ( sRegistration == "COM transport" ) OR ( sRegistration == "COM Capacity" ) ) THEN
			{
				pTradeUdf := legGetUserFields( pComponent ),
				sRoute := strTrim( legGetString( pComponent,"Route" ) ),
				IF ( sRoute <> "" ) THEN
				{
					// Block: pricing formulae for Transport not having to do with the assignment to follow now.
					pCapaCompletion := lookupResults( "MX.COM.Capacity","ALL",
													"Route",sRoute ),
					IF ( toString( pCapaCompletion ) <> "0" ) THEN
					{
						// Find out if capacity matters
						sUseCap := lookupResultsGetString( pCapaCompletion,0,1 ),
						// And if the value may be overridden or not ( default No )
						sDeliveryModeManualAllowed := lookupResultsGetString( pCapaCompletion,0,7 ),
						sOriginalDeliverySettlement := legGetString( pComponent,"Delivery_Settlement" ),

						// Capacity: force use of capacity ( no-brainer... )
						IF ( ( sRegistration == "COM Capacity" ) AND ( sOriginalDeliverySettlement <> sUseCapacity ) ) THEN
							legOverwrite( pComponent,"Delivery_Settlement",sUseCapacity )
						ELSE IF ( sRegistration == "COM transport" ) THEN
						{
							// transport: as a function of the "Allowed" flag, force the Delivery Settlement in line with the lookup table, but avoid unnecessary sets
							IF ( ( sUseCap == sYes ) AND ( sOriginalDeliverySettlement <> sUseCapacity ) ) THEN
							{
								IF ( sDeliveryModeManualAllowed == sYes ) THEN
									legSetString( pComponent,"Delivery_Settlement",sUseCapacity )
								ELSE
									legOverwrite( pComponent,"Delivery_Settlement",sUseCapacity )
							},
							// the following set is ok based on the recommended configuration, but care should be taken with advanced use of the field Delivery_Settlement ( booking a transport trade as a 3-leg SWAP for example ),
							IF ( ( sUseCap == sNo ) AND ( sOriginalDeliverySettlement == sUseCapacity ) ) THEN
							{
								IF ( sDeliveryModeManualAllowed == sYes ) THEN
									legSetString( pComponent,"Delivery_Settlement",sNoUseCapacity )
								ELSE
									legOverwrite( pComponent,"Delivery_Settlement",sNoUseCapacity )
							}
						},

						// then check against expected value
						IF ( legGetString( pComponent, "Delivery_Settlement" ) == sUseCapacity ) THEN
						{
							// Get product type and Capacity type
							sAsset := lookupResultsGetString( pCapaCompletion,0,0 ),
							sCapType := udfGetString( pTradeUdf,"CAP_TYPE" ),
							IF ( sCapType == "" ) THEN
							{
								sCapType := "DAY",
								udfSetString( pTradeUdf,"CAP_TYPE",sCapType )
							},
							/* The following works OK for European gas and power which is MXpress compliant.
							It will need amendment if it is to be extended to other continents' Gas markets due to the Asset field
							Amendment should include:
								* setting up the commodity static data Physical Products that are "attainable" by the Asset / Capacity type combinations
							It may include:
								* setting defaults for the capacity type
								* adding lookup table structures to translate Asset/Capacity type to physical product, if the rules grow too complex
							*/
							sCapProduct := "CAPACITY",
							IF ( sAsset == "GAS EU" ) THEN
								sCapProduct := "CAP NG " + sCapType
							ELSE IF ( sAsset == "PWR EU" ) THEN
								sCapProduct := "CAP PW " + sCapType,

							// now get the index for later and assign the physical product on capacity object
							IF ( sRegistration == "COM Capacity" ) THEN
							{
								sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,2 ),
								legSetString( pComponent,"Physical1",sCapProduct )
							}
							ELSE
							{
								// transport using capacity, take the transport index with capacity, and assign capacity
								sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,3 ),
								pStreams := legGetStreams( pComponent ),
								pCapaObject := streamsGetCapacityObject( pStreams ),
								CapacityObjectSetPhysicalProduct( pCapaObject,sCapProduct )
							}
						}
						ELSE // no effective capacity use
						{
							IF ( sRegistration == "COM transport" ) THEN
								sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,4 )
						},

						IF ( sExpectedIndex == "" ) THEN
							sExpectedIndex := sDefaultIndex, // provide a default, in case the lookup table is not filled

						sIndex := legGetString( pComponent,"Index1" ),
						IF ( ( sExpectedIndex == sDefaultIndex ) OR ( sExpectedIndex <> sIndex ) ) THEN
							legOverwrite( pComponent,"Index1",sExpectedIndex ) // set the index, mandatory by design of the capacity/transport pricing

					},

					/* Block: Capacity price assignment, used in case user customizes UDF "CAP_PREM"
					Capacity pricing in flow unit
					Motivation: capacity is sometimes quoted in [CCY]/MWH ( which is what MX expects )
					But also regularly in [CCY]/MW ( notably for auctions ).
					This price is obtained by multiplying the [CCY]/MWH price with the number of delivery hours.
					This mode of quotation is only relevant for "flat" delivery profiles ( not really for Custom profiles ) because of the different hourly weights allowed in such Custom profiles.
					In this part of the formula, we assure that both formats are availalble to the user and that a user change of teh UDF is propagated to the native field.
					The Closing Rule mx.preTrade.completion.COM.Closing.FCpl contains the inverse: update the UDF with the right price, after the pricing sequence is completed
					( doing it earlier will result in incorrect assignment because the implied price may still change ).
					We use the equivalence [DeliveryHours=TotalQuantity/Nominal] which holds for non-Custom profiles, because the DeliveryHours is not a native field.
					*/
					IF ( sRegistration == "COM Capacity" ) THEN
					{
						fQuantity := legGetNumeric( pComponent,"Quantity" ),
						// Only proceed if not-Custom and Quantity>0 ( = initialized AND deliveryLength>0 )
						IF ( ( legGetString( pComponent,"Volume_profile_type1" ) <> sCustomOTC ) AND ( fQuantity > 0.0 ) ) THEN
						{
							fCapPrem := udfGetNumeric( pTradeUdf,"CAP_PREM" ),
							fCapPremCopy := legGetNumeric(pComponent,"pf_cap_prem"),
							IF ( fCapPrem <> fCapPremCopy ) THEN
							{
								fNominal := legGetNumeric( pComponent,"Nominal" ),
								// the two fields are not equal. This implies that the visible one was changed by the user. React accordingly
								legOverwrite( pComponent,"Price/Margin2",fCapPrem * fNominal / fQuantity ),
								legOverwrite( pComponent,"pf_cap_prem", fCapPrem)
							}
						}
					}
				}
			},
            // Pre-trade code for precious metals spot/forward
            IF ( sRegistration == "COM Spot/Forward" ) THEN
            {
           		// Getting underlying curve quotation
            	pStreams := legGetStreams( pComponent ),		
            	pStream1 := streamsGetStream( pStreams,0,0 ),		
            	pIndex1 := streamGetIndex( pStream1 ),		
            	sCurrencyIndex1 := indexGetCurrency( pIndex1 ),		
            	sQuoteUnit := strToken( indexGetIndexLabel( pIndex1 ), "/", 1 ),	      
            	// Quotation completion
            	sCurveQuot:=sCurrencyIndex1+"/"+sQuoteUnit,
                legOverwrite(pComponent,"pf_COM_curve_quot",sCurveQuot),
            	sPattern := legGetPatternLabel( pComponent ),
                // Paper trading : rules below make pricing behavior similar to FX cash
            	IF ( sPattern == "Spot Forward Paper" ) THEN
                {	
                	// In this configuration "Price" field is used instead of price/margin2
                    fPrice:=legGetNumeric(pComponent,"Price"),   
                    // Make sure the trade price is always in line with customizable market data using solving tool
                	legOverwrite(pComponent,"Trader_Npv",0.),
                    // Fill in the second buy/sell field for display only (FX-like layout)
        			sBuySell := legGetString(pComponent,"Buy_Sell"),
        			IF (sBuySell == "Buy") THEN sBuySell2:="Sell" ELSE sBuySell2:="Buy",
        				legOverwrite(pComponent,"pf_COM_buy_sell2",sBuySell2),                        
                    // Second Nominal management        
                    fUnitConv:=legGetNumeric(pComponent,"Conversion_factor"),
                    sUnit:=legGetString(pComponent,"Nominal_unit"),
                    //Get nominal in metal
                    fNominal1:=legGetNumeric(pComponent,"Nominal"),
                    // Nominal must be brought back to ounces if needed
                    IF sUnit<>sQuoteUnit THEN  
                    	fNominal1:=fNominal1*fUnitConv,
                    // Get net price
                    fNetPrice:=legGetNumeric(pComponent,"NetRate2"),
                    // Get cash nominal
                    fNominal2:=legGetNumeric(pComponent,"pf_COM_nominal2"),
                    // For initialization
                    IF fNominal2==0.0 THEN 
                    {
                    	fNominal2:=fNominal1*fNetPrice,
                    	legSetNumeric(pComponent,"pf_COM_nominal2",fNominal1*fNetPrice)
                    },
                    // Get previous other nominal
                    fPrevious:=legGetNumeric(pComponent,"pf_COM_prev_nom2"), 
                    // Initilization of previous other nominal : by default, Metal nominal leads
                    IF fPrevious==0.00 THEN
                    {
                    	legSetNumeric(pComponent,"pf_COM_prev_nom2",fNominal1*fNetPrice),
                    	fPrevious:=fNominal1*fNetPrice
                    },
                    // Any redundant execution of this code should do nothing
                    IF fNominal1*fNetPrice<>fNominal2 THEN
                    {
                    	// If Nominal 1 has been customized, then change nominal 2
                    	IF fNominal2==fPrevious OR fPrevious*fNetPrice==fNominal2 THEN
                    	{
                    		legOverwrite(pComponent,"pf_COM_nominal2",fNominal1*fNetPrice),
                    		legOverwrite(pComponent,"pf_COM_prev_nom2",fNominal1*fNetPrice)
                    	}
                    	// If nominal 2 has been customized, then change nominal 1
                   	 ELSE IF fNominal1==fPrevious OR fPrevious==fNominal1*fNetPrice THEN
                    	{
                    	legOverwrite(pComponent,"Nominal",fNominal2/(fNetPrice*fUnitConv)),
                    	legOverwrite(pComponent,"pf_COM_prev_nom2",fNominal2/fNetPrice)
                    	}
                    // If nominals are not in line anymore (for example, currency or unit is changed) then back to initial status
                    	ELSE 
                    	{
                    		legOverwrite(pComponent,"pf_COM_nominal2",fNominal1*fNetPrice),
                    		legOverwrite(pComponent,"pf_COM_prev_nom2",fNominal1*fNetPrice)
                    	}
                   	}  
                }
                // Physical trading : defaulting of physical attributes based on the bar/coin selected
                ELSE IF ( sPattern == "Spot Forward Physical" ) THEN
                {
                	sProduct := legGetString( pComponent, "Deliverable"),
                    sForm := legGetString(pComponent,"Form1"),
                    pFormResults := lookupResults( "MX.COM.PM.Form","ALL","Metal",sProduct,"PM Physical Form", sForm ),
                    sQuality := lookupResultsGetString( pFormResults,0,0 ),                            
                    sUnit := lookupResultsGetString( pFormResults,0,1 ),
                    legSetString( pComponent, "Nominal_unit", sUnit),
                   	sUnit:=legGetString(pComponent, "Nominal_unit"),
                   	legSetString( pComponent, "Quotation_unit", sUnit),
                    legSetString(pComponent,"Quality1",sQuality)
                }
                // Cash-settled trading : protecting the fields
                ELSE IF ( sPattern == "Forward Cash-settled" ) THEN
                {
                	legProtectCell( pComponent,"Exercise1",TRUE)                
                }
             },
             // Precious metal unpriced average
             IF ( sRegistration == "COM Physical Forward" ) THEN
             {	
             	 sPattern := legGetPatternLabel( pComponent ),

                 IF sPattern == "Unpriced Average COM" THEN
                 {
                 	// Pricing index defaulting
                 	sProduct := legGetString( pComponent,"Physical" ),
                    sIndex := legGetString( pComponent, "Index" ),                   
                    legSetString( pComponent,"Underlying2", sIndex ),                           
                    // Dates defaulting
                    dPrcEnd := legGetDate(pComponent, "Pricing_end_date"),
                    dDeliveryDefault:=dPrcEnd+shift(dPrcEnd,"+0od","LNB_NYB"),
                    dPaymentDefault:=dDeliveryDefault+shift(dDeliveryDefault,"+2od","LNB_NYB"),
                    legSetDate(pComponent, "Delivery_start_date", dDeliveryDefault),            
                    dDelStart := legGetDate(pComponent, "Delivery_start_date"),
                    legSetDate(pComponent, "Delivery_end_date", dDelStart),
                    dPaymentDefault:=dDelStart+shift(dDelStart,"+2od","LNB_NYB"),
                    legSetDate(pComponent,"Payment_date1", dPaymentDefault),
                    // Physical characteristics defaulting, for precious metal only
                    sCOM_Asset := legGetString(pComponent,"COM Asset"),
                    IF (sCOM_Asset == "PMT")  THEN 
                        {
                        sProduct := legGetString( pComponent, "Physical"),
                        sForm := legGetString(pComponent,"Form1"),
                        pFormResults := lookupResults( "MX.COM.PM.Form","ALL","Metal",sProduct,"PM Physical Form", sForm ),
                        sQuality := lookupResultsGetString( pFormResults,0,0 ),                            
                        sUnit := lookupResultsGetString( pFormResults,0,1 ),
                        legSetString( pComponent, "Nominal_unit", sUnit),
                        sUnit:=legGetString(pComponent, "Nominal_unit"),
                        legSetString( pComponent, "QuotationUnit1", sUnit),
                        legSetString( pComponent, "QuotationUnit2", sUnit),
                        legSetString(pComponent,"Quality1",sQuality)
                        }  
                    }


             }

        },
		iComponent := iComponent + 1       

	},
    // Execution for STB contracts and package (outside the while loop)
    //EFP : Precious metal Exchange of Future for Physical

    		IF (sLegRegistration == "EFP")  THEN
             {  
                pLeg0 := legGetComponentAt(pLeg,0),
                pLeg1 := legGetComponentAt(pLeg,1),                        
                fFuturePrice := legGetNumeric(pLeg0,"Price_Margin2"),
                fPhysicalPrice := legGetNumeric(pLeg1,"Price_Margin2"),             
                fSpread := legGetNumeric(pLeg,"EFP"),
                sLastInput := legGetLastInputField(pLeg),
                // Spread interaction with component price fields
                IF sLastInput =="EFP" OR sLastInput =="Future#1.Price_Margin2" THEN
                	legOverwrite(pLeg1,"Price_Margin2",fFuturePrice-fSpread)
                ELSE
                	legOverwrite(pLeg,"EFP",fFuturePrice-fPhysicalPrice) 

                    },

    //Precious metal Swap (FX-like swap with a near leg and a far leg)
            IF (sLegRegistration == "Metal Swap")
            THEN
            {
                // Get pointers
                pLeg0 := legGetComponentAt(pLeg,0),
                pLeg1 := legGetComponentAt(pLeg,1),
                // Copy Nominal
                fNominal := legGetNumeric(pLeg0,"Nominal"),
                legSetNumeric(pLeg1,"Nominal",fNominal),
                // Link prices
                legSelectOutput(pLeg0,"Price"),
                fPrice1:=legGetNumeric(pLeg0,"Price_Margin2"),
                legOverwrite(pLeg1,"Spot",fPrice1)
            },

    // Precious metal Location Swap
            IF (sLegRegistration == "Location Swap")
            THEN
            {
                // Get pointers
                pLeg0 := legGetComponentAt(pLeg,0),
                pLeg1 := legGetComponentAt(pLeg,1),                         

                //Default unit and quality : leg0
                sProduct := legGetString( pLeg0, "Deliverable"),
                sForm := legGetString( pLeg0,"Form1"),
                pFormResults := lookupResults( "MX.COM.PM.Form","ALL","Metal",sProduct,"PM Physical Form", sForm ),
                sQuality := lookupResultsGetString( pFormResults,0,0 ),                            
                sUnit := lookupResultsGetString( pFormResults,0,1 ),
                legSetString( pLeg0, "Nominal_unit", sUnit),
                sUnit:=legGetString( pLeg0, "Nominal_unit"),
                legSetString( pLeg0, "Quotation_unit", sUnit ),
                legSetString( pLeg0,"Quality1",sQuality ),

                //Copy of physical attributes from one leg to the other
                sForm := legGetString( pLeg0,"Form1"),
                sQuality := legGetString( pLeg0,"Quality1"),
                sDeliveryTerms := legGetString( pLeg0,"Delivery_Terms"),
                legSetString( pLeg1,"Form1",sForm ),
                legSetString( pLeg1,"Quality1",sQuality ),
                legSetString( pLeg1,"Delivery_Terms",sDeliveryTerms ),

                //Default unit and quality : leg1            
                sForm2 := legGetString( pLeg1,"Form1"),
                pFormResults2 := lookupResults( "MX.COM.PM.Form","ALL","Metal",sProduct,"PM Physical Form", sForm2 ),
                sQuality2 := lookupResultsGetString( pFormResults2,0,0 ),                           
                legSetString( pLeg1,"Quality1",sQuality2),

                //Interaction between the fields
                fPrice1 := legGetNumeric( pLeg0,"Price_Margin2"),
                fPrice2 := legGetNumeric( pLeg1,"Price_Margin2"),
                fSpread := legGetNumeric( pLeg,"Location_Spread"),
                sLastInput := legGetLastInputField(pLeg),
            IF sLastInput =="Location_Spread" OR sLastInput =="Spot_fwd#1.Price_Margin2" THEN
            	legOverwrite(pLeg1,"Price_Margin2",fPrice1+fSpread)
            ELSE
            	legOverwrite(pLeg,"Location_Spread",fPrice2-fPrice1)          
            }
};

// mx.msl.event.completion.ALL.Empty

/*
MXpress
Empty event rule

Version  1.0
*/

bEmpty := TRUE;

// mx.preTrade.completion.ALL.ALL.Empty

/*
MXpress
Empty rule

Version  1.0
*/

bEmpty := TRUE;

// mx.preTrade.completion.ALL.ALL.TypA-FXD

/*
MXpress
FXD Typology assignment rule

Version 1.12
Replaced Criteria 4 with Criteria in MX.FXD.TypA-FC

Version 1.11
Applied MSL best practices

Version 1.10
Updated to retrieve the 5th input parameter from the ( MX.FXD.FieldMap,TypoInputField ) LUT in case of mxContractIPACKAGE_SINGLE

Version 1.9
Updated to retrieve the 5th input parameter from the ( MX.FXD.FieldMap,TypoInputField ) LUT

Version 1.8
Use the legGetRegistration function instead the ( MX.ALL.FCCLabel,ALL ) LUT 

Version 1.7
Amendment to handle properly Back-to-back packages

Version 1.6
Amemdments to handle Back-to-back packages

Version 1.5
Addition of Block trade typology

Version 1.4
Amendment to ensure the typology for flexible deals is the same at component and contract levels

Version 1.3
Amendments to handle properly cross asset structures

Version 1.2
Use the Criteria column in MX.FXD.FieldMap Lookup table instead of Context

Version 1.1
Applied MXpress scripted-rules conventions

Version  1.0

Used algorithm:
	1. The typology assignment is based on Look-Up Tables ( LUTs )
	2. Each Package/Contract/Contract Component should have its own typology
	3. Algorithm  for the typology assignment:
		1) Set the typology for the source object ( This )
		2) Check if  "This" is actually a mxContractISINGLE object, 
			If yes, everything is done, exit
			If no, go to step 3)
		3) Loop on the contracts 
			a)Check if "This" is the current contract ( pContract == This ),
				If yes, do nothing ( The contract typology was already assigned )
				If no, assign proper typology for the contract
			b)Loop on the components within the current contract, assign typologies for the contract components
			c)Check if the contract is in a strip
				If yes: 
				-- assing typology for the strip 
				-- loop on the strip and copy the typologies for the other contracts & contract components within the strip
				If no: go to 3) (Continue the loop)
	4. LUT used:
		( MX.FXD.FieldMap, TypoInputField ) : Returns the criteria used for the typology assignment
		( MX.FXD.TypA-FC, ALL) :  Returns the typology label
*/

{
	IF ( legIsInitialized( This ) ) THEN // The rule is applied only when the leg is initialized.
	{
		//Check if This (the source object) is actually the son of a strip.
		//In case it is the son of a strip and not the first son, exit (This is an optimization: the typology was already assigned)
		pFatherLeg := legGetFather( This ),
		bIsSonOfStripNotFirst := FALSE, //Variable initialization
		bIsFirstStripSon := FALSE,
		bIsTradeOnly := ( legGetRegistrationLabel( This ) == "mxContractITRADE" ),
		sBORegistrationThis := legGetRegistrationLabel( This ),

		pPackage := legGetFatherPackage( pFatherLeg ),
		// If the package type is package allocation then define Block trade as typology
		IF ( NOT isNull( pPackage ) AND ( legGetRegistrationLabel( pPackage ) == "mxContractIPACKAGE_ALLOCATION" ) ) THEN
		{
			// Retreive BlockTrade typology to be used in Generic parameters
			sBlockTradeTypology := lookupString( "MX.ALL.GParam","ALL","Key 1","BlockTradeTypology" ),     
			legSetTypology( pPackage,sBlockTradeTypology )
		},

		IF ( NOT isNull( pFatherLeg ) )  THEN
		{
			pFirstStripSon := legGetSonAt( pFatherLeg,0 ),

			IF ( strContain( legGetTitle( pFatherLeg ),"Strip" ) ) THEN
			{
				IF ( pFirstStripSon == This ) THEN
					bIsFirstStripSon := TRUE
				ELSE
					bIsSonOfStripNotFirst := TRUE
			}
		},

		IF ( bIsSonOfStripNotFirst ) THEN
		{
			pFirstStripSon := legGetSonAt( pFatherLeg,0 ),
			sSiblingTypology := legGetTypology( pFirstStripSon ),
			IF ( sSiblingTypology == "" ) THEN
				ThrowError( "Could not assign typology on " + legGetTitle( This ) + " ( Typology assignment rule )", "Typology" )
			ELSE
				legSetTypology( This,sSiblingTypology ),

			sBORegistration := legGetRegistrationLabel( pFirstStripSon ),
			IF ( ( sBORegistration <> "mxContractISINGLE" ) AND ( sBORegistration <> "mxContractITRADE" ) ) THEN
			{
				iCurrentContractComponent := 0,
				iNumContractComponent := legGetNumberOfContracts( pFirstStripSon ),

				WHILE ( iCurrentContractComponent < iNumContractComponent ) DO
				{
					pCurrentContractComponent := legGetComponentAt( This,iCurrentContractComponent ),
					pSiblingContractComponent := legGetComponentAt( pFirstStripSon,iCurrentContractComponent ),

					sSiblingComponentTypology := legGetTypology( pSiblingContractComponent ),
					IF ( sSiblingComponentTypology <> "" ) THEN
						legSetTypology( pCurrentContractComponent,sSiblingComponentTypology ),

					IF ( legGetTypology( pCurrentContractComponent ) == "" ) THEN 
						ThrowError( "Could not assign typology on " + legGetTitle( pCurrentContractComponent ) + " ( Typology assignment rule )", "Typology" ),

					iCurrentContractComponent := iCurrentContractComponent + 1
				}
			}
		}
		ELSE
		{
			//Set the typology to the source object ( This ) if it is not a strip 
			//Get the registration info about This
			pCurrentLeg := This,
			sBORegistration := legGetRegistrationLabel( pCurrentLeg ),  //sBORegistration will give info about the structure of "This".
			IF ( NOT strContain( sBORegistration,"mxContractStbStrip" ) ) THEN
			{
				// Get registration information for the source object (This)
				// Since no function is available to directly return the registration, a LUT is used to do the mapping
				// Once the function is available, use directly sRegistration:=legGetRegistration(pComponent )
				// The mapping LUT uses the Family/Group/Type vector as an input
				IF ( sBORegistration == "mxContractISINGLE" ) OR bIsTradeOnly THEN
					sRegistration:=legGetRegistration( pCurrentLeg )
				ELSE
					sRegistration := legGetTitle( pCurrentLeg ),

				// Generic block for typology assignment
				// First get the assignment criteria from the LUT: MX.FXD.FieldMap.TypoInputField
				// Then retrieve the typology from LUT  MX.FXD.TypA-FC.ALL
				sCol2Value := "DefaultValue",		//Initialize second input parameter value -- "Payout Style" (can carry different name for different registration)
				sCol3Value := "DefaultValue",		// Initialize the third input parameter value -- "Barrier"  can specify whether there is a barrier, or the barrier type
				sCol4Value := "DefaultValue",		// Initialize the fourth input parameter value -- "Model", indicate the model used for FLEX products.
				sFieldCriteria4 := "DefaultValue",	//Initialize the 5th input parameter value -- reserved for future use.

				// Get the field name and position for 2nd input parameter -- "Payout Style"
				pFieldResult := lookupResults( "MX.FXD.FieldMap","TypoInputField",
										"Registration",sRegistration,
										"Criteria","Column2" ),

				IF ( NOT isNull( pFieldResult ) ) THEN
				{
					iLegIdCol2 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
					sFieldNameCol2 := lookupResultsGetString( pFieldResult,0,1 ),

					IF ( iLegIdCol2 == 0 ) THEN
						sCol2Value := legGetString( pCurrentLeg,sFieldNameCol2 )
					ELSE
					{
						IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
						{
							pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol2 - 1 ),
							sCol2Value := legGetString( pComponentCurrentLeg,sFieldNameCol2 )
						}
						ELSE
						{
							pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol2 - 1 ),
							sCol2Value := legGetString( pSonCurrentLeg,sFieldNameCol2 )
						}
					}
				},

				// Get the field name and position for 3rd input parameter -- "Barrier"
				pFieldResult := lookupResults( "MX.FXD.FieldMap","TypoInputField",
										"Registration",sRegistration,
										"Criteria","Column3" ),

				IF ( NOT isNull( pFieldResult ) ) THEN
				{
					iLegIdCol3 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
					sFieldNameCol3 := lookupResultsGetString( pFieldResult,0,1 ),

					IF ( iLegIdCol3 == 0 ) THEN
						sCol3Value := legGetString( pCurrentLeg,sFieldNameCol3 )
					ELSE
					{
						IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
						{
							pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol3 - 1 ),
							sCol3Value := legGetString( pComponentCurrentLeg,sFieldNameCol3 )
						}
						ELSE
						{
							pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol3 - 1 ),
							sCol3Value := legGetString( pSonCurrentLeg,sFieldNameCol3 )
						}
					}
				},

				// Get the field name and position for 4th input parameter -- "Model"
				pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
									"Registration",sRegistration,
									"Criteria","Column4" ),
				IF ( NOT isNull( pFieldResult ) ) THEN
				{
					iLegIdCol4 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
					sFieldNameCol4 := lookupResultsGetString( pFieldResult,0,1 ),

					IF ( iLegIdCol4 == 0 ) THEN
						sCol4Value := legGetString( pCurrentLeg,sFieldNameCol4 )
					ELSE
					{
						IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
						{
							pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol4 - 1 ),
							sCol4Value := legGetString( pComponentCurrentLeg,sFieldNameCol4 )
						}
						ELSE
						{
							pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol4 - 1 ),
							sCol4Value := legGetString( pSonCurrentLeg,sFieldNameCol4 )
						}
					}
				},

				// Get the field name and position for 5th input parameter -- "Criteria 4"
				pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
									"Registration",sRegistration,
									"Criteria","Column5" ),

				IF ( NOT isNull( pFieldResult ) ) THEN
				{
					iLegIdCol5 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
					sFieldNameCol5 := lookupResultsGetString( pFieldResult,0,1 ),

					IF ( iLegIdCol5 == 0 ) THEN
						sFieldCriteria4 := legGetString( pCurrentLeg,sFieldNameCol5 )
					ELSE
					{
						IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
						{
							pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol5 - 1 ),
							sFieldCriteria4 := legGetString( pComponentCurrentLeg,sFieldNameCol5 )
						}
						ELSE
						{
							pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol5 - 1 ),
							sFieldCriteria4 := legGetString( pSonCurrentLeg,sFieldNameCol5 )
						}
					}
				},

				//Get the typology label if it exists for the current object
				sTypology:= lookupString( "MX.FXD.TypA-FC","ALL",
									"Registration", sRegistration,
									"Payout Style",sCol2Value,
									"Barrier",sCol3Value,
									"Model",sCol4Value,
									"Criteria",sFieldCriteria4 ),

				sFirstSiblingTypology := "",
				IF ( sTypology <> "" ) THEN 
				{
					legSetTypology( pCurrentLeg,sTypology ),
					sFirstSiblingTypology := sTypology
				},

				IF ( ( sRegistration == "Flexible Deal" ) AND ( sTypology == "" ) ) THEN
				{
					pFatherContract := legGetFatherContract( pCurrentLeg ),
					sTypology := legGetTypology( pFatherContract ),
					legSetTypology( pCurrentLeg,sTypology ),
					sFirstSiblingTypology := sTypology
				},

				IF ( legGetTypology( pCurrentLeg ) == "" ) THEN
					ThrowError( "Could not assign typology on " + legGetTitle( pCurrentLeg ) + " ( Typology assignment rule )","Typology" ),

				sFirstSiblingRegistration := sRegistration
				//End of the generic block for typology assignment.
			},// End of the assignment for the source object (This)

			//If the the source object is not a mxContractISINGLE, then loop on the contracts
			IF ( ( sBORegistration <> "mxContractISINGLE" ) OR ( bIsFirstStripSon ) ) THEN
			{
				// Scans all Contracts and their components
				iCurrentContract := 0,
				iNumContracts := legGetNumberOfContracts( This ),

				//Loop on the source object.
				//If the source object is a contract, its typology has already been assigned in in first phase
				WHILE ( iCurrentContract < iNumContracts ) DO
				{
					pContract := legGetContractAt( This,iCurrentContract ),
					sBORegistration := legGetRegistrationLabel( pContract ),

					//Check if the source object is the current contract. If yes, exit.
					IF ( pContract <> This ) THEN
					{
						//Get the registration info for the current contract.
						IF ( sBORegistration == "mxContractISINGLE" ) THEN
							sRegistration := legGetRegistration( pContract )
						ELSE
							sRegistration := legGetTitle( pContract ),

						// Generic block for typology assignment
						// First get the assignment criteria from the LUT: MX.FXD.FieldMap.TypoInputField
						// Then retrieve the typology from LUT  MX.FXD.TypA-FC.ALL
						pCurrentLeg := pContract,
						sCol2Value := "DefaultValue",		//Initialize second input parameter value -- "Payout Style" (can carry different name for different registration)
						sCol3Value := "DefaultValue",		// Initialize the third input parameter value -- "Barrier"  can specify whether there is a barrier, or the barrier type 
						sCol4Value := "DefaultValue",		// Initialize the fourth input parameter value -- "Model", indicate the model used for FLEX products.
						sFieldCriteria4 := "DefaultValue",	//Initialize the 5th input parameter value -- reserved for future use.

						// Get the field name and position for 2nd input parameter -- "Payout Style"
						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
												"Registration",sRegistration,
												"Criteria","Column2" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol2 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol2 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol2 == 0 ) THEN
								sCol2Value := legGetString( pCurrentLeg,sFieldNameCol2 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol2 - 1 ),
									sCol2Value := legGetString( pComponentCurrentLeg,sFieldNameCol2 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol2 - 1 ),
									sCol2Value := legGetString( pSonCurrentLeg,sFieldNameCol2 )
								}
							}
						},

						// Get the field name and position for 3rd input parameter -- "Barrier"
						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column3" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol3 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol3 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol3 == 0 ) THEN
								sCol3Value := legGetString( pCurrentLeg,sFieldNameCol3 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol3 - 1 ),
									sCol3Value := legGetString( pComponentCurrentLeg,sFieldNameCol3 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol3 - 1 ),
									sCol3Value := legGetString( pSonCurrentLeg,sFieldNameCol3 )
								}
							}
						},

						// Get the field name and position for 4th input parameter -- "Model"
						pFieldResult := lookupResults( "MX.FXD.FieldMap","TypoInputField",
												"Registration",sRegistration,
												"Criteria","Column4" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol4 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol4 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol4 == 0 ) THEN
								sCol4Value := legGetString( pCurrentLeg,sFieldNameCol4 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol4 - 1 ),
									sCol4Value := legGetString( pComponentCurrentLeg,sFieldNameCol4 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol4 - 1 ),
									sCol4Value := legGetString( pSonCurrentLeg,sFieldNameCol4 )
								}
							}
						},

						// Get the field name and position for 5th input parameter -- "Criteria 4"
						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column5" ),

						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol5 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol5 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol5 == 0 ) THEN
								sFieldCriteria4 := legGetString( pCurrentLeg,sFieldNameCol5 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol5 - 1 ),
									sFieldCriteria4 := legGetString( pComponentCurrentLeg,sFieldNameCol5 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol5 - 1 ),
									sFieldCriteria4 := legGetString( pSonCurrentLeg,sFieldNameCol5 )
								}
							}
						},

						sTypology := lookupString( "MX.FXD.TypA-FC","ALL",
											"Registration",sRegistration, 
											"Payout Style",sCol2Value,
											"Barrier",sCol3Value,
											"Model",sCol4Value,
											"Criteria",sFieldCriteria4 ),

						IF ( sTypology == "" ) THEN  
							ThrowError( "Could not assign typology on " + legGetTitle( pCurrentLeg ) + " ( Typology assignment rule )", "Typology" )
						ELSE
							legSetTypology( pCurrentLeg,sTypology ),

						//End of the generic block for typology assignment.
						sFirstSiblingRegistration := sRegistration,
						sFirstSiblingTypology := sTypology
					},//End of typology assignment for current contract.

					//Check if the current contract is actually a mxContractISINGLE. If not, run through its components.
					IF ( ( sBORegistration <> "mxContractISINGLE" ) AND ( sBORegistration <> "mxContractITRADE" ) ) THEN
					{
						iCurrentContractComponent := 0,
						iNumContractComponent := legGetNumberOfComponents( pContract ),	//the total component number of the current contract.

						WHILE ( iCurrentContractComponent < iNumContractComponent ) DO
						{
							pCurrentContractComponent := legGetComponentAt( pContract,iCurrentContractComponent ),
							sRegistration := legGetRegistration( pCurrentContractComponent ),

							// Generic block for typology assignment
							// First get the assignment criteria from the LUT: MX.FXD.FieldMap.TypoInputField
							// Then retrieve the typology from LUT  MX.FXD.TypA-FC.ALL
							pCurrentLeg := pCurrentContractComponent,
							sCol2Value := "DefaultValue",		//Initialize second input parameter value -- "Payout Style" (can carry different name for different registration)
							sCol3Value := "DefaultValue",		// Initialize the third input parameter value -- "Barrier"  can specify whether there is a barrier, or the barrier type
							sCol4Value := "DefaultValue",		// Initialize the fourth input parameter value -- "Model", indicate the model used for FLEX products.
							sFieldCriteria4 := "DefaultValue",	//Initialize the 5th input parameter value -- reserved for future use.

							// Get the field name and position for 2nd input parameter -- "Payout Style"
							pFieldResult := lookupResults( "MX.FXD.FieldMap","TypoInputField",
													"Registration",sRegistration,
													"Criteria","Column2" ),
							IF ( NOT isNull( pFieldResult ) ) THEN
							{
								iLegIdCol2 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
								sFieldNameCol2 := lookupResultsGetString( pFieldResult,0,1 ),

								IF ( iLegIdCol2 == 0 ) THEN
									sCol2Value := legGetString( pCurrentLeg,sFieldNameCol2 )
								ELSE
								{
									IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
									{
										pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol2 - 1 ),
										sCol2Value := legGetString( pComponentCurrentLeg,sFieldNameCol2 )
									}
									ELSE
									{
										pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol2 - 1 ),
										sCol2Value := legGetString( pSonCurrentLeg,sFieldNameCol2 )
									}
								}
							},
							// Get the field name and position for 3rd input parameter -- "Barrier"
							pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
													"Registration",sRegistration,
													"Criteria","Column3" ),
							IF ( NOT isNull( pFieldResult ) ) THEN
							{
								iLegIdCol3 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
								sFieldNameCol3 := lookupResultsGetString( pFieldResult,0,1 ),

								IF ( iLegIdCol3 == 0 ) THEN
									sCol3Value := legGetString( pCurrentLeg,sFieldNameCol3 )
								ELSE
								{
									IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
									{
										pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol3 - 1 ),
										sCol3Value := legGetString( pComponentCurrentLeg,sFieldNameCol3 )
									}
									ELSE
									{
										pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol3 - 1 ),
										sCol3Value := legGetString( pSonCurrentLeg,sFieldNameCol3 )
									}
								}
							},
							// Get the field name and position for 4th input parameter -- "Model"
							pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
												"Registration",sRegistration,
												"Criteria","Column4" ),
							IF ( NOT isNull( pFieldResult ) ) THEN
							{
								iLegIdCol4 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
								sFieldNameCol4 := lookupResultsGetString( pFieldResult,0,1 ),

								IF ( iLegIdCol4 == 0 ) THEN
									sCol4Value := legGetString( pCurrentLeg,sFieldNameCol4 )
								ELSE
								{
									IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
									{
										pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol4 - 1 ),
										sCol4Value := legGetString( pComponentCurrentLeg,sFieldNameCol4 )
									}
									ELSE
									{
										pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol4 - 1 ),
										sCol4Value := legGetString( pSonCurrentLeg,sFieldNameCol4 )
									}
								}
							},

							sTypology:= lookupString( "MX.FXD.TypA-FC","ALL",
												"Registration", sRegistration,
												"Payout Style",sCol2Value,
												"Barrier",sCol3Value,
												"Model",sCol4Value,
												"Criteria",sFieldCriteria4 ),

							IF ( sTypology <> "" ) THEN
								legSetTypology( pCurrentLeg,sTypology ),

							IF ( sRegistration == "Flexible Deal" ) THEN
							{
								pFatherContract := legGetFatherContract( pCurrentLeg ),
								sTypology := legGetTypology( pFatherContract ),
								legSetTypology( pCurrentLeg,sTypology )
							},

							IF ( legGetTypology( pCurrentLeg ) == "" ) THEN
								ThrowError( "Could not assign typology on " + legGetTitle( pCurrentLeg ) + " ( Typology assignment rule )", "Typology" ),

							//End of the generic block for typology assignment.
							//End of thje typology asisgnment for current contract component
							iCurrentContractComponent := iCurrentContractComponent + 1
						}
					},

					//Check if the current contract is in a strip. 
					//If so, assign typology for the strip and copy the typologies for the other contarcts within the strip.
					pFatherLeg := legGetFather( pContract ),
					IF ( ( NOT isNull( pFatherLeg ) ) AND ( strContain( legGetTitle( pFatherLeg ),"Strip") ) ) THEN
					{
						//There should be a generic function to retreive this info.
						sRegistration := "Strip of " + sFirstSiblingRegistration, 

						// Generic block for typology assignment
						pCurrentLeg := pFatherLeg,
						sCol2Value := "DefaultValue",
						sCol3Value := "DefaultValue",
						sCol4Value := "DefaultValue",
						sFieldCriteria4 := "DefaultValue",

						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column2" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol2 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol2 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol2 == 0 ) THEN
								sCol2Value := legGetString( pCurrentLeg,sFieldNameCol2 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol2 - 1 ),
									sCol2Value := legGetString( pComponentCurrentLeg,sFieldNameCol2 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol2 - 1 ),
									sCol2Value := legGetString( pSonCurrentLeg,sFieldNameCol2 )
								}
							}
						},

						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column3" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol3 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol3 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol3 == 0 ) THEN
								sCol3Value := legGetString( pCurrentLeg,sFieldNameCol3 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol3 - 1 ),
									sCol3Value := legGetString( pComponentCurrentLeg,sFieldNameCol3 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol3 - 1 ),
									sCol3Value := legGetString( pSonCurrentLeg,sFieldNameCol3 )
								}
							}
						},

						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column4" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol4 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol4 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol4 == 0 ) THEN
								sCol4Value := legGetString( pCurrentLeg,sFieldNameCol4 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol4 - 1 ),
									sCol4Value := legGetString( pComponentCurrentLeg,sFieldNameCol4 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol4 - 1 ),
									sCol4Value := legGetString( pSonCurrentLeg,sFieldNameCol4 )
								}
							}
						},

						pFieldResult:= lookupResults( "MX.FXD.FieldMap","TypoInputField",
											"Registration",sRegistration,
											"Criteria","Column5" ),

						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLegIdCol5 := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sFieldNameCol5 := lookupResultsGetString( pFieldResult,0,1 ),

							IF ( iLegIdCol5 == 0 ) THEN
								sFieldCriteria4 := legGetString( pCurrentLeg,sFieldNameCol5 )
							ELSE
							{
								IF ( sBORegistrationThis == "mxContractIPACKAGE_SINGLE" ) THEN
								{
									pComponentCurrentLeg := legGetComponentAt( pCurrentLeg,iLegIdCol5 - 1 ),
									sFieldCriteria4 := legGetString( pComponentCurrentLeg,sFieldNameCol5 )
								}
								ELSE
								{
									pSonCurrentLeg := legGetSonAt( pCurrentLeg,iLegIdCol5 - 1 ),
									sFieldCriteria4 := legGetString( pSonCurrentLeg,sFieldNameCol5 )
								}
							}
						},

						sTypology:= lookupString( "MX.FXD.TypA-FC","ALL",
											"Registration", sRegistration, 
											"Payout Style",sCol2Value,
											"Barrier", sCol3Value,
											"Model",sCol4Value,
											"Criteria",sFieldCriteria4 ),

						IF ( sTypology <> "" ) THEN
							legSetTypology( pCurrentLeg,sTypology ),
						IF ( ( sRegistration == "Flexible Deal" ) AND ( sTypology == "" ) ) THEN
						{
							pFatherContract := legGetFatherContract( pCurrentLeg ),
							sTypology := legGetTypology( pFatherContract ),
							legSetTypology( pCurrentLeg,sTypology )
						},

						IF ( legGetTypology( pCurrentLeg ) == "" ) THEN
							ThrowError( "Could not assign typology on " + legGetTitle( pCurrentLeg ) + " ( Typology assignment rule )", "Typology" ),

						//End of generic block for typology assignment.
						// End of the assignment for the father strip 

						//Loop on the strip to copy the typologies.
						iCurrentStripContract := 1,  //The first contract has been handled. So begin with the second one.
						iNumStripContract := legGetNumberOfSons( pFatherLeg ),  //Get the number of sons of the strip
						WHILE ( iCurrentStripContract < iNumStripContract ) DO
						{
							pCurrentStripContract := legGetSonAt( pFatherLeg,iCurrentStripContract ),

							//sFirstSiblingTypology is the typology for the first contract in the strip.

							IF ( sFirstSiblingTypology == "" ) THEN
								ThrowError( "Could not assign typology on " + legGetTitle( pCurrentStripContract ) + " ( Typology assignment rule )", "Typology" )
							ELSE
								legSetTypology( pCurrentStripContract,sFirstSiblingTypology ),

							//If the strip son is not a mxContractISINGLE",  run through the components and copy the typologies from first contract components.
							IF ( ( sBORegistration <> "mxContractISINGLE" ) AND ( sBORegistration <>  "mxContractITRADE" ) ) THEN
							{
								iCurrentStripContractComponent := 0,
								iNumStripContractComponent := iNumContractComponent,

								WHILE ( iCurrentStripContractComponent < iNumStripContractComponent ) DO
								{
									pCurrentStripContractComponent := legGetComponentAt( pCurrentStripContract,iCurrentStripContractComponent ),

									pSiblingContractComponent := legGetComponentAt( pContract,iCurrentStripContractComponent ),
									sSiblingTypology := legGetTypology( pSiblingContractComponent ),

									IF ( sSiblingTypology == "" ) THEN
										ThrowError( "Could not assign typology on " + legGetTitle( pCurrentStripContractComponent ) + " ( Typology assignment rule )", "Typology" )
									ELSE
										legSetTypology( pCurrentStripContractComponent,sSiblingTypology ), 

									iCurrentStripContractComponent := iCurrentStripContractComponent + 1
								}
							},
							iCurrentStripContract := iCurrentStripContract + 1
						},
						iCurrentContract := iCurrentContract + iNumStripContract - 1
					},
					iCurrentContract := iCurrentContract + 1
				}
			}
		},

		//To assign a typology in case of Back-to-back
		pPackage := legGetFatherPackage( legGetFather( This ) ),
		sBORegistrationPackage := legGetRegistrationLabel( pPackage ),
		IF ( sBORegistrationPackage == "mxContractIPACKAGE_SINGLE" ) THEN
		{
			pContract := legGetFather( This ),
			sContractRegistration := legGetRegistration( pContract ),

			//Gets the package typology from the LUT
			sTypology := lookupString( "MX.FXD.TypA-PK","ALL",
									"Package Label",sBORegistrationPackage,
									"Registration",sContractRegistration ),

			IF ( sTypology == "" )  THEN
				//Throws an error if no typology was assigned to the package
				ThrowError( "Could not assign typology on package ( Typology assignment  rule )","Typology" )
			ELSE
				//Sets the package typology
				legSetTypology( pPackage,sTypology )
		}
	}
};

 // mx.preTrade.completion.ALL.ALL.TypA-FXMM

/*
MXpress
FXMM Typology assignment rule

Version 1.23
- To remove the multi leg swap references

Version 1.22
- To handle FTP packages
- Fix the package typology assignment

Version 1.21
- Amend to handle Non deliverable loan/deposit deals

Version 1.20
- Amended to handle the Brokerage Fee.

Version 1.19
- Applied MSL best practices
- Remove Par Forward Contract trade typology assignment

Version 1.18
Amended to handle the renaming of USD T-Bill into T-Bill

Version 1.17
Amended to handle:
- SCFs assigned by the cash reconciliation tool
- Pay In Schedule Type for SCF

Version 1.16
Amended to handle STB contract

Version 1.15
Amended to handle Islamic deals

Version 1.14
Amended to handle Fixing deals

Version 1.13
Amended to handle Prorata

Version 1.12
Amended to handle the column change applied on the (MX.FXMM.TypA-PK,ALL) lookup table

Version 1.11
Use the legGetRegistration function instead the ( MX.ALL.FCCLabel,ALL ) LUT 

Version 1.10
Amendments to handle
- properly cross asset structures
- collateral management for Call deposits

Version 1.9
- Do not assign typologies on mxContractStbIPACKAGE

Version 1.8
- Remove Repo trade typology assignment

Version 1.7
- The structure of the ( MX.FXMM.TypA-PK,ALL ) LUT has changed: column Payout is no more used

Version 1.6
-Remove typology assignment for Cash Transfer and IB Account

Version 1.5
- Correct the generator name to handle US T-Bill

Version 1.4
- Callable field is now available for Loans/Deposits

Version 1.3
- If the start date is equal to the maturity date, the FX spot-forward should not be considered as a callable deal

Version 1.2
- Add the Call Deposit and Call Loan typologies

Version 1.1
- An exotic FX deal with a maturity of spot should have a typology corresponding to the exotic and not spot
- Second delivery criteria: a Split Value typology is assigned only if second delivery = "Yes" and maturity date <> second delivery date

Version 1.0
The purpose of this rule is to assign a typology to each package,each contract and each financial contract component
This rule is designed for FXMM products,it uses a set of Look-Up Tables ( LUT ):
( MX.FXMM.TypA-PK,ALL ) contains the typology assignment formula logic for packages
( MX.FXMM.TypA-FC,ALL ) contains the typology assignment formula logic for financial contracts
*/

{
	pLeg := This,
	sPIS := "",
	bIsTradeOnly := ( legGetRegistrationLabel( This ) == "mxContractITRADE" ),

	IF ( legIsInitialized( pLeg ) ) THEN
	{
		pMainComponent := legGetMainComponent( pLeg ),
		pMainContract := legGetFatherContract( pMainComponent ),

		// Constants
		// These variables are used to lookup up the maturity as retrieved from the internal typology
		// And map it to a  more explicit sring. Both strings are stored in "priority" order 
		// The most "important" priority is passed to the contract ( in case of swap )
		sMATURITY_FROM := "???/FWD/TDY/TOM/SPT",
		sMATURITY_TO := "???/FORWARD/TODAY/TOMORROW/SPOT",

		// Contract typology assignment

		// The algorithm loops on all contracts in descending order.
		// The reason for this is that the main contract ( the contract that contains the main component ) is usually the first one. 
		// This way,variables are properly set to assign the package typology: this is an optimization.
		// In pathological cases ( imported deals with contracts passed in random order ) ...
		// ... the main contract is skipped if not encountered in first position( =last iteration ),and handled at the end.

		bEndsWithMainContract := TRUE,// Variable Initialization

		iNbContracts := legGetNumberOfContracts( pLeg ),
		iContract := iNbContracts - 1,//This is the last contract,the first one having the index 0

		IF ( bIsTradeOnly ) THEN 
			iContract := iNbContracts,

		//The block of code is executed until all contracts have been looped through ...
		//... or if it is required to handle the main contract that was found in a previous iteration ...
		//... in a position different from the first one
		WHILE ( ( iContract > -1 ) OR ( NOT bEndsWithMainContract ) ) DO 
		{
			IF ( bIsTradeOnly ) THEN
				pContract := pLeg             
			// Usual case: Looping through the contracts in descending order,not all contracts have been looped through yet
			ELSE IF ( iContract > -1 ) THEN
				pContract := legGetContractAt( pLeg,iContract )
			// iContract <=-1,this means that all contracts have been looped through
			// In this final iteration,the purpose is to handle the main contract that was skipped in a previous iteration
			ELSE 
			{
				pContract := pMainContract,// pContract points to the main contract since it was skipped when it was detected
				bEndsWithMainContract := TRUE //bEndsWithMainContract is set to TRUE to exit the loop at the end of the current and final iteration
			},

			// This is the main contract and it is not in the first position
			// Skip it and sets the bEndsWithMainContract boolean to FALSE,this will be used to enter the WHILE ... loop one last time ...
			// ... after the contract with index O was taken care of  in order to handle the main contract
			IF ( ( pContract == pMainContract ) AND ( iContract > 0 ) ) THEN 
			{
				iContract := iContract - 1,
				pContract := legGetContractAt( pLeg,iContract ),
				bEndsWithMainContract := FALSE
			},

			iNbComponents := legGetNumberOfComponents( pContract ),//Number of components in the main contract
			iComponent := 0,//Initialization of the component index

			// Variable initialization
			iContractMaturity := 0,//This is the maturity index in the maturity constant ( pseudo-list ) defined above
			bContractNonDeliverable := FALSE,
			bContractCallable := FALSE,

			// For each contract,loop on all the components within the contract
			WHILE ( iComponent < iNbComponents ) DO
			{
				pComponent := legGetComponentAt( pContract,iComponent ),

				// Fields Initialization/Reset
				sTypology := "",
				iMaturity := 0,//This is the maturity index in the maturity constant ( pseudo-list ) defined above
				sMaturity := "",//This is the maturity label mapped from the maturity constant ( pseudo-list ) defined above
				sNonDeliverable := "",
				sFixing := "",
				sSecondDelivery := "",
				sCallable := "",
				sProrata := "",
				sPayout := "",
				sPattern := "",
				sGenerator := "",

				sRegistration := legGetRegistration( pComponent ),

				// If sRegistration == Futures there is nothing else to test

				// Spot/Forwards
				// For Spot/Forwards,flags are stored for the contract in case the contract is a swap
				// E.g. if any Spot/Forward within a swap ( Fx swap ... ) is callable,the swap is callable
				IF ( ( sRegistration == "Spot-Forward" ) OR ( sRegistration == "Forex-Swap Leg" ) ) THEN
				{
					// The Internal typology for Spot/Forwads has the form:
					// MAT[FXG|CAL][NDF] where MAT is the maturity: TDY/TOM/SPT/FWD
					//
					// It is used rather than ( complex ) date computations because date computation involves retrieving calendar/shifter
					// Note: maturity ( spot,tdy... ) is computed wrt the trade date ( not the system date )
					// It may change during a Cancel&Reissue / Restructure.

					//This is the internal typology
					sInternalTypology := legGetInternalTypology( pComponent ),

					// Look-Up to get a  more expressive names for the maturity
					//Gets the maturity index in sMATURITY_FROM
					iMaturity := strIndexOf( sMATURITY_FROM,strSubString( sInternalTypology,0,3 ) )/4,
					//Determines the intelligible maturity label
					sMaturity := strToken( sMATURITY_TO,"/",iMaturity ),

                     //BAB addition
                    IF sMaturity == "TODAY" OR sMaturity =="TOMORROW" THEN
                     {	
                     	sMaturity:="SPOT"
                     }, 
					// Most "important" maturity
					// This value will be passed to the contract,in case of an FX Swap 
					// ( or more generally a multi-component contract ) and even to the package ( if this is the main contract )
					iContractMaturity := MAX( iContractMaturity,iMaturity ),

					// Callable
					// Using field ( alternative: using internal typology )
					sStartDate := legGetString( pComponent,"Callable window" ),
					sMaturityDate := legGetString( pComponent,"Maturity label" ),
					IF ( sStartDate == sMaturityDate ) THEN
						sCallable := "No"
					ELSE
						sCallable := legGetString( pComponent,"Callable" ),
					bContractCallable := bContractCallable OR ( sCallable == "Yes" ),//Tells whether the contract is callable

					// Non deliverable
					// Using a native field ( alternative: use the internal typology )
					sNonDeliverable := legGetString( pComponent,"Non deliverable" ),
					bContractNonDeliverable := bContractNonDeliverable OR ( sNonDeliverable == "Yes" ),//Tells whether the contract is non-deliverable

					// FX Fixing
					sFixing := legGetString( pComponent,"Fixing" ),
					IF ( sFixing == "Fix Price" ) OR ( sFixing == "Fix Spot" ) THEN //Tells whether the contract is FX Fixing
						sFixing := "Yes"
					ELSE
						sFixing := "No",

					// 2nd delivery
					sSecondDelivery := legGetString( pComponent,"Second delivery" ),
					dMaturityDate := legGetDate( pComponent,"Maturity" ),
					dSecondDeliveryDate := legGetDate( pComponent,"Second del date" ),

                     //BAB Addition for the UDF accounting
                    pTradeUDF:=legGetUserFields(pComponent),
                    sSecondDeliveryCurr := legGetString( pComponent,"Second del currency" ),
                    sDenUnit := legGetString( pComponent,"Den unit" ),
                    fDenNominal :=legGetNumeric( pComponent,"Den nominal" ),
                    sNumUnit :=legGetString( pComponent,"Num unit" ),
                    fNumNominal :=legGetNumeric( pComponent,"Num nominal" ),
                    sDenBuySell := legGetString( pComponent,"Den Buy Sell" ),
                    sNumBuySell := legGetString( pComponent,"Num Buy Sell" ),
                    //end of BAB addition

					IF ( ( sSecondDelivery == "Yes" ) AND ( dMaturityDate <> dSecondDeliveryDate ) ) THEN
						sSecondDelivery := "Yes"
					ELSE
						sSecondDelivery := "No",

                      //BAB addition for UDF accounting

                    IF ( sSecondDelivery == "Yes" ) THEN
                    {

                        udfSetDate(pTradeUDF,"VDATE1",dMaturityDate),

                        IF (sSecondDeliveryCurr == sDenUnit AND sDenBuySell == "Buy") THEN

                         	{ 

                              udfSetString(pTradeUDF,"SVCURR2",sDenUnit),
                              udfSetString(pTradeUDF,"SVCURR1",sNumUnit),
                              udfSetNumeric(pTradeUDF,"SVNOM2",fDenNominal),
	                          udfSetNumeric(pTradeUDF,"SVNOM1",-fNumNominal)                    
                        	},

                         IF (sSecondDeliveryCurr == sDenUnit AND sDenBuySell == "Sell") THEN

                         	{ 

                              udfSetString(pTradeUDF,"SVCURR2",sDenUnit),
                              udfSetString(pTradeUDF,"SVCURR1",sNumUnit),
                              udfSetNumeric(pTradeUDF,"SVNOM2",-fDenNominal),
	                          udfSetNumeric(pTradeUDF,"SVNOM1",fNumNominal)                    
                        	},

                        IF (sSecondDeliveryCurr == sNumUnit AND sNumBuySell == "Buy")  THEN

                        { udfSetString(pTradeUDF,"SVCURR2",sNumUnit),
                          udfSetString(pTradeUDF,"SVCURR1",sDenUnit),
                          udfSetNumeric(pTradeUDF,"SVNOM2",fNumNominal),
                          udfSetNumeric(pTradeUDF,"SVNOM1",-fDenNominal)
                        },

                        IF (sSecondDeliveryCurr == sNumUnit AND sNumBuySell == "Sell")  THEN

							{ udfSetString(pTradeUDF,"SVCURR2",sNumUnit),
                              udfSetString(pTradeUDF,"SVCURR1",sDenUnit),
                              udfSetNumeric(pTradeUDF,"SVNOM2",-fNumNominal),
	                          udfSetNumeric(pTradeUDF,"SVNOM1",fDenNominal)
                        	}


                        },
                     //end of BAB addition

					// Prorata
					sProrata := legGetString( pComponent,"Prorata" ),
                    sPattern := legGetPatternLabel( pContract ),
                     //BAB Addition
                    //Typology assignment based on Usage when Usage is FX Waad or FX Mura, mainly for Murabaha deals
                 /*   IF(sPattern=="FX Forward" OR sPattern=="FX Forward Split") THEN
                    {
                    legSetIsCustomizedUsage(pContract,TRUE),
                    sUsage := legGetUsage(pComponent),
                    sPattern := sUsage,
                    //test
                    IF(legGetPatternLabel( pContract )=="FX Forward Split") THEN
                    {
                   // pPackage:=legGetFatherPackage(pContract),
                    pMainDeal:=legGetMainComponent(pContract),
                   // sMainTypology:=legGetTypology(pMainDeal),
                    sUsageMain := legGetUsage(pMainDeal),
                    sPattern := sUsageMain
                    }

                    }  ,        */           
                    //End of BAB Addition
                     //BAB Addition
                    IF sPattern == "Spot Split" OR sPattern == "Outright Split" OR sPattern == "Spot Split HVA" THEN
                    {
                     pPackage := legGetFatherPackage( pContract ),
					 IF ( NOT isNull( pPackage ) ) THEN //If there is a package
					 {
                     	sPackageTypology:=legGetTypology(pPackage),
                        IF sPackageTypology =="Split Spot" THEN
                        sPattern:="Spot Split"
                        ELSE
                        sPattern:="Outright Split"
                     }
                     } 
                    //End of BAB Addition
				}
				// Short Papers
				ELSE IF ( sRegistration == "CP/CD" ) THEN
				{
					// for T-Bills
					sGenerator := legGetString( pComponent,"Generator" ),
					IF ( strContain( sGenerator,"BILL" ) ) THEN
						sGenerator := "BILL"
					ELSE
					{
						// Pattern
						// ... Dependent on how the deal is entered...
						sPattern := legGetPatternLabel( pContract )
					}
				}
				// Loan/Deposits
				ELSE IF ( sRegistration == "Loans/Deposits" ) THEN
				{
					// Payout
					// Using a native field ( alternative: use the internal typology )
					sPayout := legGetString( pComponent,"Payout" ),
					// Callable
					sCallable := legGetString( pComponent,"Callable" ),
					IF ( sCallable <> "No" ) THEN
						sCallable := "Yes",
					bContractCallable := bContractCallable OR ( sCallable == "Yes" ),
					// Pattern
					// ... Dependent on how the deal is entered...
                                        //BAB Addition
                    //Typology assignment based on Usage when Usage is DI or BA, mainly for Murabaha deals
                 /*   legSetIsCustomizedUsage(pContract,TRUE),
                    sUsage := legGetUsage(pComponent),
                    sOriginalPattern := legGetPatternLabel(pContract),
                    IF ( ( sUsage == "DI" OR sUsage =="BA" ) AND ( legGetPatternLabel(pContract)=="Murabaha Borrowing" OR legGetPatternLabel(pContract)=="Murabaha Placement" OR legGetPatternLabel(pContract)=="LTM Vanilla") )  THEN
                    {
                        	sPattern := sOriginalPattern+sUsage

                    }
                    //End of BAB Addition */
                    //For all other cases
                   // ELSE
					sPattern := legGetPatternLabel( pContract ),
                    //Non deliverable
                    pStreams := legGetStreams( pComponent ),
                    IF ( NOT isNull( pStreams ) ) THEN
                    {
                        iNbPhases := streamsGetNumberOfPhases( pStreams ),
                        iPhase := 0,
                        WHILE ( iPhase < iNbPhases ) DO
                        {
                            pStream := streamsGetStream( pStreams,iPhase,0 ),
                            IF ( NOT isNull(pStream) ) THEN
                            {
                                pStreamGenerator := streamGetGenerator( pStream ),
                                IF ( NOT isNull( pStreamGenerator ) ) THEN
                                	bMultiCurrency := streamGeneratorIsMultiCurrency( pStreamGenerator )
                            },
                            IF ( bMultiCurrency ) THEN
                            	sNonDeliverable := "Yes",

                            iPhase := iPhase + 1
                        }
					},        
                    bContractNonDeliverable := bContractNonDeliverable OR ( sNonDeliverable == "Yes" )
				}
				// Call deposits
				ELSE IF ( sRegistration == "Call deposits" ) THEN
				{
					// Payout
					// Using a native field ( alternative: use the internal typology )
					sPayout := legGetString( pComponent,"Payout" )
				},

				// CLS: Get the Pay In Schedule Type based on the trade information IN_OUT and PIS_TYPE
				IF ( sRegistration == "Simple cash flow" ) THEN
				{
					sPattern := legGetPatternLabel( pContract ),
                	sInOut := legGetString( pComponent,"IN_OUT" ),
					sPisType := legGetString( pComponent,"PIS_TYPE" ),
					IF ( ( sInOut == "IN" ) AND ( sPisType == "IPIS" ) ) THEN
						sPIS := "IPIS_IN"
					ELSE IF ( ( sInOut == "OUT" ) AND ( sPisType == "IPIS" ) ) THEN
						sPIS := "IPIS_OUT"
					ELSE IF ( ( sInOut == "IN" ) AND ( sPisType == "RPIS" ) ) THEN
						sPIS := "RPIS_IN"
					ELSE IF ( ( sInOut == "OUT" ) AND ( sPisType == "RPIS" ) ) THEN
						sPIS := "RPIS_OUT"
				},

               //BAB addition for the Loan inside the Dual CUr Deposit
               sMainRegistration := legGetRegistration( pMainContract ),
               IF sMainRegistration == "Dual Cur Deposit" THEN
               {
              	 sPattern := legGetPatternLabel( pMainContract )
               },
               //end of BAB addition

				// Handle the SCFs booked by the Cash Reconciliation tool
				sSourceModule := legGetSourceModule( pComponent ),
				sNostroCashRecActivated := strToUpperCase( lookupString( "MX.ALL.GParam","ALL",
																		"Key 1","NostroCashReconciliation" ) ),

                IF sRegistration == "Simple cash flow" THEN
                sVATWHT := strToUpperCase(legGetString(pComponent,"VAT_WHT")), //BAB addition for below typology assignment

				IF ( ( sSourceModule == "rec.nostroCashRec" )
				AND  ( sRegistration == "Simple cash flow" )
				AND  ( sNostroCashRecActivated == "YES" ) ) THEN
				{
					// Keep the typology that has been specified during the booking
					sTypology := legGetTypology( pComponent )
				}
                //BAB addition for WHT and VAT SCF's inserted via workflow from OPS
                ELSE IF ( (sRegistration == "Simple cash flow") AND sVATWHT == "YES" )  THEN
                {
                	sTypology := legGetTypology(pComponent)
                }
                //End of BAB addition

				// Default logic
				ELSE
				{
					//This gets the typology from the LUT
					sTypology := lookupString( "MX.FXMM.TypA-FC","ALL",
											"Registration",sRegistration,
											"Non Deliverable",sNonDeliverable,
											"Second Delivery",sSecondDelivery,
											"Callable",sCallable,
											"Prorata",sProrata,
											"Fixing",sFixing,
                                            "Pattern Templ",sPattern,
											"Maturity",sMaturity,
											"Generator",sGenerator,
											"Pay In Schedule Type",sPIS )
				},

				IF ( sTypology == "" )  THEN
                {
                	//Call the IRD scripted rule to assign IRD typology for FTP components
                    //In case of non-assigned typology, the error is pushed in the IRD typology scripted rule
                	callPreTradeFormula(pContract, "mx.completion.ALL.ALL.TypA-IRD")
                }
				ELSE
					//Sets the component typology
					legSetTypology( pComponent,sTypology ),

				iComponent := iComponent + 1
			},

			// Now handling the contract
			// Values have been set to variables

			// If the contract is not part of an STB contract
			IF NOT ( bIsTradeOnly ) THEN
			{
				sContractRegistrationLabel := legGetRegistrationLabel( pContract ),
				// If the contract is a Contract Single le ( i.e. with only one component ),assign the component typology to the contract           
				IF  ( sContractRegistrationLabel == "mxContractISINGLE" ) THEN 
					legSetTypology( pContract,sTypology )
				// Else if the contract is a Swap or a ParForward
				ELSE IF ( ( strContain( sContractRegistrationLabel,"SWAP" ) ) 
				OR ( strContain( sContractRegistrationLabel,"PARFORWARD" ) ) ) 
				OR ( sContractRegistrationLabel == "mxContractStbICONTRACT" ) THEN
				{
					// A set of variables is known:
					// - Maturity ( passed through iContractMaturity )
					// - Non deliverable ( passed through bContractNonDeliverable )
					// - Callable ( passed throught bContractCallable )
					// For maturity,the value is the "index" within the "/"-separated constant string
					// The index is mapped back to the string
					IF ( strContain( sContractRegistrationLabel,"SWAP" ) ) THEN
						sRegistration := "FX swap"
					ELSE
						sRegistration := legGetRegistration( pContract ),

					sMaturity := strToken( sMATURITY_TO,"/",iContractMaturity ),//The maturity string
					IF ( bContractNonDeliverable ) THEN 
						sNonDeliverable := "Yes" 
					ELSE 
						sNonDeliverable := "No",

					IF ( bContractCallable ) THEN 
						sCallable := "Yes" 
					ELSE 
						sCallable := "No",

					//This gets the typology from the LUT
					sTypology := lookupString( "MX.FXMM.TypA-FC","ALL",
											"Registration",sRegistration,
											"Non Deliverable",sNonDeliverable,
											"Second Delivery",sSecondDelivery,
											"Callable",sCallable,
											"Prorata",sProrata,
											"Fixing",sFixing,
                                            "Pattern Templ",sPattern,
											"Maturity",sMaturity,
											"Generator",sGenerator,
											"Pay In Schedule Type",sPIS ),

					IF ( sTypology == "" )  THEN
						//Throws an error if no typology was assigned to the current contract
						ThrowError( "Could not assign typology to contract #" + toString( iContract + 1 ) + " ( Typology assignment  rule )","Typology" )
					ELSE
						//Sets the contract typology
						legSetTypology( pContract,sTypology )
				}
				// The nature of the contract is unknown, this throws an error
				ELSE
					ThrowError( "Could not figure out the nature of the contract " + sContractRegistrationLabel + " ( Typology assignment rule )","Contract Nature" )
			},

			iContract := iContract - 1
		},

		//Now handling the package
        pMaincomponent := legGetMainComponent( pLeg ),
        pContract := legGetFatherContract( pMaincomponent ),
		pPackage := legGetFatherPackage( pContract ),
		IF ( NOT isNull( pPackage ) ) THEN //If there is a package
		{
			sPackageRegistrationLabel := "",//Variable initialization
			// All variables are inherited from he contract typology assignment
			// From the main contract:
			// sMaturity,sCallable,sNonDeliverable
			sPackageRegistrationLabel := legGetRegistrationLabel( pPackage ),
			// When the package is an eTradepad "On The Fly" package,no typology should be assigned to the Package
			IF ( ( sPackageRegistrationLabel <> "mxContractStbIREGISTERED_PACKAGE" )
				AND ( sPackageRegistrationLabel <> "mxContractStbIPACKAGE" ) ) THEN
			{
				//pContract is the main contract
				sContractRegistration := legGetRegistration( pContract ),

                //Tells whether the current contract is a FTP loan
                IF ( sContractRegistration == "Loans/Deposits" ) THEN
                	callPreTradeFormula( sOutput,pContract,"mx.routing.FXMM.Pricing.Rout-FTP" ),                

				//Gets the package typology from the LUT
				sTypology := lookupString( "MX.FXMM.TypA-PK","ALL",
							"Package Label",sPackageRegistrationLabel,
							"Registration",sContractRegistration,
							"Non Deliverable",sNonDeliverable,
							"Callable",sCallable,
							"Prorata",sProrata,
							"Maturity",sMaturity,
                            "Criteria 1",sOutput ),                            

				IF ( sTypology == "" )  THEN
					//Throws an error if no typology was assigned to the package
					ThrowError( "Could not assign typology on package ( Typology assignment rule )","Typology" )
				ELSE
					//Sets the package typology
					legSetTypology( pPackage,sTypology )
			}
		},

		sPortfolio := legGetString( pMainComponent,"Portfolio" ),
		IF ( sPortfolio <> "" ) THEN
		{
			// To set typology in case of Collateral Management
			bIsCollateralBook := ptfIsCollateralBook( sPortfolio ),
			IF ( bIsCollateralBook ) AND ( sRegistration == "Call deposits" ) THEN
			{
				sRegistration := legGetRegistration( pMainComponent ),
				//Define another criteria is needed and store the value in sCriteria
				//sCrieteria := ...

				//This gets the typology from the LUT
				sTypology := lookupString( "MX.ALL.TypAColl","ALL",
							"Registration",sRegistration,
							"Criteria",sCriteria ),

				IF ( sTypology == "" ) THEN
					//Throws an error if no typology was assigned to the current component
					ThrowError( "Could not assign a typology to component #" + toString ( iComponent+1 ) + " ( Typology assignment rule )","Typology" )
				ELSE
				{
					legSetTypology( pMainComponent,sTypology ),
					// To set typology for father contract
					legSetTypology( pContract,sTypology )
				}
			}
		}              
	}
};

// mx.preTrade.completion.ALL.ALL.TypA-IE

/*
MXpress
Inter-Entity typology assignment rule

Used algorithm
Get pointer on current package
If pointer is not empty
	If package is internal
		Set "Inter Entity" typology
	End if
End if

Version 1.0
The purpose of this rule is to assign a typology to new packages created through the Inter-Entity task
*/

{
	pLeg := NPD_HDL_THIS,

	pPackage := legGetFatherPackage( pLeg ),
	IF ( NOT isNull( pPackage ) ) THEN //If there is a package
	{
		sPackageRegistrationLabel := legGetRegistrationLabel( pPackage ),
		IF ( sPackageRegistrationLabel == "mxContractIPACKAGE_INTERNAL" ) THEN
		{
			sTypology := "Inter Entity",
			//Sets the package typology
			legSetTypology( pPackage,sTypology )
		}
	}
};

// mx.preTrade.completion.COM.Closing.FCpl

/*
MXpress
COM Field Generic completion and checks rules

Used algorithm
Loop on all components
	Retrieve the registration
	// Block preference list assignment
	For the COM Swap based registration:
		Retrieve from Look-Up Tables potential the volume profile's preference list
		If valid result obtained then the preference list is assigned

	// Block Capacity and Transport management
	For the COM Capacity and the Transport registrations:
	Check that the following fields are correctly set before booking, derived from Look-Up Table:
		* Index, as a function of type and capacity use
		* Counterpart ( including a possibe mandatory assignment)
	Complete the pricing information by assigning the UDF CAP_PREM the right value ( derived from the 'Price/Margin2' field )
End loop

Version 1.3
Updated to handle the centralized mapping field, using the 
- ( "MX.ALL.FieldMapping","Location") lookup table

Version 1.2
Replaced the UDF CAP_PREM_T by the pretrade field pf_cap_prem. This field holds the previous value of the capacity premium.
Used for technical reasons to dientify when the user changes the premium value.

Version 1.0
The purpose of this rule is to provide basic completion rules for COM products:
- For Power & Gas Capacity & Transport, check that all fields are correctly initialized and provide lowlevel feedback
- For all Commodity trade types, provide detailed preference list assignment based on a Look-Up Table

This rule uses a set of Look-Up Tables ( LUT ):
- ( MX.COM.PrefList,ALL ) contains the COM preference lists by asset class and data type ( location, route, profile )
- ( MX.COM.Capacity,ALL ) provids assignment details for indices, counterparts, mandatory and overridable settings for COM Capacity and COM transport registrations
*/

{
	// Field initialization / reset
	pLeg := This,
	sYes := "Yes",
	sNo := "No",
	sCustomOTC := "Custom",	
	sRegistration := "",
	sAsset := "",
	sLocationFieldName := "",
	sLocationType := "",
	sLocationEntry := "NONE",
	sLocationCriteria := "",
	sExercise1 := "",
	sExercise2 := "",
	sWarning := "",
	fMargin1 := 0.0,
	fMargin2 := 0.0,
	sUseCap := sYes,
	sUsedCap := sYes,
	sCtpManualAllowed := "",
	sDeliveryModeManualAllowed := "",
	sIndex := "",
	sExpectedIndex := "",
	sInternal := "",
	sExpectedCounterpart := "",
	sCounterpart := "",
	fQuantity := 0.0,
	fCapPrem := 0.0,
	fCapPremCopy := 0.0,
	fNominal := 0.0,
	fPrice := 0.0,

	// loop on all components
	iNbComponents := legGetNumberOfComponents( pLeg ),
	iComponent := 0,
	WHILE ( iComponent < iNbComponents ) DO
	{
		pComponent := legGetComponentAt( pLeg,iComponent ),
		IF ( legIsInitialized( pComponent ) ) THEN
		{
			sRegistration := legGetRegistration( pComponent ),

			// Block: Assignment of preference lists based on Registration, Asset and other criteria
			// Power & Gas related assignment: volume profile, units....
			IF ( sRegistration <> "COM Buy and Sell Back" ) THEN // COM Asset field should be added for COM Buy and Sell Back           
				sAsset := legGetString( pComponent,"COM Asset" ),

			pFieldMapLocationResult := pNULL,
			sField := "Location",
			pFieldMapLocationResult := lookupResults( "MX.ALL.FieldMapping",sField,
									"Registration",sRegistration,
									"Criteria 1","",
									"Criteria 2","",
									"Criteria 3","" ),
			IF ( NOT isNull( pFieldMapLocationResult ) ) THEN
			{
				sLocationFieldName := lookupResultsGetString( pFieldMapLocationResult,0,1 ),
				sLocationType := lookupResultsGetString( pFieldMapLocationResult,0,2),
				sLocationEntry := strSubString( legGetString( pComponent,sLocationFieldName ),0,2 ),
				sLocationCriteria := legGetString( pComponent,"Instrument" )
			},

			// Retrieve preference lists for Swap/PhysFwd based on location/route in sLocationEntry
			IF ( sLocationEntry <> "NONE" ) THEN
			{
				// 1. Volume profiles
				sPrefList := "", // reset
				sPrefList := lookupString( "MX.COM.PrefList","ALL",
										"COM Asset",sAsset,
										"Pref list type","Volume profiles",
										"Criteria",sLocationEntry ),
				// Assign the volume profile preference list
				IF ( sPrefList <> "" ) THEN
					legSetList( pComponent,"Volume profile1",sPrefList ),

				// 2. Locations & Routes
				sPrefList := "", // reset
				sPrefList := lookupString( "MX.COM.PrefList","ALL",
										"COM Asset",sAsset,
										"Pref list type",sLocationType,
										"Criteria",sLocationCriteria ),
				// Assign the location/Route preference list
				IF ( sPrefList <> "" ) THEN 
					legSetList( pComponent,sLocationFieldName,sPrefList )

				// X. Other Assignment
				// Placeholder for future extensions.
			},

			// Block: Capacity index/route lookup and capacity product assignment
			// Capacity index/route lookup and capacity product assignment
			IF ( ( sRegistration == "COM transport" )
				OR ( sRegistration == "COM Capacity" ) ) THEN
			{
				pTradeUdf := legGetUserFields( pComponent ),
				sRoute := strTrim( legGetString( pComponent,"Route" ) ),
				// Check if Route is properly filled-in, if not highlight the cell in warning color
				IF ( sRoute <> "" ) THEN
				{
					// Check if the Capacity allocation look-up table yields a result for the Route selected, if not throw a Warning
					pCapaCompletion := lookupResults( "MX.COM.Capacity","ALL",
													"Route",sRoute ),
					IF ( toString( pCapaCompletion) == "0" ) THEN
					{
						// no matching lookup found
						legSetCellColorAsError( pComponent,"Route" ),
						sWarning := "The route " + sRoute + " does not have an Index assignment.",
						ThrowError( pComponent,sWarning,"Route" )
					}
					ELSE
					{
						sUseCap := lookupResultsGetString( pCapaCompletion,0,1 ),
						sCtpManualAllowed := lookupResultsGetString( pCapaCompletion,0,6 ),
						sDeliveryModeManualAllowed := lookupResultsGetString( pCapaCompletion,0,7 )
					},

					// If Capacity doesn't need to be used for transport on the route, then the deal is irrelevant ( why buying it if you don't need to use it?), throw a warning accordingly
					IF ( legGetString( pComponent,"Delivery_Settlement" ) <> "Capacity" ) THEN
					{
						sUsedCap := sNo,
						IF ( ( sRegistration == "COM Capacity" ) AND ( sUseCap == sNo ) ) THEN
						{
							sWarning := "The route " + sRoute + " does not need capacity to be booked, index cannot be assigned.",
							ThrowError( pComponent,sWarning,"Route" )
						}
					},

					// For a transport deal, check conformity between Route setting according to lookup table and trade delivery settlement setting
					IF ( ( sRegistration == "COM transport") AND ( sUsedCap <> sUseCap ) ) THEN
					{
						IF ( sDeliveryModeManualAllowed == sYes ) THEN
						{
							sWarning := "Custom Delivery settlement for capacity use on route " + sRoute + ".",
							ThrowLowPriorityWarning( pComponent,sWarning,"Delivery_Settlement" )
						}
						ELSE
						{
							sWarning := "Delivery settlement for capacity use on route " + sRoute + " is not in line with mandatory setting.",
							ThrowLowPriorityError( pComponent,sWarning,"Delivery_Settlement" )
						}
					},

					// Check that an index has correctly been assigned to the relevant field
					sIndex := legGetString( pComponent,"Index1" ),
					IF ( sRegistration == "COM transport" ) THEN
					{
						IF ( sUseCap == sYes ) THEN
							sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,3 )
						ELSE
							sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,4 )
					}
					ELSE // Capacity
						sExpectedIndex := lookupResultsGetString( pCapaCompletion,0,2 ),

					IF ( ( sIndex == "" ) OR ( sIndex == "__SPOT24 USD/MWH" ) ) THEN
					{
						sWarning := "The route " + sRoute + " does not have a valid Index assigned: " + sIndex,
						ThrowError( pComponent,sWarning,"Route" )
					}
					// Check that an index is not conflicting a potential mandatory index assignement
					ELSE IF ( sIndex <> sExpectedIndex ) THEN
					{
						sWarning := "The route " + sRoute + " does not have the expected Index assigned: " + sExpectedIndex,
						ThrowError( pComponent,sWarning,"Route" )
					},

					IF ( sRegistration == "COM Capacity" ) THEN
					{
						fQuantity := legGetNumeric( pComponent, "Quantity" ),
						// Only proceed if not-Custom and Quantity>0 ( = initialized AND deliveryLength>0)
						IF ( ( legGetString( pComponent,"Volume_profile_type1" ) <> sCustomOTC ) AND ( fQuantity > 0.0 ) ) THEN
						{
							fCapPrem := udfGetNumeric( pTradeUdf, "CAP_PREM" ),
							fCapPremCopy := udfGetNumeric( pTradeUdf, "CAP_PREM_T" ),

							IF ( fCapPrem == fCapPremCopy ) THEN
							{
								fNominal := legGetNumeric( pComponent, "Nominal" ),
								fPrice := legGetNumeric( pComponent, "Price/Margin2" ),
								// calculate premium and set it
								fCapPrem := fPrice * fQuantity / fNominal,
								udfOverwriteNumeric( pTradeUdf,"CAP_PREM",fCapPrem ),
								legOverwrite( pComponent,"pf_cap_prem",fCapPrem )
							}
						}
						ELSE
						{
							udfOverwriteNumeric( pTradeUdf,"CAP_PREM",0.0 ),
							legOverwrite( pComponent,"pf_cap_prem",0.0 )
						}
					}
				}
			}
		},
		iComponent := iComponent + 1
	}
};

// mx.preTrade.completion.COM.Closing.SanityCheck

/*
MXpress COM Specific completion

Version 2.4 
Call SanityCheckCommon function for Common Santity Checks

Version 2.3
- Counterparty is optional for what if (draft trades)

Version 2.2
- Applied MSL best practices
- Deletion of Compound Option

Version 2.1
Updated to handle the centralized mapping field, using the 
- ( "MX.ALL.FieldMapping","Maturity") lookup table

Version 2.0

Notes:
The goal of this rule is to analyze every leg/component of a transaction and check if they are sane.
When a sanity check is not fulfilled, a warning or error code is generated with legAddMessage function.
Those codes will then be analysed in mx.preTrade.completion.ALL.ALL.CheckMsg rule and error/warning messages will be pushed to user and tradability status computed accordingly.

Checks included by default and their code:
	For barriers, check the sanity of the barrier level(s):
		- If the 1st barrier is already knocked								: "K1"
		- If the 2nd barrier is already knocked								: "K2"
		- For an up and out call, if the strike is greater than the barrier : "SKOUp"
		- For a down and out put, if the strike is smaller than the barrier : "SKOLow"
	For physical delivery:
		- Date consistency 													: "SDFys", "EDFys", "DFys"
	For external COM transport and COM Capacity registrations:
		- Counterparty set is not the expected 								: "MC"
	Generic Common Sanity Checks (See SanityCheckCommon function for codes)

If customizations of the warning/error level are necessary, in order to get the required user notification level:
For Sanity warning
	-> legAddMessage( pComponent,"<message>","<field>","Sane-<code>-",messageSysGetWarningLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark
For Sanity error
	->  legAddMessage( pComponent,"<message>","<field>","Sane-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark
	Booking is prevented
For Sanity error Intrusive
	-> legAddMessage( pComponent,"<message>","<field>","Sane-Intrusive-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message pops up systematically. Very intrusive for the user.
	Booking is prevented
*/

{
	callPreTradeFormula( This,"mx.completion._Functions.ALL.SanityCheckCommon","COM" ),

	// Fields Initialization/Reset
	pLeg := This,
	sAction := properties.Get( "mx.preTrade.action" ),
	sRegistration := "",
	pAllMessages := pNULL,
	sCounterpart := "",
	sInternal := "",
	sRoute := "",
	sExercizeMode := "",
	sExpectedCounterpart := "",
	sCtpManualAllowed := "",

	iCount := 0,
	iNbLegs := legGetNumberOfComponents( pLeg ),
	// For each of the component of the transaction, perform sanity checks
	WHILE ( iCount < iNbLegs ) DO
	{
		pComponent := legGetComponentAt( pLeg,iCount ),

		sRegistration := legGetRegistration( pComponent ),
		pAllMessages := legGetMessages( pComponent ),
		sCounterpart := legGetString( pComponent,"Counterpart" ),

		// Barrier level checks
		IF ( sRegistration == "COM Simple option" ) THEN
		{
			IF ( legIsInitialized( pComponent ) ) THEN
			{
				IF ( sAction == "INS" ) THEN 
				{
					sBarrierType := legGetString( pComponent,"Barriers_Type" ),
					IF ( sBarrierType <> "None" ) THEN
					{
						sBarrierObs := legGetString( pComponent,"Barriers_Knock" ),
						sBarrierStyle := legGetString( pComponent,"Barriers_Kill" ),
						sPayOut := legGetString( pComponent,"Payout" ),
						fBarrier1 := legGetNumeric( pComponent,"Barriers_Strike" ),
						fBarrier2 := legGetNumeric( pComponent,"Barriers_Strike2" ),
						fStrike := legGetNumeric( pComponent,"Strike" ),
						bIsBarrier1Knocked := FALSE,
						bIsBarrier2Knocked := FALSE,

						IF ( sBarrierObs == "Spot" ) THEN
						{
							fMarketPrice := legGetNumeric( pComponent,"Spot" ),
							sWarningBarrier1 := "Barrier 1 is knocked at current spot",
							sWarningBarrier2 := "Barrier 2 is knocked at current spot"
						}
						ELSE
						{
							fMarketPrice := legGetNumeric( pComponent,"Price" ),
							sWarningBarrier1 := "Barrier 1 is knocked at current forward price",
							sWarningBarrier2 := "Barrier 2 is knocked at current forward price"
						},

						IF ( sBarrierStyle == "American" ) THEN
						{
							IF ( ( sBarrierType == "Up & In (>=)" ) OR ( sBarrierType=="Up & Out (>=)" ) ) THEN
								bIsBarrier1knocked := ( fMarketPrice>=fBarrier1 )
							ELSE IF ( ( sBarrierType == "Up & In (>)" ) OR ( sBarrierType=="Up & Out (>)" ) ) THEN
								bIsBarrier1knocked := ( fMarketPrice>fBarrier1 )
							ELSE IF ( ( sBarrierType == "Down & In (<=)" ) OR ( sBarrierType=="Down & Out (<=)" ) ) THEN
								bIsBarrier1knocked := ( fMarketPrice<=fBarrier1 )
							ELSE IF ( ( sBarrierType == "Down & In (<)" ) OR ( sBarrierType=="Down & Out (<)" ) ) THEN
								bIsBarrier1knocked := ( fMarketPrice<fBarrier1 )
							ELSE IF ( ( sBarrierType == "Double In" ) OR ( sBarrierType=="Double Out" ) ) THEN
							{
								bIsBarrier1knocked := ( fMarketPrice<=fBarrier1 ),
								bIsBarrier2knocked := ( fMarketPrice>=fBarrier2 )
							}
						},

						IF ( bIsBarrier1knocked AND ( fMarketPrice>0.0 ) ) THEN
						{
							IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-K1-" ) == 0 ) THEN
							legAddMessage( pComponent,sWarningBarrier1,"Barriers_Type","Sane-K1-",messageSysGetWarningLabel( ) )
						},
						IF ( bIsBarrier2knocked AND ( fMarketPrice>0.0 ) ) THEN
						{
							IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-K2-" ) == 0 ) THEN
							legAddMessage( pComponent,sWarningBarrier2,"Barriers_Type","Sane-K2-",messageSysGetWarningLabel( ) )
						},

						IF ( ( NOT bIsBarrier1knocked ) AND ( sPayOut=="Call" ) AND strContain( sBarrierType,"Up & Out" ) AND ( fStrike>fBarrier1 ) ) THEN
						{
							IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-SKOUp-" ) == 0 ) THEN
							legAddMessage( pComponent,"Barrier is lower than strike, payoff is null","Barriers_Type","Sane-SKOUp-",messageSysGetWarningLabel( ) )
						}
						ELSE IF ( ( NOT bIsBarrier1knocked ) AND ( sPayOut=="Put" ) AND strContain(sBarrierType,"Down & Out") AND ( fStrike<fBarrier1 ) ) THEN
						{
							IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-SKOLow-" ) == 0 ) THEN
							legAddMessage( pComponent,"Barrier is greater than strike, payoff is null","Barriers_Type","Sane-SKOLow-",messageSysGetWarningLabel( ) )
						}
					}
				}
			}
		},

		// Physical delivery date consistency checks
		IF ( sRegistration == "COM Simple option" ) THEN
		{
			sOptionDeliveryMode := legGetString( pComponent,"Option exercise" ),
			IF ( sOptionDeliveryMode <> "Cash" ) THEN
				sExercizeMode := "FYS"
		}
		ELSE IF ( sRegistration == "COM Buy and Sell Back" ) THEN
		{
			sExercizeMode := "" // Skip dates check for COM Buy and Sell Back
		}        
		ELSE IF ( sRegistration <> "COM Asian" ) THEN
		{
			sUnderlyingPhysFin := legGetString( pComponent,"Exercise1" ),
			IF ( sUnderlyingPhysFin == "Physical delivery" ) THEN
				sExercizeMode := "FYS"
		},
		IF ( sExercizeMode == "FYS" ) THEN
		{
			pFieldResultStart := pNULL,
			sField := "Maturity",
			pFieldResultStart := lookupResults( "MX.ALL.FieldMapping",sField,
							"Registration",sRegistration,
							"Criteria 1","Start",
							"Criteria 2","",
							"Criteria 3","" ),
			sFieldDateStart := lookupResultsGetString( pFieldResultStart,0,1 ),

			pFieldResultLast := pNULL,
			pFieldResultLast := lookupResults( "MX.ALL.FieldMapping",sField,
							"Registration",sRegistration,
							"Criteria 1","Last",
							"Criteria 2","",
							"Criteria 3","" ),
			sFieldDateLast := lookupResultsGetString( pFieldResultLast,0,1 ),

			IF ( sFieldDateStart == sFieldDateLast ) THEN
			{
				IF ( legGetFieldType( pComponent,sFieldDateStart ) == "date" ) THEN
				{
					dEndDate := legGetDate( pComponent,sFieldDateStart ),
					dStartDate := dEndDate
				}
				ELSE
				{
					sEndDate := legGetString( pComponent,sFieldDateStart )
				}
			}
			ELSE
			{
				dStartDate := legGetDate( pComponent, sFieldDateStart ),

				dEndDate := legGetDate( pComponent, sFieldDateStart )
			},

			dTradingDate := legGetTradingDate( pLeg ),
			IF ( sRegistration <> "COM Future" ) AND ( sRegistration <> "COM Forward" ) AND ( sRegistration <> "COM Cleared swap" ) AND ( dStartDate < dTradingDate ) THEN
			{
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-SDFys-" ) == 0 ) THEN
					legAddMessage( pComponent,"Start date is sooner than " + toString1( dTradingDate ) + " ( Trading date )","Start","Sane-SDFys-",messageSysGetErrorLabel( ) )
			},

			IF ( toString( dEndDate ) == "00000000" ) THEN
			{
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-EDFys-" ) == 0 ) THEN
					legAddMessage( pComponent,"End date is empty","Maturity period","Sane-EDFys-",messageSysGetErrorLabel( ) )
			}
			ELSE IF ( dEndDate < dStartDate ) THEN
			{
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-DFys-" ) == 0 ) THEN
					legAddMessage( pComponent,"End date is sooner than start date","Delivery Last","Sane-DFys-",messageSysGetErrorLabel( ) )
			}
		},

		// Capacity index/route lookup and capacity product assignment
		IF ( ( sRegistration == "COM transport" ) OR ( sRegistration == "COM Capacity" ) ) THEN
		{
			// Check that the counterpart is not conflicting a potential mandatory counterpart ( for external trades only)
			sInternal := legGetString( pComponent,"Internal" ),
			sRoute := strTrim( legGetString( pComponent,"Route" ) ),
			IF ( ( sInternal == "No" ) AND ( sRoute <> "" ) ) THEN
			{
				// Check if the Capacity allocation look-up table yields a result for the Route selected, if not throw a Warning
				pCapaCompletion := lookupResults( "MX.COM.Capacity","ALL","Route",sRoute ),
				IF ( toString( pCapaCompletion) <> "0" ) THEN
				{
					sExpectedCounterpart := lookupResultsGetString( pCapaCompletion,0,5 ),
					IF ( sExpectedCounterpart <> "" ) THEN
					{
						sCtpManualAllowed := lookupResultsGetString( pCapaCompletion,0,6 ),
						sCounterpart := legGetString( pComponent, "Counterpart" ),
						IF ( ( sCtpManualAllowed == "No" ) AND ( sExpectedCounterpart <> sCounterpart ) ) THEN
						{
							IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MC-" ) == 0 ) THEN
							legAddMessage( pComponent,"The route " + sRoute + " expects mandatory Counterparty","Counterpart","Sane-MC-",messageSysGetErrorLabel( ) )
						}
					}
				}
			}
		},
		iCount := iCount + 1
	}
};

// mx.preTrade.completion.EQD.Closing.TradabilityCheck

/*
MXpress EQD Specific completion

Version 2.4
Move maturity and nominal checks into generic checks: TradabilityCheckCommon

Version 2.3
Call TradabilityCheckCommon function for Common Tradability Checks

Version 2.2
Applied MSL best practices

Version 2.1
Updated to handle the centralized mapping field, using the 
- ( "MX.ALL.FieldMapping","Instrument"), 
- ( "MX.ALL.FieldMapping","NominalUnit"), 
- ( "MX.ALL.FieldMapping","Maturity"), 
- ( "MX.ALL.FieldMapping","Nominal") lookup tables

Version 2.0

Notes:
If the tradability is active, the goal of this rule is to analyze every component of a transaction and check if they are tradable.
When a tradability check is not fulfilled, a warning/error code is is generated with legAddMessage function.
Those codes will then be analysed in mx.preTrade.completion.ALL.ALL.CheckMsg rule and error/warning messages will be pushed to user and tradability status computed accordingly.

Checks included by default and their code:
		- Traded nominal is to high		: "N"
		- Expiry is beyond maximal		: "EMax"
	Generic Common Tradability Checks (See TradabilityCheckCommon for codes)

If customizations of the warning/error level are necessary, in order to get the required user notification level:
For Tradability warning
	-> legAddMessage( pComponent,"<message>","<field>","Tradability-<code>-",messageSysGetWarningLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark - trade is Tradable
For Tradability error for all users
	-> legAddMessage( pComponent,"<message>","<field>","Tradability-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark - trade is Not tradable
	Booking is prevented    
For Tradability error requiring confirmation
	->  legAddMessage( pComponent,"<message>","<field>","TradabilityToConfirm-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark
    For Trader: Trade is Tradable and can be booked.
    For Sales: Trade Requires confirmation if communication is activated. Otherwise it's Not tradable.   
*/
{
	pLeg := This,
	IF ( legIsInitialized( pLeg ) ) THEN
	{
		sEvalActive := properties.Get( "mx.preTrade.evaluation.active" ),
		sAction := properties.Get( "mx.preTrade.action" ),

		sIsTradabilityCheckActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","TradabilityCheck.EQD" ) ),
		IF ( ( sIsTradabilityCheckActive <> "YES" ) AND ( sIsTradabilityCheckActive <> "NO" ) ) THEN 
			ThrowError( "Error in MX.ALL.GParam", "wrong returned value for Key 1 = TradabilityCheck.EQD ( should be YES or NO )" ),

		IF ( sIsTradabilityCheckActive == "YES" )  THEN 
		{
	        callPreTradeFormula( This,"mx.completion._Functions.ALL.TradabilityCheckCommon","EQD" )
        }
	},

        // BAB CR EXT-Addition
    iCount := 0,
    iNbLegs := legGetNumberOfComponents( pLeg ),
    WHILE ( iCount < iNbLegs ) DO
    {
    	pComponent := legGetComponentAt( pLeg, iCount ),
        sRegistration := legGetRegistration(pComponent),
        sCurrency := legGetString(pComponent,"Other_nominal_unit"),
        sAllowed := lookupString("BAB.ALL.Equity.Allowed.Ccy","ALL","CURRENCY",sCurrency),
        sNonObjectionCertificate := legGetString(pComponent,"NOC"),
        sNonObjectionCertificateID := legGetString(pComponent,"NOC_ID"),
        sInstrument := legGetString(pComponent,"Instrument"),
        sInvestmentType := secGetUdfString(sInstrument, "INV_TYPE"),
        pSecurity := secGetSecurityData(sInstrument),
        sSector := securityGetSectorLabel(pSecurity),
        sMarket := securityGetMarket(pSecurity),

        IF (sRegistration == "Equities") THEN
        {       
            //Block any listed equity booked with a currency different than USD and GCC currencies
            IF (sInvestmentType == "Listed Equity" AND sAllowed == "No") THEN
            {
                ThrowError (pComponent,"Listed Equity booked with a currency different than USD or GCC curencies","Other_nominal_unit")
            },

            //Block any unquoted equity booked with a currency different than SAR
            IF (sInvestmentType == "Non-Listed Equity" AND sCurrency <> "SAR") THEN
            {
                ThrowError (pComponent,"Non-Listed Equity booked with a currency different than SAR","Other_nominal_unit")
            },

            //Block any local bank equity booked without a non-objection certificate from SAMA
            /*IF (sInvestmentType == "Listed Equity" AND (sNonObjectionCertificate == "NO" OR sNonObjectionCertificateID == "")) THEN
            {
                ThrowError (pComponent,"Listed Equity non-objection certificate required","NOC")
            },*/

            //Block any fund trade booked with a currency different than USD, GBP, EUR, or GCC currencies
            IF (sRegistration == "Equities" AND (sInvestmentType == "Managed Fund - Equity" OR sInvestmentType == "Managed Fund - Others" OR sInvestmentType == "Money Market Funds" OR sInvestmentType == "Mutual Fund - Equity" OR sInvestmentType == "Mutual Fund - FI" OR sInvestmentType == "Real Estate Funds")) THEN
            {
                IF (sAllowed == "No") THEN
                {
                    ThrowError (pComponent,"Fund booked with a currency different than USD, EUR, GBP, or GCC curencies","Currency")
                }
            } 
        },
        iCount := iCount + 1
    }
    // BAB CR EXT-End
};

// public.msl.event.completion.UPIRetrieval
/*

This pre-trade is setting UPI UDF to empty in order to fetch it again
---------------------------
*/
{
   pEvent := This,
   sLastEventClass := properties.Get("mx.preTrade.BO.class"),

   IF (sLastEventClass == "mxContractEventICANCEL_REISSUE" OR sLastEventClass == "mxContractEventIRESTRUCTURE" OR sLastEventClass == "mxContractEventIINDEX_TRANSITION") THEN
	{
		iVersionedBO := 0,
		iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),

		WHILE ( iVersionedBO < iNbVersionedBOs ) DO
		{
			pVersionedBO := evtGetVersionedBOAt( This,iVersionedBO ),
			pOld := evtVersionedBOGetOld(pVersionedBO),
			pLeg := evtVersionedBOGetNew(pVersionedBO),

			pOldLeg:= legGetMainComponent( pOld ),

			pPackage := legGetFatherPackage(pLeg),
			pOldTradeUDFs := legGetUserFields(pOldLeg),

			sUPI := udfGetString(pOldTradeUDFs,"UPI_ID"),

			iContract := 0,

            // Initialization of number of contracts for a PCK otherwise 1 for a single FC
            IF (NOT(isNull(pPackage))) THEN
			{
				iNbContracts := legGetNumberOfContracts(pPackage)
			}
			ELSE
			{
				iNbContracts := 1
			},

			// Loop on FC
            WHILE (iContract < iNbContracts) DO
			{
				IF (NOT(isNull(legGetContractAt(pPackage, iContract)))) THEN
                {
					pLeg := legGetContractAt(pPackage, iContract)
                },

				pNewLeg:= legGetMainComponent( pLeg ),
				pNewTradeUDFs := legGetUserFields(pNewLeg),

				// Emptying the UPI of the issued contract in case it is filled 
				IF (sUPI <> "") THEN
				{
                    udfSetString(pNewTradeUDFs,"UPI_ID", "")
				},

				iContract := iContract + 1
			},

			iVersionedBO := iVersionedBO + 1 
		}
	}  
};

// mx.preTrade.completion.FXD.Booking.Sanit-Hedge

/*
MXpress
FXD Hedge type handling

Version 1.3
Applied MSL best practices

Version 1.2
Remove the "HEDGE_TYPE" UDF filling, fill the Hedge type field instead

Version 1.1
Applied MXpress scripted-rules conventions

Version  1.0
1. Map the udf  "HEDGE_TYPE" et native field "Hedge type" (temporary)
2. Check the "Hedge type" consistency for strip package
*/

{
	sAction := properties.Get( "mx.preTrade.action" ),

	//  Hedge type consistency check for Strips
	sBORegistration := legGetRegistrationLabel( This ),
	IF ( ( sAction == "INS" ) AND ( strCONTAIN( sBORegistration,"PACKAGE" ) ) ) THEN 
	{
		IF ( strCONTAIN( sBORegistration,"Strip" ) ) THEN
		{
			iCurrentComponent := 0,
			iNumComponent := legGetNumberOfComponents( This ),

			sFirstHedgeType := "", 
			WHILE ( iCurrentComponent < iNumComponent ) DO //Loop on the FCC
			{
				pCurrentComponent := legGetComponentAt( This,iCurrentComponent ),
				IF ( ( legGetProductFamily( pCurrentComponent ) == "CURR" ) AND ( legGetProductGroup( pCurrentComponent ) == "OPT" ) ) THEN 
				{
					sCurrentHedgeType := legGetString( pCurrentComponent,"Hedge type" ), 
					IF ( sFirstHedgeType == "" ) THEN
						sFirstHedgeType := sCurrentHedgeType
					ELSE
					{
						IF ( sFirstHedgeType <> sCurrentHedgeType ) THEN
						{
							ThrowError( pCurrentComponent,"Inconsistent hedge type ( Hedge sanitization rule )","Hedge type" ),
							iCurrentComponent := iNumComponent
						}
					}
				},
				iCurrentComponent := iCurrentComponent + 1 
			}
		}
		ELSE
		{
			iCurrentSon := 0,
			iNumSons := legGetNumberOfSons( This ),

			WHILE ( iCurrentSon < iNumSons ) DO
			{
				pSon := legGetSonAt( This,iCurrentSon ),

				IF ( legGetProductLabel( pSon ) == "Strip" ) THEN 
				{
					iCurrentComponent := 0,
					iNumComponent := legGetNumberOfComponents( pSon ),

					sFirstHedgeType := "",

					WHILE ( iCurrentComponent < iNumComponent ) DO  //Loop on the FCC
					{
						pCurrentComponent := legGetComponentAt( pSon,iCurrentComponent ),
						IF ( ( legGetProductFamily( pCurrentComponent ) == "CURR" ) AND ( legGetProductGroup( pCurrentComponent ) == "OPT" ) ) THEN 
						{
							sCurrentHedgeType := legGetString( pCurrentComponent,"Hedge type" ),
							IF ( sFirstHedgeType == "" ) THEN
								sFirstHedgeType := sCurrentHedgeType
							ELSE
							{
								IF ( sFirstHedgeType <> sCurrentHedgeType ) THEN
								{
									ThrowError( pCurrentComponent,"Inconsistent hedge type ( Hedge sanitization rule )","Hedge type" ),
									iCurrentComponent := iNumComponent
								}
							}
						},
						iCurrentComponent := iCurrentComponent + 1 
					}
				},
				iCurrentSon := iCurrentSon + 1
			}
		}
	}
};

// mx.preTrade.completion.FXMM.Booking.IESalesMg

/*
MXpress
Specific formula for internal split FXMM products

Used alogrithm
Default output: Regular
If the package is an inter entity simple trade (i.e. not FX package inter entity)
	Retrieve the mirrored contract
	Change the sign of the margins depending on the product type
End if

Version 1.0
The purpose of this rule is to change the sign of sales margin fields of mirrored legs within inter-entity deals.
*/

{
	pLeg := NPD_HDL_THIS,
    IF ( legGetRegistrationLabel( pLeg ) == "mxContractIPACKAGE_INTERNAL" ) THEN
    {
        pMainContract := legGetFatherContract( legGetMainComponent( pLeg ) ),
    	pMirroredContract := legGetContractAt( pLeg,1 ),
	    sMirroredRegistration := legGetRegistration( pMirroredContract ),

        IF ( sMirroredRegistration == "Spot-Forward" ) THEN
        {
			sInternalTypology := legGetInternalTypology( pMirroredContract ),
            IF ( sInternalTypology == "SPT" ) THEN
				legOverwrite( pMirroredContract,"Sales margin",-1.0*legGetNumeric( pMainContract,"Sales margin" ) )
			ELSE
            {
				legOverwrite( pMirroredContract,"Swap sales margin",-1.0*legGetNumeric( pMainContract,"Swap sales margin" ) ),
				legOverwrite( pMirroredContract,"Spot sales margin",-1.0*legGetNumeric( pMainContract,"Spot sales margin" ) )
			}
        }
        ELSE IF ( sMirroredRegistration == "FX swap" ) THEN
        {
        	legOverwrite( pMirroredContract,"Sales margin",-1.0*legGetNumeric(pMainContract,"Sales margin" ) ),
			legOverwrite( pMirroredContract,"Sales margin 2",-1.0*legGetNumeric(pMainContract,"Sales margin 2" ) )
        }
        ELSE IF ( sMirroredRegistration == "Loans/Deposits" ) THEN
        {
        	legOverwrite( pMirroredContract,"Sales margin",-1.0*legGetNumeric( pMainContract,"Sales margin" ) ),
			legOverwrite( pMirroredContract,"Corporate Margin",-1.0*legGetNumeric( pMainContract,"Corporate Margin" ) )
        }
        ELSE IF ( sMirroredRegistration == "Call deposits" ) THEN
        {
    		IF( legGetString( pMirroredContract,"Payout" ) == legGetString( pMainContract,"Payout" ) ) THEN
            {
            	IF (legGetString( pMainContract,"Payout") == "Borrow" ) THEN
                	legOverwrite( pMirroredContract,"Payout","Lend" )
                ELSE 
		       		legOverwrite( pMirroredContract,"Payout","Borrow" )
            },
        	legOverwrite( pMirroredContract,"Sales margin",-1.0*legGetNumeric( pMainContract,"Sales margin" ) ),
			legOverwrite( pMirroredContract,"Corporate Margin",-1.0*legGetNumeric( pMainContract,"Corporate Margin" ) )
        }
    }
};

// mx.preTrade.completion.FXMM.Closing.TradabilityCheck

/*
MXpress FXMM Specific completion

Version 2.3
- Adding a specific logic to get the split value market rate because the field mkt fwd will give the simple forward, and setting the npv to zero does not work when one of maturities is spot. The implemented logic is to price a virtual leg from scratch and get the price proposed by the system.
- Update the usage of MX.ALL.Tradability look up table

Version 2.2
- Amendment to handle the difference between the Contractual rate and the Net price, the same way as it is done between the Gross price and the Net price.
- Applied MSL best practices

Version 2.1
Updated to handle the centralized mapping field, using the 
- ( "MX.ALL.FieldMapping","Instrument"), 
- ( "MX.ALL.FieldMapping","NominalUnit"), 
- ( "MX.ALL.FieldMapping","Maturity"), 
- ( "MX.ALL.FieldMapping","Nominal") lookup tables

Version 2.0

Notes:
If the tradability is active, the goal of this rule is to analyze every component of a transaction and check if they are tradable.
When a tradability check is not fulfilled, a warning/error code is is generated with legAddMessage function.
Those codes will then be analysed in mx.preTrade.completion.ALL.ALL.CheckMsg rule and error/warning messages will be pushed to user and tradability status computed accordingly.

Checks included by default and their code:
		- PSR check						: "PSRMin" and "PSRMax"
		- Rate compated with market 	: "*Rate"
		- Swap Rate compared with market: "*SwapRate"
		- Negative Margin amount		: "NegMargin*"
		- Generic maturity				: "GMat"
		- Generic nominal				: "GNom"

If customizations of the warning/error level are necessary, in order to get the required user notification level:
For Tradability warning
	-> legAddMessage( pMainComponent,"<message>","<field>","Tradability-<code>-",messageSysGetWarningLabel( ) )
	Highlight the field and an explanatory message is accessible by clicking on exclamation mark - trade is Tradable
For Tradability error for all users
	-> legAddMessage( pMainComponent,"<message>","<field>","Tradability-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accessible by clicking on exclamation mark - trade is Not tradable
	Booking is prevented    
For Tradability error requiring confirmation
	->  legAddMessage( pMainComponent,"<message>","<field>","TradabilityToConfirm-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accessible by clicking on exclamation mark
	For Trader: Trade is Tradable and can be booked.
	For Sales: Trade Requires confirmation if communication is activated. Otherwise it's Not tradable.
*/

{
	pLeg := This,
    // Remove check for trade in RFQ
    bRFQTraderSkipCheck := sysGetRFQRole() <> "PROVIDER" OR  properties.Get("mx.preTrade.pricing.context") <> "MAIL",

	IF ( legIsInitialized( pLeg ) ) THEN
	{
		bTradability := FALSE,
		sEvalActive := properties.Get( "mx.preTrade.evaluation.active" ),
		sAction := properties.Get( "mx.preTrade.action" ),
		pLeg0 := legGetComponentAt( pLeg,0 ),
		pMainComponent := legGetMainComponent( pLeg0 ),
		sPortfolio := legGetString( pMainComponent,"Portfolio" ),
		sRefCCY := ptfGetEntityCurrency( sPortfolio ),
		sIsTradabilityCheckActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","TradabilityCheck.FXMM" )),
		IF ( ( sIsTradabilityCheckActive <> "YES" ) AND ( sIsTradabilityCheckActive <> "NO" ) ) THEN 
			ThrowError( "Error in MX.ALL.GParam", "wrong returned value for Key 1 = TradabilityCheck.FXMM ( should be YES or NO )" ),    

		sSourceModule := legGetSourceModule( pLeg0 ),
		bTradability := ( sIsTradabilityCheckActive == "YES" )
					AND ( sSourceModule <> "mx.sellDown" )
					AND ( sSourceModule <> "mx.futureFlowSellDow" )
					AND ( sSourceModule <> "mx.rollover" ),
		IF ( bTradability ) THEN 
		{
			// For main component of the transaction, perform tradability checks
			sUserGroup := sysGetGroup(),
			sPattern := legGetPatternLabel( pLeg0 ), 

			IF ( sEvalActive == "YES" ) AND ( sAction == "INS" ) THEN
			{
				// Retrieves the dynamic values that will be used to check the tradability of the transaction
				pMainContract := legGetFatherContract( pMainComponent ),
				pPackage := legGetFatherPackage( pMainContract ),
				pAllMessages := legGetMessages( pMainComponent ),
				sPublishingSystem := legGetPublishingSystem( legGetFatherContract( pMainComponent ) ),
				sSourceModule := legGetSourceModule( legGetFatherContract( pMainComponent ) ),
				sBOContractRegistration := legGetRegistrationLabel( pMainContract ),
				sBOPackageRegistration := legGetRegistrationLabel( pPackage ),
                sRegistration := legGetRegistration( pMainContract ), // BAB addition
				fVarianceFactor := 100.0,
				sString := "",

				dTradingDate := legGetDate( pMainComponent,"Trading Date" ),
				dMarketDate := legGetDate( pMainComponent,"Marketdata date" ),

				//Market variables
				fMarketRate := 0.0,
				fMarketRate2 := 0.0,

				//Sanity on negative sales margin
				fSalesMargin1 := 0.0,
				fSalesMargin2 := 0.0,
				fSalesMargin3 := 0.0,
				fSalesMargin4 := 0.0,
				fSalesMargin5 := 0.0,
				fSalesMargin6 := 0.0,
				sSalesMarginField1 := "Sales_margin pips",
				sSalesMarginField2 := "Spot_sales_margin pips",
				sSalesMarginField3 := "Swap_sales_margin",
				sSalesMarginField4 := "Swap_sales_mrg_fwd_fwd",
				sSalesMarginField5 := "Sales_margin_2 pips",
				sSalesMarginField6 := "Sales_margin",

				//Ensure the PSR is between 0 and 100
				IF ( ( sPattern == "Mudarabah" ) OR ( sPattern == "Musharaka" ) ) THEN
				{
					fPsr := legGetNumeric( pLeg0,"IS_PSR" ), 
					IF ( fPsr < 0.0 ) THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-PSRMin-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"PSR couldn't be smaller than 0", "IS_PSR","Tradability-PSRMin-",messageSysGetWarningLabel( ) )
					}
					ELSE IF ( fPsr > 100.0 ) THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-PSRMax-" ) == 0 ) THEN
							legAddMessage( pMainComponent, "PSR couldn't be greater than 100", "IS_PSR","Tradability-PSRMax-",messageSysGetWarningLabel( ) )
					}
				},

                        //BAB addition for the Bank note soft warning regardin the value dates
            sTypology := legGetString(pMainComponent,"Typology"),
            IF sTypology == "Banknotes" OR sTypology == "Banknotes Credit" THEN
            {
            sNoteCurr := legGetString(pMainComponent, "BANK_NOTE"),
            sDenCurr := legGetString(pMainComponent,"Den_unit"),
            sNumCurr := legGetString(pMainComponent,"Num_unit"),
            sDelCurr :=legGetString(pMainComponent,"Second_del_currency"),
            sDenPayout := legGetString(pMainComponent,"Den_Buy_Sell"),
            dDate1 := legGetDate(pMainComponent,"Maturity"),
            dDate2 := legGetDate(pMainComponent,"Second_del_date"),
            IF sNoteCurr == sDenCurr AND sDenPayout == "Sell" THEN
            {
            IF sNoteCurr == sDelCurr THEN
            {
            IF dDate2 > dDate1 THEN
            {
            ThrowWarning("Value date","The value date of the swift leg is less than the value date of the notes leg")
            }
            }
            },
            IF sNoteCurr == sNumCurr AND sDenPayout == "Buy" THEN
            {
            IF sNoteCurr == sDelCurr THEN
            {
            IF dDate2 > dDate1 THEN
            {
            ThrowWarning("Value date","The value date of the swift leg is less than the value date of the notes leg")
            }
            }
            }
            },


  //BAB Addition
                //Deal booking should be blocked if Who promises to sell field is empty.
                sBOClass := properties.Get( "mx.preTrade.BO.source.class" ),
                sTypology := legGetString(pMainComponent,"Typology"),
                sPatternLabel := legGetPatternLabel(pMainComponent),
                IF (sTypology == "FX Waad" AND (sPatternLabel <> "FX Swap" AND sBOClass <> "mxContractEventFxIEXTENSION_OFFSETTING")
                AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_OFFSETTING" )
                AND ( sBOClass <> "mxContractEventFxIEXERCISE" )
                AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_TERMINATE")
                ) THEN
				{
					sPRMSELL:=legGetString(pMainComponent,"IS_PRM_SEL"),
					IF (sPRMSELL == "") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-PRM_SEL-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with Who promises to sell field empty", "IS_PRM_SEL","Tradability-PRM_SEL-",messageSysGetErrorLabel( ) )
					}

				},

                 //Check for Broker A and Broker B in Murabaha Details
         		IF  legIsElementValid( pMainComponent,"IS_BROKER1" ) THEN
                	sBrokerA := legGetString(pMainComponent,"IS_BROKER1"),
        	 	IF  legIsElementValid( pMainComponent,"IS_BROKER2" ) THEN
         			sBrokerB := legGetString(pMainComponent,"IS_BROKER2"),
         		IF sBrokerB <> "" AND sBrokerA <> "" THEN   
         		{
         			IF sBrokerA == sBrokerB THEN
            		{
                    	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-IS_BROKER-" ) == 0 ) THEN
            			legAddMessage( pMainComponent,"Cannot book Deal with Broker B Same as Broker A","IS_BROKER2","Tradability-IS_BROKER-",messageSysGetErrorLabel( ) )
            		}
         		},
               //end of BAB addition


               //BAB addition currency in sales margin 
              pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","Currency","Criteria 2", sCriteria2 ),
                    IF ( NOT isNull( pFieldResult ) ) THEN
                    {
                        iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
                        sNativeSalesMarginCurrencyField := lookupResultsGetString( pFieldResult,0,1 ),
                        sNativeSalesMarginCurrency := legGetString( pMainComponent,sNativeSalesMarginCurrencyField )
                    },

                   //BAB addition - sales group
                    sGroup := sysGetGroup(),
                    pGroupResults := lookupResults("MX.ALL.UserGroupProfile","ALL","USER_GROUP",sGroup),
                    sGroupType := lookupResultsGetString(pGroupResults,0,0),


                    //BAB addition for DCD
                    IF legIsElementValid(pMainComponent,"STRTG_LBL") THEN
                    sStrategylabel:= legGetString(pMainComponent,"STRTG_LBL"),
                    //end of BAB addition

                              //BAB addition for IB rate and ccy pair
                IF (sGroupType == "Sales" AND sNativeSalesMarginCurrency <> "SAR") THEN
                {
                // start of BAB Addition for Bank Notes - C-1168405
                IF sTypology == "Banknotes" OR sTypology == "Banknotes Credit" THEN 
               		{
                        fSpot := legGetNumeric(pMainComponent,"Spot"),
                        sCurr1 := legGetString(pMainComponent,"Den_unit"),
                        sCurr2 := legGetString(pMainComponent,"Num_unit")
                    },

                     IF ((sTypology == "Banknotes" OR sTypology == "Banknotes Credit") AND (strSubString(sCurr1, 0, 2) <> strSubString(sCurr2, 0, 2))) OR ((sTypology == "Banknotes" OR sTypology == "Banknotes Credit") AND ((strSubString(sCurr1, 0, 2) == strSubString(sCurr2, 0, 2))) AND ((strSubString(sCurr1, 2, 3) <> "N") AND (strSubString(sCurr2, 2, 3) <> "N") AND (strSubString(sCurr1, 2, 3) <> "O") AND (strSubString(sCurr2, 2, 3) <> "O"))) THEN
                     {
                        IF legIsElementValid(pMainComponent, "MRG_FX_RT") THEN
                        fIBRate:=legGetNumeric(pMainComponent,"MRG_FX_RT"),
                        IF legIsElementValid(pMainComponent, "MRG_FX_CCY") THEN
                        sCcypair:=legGetString(pMainComponent,"MRG_FX_CCY"),
                        IF (fIBRate == 0.0) THEN
                        {
                            IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_RT-" ) == 0 ) THEN
                                legAddMessage( pMainComponent,"Cannot book deal with IB Rate field empty", "MRG_FX_RT","Tradability-MRG_FX_RT-",messageSysGetErrorLabel( ) )
                        },

                        IF (sCcypair == "") THEN
                        {
                            IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_CCY-" ) == 0 ) THEN
                                legAddMessage( pMainComponent,"Cannot book deal with Ccy pair field empty", "MRG_FX_CCY","Tradability-MRG_FX_CCY-",messageSysGetErrorLabel( ) )
                        }
                     },
				// end of BAB Addition for Bank Notes

                // BAB addition - update for FX Swap IB rate message
                    IF ( sRegistration == "FX swap" ) THEN
                    {
                        iNumberOfComponentFxSwap := legGetNumberOfComponents(pMainContract),
                        iComponentFxSwap := 0,
                        //Loop on FX Swap components
                        WHILE iComponentFxSwap < iNumberOfComponentFxSwap DO
                        {
                        pComponentFxSwap := legGetComponentAt(pMainContract,iComponentFxSwap), //get pointer to current component
                        IF legIsElementValid(pComponentFxSwap, "MRG_FX_RT") THEN
                        	fIBRate:=legGetNumeric(pComponentFxSwap,"MRG_FX_RT"),
                        		IF legIsElementValid(pComponentFxSwap, "MRG_FX_CCY") THEN
                                    sCcypair:=legGetString(pComponentFxSwap,"MRG_FX_CCY"),
                                    IF (fIBRate == 0.0) 
                                    AND (sBOClass <> "mxContractEventFxIEARLY_TAKEUP_TERMINATE")
			                     	AND (sBOClass <> "mxContractEventFxIEXTENSION_OFFSETTING")
            			            AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_OFFSETTING" ) THEN
                                    {
                                        IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_RT-" ) == 0 ) THEN
                                            legAddMessage( pComponentFxSwap,"Cannot book deal with IB Rate field empty", "MRG_FX_RT","Tradability-MRG_FX_RT-",messageSysGetErrorLabel( ) )
                                    },
                                    IF (sCcypair == "") 
                                    AND (sBOClass <> "mxContractEventFxIEARLY_TAKEUP_TERMINATE")
			                     	AND (sBOClass <> "mxContractEventFxIEXTENSION_OFFSETTING")
            			            AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_OFFSETTING" ) THEN
                                    {
                                        IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_CCY-" ) == 0 ) THEN
                                            legAddMessage( pComponentFxSwap,"Cannot book deal with Ccy pair field empty", "MRG_FX_CCY","Tradability-MRG_FX_CCY-",messageSysGetErrorLabel( ) )
                                    },
                                    iComponentFxSwap := iComponentFxSwap +1
                             }


                      },

                // Commented for C-1168405 IF sRegistration == "Spot-Forward" OR sRegistration == "Forex-Swap Leg" THEN
                IF (sRegistration == "Spot-Forward" OR sRegistration == "Forex-Swap Leg") AND (sTypology <> "Banknotes" OR sTypology <> "Banknotes Credit") 
                AND (sBOClass <> "mxContractEventFxIEARLY_TAKEUP_TERMINATE")
               	AND (sBOClass <> "mxContractEventFxIEXTENSION_OFFSETTING")
                AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_OFFSETTING") AND (sBOClass <> "mxContractEventFxIEXERCISE") THEN
                 {
					IF legIsElementValid(pMainComponent, "MRG_FX_RT") THEN
					fIBRate:=legGetNumeric(pMainComponent,"MRG_FX_RT"),
                    IF legIsElementValid(pMainComponent, "MRG_FX_CCY") THEN
                    sCcypair:=legGetString(pMainComponent,"MRG_FX_CCY"),

                    IF  sStrategylabel <> "Dual Currency Depo" THEN
                    {
					IF (fIBRate == 0.0) THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_RT-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with IB Rate field empty", "MRG_FX_RT","Tradability-MRG_FX_RT-",messageSysGetErrorLabel( ) )
					},
                    IF (sCcypair == "") THEN
                    {
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-MRG_FX_CCY-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with Ccy pair field empty", "MRG_FX_CCY","Tradability-MRG_FX_CCY-",messageSysGetErrorLabel( ) )
					}
                    }
                 }

				}, 
                //end of BAB addition for the IB rate and the ccy pair

                //BAB addition for bank note cash center
                IF (sTypology == "Banknotes" OR sTypology == "Banknotes Credit") THEN
				{
					sCashCenter:=legGetString(pMainComponent,"CASH_CNTR"),
					IF (sCashCenter == "") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-CASH_CNTR-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with Cash Center field empty", "CASH_CNTR","Tradability-CASH_CNTR-",messageSysGetErrorLabel( ) )
					}

				}, 
                //end of BAB addition for cash center
                sUsage := legGetString(pLeg,"Usage"),
                IF (sTypology == "FX Murabaha") 
                OR (sTypology == "Murabaha Placement" AND sUsage == "BA") 
                OR (sTypology == "SAMA Bill") 
                OR (sTypology == "Murabaha Borrowing" AND sUsage == "DI")
                OR (sTypology == "CD Issuance" AND sUsage == "Murabaha DI")
                OR (sTypology == "RR SAMA") 
                OR (sTypology == "LTM" AND sUsage == "BA") THEN
				{

					sIsCommo:=legGetString(pMainComponent,"IS_COMMO"),
                    sIsBrk1:=legGetString(pMainComponent,"IS_BROKER1"),
                    sIsBrk2:=legGetString(pMainComponent,"IS_BROKER2"),
                    fIsBrkPrice:=legGetNumeric(pMainComponent,"IS_BRPRICE"),
                    IF legIsElementValid(pMainComponent,"IS_BA_RATE") THEN
                    fBaiAjalRate:=legGetNumeric(pMainComponent,"IS_BA_RATE"),

					IF (sIsCommo == "") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-ISCOMMO-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with empty commodity name", "IS_COMMO","Tradability-IS_COMMO-",messageSysGetErrorLabel( ) )
					},

                    IF (sIsBrk1== "") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-ISBRK1-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with empty commodity broker1", "IS_BROKER1","Tradability-IS_BROKER1-",messageSysGetErrorLabel( ) )
					},

                    IF (sIsBrk2== "") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-ISBRK2-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with empty commodity broker2", "IS_BROKER2","Tradability-IS_BROKER2-",messageSysGetErrorLabel( ) )
					},


                    IF (fIsBrkPrice == 0.0) THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-ISBRKPR-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Cannot book deal with empty commodity broker price", "IS_BRPRICE","Tradability-IS_BRPRICE-",messageSysGetErrorLabel( ) )
					},

                    IF legIsElementValid(pMainComponent,"IS_BA_RATE") THEN
                    {
                        IF (fBaiAjalRate == 0.0) THEN
                        {
                            IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-ISBARATE-" ) == 0 ) THEN
                                legAddMessage( pMainComponent,"Cannot book deal with empty Bai Ajal rate", "IS_BA_RATE","Tradability-IS_BA_RATE-",messageSysGetErrorLabel( ) )
                        }
					}
				}, 

                //End of BAB Addition


                 //BAB addition for WHT_CHARG
                IF (sTypology == "Wakala Borrowing" OR sTypology == "Murabaha Borrowing" OR sTypology == "Wakala Borrowing CFC" OR sTypology == "CD Issuance") THEN
				{
					sEligible := legGetString(pMainComponent,"PROFIT_WHT"),
                    sWHTCharg := legGetString(pMainComponent,"WHT_CHARG"),
					IF (sEligible == "Yes" AND sWHTCharg =="") THEN
					{
						IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-WHT_CHARG-" ) == 0 ) THEN
							legAddMessage( pMainComponent,"Please specify if WHT should be charged to the counterpart", "WHT_CHARG","Tradability-WHT_CHARG-",messageSysGetErrorLabel( ) )
					}

				},
                //end of BAB addition for WHT_CHARG



				//Special tradability checks
				IF ( ( sPublishingSystem == "MX" ) 
				AND ( sSourceModule <> "mx.sellDown" )
				AND ( sSourceModule <> "mx.rollover")
				AND ( sSourceModule <> "mx.futureFlowSellDow")
				AND ( sSourceModule <>"mx.fixing")
				AND ( properties.Get( "mx.preTrade.BO.source" ) == "" )
				AND ( sSourceModule <> "mx.bulkCtpMod" )
				AND ( sSourceModule <> "mx.bulkPtfMod" ) 
				AND ( dTradingDate == dMarketDate ) 
				AND ( sBOContractRegistration <> "mxContractStbICONTRACT" ) ) THEN 
				{
					IF( NOT isNull ( pPackage ) ) THEN
					{
						sPackageRegistration := legGetRegistrationLabel( pPackage ),
						IF ( sPackageRegistration == "mxContractFxIFUNDINGSWAP" ) THEN
						{
							iNumber := legGetNumberOfContracts( pPackage ),
							iIndex := 0,
							WHILE ( iIndex < iNumber ) DO
							{
								pContract := legGetContractAt( pPackage,iIndex ),
								IF ( legGetRegistration( pContract ) == "FX swap" ) THEN
									pMainComponent := legGetMainComponent( pContract ),

								iIndex := iIndex + 1
							}
						}
					},

					//Registrations on which the price sanity is not supported yet
					IF ( sBOContractRegistration == "mxContractFxIPARFORWARD_CONTRACT"  
					OR sBOPackageRegistration == "mxContractFxIPARFORWARD" 
					OR sBOPackageRegistration == "mxContractFxIFORWARD_AUTOSPOT" 
					OR sBOPackageRegistration == "mxContractFxISWAP_AUTOSPOT" 
					OR sBOPackageRegistration == "mxContractFxIFUNDINGSWAP") THEN
						sInternal := "Yes"
					ELSE
					{
						pMainContract := legGetFatherContract( pMainComponent ),
						sInternal := legGetString( pMainContract,"Internal" )
					},
					IF ( sInternal == "No" ) THEN
					{
						sTypology := legGetTypology( pMainContract ),
						pFieldResult := pNULL,
						sField := "Instrument",
						sRegistration := legGetRegistration( pMainContract ),

						pFieldResult := lookupResults( "MX.ALL.FieldMapping",sField,
										"Registration",sRegistration,
										"Criteria 1","" ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sInstrumentField := lookupResultsGetString( pFieldResult,0,1 )
						},
						sInstrument := legGetString( pMainContract, sInstrumentField ),

						sContractRegistration := legGetRegistration( pMainContract ),
						sGroup := legGetProductGroup( pMainComponent ),
						sType := legGetProductType( pMainComponent ),

						// Gets FO product results
						pResults := lookupResults( "MX.FXMM.PriceSanityFOProduct","ALL","Typology",sTypology ),
						IF ( NOT isNull( pResults ) ) THEN
						{
							sBOProduct := lookupResultsGetString( pResults,0,0 ),
							sCheck := lookupResultsGetString( pResults,0,1 ),
							sCategory := "",
							IF ( sCheck == "Yes" ) THEN
							{
								IF ( sGroup == "FXD" ) THEN
								{
									sCategory := fxCntGetCategory( sInstrument ),
									IF ( sContractRegistration == "Spot-Forward" ) THEN
									{
										// Get market rate
										sCallable := legGetString( pMainContract,"Callable" ),
										sNDF := legGetString( pMainContract,"Non deliverable" ),
										sSecDelivery := legGetString( pMainContract,"Second delivery" ),
										sFixing := legGetString( pMainContract,"Fixing" ),
										sProrata := legGetString( pMainContract,"Prorata" ),

										// Get market rate specifically for Split Value deals
										IF ( sSecDelivery == "Yes" ) THEN
										{
											sBOContractRegistration := legGetRegistrationLabel( pMainContract ),
											sContractRegistration := legGetRegistration( pMainContract ),
											sPatternSpotForward := legGetPatternLabel( pMainContract ),

											//Pricing a new leg from scratch to get the market price
											pContainer := npOpen( TRUE ),
											pNew := legInsertComponent( pContainer,sBOContractRegistration,sContractRegistration,sPatternSpotForward ),

											//Getting the target trade characteristics
											fCurAmt1 := legGetNumeric( pMainContract,"Den_nominal" ),
											sInstSw := legGetString( pMainContract,"Instrument" ),
											sQuotation := legGetString( pMainContract,"Price_quotation" ),
											sDenBuySell := legGetString( pMainContract,"Den_Buy_Sell" ),
											dMaturity := legGetDate( pMainContract,"Maturity" ),
											dSecDeliveryDate := legGetDate( pMainContract,"Second_del_date" ),
											sSecondDelivery := legGetString( pMainContract,"Second_delivery" ),
											sSecDelCurr := legGetString( pMainContract,"Second_del_currency" ),

											//Setting the previously get characteristics on the new leg
											legOverwrite( pNew,"Instrument",sInstSw ),
											legOverwrite( pNew,"Maturity",dMaturity ),
											legOverwrite( pNew,"Price_quotation",sQuotation ),
											legOverwrite( pNew,"Den_Buy_Sell",sDenBuySell ),
											legOverwrite( pNew,"Den_nominal",fCurAmt1 ),
											legOverwrite( pNew,"Second_delivery",sSecondDelivery ),
											legOverwrite( pNew,"Second_del_currency",sSecDelCurr ),
											legOverwrite( pNew,"Second_del_date",dSecDeliveryDate ),

											//Getting the FX Forward as market rate
											fMarketRate := legGetNumeric( pNew,"Forward" ),

											//Closing the new leg
											 npClose( pContainer )

										 },

										IF ( sCallable == "Yes" OR sNDF == "Yes" OR sSecDelivery == "Yes" OR sProrata == "Yes") THEN
										{
											pContainer := npOpen( ),
											pNew := legClone( pContainer,pMainContract ),
											legOverwrite( pNew,"Spot sales margin",0.0 ),
											legOverwrite( pNew,"Swap sales margin",0.0 ),
											legOverwrite( pNew,"Npv",0.0 ),
											fMarketRate := legGetNumeric( pNew,"Forward" ),
											npClose( pContainer )
										}
										ELSE IF ( sFixing == "Fix Price" OR sFixing == "Fix Spot" ) THEN
											fMarketRate := 0.0
										ELSE
											fMarketRate := legGetNumeric( pMainComponent,"Mkt forward" ),

										// Get transaction rate
										sPriceField := "Forward",
										sNetPriceField := "Net Forward",
										sContractualRateField := "Contractual rate",
										fContractRate := legGetNumeric( pMainComponent,sPriceField ),
										fContractNetRate := legGetNumeric( pMainComponent,sNetPriceField ),
										fContractualRate := legGetNumeric( pMainComponent,sContractualRateField ),

										// Sanity check on negative sales margin
										fSalesMargin1 := legGetNumeric( pMainContract,sSalesMarginField1 ),
										fSalesMargin2 := legGetNumeric( pMainContract,sSalesMarginField2 ),
										fSalesMargin3 := legGetNumeric( pMainContract,sSalesMarginField3 )
									}
									ELSE IF ( sContractRegistration == "FX swap" ) THEN
									{
										// Get market rate
										sCallable := legGetString( pMainContract,"Callable" ),
										sNDF := legGetString( pMainContract,"Non deliverable" ),
										sNDF2 := legGetString( pMainContract,"Non deliverable 2" ),
										sSecDelivery := legGetString( pMainContract,"Second delivery" ),
										sSecDelivery2 := legGetString( pMainContract,"Second delivery 2" ),

										IF ( sCallable == "Yes" OR sNDF == "Yes" OR sNDF2 == "Yes" OR sSecDelivery == "Yes" OR sSecDelivery2 == "Yes" ) THEN
										{
											pContainer := npOpen( ),
											pNew := legClone( pContainer,pMainContract ),
											legOverwrite( pNew,"Spot sales margin",0.0 ),
											legOverwrite( pNew,"Swap sales margin",0.0 ),
											legOverwrite( pNew,"Swap sales margin far",0.0 ),
											legOverwrite( pNew,"Npv",0.0 ),
											fMarketRate := legGetNumeric( pNew,"Forward" ),
											npClose( pContainer )
										} 
										ELSE
										{
											fMarketRate := legGetNumeric( pMainContract,"Mkt forward" ),
											fMarketRate2 := legGetNumeric( pMainContract,"Mkt forward (leg2)" )
										},

										// Get transaction rate (near leg)
										sPriceField := "Forward",
										sNetPriceField := "Net Forward",
										sContractualRateField := "Contractual rate",
										fContractRate := legGetNumeric( pMainContract,sPriceField ),
										fContractNetRate := legGetNumeric( pMainContract,sNetPriceField ),
										fContractualRate := legGetNumeric( pMainComponent,sContractualRateField ),
										// Get transaction rate (far leg)
										sPriceField2 := "Forward (leg2)",
										sNetPriceField2 := "Net Forward (leg2)",
										sContractualRateField2 := "Contractual rate2",
										fContractRate2 := legGetNumeric( pMainContract,sPriceField2 ),
										fContractNetRate2 := legGetNumeric( pMainContract,sNetPriceField2 ),
										fContractualRate2 := legGetNumeric( pMainComponent,sContractualRateField2 ),

										// Sanity check on negative sales margin
										fSalesMargin1 := legGetNumeric( pMainContract,sSalesMarginField1 ),
										fSalesMargin4 := legGetNumeric( pMainContract,sSalesMarginField4 ),
										fSalesMargin5 := legGetNumeric( pMainContract,sSalesMarginField5 )
									}
								}
								ELSE IF ( sGroup == "FUT" ) THEN 
								{
									// Get market rate
									fMarketRate := legGetNumeric( pMainComponent,"Market price" ),
									// Get transaction rate
									sPriceField := "Price",
									sNetPriceField := sPriceField,
									fContractRate := legGetNumeric( pMainComponent,sPriceField ),
									fContractNetRate := fContractRate
								}
								ELSE IF ( sGroup == "LN_BR" ) THEN 
								{
									sCategory := fxCurrencyGetCategory( legGetString( pMainComponent,"Flat amount unit" ) ),
									// Get market rate
									pContainer := npOpen( ),
									dMaturity := legGetDate( pMainComponent,"Maturity" ),
									sMaturity := toString1( dMaturity ),
									pStreams := legGetStreams( pMainComponent ),
									IF ( sMaturity <> "19800101" AND sMaturity <> "00000000" ) AND ( NOT isNull( pStreams ) ) THEN
									{
										pStream := streamsGetStream( pStreams,0,0 ),
										pNew := legClone( pContainer,pMainComponent ),
										legOverwrite( pNew,"Rate/Margin",0.0 ),
										legOverwrite( pNew,"Sales margin",0.0 ),
										legOverwrite( pNew,"Corporate Margin",0.0 ),
										legOverwrite( pNew,"Npv",0.0 ),
										pStreams := legGetStreams( pNew ),
										fMarketRate := streamsGetImpliedRate( pStreams )
									},
									npClose( pContainer ),
									// Get transaction rate
									sPriceField := "Rate/Margin",
									sNetPriceField := "NetRate",
									fContractRate := legGetNumeric( pMainComponent,sPriceField ),
									fContractNetRate := legGetNumeric( pMainComponent,sNetPriceField ),

									// Sanity check on negative sales margin
									fSalesMargin6 := legGetNumeric( pMainContract,sSalesMarginField6 )
								}
								// Sanity check on negative sales margin on call deposits
								ELSE IF ( sGroup == "CD" ) THEN
									fSalesMargin6 := legGetNumeric( pMainContract,sSalesMarginField6 )
								ELSE IF ( sType == "CPCD" ) THEN
								{
									sCategory := fxCurrencyGetCategory( legGetString( pMainComponent,"Currency" ) ),
									// Get market rate
									fMarketRate := legGetNumeric( pMainComponent,"EvalPrice" ),
									// Get transaction rate
									sPriceField := "Settl. dirty price",
									sNetPriceField := sPriceField,
									fContractRate := legGetNumeric( pMainComponent,sPriceField ),
									fContractNetRate := fContractRate
								},
								pResults := lookupResults( "MX.FXMM.PriceSanity","ALL",
															"FO Product",sBOProduct,
															"Instrument Category",sCategory ),
								IF( NOT isNull( pResults ) ) THEN
								{
									fWarning := lookupResultsGetNumeric( pResults,0,0 ),
									fError := lookupResultsGetNumeric( pResults,0,1 ),
									sWarningCalc := lookupResultsGetString( pResults,0,2 ),
									fWarningCust := lookupResultsGetNumeric( pResults,0,3 ),
									fErrorCust := lookupResultsGetNumeric( pResults,0,4 ),
									sWarningCustCalc := lookupResultsGetString( pResults,0,5 ),
									fWarningCR := lookupResultsGetNumeric( pResults,0,6 ),
									fErrorCR := lookupResultsGetNumeric( pResults,0,7 ),
									sWarningCRCalc := lookupResultsGetString( pResults,0,8 )
								},

								IF ( sWarningCalc == "Percentage" ) THEN
								{
									sDeltaWarning := toString( fWarning ) + "%",
									sDeltaError := toString( fError ) + "%"
								}
								ELSE
								{
									sDeltaWarning := toString( fWarning ) + " points",
									sDeltaError := toString( fError ) + " points"
								},
								IF ( sWarningCustCalc == "Percentage" ) THEN
								{
									sDeltaCustWarning := toString( fWarningCust ) + "%",
									sDeltaCustError := toString( fErrorCust ) + "%"
								} 
								ELSE
								{
									sDeltaCustWarning := toString( fWarningCust ) + " points",
									sDeltaCustError := toString( fErrorCust ) + "points"
								},
								IF ( sWarningCRCalc == "Percentage" ) THEN
								{
									sDeltaCRWarning := toString( fWarningCR ) + "%",
									sDeltaCRError := toString( fErrorCR ) + "%"
								} 
								ELSE
								{
									sDeltaCRWarning := toString( fWarningCR ) + " points",
									sDeltaCRError := toString( fErrorCR ) + "points"
								},

								// If the market rate is not null, then check the variation/percentage for trader's and sales' rates
								IF ( ( fMarketRate <> 0.0 ) OR ( sWarningCalc <> "Percentage" AND sWarningCustCalc <> "Percentage" ) ) THEN
								{
									// Check the trader's rate
									IF ( sWarningCalc == "Percentage" ) THEN
										fDelta := 100.0 * ABS( ( fContractRate - fMarketRate ) / fMarketRate )
									ELSE
										fDelta := ABS( fContractRate - fMarketRate ) * fVarianceFactor,

									// Check the sales' rate
									IF ( sWarningCustCalc == "Percentage" ) THEN
										fDeltaCust := 100.0 * ABS( ( fContractNetRate-fContractRate ) / fContractRate )
									ELSE
										fDeltaCust := ABS( fContractNetRate - fContractRate ) * fVarianceFactor,

									// Check the Contractual rate
									IF ( sWarningCRCalc == "Percentage" ) THEN
										fDeltaCR := 100.0 * ABS( ( fContractualRate-fContractNetRate ) / fContractNetRate )
									ELSE
										fDeltaCR := ABS( fContractualRate - fContractNetRate ) * fVarianceFactor,

									//Throw warning for trader's rate
									IF ( ( fWarning > 0.0 AND fWarning <= fError AND fDelta >= fWarning AND fDelta < fError ) 
									OR ( fWarning > 0.0 AND fWarning > fError AND fDelta >= fWarning ) ) THEN
									{
										sString := "Difference between Contract Rate[" + toString( fContractRate ) + "] and Market Rate[" + toString( fMarketRate ) + "] exceeds the tolerance " + sDeltaWarning,

										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-TRate-" ) == 0 ) THEN

											legAddMessage( pMainComponent, sString,sPriceField,"Tradability-TRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for trader's rate
									ELSE IF ( fError > 0.0 AND fDelta >= fError ) THEN 
									{
										sString := "Difference between Contract Rate[" + toString( fContractRate ) + "] and Market Rate[" + toString( fMarketRate ) + "] exceeds the tolerance " + sDeltaError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-TERate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sPriceField,"Tradability-TERate-",messageSysGetErrorLabel( ) )
									},

									//Throw warning for sales' rate
									IF ( ( fWarningCust > 0.0 AND fWarningCust <= fErrorCust AND fDeltaCust >= fWarningCust AND fDeltaCust < fErrorCust ) 
									OR ( fWarningCust > 0.0 AND fWarningCust > fErrorCust AND fDeltaCust >= fWarningCust ) ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate ) + "] and Gross Rate[" + toString( fContractRate ) + "] exceeds the tolerance " + sDeltaCustWarning,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-SRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sNetPriceField,"Tradability-SRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for sales' rate
									ELSE IF ( fErrorCust > 0.0 AND fDeltaCust >= fErrorCust ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate ) + "] and Gross Rate[" + toString( fContractRate ) + "] exceeds the tolerance " + sDeltaCustError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-SERate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sNetPriceField,"Tradability-SERate-",messageSysGetErrorLabel( ) )
									},

									//Throw warning for Contractual rate
									IF ( ( fWarningCR > 0.0 AND fWarningCR <= fErrorCR AND fDeltaCR >= fWarningCR AND fDeltaCR < fErrorCR ) 
									OR ( fWarningCR > 0.0 AND fWarningCR > fErrorCR AND fDeltaCR >= fWarningCR ) ) THEN
									{
										sString := "Difference between Client Net Rate[" + toString( fContractNetRate ) + "] and Contractual Rate[" + toString( fContractualRate ) + "] exceeds the tolerance " + sDeltaCRWarning,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-CRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sContractualRateField,"Tradability-CRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for Contractual rate
									ELSE IF ( fErrorCR > 0.0 AND fDeltaCR >= fErrorCR ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate ) + "] and Contractual Rate[" + toString( fContractualRate ) + "] exceeds the tolerance " + sDeltaCRError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-CERate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sContractualRateField,"Tradability-CERate-",messageSysGetErrorLabel( ) )
									}
								},
								// If the market rate is not null, then check the variation/percentage for trader's and sales' rates
								// Specific case of FX swap far leg
								IF ( fMarketRate2 <> 0.0 OR ( sWarningCalc <> "Percentage" AND sWarningCustCalc <> "Percentage") ) THEN
								{
									// Check the trader's rate
									IF ( sWarningCalc == "Percentage" ) THEN
										fDelta := 100. * ABS( ( fContractRate2 - fMarketRate2 ) / fMarketRate2 ) 
									ELSE
										fDelta := ABS( fContractRate2 - fMarketRate2 ) * fVarianceFactor,

									// Check the sales' rate
									IF ( sWarningCustCalc == "Percentage" ) THEN
										fDeltaCust := 100. * ABS( ( fContractNetRate2 - fContractRate2 ) / fContractRate2 )
									ELSE
										fDeltaCust := ABS( fContractNetRate2 - fContractRate2 ) * fVarianceFactor,

									// Check the Contractual rate
									IF ( sWarningCRCalc == "Percentage" ) THEN
										fDeltaCR := 100. * ABS( ( fContractualRate2 - fContractNetRate2 ) / fContractNetRate2 )
									ELSE
										fDeltaCR := ABS( fContractualRate2 - fContractNetRate2 ) * fVarianceFactor,    

									//Throw warning for trader's rate
									IF ( ( fWarning > 0.0 AND fWarning <= fError AND fDelta >= fWarning AND fDelta < fError ) 
									OR ( fWarning > 0.0 AND fWarning > fError AND fDelta >= fWarning ) ) THEN
									{
										sString := "Difference between Contract Rate[" + toString( fContractRate2 ) + "] and Market Rate[" + toString( fMarketRate2 ) + "] exceeds the tolerance " + sDeltaWarning,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-TSwapRate-" ) == 0 ) THEN

											legAddMessage( pMainComponent, sString,sPriceField2,"Tradability-TSwapRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for trader's rate
									ELSE IF ( fError > 0.0 AND fDelta >= fError ) THEN
									{
										sString := "Difference between Contract Rate[" + toString( fContractRate2 ) + "] and Market Rate[" + toString( fMarketRate2 ) + "] exceeds the tolerance " + sDeltaError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-TESwapRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sPriceField2,"Tradability-TESwapRate-",messageSysGetErrorLabel( ) )
									},

									//Throw warning for sales' rate
									IF ( ( fWarningCust > 0.0 AND fWarningCust <= fErrorCust AND fDeltaCust >= fWarningCust AND fDeltaCust < fErrorCust ) 
									OR ( fWarningCust > 0.0 AND fWarningCust > fErrorCust AND fDeltaCust >= fWarningCust ) ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate2 ) + "] and Gross Rate[" + toString( fContractRate2 ) + "] exceeds the tolerance " + sDeltaCustWarning,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-SSwapRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sNetPriceField2,"Tradability-SSwapRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for sales' rate
									ELSE IF ( fErrorCust > 0.0 AND fDeltaCust >= fErrorCust ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate2 ) + "] and Gross Rate[" + toString( fContractRate2 ) + "] exceeds the tolerance " + sDeltaCustError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-SESwapRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sNetPriceField2,"Tradability-SESwapRate-",messageSysGetErrorLabel( ) )
									},
									//Throw warning for Contractual rate
									IF ( ( fWarningCR > 0.0 AND fWarningCR <= fErrorCR AND fDeltaCR >= fWarningCR AND fDeltaCR < fErrorCR ) 
									OR ( fWarningCR > 0.0 AND fWarningCR > fErrorCR AND fDeltaCR >= fWarningCR ) ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate2 ) + "] and Contractual Rate[" + toString( fContractualRate2 ) + "] exceeds the tolerance " + sDeltaCRWarning,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-CRSwapRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sContractualRateField2,"Tradability-CRSwapRate-",messageSysGetWarningLabel( ) )
									}
									//Throw error for Contractual rate
									ELSE IF ( fErrorCust > 0.0 AND fDeltaCust >= fErrorCust ) THEN
									{
										sString := "Difference between Client Rate[" + toString( fContractNetRate2 ) + "] and Contractual Rate[" + toString( fContractualRate2 ) + "] exceeds the tolerance " + sDeltaCRError,
										IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-CRESwapRate-" ) == 0 ) THEN
											legAddMessage( pMainComponent, sString,sContractualRateField2,"Tradability-CRESwapRate-",messageSysGetErrorLabel( ) )
									}
								},
								// If any sales margin amount is negative during booking, generate an exception
								IF ( fSalesMargin1 < 0.0 OR fSalesMargin2 < 0.0 OR fSalesMargin3 < 0.0 OR fSalesMargin4 < 0.0 OR fSalesMargin5 < 0.0 OR fSalesMargin6 < 0.0 ) THEN
								{
									sString := "Negative margin amount",
									IF ( ( fSalesMargin1 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin1-" ) == 0 ) ) THEN
										legAddMessage( pMainComponent, sString,sSalesMarginField1,"Tradability-NegMargin1-",messageSysGetWarningLabel( ) ),

									IF ( ( fSalesMargin2 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin2-" ) == 0 ) ) THEN
											legAddMessage( pMainComponent, sString,sSalesMarginField2,"Tradability-NegMargin2-",messageSysGetWarningLabel( ) ),

									IF ( ( fSalesMargin3 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin3-" ) == 0 ) ) THEN
											legAddMessage( pMainComponent, sString,sSalesMarginField3,"Tradability-NegMargin3-",messageSysGetWarningLabel( ) ),

									IF ( ( fSalesMargin4 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin4-" ) == 0 ) ) THEN
											legAddMessage( pMainComponent, sString,sSalesMarginField4,"Tradability-NegMargin4-",messageSysGetWarningLabel( ) ),

									IF ( ( fSalesMargin5 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin5-" ) == 0 ) ) THEN
										legAddMessage( pMainComponent, sString,sSalesMarginField5,"Tradability-NegMargin5-",messageSysGetWarningLabel( ) ),

									IF ( ( fSalesMargin6 < 0.0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-NegMargin6-" ) == 0 ) ) THEN
										legAddMessage( pMainComponent, sString,sSalesMarginField6,"Tradability-NegMargin6-",messageSysGetWarningLabel( ) )
								}
							}
						}
					}
				},

				sRegistration := legGetRegistration( pMainContract ),
				pFieldResult := pNULL,
				sField := "Instrument",
				pFieldResult := lookupResults( "MX.ALL.FieldMapping",sField,
								"Registration",sRegistration,
								"Criteria 1","" ),
				IF ( NOT isNull( pFieldResult ) ) THEN
				{
					iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
					sInstrumentField := lookupResultsGetString( pFieldResult,0,1 )
				},
				sInstrument := legGetString( pMainComponent,sInstrumentField ),

				sContext := "",
				IF ( sBOPackageRegistration == "mxContractFxIFUNDINGSWAP" ) THEN
					sContext := "Internal",

				sCalendar := fxCntGetDateToValueDateCalendar( sInstrument ),

				// CHECK: Generic maturity
                IF bRFQTraderSkipCheck THEN 
	            {
				sNominalUnitValue := "",
				pFieldMapNominalUnitResult := pNULL,
				sField := "NominalUnit",
				pFieldMapNominalUnitResult := lookupResults( "MX.ALL.FieldMapping",sField,
														"Registration",sRegistration,
														"Criteria 1","" ),
				IF ( NOT isNull( pFieldMapNominalUnitResult ) ) THEN
				{
					iLeg := toInt( lookupResultsGetNumeric( pFieldMapNominalUnitResult,0,0 ) ),
					sNominalUnitField := lookupResultsGetString( pFieldMapNominalUnitResult,0,1 ),
					IF ( iLeg == 0 ) THEN
						sNominalUnitValue := legGetString( pMainComponent,sNominalUnitField )
				},

				pFieldMapMaturityResult := pNULL,
				sField := "Maturity",
				pFieldMapMaturityResult := lookupResults( "MX.ALL.FieldMapping","Maturity",
													"Registration",sRegistration,
													"Criteria 1",sContext ),
				dMaturityValue := dTradingDate,
				iResult := 0,
				iNbResults := lookupResultsGetNumberOfLines( pFieldMapMaturityResult ),
				WHILE ( iResult < iNbResults )  DO 
				{
					IF ( NOT isNull( pFieldMapMaturityResult ) ) THEN
					{
						iLeg := toInt( lookupResultsGetNumeric( pFieldMapMaturityResult,iResult,0 ) ),
						sMaturityField := lookupResultsGetString( pFieldMapMaturityResult,iResult,1 ),
						IF ( iLeg == 0 ) THEN
							dMaturityValue := legGetDate( pMainComponent, sMaturityField )
					},

					/*sMaxMaturity := lookupString( "MX.ALL.Tradability","Maturity",
												"Registration",sRegistration,
												"Criteria",sNominalUnitValue,
												"Instrument",sInstrument),*/


 //BAB addition for minimum maturity
                    sTypology := legGetString(pMainComponent, "Typology"),

                    sUsage := legGetString(pMainComponent, "Usage"),

                    IF sTypology == "CD Issuance" THEN                  
                    	pMinMaxMaturity := lookupResults( "MX.ALL.Tradability","Maturity",
												"Registration",sRegistration,
												"Criteria",sUsage,
												"Instrument",sInstrument)

                    ELSE 
                    	pMinMaxMaturity := lookupResults( "MX.ALL.Tradability","Maturity",
												"Registration",sRegistration,
												"Criteria",sNominalUnitValue,
												"Instrument",sInstrument),
					iMatResult := 0,
					iNbMatResults := lookupResultsGetNumberOfLines( pMinMaxMaturity ),
					WHILE ( iMatResult < iNbMatResults )  DO 
					{
					IF ( NOT isNull( pMinMaxMaturity ) ) THEN
					{
						sMinMaturity := lookupResultsGetString( pMinMaxMaturity,iMatResult,0 ),

						sMaxMaturity := lookupResultsGetString( pMinMaxMaturity,iMatResult,1 )

                    },
                    iMatResult := iMatResult +1
                    },

					dMaxMaturity := dTradingDate + shift( dTradingDate, sMaxMaturity, sCalendar ),
                    dMinMaturity := dTradingDate + shift( dTradingDate, sMinMaturity, sCalendar ),

					IF ( ( sMaxMaturity <> "" ) AND ( dMaturityValue > dMaxMaturity ) ) THEN
					{
						IF ( ( iResult == 0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-GMaxMat0-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Expiry later than " + toString1( dMaxMaturity ) + " (" + sMaxMaturity + ")",sMaturityField,"Tradability-GMaxMat0-",messageSysGetErrorLabel( ) )
						ELSE IF ( ( iResult == 1 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-GMaxMat1-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Expiry later than " + toString1( dMaxMaturity ) + " (" + sMaxMaturity + ")",sMaturityField,"Tradability-GMaxMat1-",messageSysGetErrorLabel( ) )
						ELSE
							legAddMessage( pMainComponent,"Expiry later than " + toString1( dMaxMaturity ) + " (" + sMaxMaturity + ")",sMaturityField,"Tradability-GMaxMat-",messageSysGetErrorLabel( ) )
					},
                    IF ( ( sMinMaturity <> "" ) AND ( dMaturityValue < dMinMaturity ) ) THEN
					{
						IF ( ( iResult == 0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-GMinMat0-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Expiry earlier than " + toString1( dMinMaturity ) + " (" + sMinMaturity + ")",sMaturityField,"Tradability-GMinMat0-",messageSysGetErrorLabel( ) )
						ELSE IF ( ( iResult == 1 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-GMinMat1-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Expiry earlier than " + toString1( dMinMaturity ) + " (" + sMinMaturity + ")",sMaturityField,"Tradability-GMinMat1-",messageSysGetErrorLabel( ) )
						ELSE
							legAddMessage( pMainComponent,"Expiry earlier than " + toString1( dMinMaturity ) + " (" + sMinMaturity + ")",sMaturityField,"Tradability-GMinMat-",messageSysGetErrorLabel( ) )
					},
					iResult := iResult + 1
				},	

				// CHECK: Generic nominal
				pFieldMapNominalResult := pNULL,
				sField := "Nominal",
				pFieldMapNominalResult := lookupResults( "MX.ALL.FieldMapping",sField,
													"Registration",sRegistration,
													"Criteria 1","" ),
				fNominalValue := 0.0,
				iResult := 0,
				iNbResults := lookupResultsGetNumberOfLines( pFieldMapNominalResult ),
				WHILE ( iResult < iNbResults )  DO 
				{
					IF ( NOT isNull( pFieldMapNominalResult ) ) THEN
					{
						iLeg := toInt( lookupResultsGetNumeric( pFieldMapNominalResult,iResult,0 ) ),
						sNominalField := lookupResultsGetString( pFieldMapNominalResult,iResult,1 ),
						IF ( iLeg == 0 ) THEN
							fNominalValue := legGetNumeric( pMainComponent,sNominalField )
					},
					IF ( sNominalUnitValue <> sRefCCY ) THEN
						fRate := cuGetFxRate( sRefCCY,sNominalUnitValue )
					ELSE
						fRate := 1.0,
					fEquivNominalValue := fNominalValue * fRate,

					fMaxNominal := lookupString( "MX.ALL.Tradability","Nominal",
												"Registration",sRegistration,
												"Criteria",sNominalUnitValue,
												"Instrument",sInstrument),

                    //BAB addition for RFQ: Only check the OTB Nominal tradability check for Sales user group profile.
                    //Max Nominal is checked to decide whether the trade priced from Sales profile (RFQ Requester) should be sent for Trader price confirmation, status "Requires Confirmation"
                    //sTitle := legGetTitle(legGetFatherPackage(legGetComponentAt (pLeg,0))),
                    //BAB addition for RFQ: Only check the OTB Nominal tradability check for Sales user group profile.
                //Max Nominal is checked to decide whether the trade priced from Sales profile (RFQ Requester) should be sent for Trader price confirmation, status "Requires Confirmation"
                //BAB addition: RFQ eligibility check
                sFatherRegistration := legGetRegistration(pLeg),
    			sFatherPattern := legGetPatternLabel(pLeg),
                IF sFatherRegistration == "FX swap" THEN
                    sTypology := "FX Swap" 
                ELSE IF sFatherPattern == "Depo CapFloorCollar" THEN
                    sTypology := legGetString(pLeg,"Typology")
                ELSE
                    sTypology := legGetTypology(pLeg),


                	pResult := lookupResults( "BAB.ALL.RFQEligibility","ALL","Registration",sFatherRegistration,"Typology",sTypology),
                    sRFQIsEligible := lookupResultsGetString(pResult,0,0),  
				//BAB addition: Check event class, to be used for assigning Requester restricted Layout, to prevent updating RFQ-impacting financial data during events on the generated contract
                    bEventRFQ :=   sBOClass == "mxContractEventFxIEXERCISE"
                                OR sBOClass == "mxContractEventICANCEL_REISSUE"
                                OR sBOClass == "mxContractEventFxIEARLY_TAKEUP_OFFSETTING"
                                OR sBOClass == "mxContractEventFxIEXTENSION_OFFSETTING"
                                OR sBOClass == "mxContractEventFxIEARLY_TAKEUP_TERMINATE",


                    pStrategy := legGetFather(pLeg),                   
					sTitle:= legGetTitle(pStrategy),

                    IF sGroupType == "Sales" AND sTitle <> "Dual Currency Depo" AND sRFQIsEligible =="Yes" AND (NOT (bEventRFQ)) THEN 
                    {
						IF ( ( fMaxNominal <> 0.0 ) AND ( fEquivNominalValue > fMaxNominal ) ) THEN
						{
						IF ( ( iResult == 0 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"TradabilityToConfirm-GNom0-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Near nominal > " + toString( fMaxNominal / fRate, 20, 0, TRUE, 0 ) + " " + sNominalUnitValue + " (" + toString( fMaxNominal,20,0,TRUE,0 ) + " " + sRefCCY + " Equivalent)",sNominalField,"TradabilityToConfirm-GNom0-",messageSysGetErrorLabel( ) )
						ELSE IF ( ( iResult == 1 ) AND ( messagesGetNbOfMessagesFromCode( pAllMessages,"TradabilityToConfirm-GNom1-" ) == 0 ) ) THEN
							legAddMessage( pMainComponent,"Far nominal > " + toString( fMaxNominal / fRate, 20, 0, TRUE, 0 ) + " " + sNominalUnitValue + " (" + toString( fMaxNominal,20,0,TRUE,0 ) + " " + sRefCCY + " Equivalent)",sNominalField,"TradabilityToConfirm-GNom1-",messageSysGetErrorLabel( ) )
						ELSE
							legAddMessage( pMainComponent,"Nominal > " + toString( fMaxNominal / fRate, 20, 0, TRUE, 0 ) + " " + sNominalUnitValue + " (" + toString( fMaxNominal,20,0,TRUE,0 ) + " " + sRefCCY + " Equivalent)",sNominalField,"TradabilityToConfirm-GNom-",messageSysGetErrorLabel( ) )
						}
                    },//End of BAB addition for Sales profile RFQ  
					iResult := iResult + 1
				}
			}
		}
	}
  }
};

// mx.preTrade.routing.FXD.Booking.Rout-Broker

/*
MXpress
FXD Routing for Broker strategies 

Version 1.0

Notes: Routing rules:
	Output1 - not a Broker strategy
	Output2 - Broker strategy
*/

{
	//Initialize the parameters for structure scan
	iContract := 0,
	iNbContracts := legGetNumberOfContracts( NPD_HDL_THIS ),

	sOutput := "Output1", //default output is set to Output1

	//scan each contract and check if it is a broker strategy
	WHILE ( iContract < iNbContracts ) DO
	{
		pContract := legGetContractAt( NPD_HDL_THIS, iContract ),
		sProductLabel := legGetProductLabel( pContract ),
		IF ( strStartsWith( sProductLabel,"Broker Strangle" ) ) THEN
		{
			sOutput := "Output2",
			iContract := iNbContracts
		},

		iContract := iContract + 1
	}
};

// mx.preTrade.completion.FXD.Pricing.Broker-Pre

/*
MXpress
FXD Broker Strategies - Pre-calculationsxCalibVolCall

Version 1.1
Applied MSL best practices

Version 1.0

Notes: 
This task handles:
- the single delta input
- the volatility input:
* in vol surface mode, the local vol is copied into the calibrated vol
* in customized mode, the customized vol is copied into the calibrated vol,
  using a different input field in one-side and two-sides modes
*/

{
	// Fields Initialization/Reset
	sRegistration := "",
	sEvaluationActive := properties.Get( "mx.preTrade.evaluation.active" ),
	sKeyInputLeg1 := "",
	bKeyInputContainsStrike := FALSE,
	sVolInput := "",
	fLocalAStrikeVol := 0.0,
	xLocalVolCallBidStrike := "0.0/0.0",
	xLocalVolCallAskStrike := "0.0/0.0",
	xLocalVolPutBidStrike := "0.0/0.0",
	xLocalVolPutAskStrike := "0.0/0.0",
	xCalibVolCall := "0.0/0.0", 
	xCalibVolPut := "0.0/0.0", 
	xCalibVol := "0.0/0.0", 
	fCalibVolCallBid := 0.0,
	fCalibVolCallAsk := 0.0,
	fCalibVolPutBid := 0.0,
	fCalibVolPutAsk := 0.0,
	sOneSideBA := "",
	xOneVolTwoSides := "0.0/0.0",
	sBuySell := "",
	fOneVolOneSide := 0.0,

	IF legIsInitialized( This ) THEN
	{
		sRegistration := legGetRegistration( This ),
		IF ( sRegistration == "Broker Strangle FXD" ) THEN
		{
			pVanillaPut := legGetComponentAt( This,0 ),
			pVanillaCall := legGetComponentAt( This,1 ),

			//SINGLE DELTA INPUT:
			//If the key input for the first leg is a moneyness or delta input, copy it to the second leg
			sKeyInputLeg1 := legGetString( pVanillaPut,"Key input" ),
			bKeyInputContainsStrike := strContain( sKeyInputLeg1,"strike" ),
			IF ( ( sKeyInputLeg1 <> "" ) AND ( bKeyInputContainsStrike == FALSE ) ) THEN
				legSetString( pVanillaCall,"Key input",sKeyInputLeg1 ),

			//VOLATILITY INPUT
			IF ( sEvaluationActive == "YES" ) THEN
			{
				sVolInput := legGetString( This,"Vol_input" ),

				//If the vol input is not set, default to vol surface
				IF ( sVolInput == "" ) THEN
					legSetString( This,"Vol_input","Vol surface" ),

				//VOL SURFACE INPUT: Copy the local vol (interpolated from the vol surface) into the calibrated vol
				IF ( sVolInput == "Vol surface" ) THEN
				{
					fLocalAStrikeVol := legGetNumeric( pVanillaCall,"Local a.strike vol" ),
					IF ( ( fLocalAStrikeVol > 0.0 ) AND ( sEvaluationActive == "YES" ) ) THEN
					{
						//Get the bid/ask local vols for the bid and ask strikes of the strategy
						xLocalVolCallBidStrike := legGetBidAsk( pVanillaCall,"Local b.strike vol" ),
						xLocalVolCallAskStrike := legGetBidAsk( pVanillaCall,"Local a.strike vol" ),
						xLocalVolPutBidStrike := legGetBidAsk( pVanillaPut,"Local b.strike vol" ),
						xLocalVolPutAskStrike := legGetBidAsk( pVanillaPut,"Local a.strike vol" ),

						//Get the correct side of the vol for each strike
						fCalibVolCallBid := getBID( xLocalVolCallBidStrike ),
						fCalibVolCallAsk := getASK( xLocalVolCallAskStrike ),
						fCalibVolPutBid := getBID( xLocalVolPutBidStrike ),
						fCalibVolPutAsk := getASK( xLocalVolPutAskStrike ),

						//Overwrite the bid/ask calibrated vol for each leg
						setBID( xCalibVolCall,fCalibVolCallBid ),
						setASK( xCalibVolCall,fCalibVolCallAsk ),
						setBID( xCalibVolPut,fCalibVolPutBid ),
						setASK( xCalibVolPut,fCalibVolPutAsk ),
						legSetBidAsk( pVanillaCall,"Calibrated volatility",xCalibVolCall ),
						legSetBidAsk( pVanillaPut,"Calibrated volatility",xCalibVolPut )
					}
				}
				//CUSTOMIZED VOL INPUT: Copy the customized vol into the calibrated vol
				ELSE IF ( sVolInput == "Customized" ) THEN
				{
					sOneSideBA := legGetString( This,"One side B/A" ),
					//Two-sides - Copy the two-sides customized vol into the calibrated vol
					//and into the one-side customized vol
					IF ( sOneSideBA == "No" ) THEN
					{
						xOneVolTwoSides := legGetBidAsk( This,"One Vol 2sides" ),
						legSetBidAsk( pVanillaPut,"Calibrated_volatility",xOneVolTwoSides ),
						legSetBidAsk( pVanillaCall,"Calibrated_volatility",xOneVolTwoSides ),
						sBuySell := legGetString( pVanillaPut,"Buy_Sell" ),
						IF ( sBuySell == "Buy" ) THEN
							legOverwrite( This,"One Vol 1side",getBID( xOneVolTwoSides ) )
						ELSE IF ( sBuySell == "Sell" ) THEN
							legOverwrite( This,"One Vol 1side",getASK( xOneVolTwoSides ) )
					}
					//One-side - Copy the one-side customized vol into the calibrated vol
					//and into the two-sides customized vol
					ELSE
					{
						fOneVolOneSide := legGetBidAsk( This,"One Vol 1side" ),
						setBID( xCalibVol,fOneVolOneSide ),
						setASK( xCalibVol,fOneVolOneSide ),
						legSetBidAsk( pVanillaPut,"Calibrated_volatility",xCalibVol ),
						legSetBidAsk( pVanillaCall,"Calibrated_volatility",xCalibVol ),
						legSetBidAsk( This,"One Vol 2sides",xCalibVol )
					}
				}
			}
		}
	}
};

 // mx.preTrade.completion.FXMM.Pricing.FInit-Islamic

/*
MXpress
FXMM Field Initialization rule for Islamic products

Used algorithm:
If leg is intialized
	Loop on all components
		Default the payout
		Default the rate/margin
		If current pattern is Wakala
			If first fixing is positive
				If streams is not null
					Loop on all phases
						Loop on all legs
							If current stream is not null
								If current stream is floating
									Loop on all periods
										Set the period rate with the first fixing value
									End loop
								End if
							End if
						End loop
					End loop
				End if
			End if
		Else if current pattern is Mudarabah or Musharaka
			Set PSR
			If current index is empty
				If streams is not null
					If stream in first phase and first leg is not null
						If indexations are not null
							If indexation list is not null
								If template indexation is not null
									Set price factor with the PSR value
								End if
							End if
						End if
					End if
				End if
			Else
				Set rate factor with the PSR value
			End if
		End if
	End loop
End if

Version 1.2
Applied MSL best practices

Version 1.1
Correction of the solving

Version 1.0
The purpose of this rule is to initialize fields for Islamic FXMM products
*/

{
	pLeg := This,

	IF ( legIsInitialized( pLeg ) ) THEN
	{
		// Field Initialization/Reset
		iComponent := 0,
		iNbComponents := legGetNumberOfComponents( pLeg ),
		sPattern := legGetPatternLabel( pLeg ),
		sPayer := "",
		fExpectedRate := 0.0,
		pStreams := pNull,
		iPhase := 0,
		iNbPhases := 0,
		iNbLegs := 0,
		iLeg := 0,
		pStream := pNull,
		iPeriod := 0,
		fPSR := 1.0, // Initialization of PSR to 100%
		sIndex := "",
		pIndex := pNULL,
		pStreams := pNull,
		pStream := pNull,
		pIndexations := pNull,
		pIndexList := pNull,
		pIndexation := pNull,
		pTemplate := pNull,

		pMainComponent := legGetMainComponent( pLeg ),
		pMainContract := legGetFatherContract( pMainComponent ),
		sSourceModule := legGetSourceModule( pMainContract ),
        sFamilyGroup:=legGetProductGroup(pMainComponent),

		// Loop on all components
		WHILE ( iComponent < iNbComponents ) DO
		{
			pComponent := legGetComponentAt( pLeg,iComponent ),
			sTypology := legGetTypology (pComponent),
            // BAB Addition to get tenor for broker fee computation
            IF legIsElementValid(pComponent,"Start") THEN
            {
            dStartDate:=legGetDate(pComponent,"Start")
            },
            dEndDate:=legGetDate(pComponent,"Maturity"),
            fTenor:=dEndDate-dStartDate,

            IF legIsElementValid(pComponent,"IS_BRTENOR") THEN
            legSetNumeric(pComponent, "IS_BRTENOR",fTenor),

                    //BAB Addition to calculate estimated repayment in case of Murabaha/wakala

        IF (sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "Wakala Borrowing" OR sTypology == "Wakala Placement" OR sTypology == "Wakala Borrowing CFC" OR sTypology == "CD Issuance") THEN
    	{	
    		pStreams := legGetStreams(pComponent),
        	pStream1 := streamsGetStream(pStreams, 0, 0),
    		iPeriods := streamGetNumberOfPeriods(pStream1),
    		iPeriod := 0,
        	fRepayment := 0.0,
       		WHILE ( iPeriod < iPeriods ) DO
        	{
        		fRepayment := fRepayment + streamGetPeriodInterestFlow(pStream1,iPeriod),

        		iPeriod := iPeriod + 1
        	},
    	legOverwrite(pComponent,"EST_PROFIT",fRepayment) 
    	},    



            // End of tenor block

		/*	// Setting the NPV as local implied
			legSetLocalImplied(pComponent,"Npv"),

			// Setting the payer and the receiver
			sPayer := legGetString( pComponent,"IS_PAYER" ),
			IF ( sPayer == "Counterparty" ) THEN
				legOverwrite( pComponent,"Payout","Lend" )
			ELSE
				legOverwrite( pComponent,"Payout","Borrow" ),

			// Margin = 0
			legOverwrite( pComponent,"Rate_Margin",0.0 ),  */
	/*		IF ( sPattern == "Wakala" ) THEN
			{
				// Setting the Cap: Expected Rate of Return
				legOverwrite( pComponent,"First_embedded_option","Capped rate"),

				// Propagation of the rate to all periods
				fExpectedRate := legGetNumeric( pComponent,"Strike" ),

				// Not applied when doing the final fixing
				IF ( fExpectedRate > 0.0 ) AND ( sSourceModule <>"mx.fixing" ) THEN
				{
					pStreams := legGetStreams( pComponent ),
					IF ( NOT isNull( pStreams ) ) THEN
					{
						iPhase := 0,
						iNbPhases := streamsGetNumberOfPhases( pStreams ),
						iNbLegs := streamsGetNumberOfLegsPerPhase( pStreams ),
						WHILE ( iPhase < iNbPhases ) DO
						{
							iLeg := 0,
							WHILE ( iLeg < iNbLegs ) DO
							{
								pStream := streamsGetStream( pStreams,iPhase,iLeg ),
								IF ( NOT isNull( pStream ) ) THEN
								{
									// Check on the number of periods
									IF ( streamIsFloating( pStream ) ) THEN
									{
										iPeriod := 0,
										iNbPeriods := streamGetNumberOfPeriods( pStream ),
										WHILE ( iPeriod < iNbPeriods ) DO
										{
											// Check if Index fixed
											sIndex := legGetString( pComponent,"Index" ),
											pIndex := indexGetIndexByLabel( sIndex ),
											dDate := streamGetPeriodFixingDate( pStream,0 ),
											fIndexValue := indexGetFixingValue( pIndex,dDate ),

											// Set expected Rate of return for each period
											IF ( fIndexValue == 0.0 ) THEN
												streamSetPeriodRate( pStreams,pStream,iPeriod,fExpectedRate ),

											iPeriod := iPeriod + 1
										}
									}
								},
								iLeg := iLeg + 1
							},
							iPhase := iPhase + 1
						}
					}
				}
			}  

			ELSE */ IF ( ( sPattern == "Mudarabah" ) OR ( sPattern == "Musharaka" ) ) THEN
			{
				// Profit Sharing Ratio
				IF legGetNumeric( pComponent,"IS_PSR" ) > 0. THEN
					fPSR := legGetNumeric( pComponent,"IS_PSR" ) / 100.0,

				// Rate or Amount input
				sIndex := legGetString( pComponent,"Index" ),
				IF ( sIndex == "" ) THEN
				{                
					pStreams := legGetStreams( pComponent ),
					IF ( NOT isNull( pStreams ) ) THEN
					{
						pStream := streamsGetStream( pStreams,0,0 ),
						IF ( NOT isNull( pStream ) ) THEN
						{
							pIndexations := streamGetIndexations( pStream ),
							IF ( NOT isNull( pIndexations ) ) THEN
							{
								pIndexList := indexationsGetInterestFlowIndexationList( pIndexations ),
								IF ( NOT isNull( pIndexList ) ) THEN
								{
									pIndexation := indexationListGoto( pIndexList,0 ),
									IF ( NOT isNull( pIndexation ) ) THEN
									{
										pTemplate := indexationGetTemplate( pIndexation ),
										IF ( NOT isNull( pTemplate ) ) THEN
											indexationTemplateSetPriceFactor( pTemplate,fPSR )
									}
								}
							}
						}
					}
				}
				ELSE
					legSetNumeric( pComponent,"Rate_factor",fPSR )
			},

               //BAB Addition
             //Repo SAMA Price calculation

           sTypology:=legGetTypology(pComponent),

          IF ( ((sTypology == "Repo SAMA") OR (sTypology == "RR SAMA") OR (sTypology == "SAMA Bill") ) ) THEN
            {

               //Addition for Repo price mode: Rate or Discounted Price
               sSAMAUDF :=legGetString(pComponent,"IS_RSAMA"),

               //Repo Rate mode
               IF sSAMAUDF == "Rate" THEN
               IF (sTypology <> "SAMA Bill") THEN
               {
                    fNominal := legGetNumeric(pComponent, "Nominal"),

                    fRepayment := legGetNumeric(pComponent, "Repayment"), 

                    //fNumberOfDays := legGetNumeric(pComponent, "Number_of_days"),
                    //Set number of days as Maturity minus Start date, to pick up the correct number of days on the first pass, to have the Nominal refreshed correctly
                    fNumberOfDays:= fTenor,

                    sNumberOfDays := toString(toInt(fNumberOfDays)),
                    pRSAMArate := lookupResults("BAB.ALL.RSAMARate","ALL","Typology",sTypology, "Number_of_days",sNumberOfDays ),
                    fRSAMArate := lookupResultsGetNumeric( pRSAMArate,0,0),

                    IF ( isNull(pRSAMArate)  ) THEN
                    {                
                        ThrowError(pComponent,"Missing "+sTypology+" rate for Number of Days = "+sNumberOfDays+". Contact MO desk for correction. Resetting to 1%", "Rate_Margin"),
                        legSetCellColorAsError(pComponent,"Rate_Margin"),
                        legSetNumeric(pComponent,"Rate_Margin",1.0)
                    },

                    //For when we first switch from Price to Rate mode, to OVERWRITE the rate as per LUT, otherwise SET it, to cater for when rate is manually changed
                    sPortfolio:=legGetString(pComponent,"Portfolio"),


                    //Set Repo Rate in a UDF and show on ticket
                    IF legGetLastInputField(pComponent) == "IS_RSAMA" OR sPortfolio == "" THEN
                    legOverwrite(pComponent,"S_REPO_RT",fRSAMArate)

                    ELSE
                    {
                        legSetNumeric(pComponent,"S_REPO_RT",fRSAMArate)
                    },

                    //Re-Get the RSAMArate in case it's customized from the Rate UDF S_REPO_RT
                    fRSAMArate := legGetNumeric(pComponent,"S_REPO_RT"),


                    //Get equivalent profit at provided rate in UDF on the Repayment amount i.e. the clean nominal

                    bRepaymentInitialized := FALSE,

                    IF fRepayment == 0.0 THEN
                    {
                    	fInitializeRepayment := 100.0,
                        bRepaymentInitialized := TRUE
                    },


                    //Set Repayment to the Initializing value for the first Virtual leg computation below
                    IF bRepaymentInitialized THEN
                    fRepaymentVirtual := fInitializeRepayment
                    //Else get the input value
                    ELSE
                    fRepaymentVirtual := fRepayment,

                    //Open Container
                    pContainer := npOpen(TRUE),
                    	pClone := npCloneLeg( pContainer,pComponent),
                        legOverwrite(pClone,"Nominal", fRepaymentVirtual), //Set Nominal of clone as clean repayment of main deal
                        legOverwrite(pClone,"Rate_Margin",fRSAMArate),
                        legSetLocalImplied(pComponent,"Npv"),
                        legCompute( pClone,"noWorkflow"),

                        //Get the Profit amount
                        pStreams := legGetStreams(pClone),
                        iPhase := 0,
                        pLegStream := streamsGetStream(pStreams,iPhase,0),
                        iPeriod := 0,

                        fProfit := streamGetPeriodInterestFlow(pLegStream,iPeriod),
                    npClose(pContainer),


                    //Calculate Equivalent Nominal
                    IF bRepaymentInitialized THEN
                    fEquivalentNominalInRateMode := fRepaymentVirtual - abs(fProfit) //Get equivalent initialize nominal
                    ELSE
                    fEquivalentNominalInRateMode := fRepayment - abs(fProfit), //Use the actual Repayment entered

                    //Use the RSamaPrice pricing logic below
                    //Let the system solve for an equivalent rate but show the UDF actual rate of Repayment on deal ticket

                    IF (fRepayment == 0.0) THEN
                        legOverwrite(pComponent, "Nominal",fEquivalentNominalInRateMode) //Initialze Nominal

                    ELSE IF ( ( NOT legIsSolverOn(pComponent) ) AND ( properties.Get("mx.preTrade.evaluation.active")=="" ) ) THEN
                    { 	
                        legSetLocalImplied(pComponent,"Rate_Margin"),
                        fCalcul := 	fEquivalentNominalInRateMode,
                        legOverwrite(pComponent, "Nominal", fCalcul),
                        legOverwrite(pComponent, "Repayment",fRepayment)


                    }

               }

               ELSE

                          {
                    fNominal := legGetNumeric(pComponent, "Nominal"),
                    fRepayment := legGetNumeric(pComponent, "Repayment"), 

                    //Get the number of days
                    fNumberOfDays := legGetNumeric(pComponent, "Number_of_days"),
                    sNumberOfDays := toString(toInt(fNumberOfDays)),

                    //Get the Repo or Reverse Repo Rate from the Lookup table
                    pRSAMArate := lookupResults("BAB.ALL.RSAMARate","ALL","Typology",sTypology, "Number_of_days",sNumberOfDays ),
                    fRSAMArate := lookupResultsGetNumeric( pRSAMArate,0,0),

                    //For when we first switch from Price to Rate mode, to OVERWRITE the rate as per LUT, otherwise SET it, to cater for when rate is manually changed. The Portfolio is used to OVERWRITE the rate to the fSAMArate when the deal is initially priced.

                    sPortfolio:=legGetString(pComponent,"Portfolio"),
                    IF legGetLastInputField(pComponent) == "IS_RSAMA" OR sPortfolio == "" THEN
                    legOverwrite(pComponent,"Rate_Margin",fRSAMArate)
                    ELSE
                    {
                    	legSetNumeric(pComponent,"Rate_Margin",fRSAMArate)
                    },

                    //Throw error if the rate is missing for the specific number of days
                    IF ( isNull(pRSAMArate)  ) THEN
                    {                
                        ThrowError(pComponent,"Missing "+sTypology+" rate for Number of Days = "+sNumberOfDays+". Contact MO desk for correction. Resetting to 1%", "Rate_Margin"),
                        legSetCellColorAsError(pComponent,"Rate_Margin"),
                        legSetNumeric(pComponent,"Rate_Margin",1.0)
                    },


                    IF (fRepayment == 0.0) THEN 	//To initialize Repayment
                    	legOverwrite(pComponent, "Nominal",100.0)

                    ELSE IF ( ( NOT legIsSolverOn(pComponent) ) AND ( properties.Get("mx.preTrade.evaluation.active")=="" ) ) THEN //If Repayment is populated
                    { 	  
                        legSetLocalImplied(pComponent,"Nominal"),
                        legOverwrite(pComponent, "Repayment",fRepayment)
                    },

                    //Calculate equivalent Discount price and store in UDF RSAMAPRICE - for consistency, it won't be used
                    fRSAMArate := legGetNumeric(pComponent,"Rate_Margin"),
                    fEquivalentPrice :=  ( 1.0 / (1.0 + fRSAMArate*(fNumberOfDays/36000.0)) )*100.0,
                    legOverwrite(pComponent,"RSAMAPRICE",fEquivalentPrice)

               }//End of Repo Rate mode

               //Repo Discounted Price mode
               ELSE
               {
                    fNominal := legGetNumeric(pComponent, "Nominal"),
                    fRepayment := legGetNumeric(pComponent, "Repayment"), 

                    //Get the number of days
                    //fNumberOfDays := legGetNumeric(pComponent, "Number_of_days"),
                    //Set number of days as Maturity minus Start date, to pick up the correct number of days on the first pass, to have the Nominal refreshed correctly
                    fNumberOfDays:= fTenor,

                    sNumberOfDays := toString(toInt(fNumberOfDays)),

                    //Get the Repo or Reverse Repo Price from the Lookup table
                    pRSAMAprice := lookupResults("BAB.ALL.RSAMAPrice","ALL","Typology",sTypology, "Number_of_days",sNumberOfDays ),
                    fRSAMAprice := lookupResultsGetNumeric( pRSAMAprice,0,0),

                    //For when we first switch from Rate to Price mode, to OVERWRITE the Price as per LUT, otherwise SET it, to cater for when Price is manually changed
                    IF legGetLastInputField(pComponent) == "IS_RSAMA" THEN
                    legOverwrite(pComponent,"RSAMAPRICE",fRSAMAprice)
                    ELSE
                    legSetNumeric(pComponent,"RSAMAPRICE",fRSAMAprice),

                    fRSAMAprice:=legGetNumeric(pComponent,"RSAMAPRICE"),

                    //Throw error if the price is missing for the specific number of days
                    IF ( isNull(pRSAMAprice)  ) THEN
                           {                
                        ThrowError(pComponent,"Missing "+sTypology+" price for Number of Days = "+sNumberOfDays+". Contact MO desk for correction", "RSAMAPRICE"),
                        legSetCellColorAsError(pComponent,"RSAMAPRICE")
                        },

                    IF (fRepayment == 0.0) THEN
                        legOverwrite(pComponent, "Nominal",fRSAMAprice)

                    ELSE IF ( ( NOT legIsSolverOn(pComponent) ) AND ( properties.Get("mx.preTrade.evaluation.active")=="" ) ) THEN
                    { 	
                        legSetLocalImplied(pComponent,"Rate_Margin"),
                        fCalcul := 	((fRepayment * fRSAMAprice )/100.0),
                        legOverwrite(pComponent, "Nominal", fCalcul),
                        legOverwrite(pComponent, "Repayment",fRepayment)


                    }
                }//End of Repo Discounted price mode
          	},
            //End of BAB Addition


             //BAB Addition Purchase SAMA Price 
             IF sPattern == "SAMA Purchase" THEN
             {
             legSetString(pComponent,"Maturity_period","TODAY"),
             legSetString(pComponent,"Second_del_date_period","TOM"),
             sPayout := legGetString(pComponent,"Den_Buy_Sell"),
                IF sPayout == "Sell" THEN
                {
                sSellCurr := legGetString(pComponent,"Den_unit"),
                sBuyCurr:= legGetString(pComponent,"Num_unit"),
                legSetString(pComponent,"Second_del_currency",sBuyCurr)
                }
                ELSE
                {
                sSellCurr := legGetString(pComponent,"Num_unit"),
                sBuyCurr:= legGetString(pComponent,"Den_unit"),
                legSetString(pComponent,"Second_del_currency",sBuyCurr)
                },
             pPSAMAprice := lookupResults("BAB.ALL.SAMAPurchasePrice","ALL","Typology",sTypology,"Sell Currency",sSellCurr),
             fPSAMAprice := lookupResultsGetNumeric( pPSAMAprice,0,0),
             legSetNumeric(pComponent, "Forward",fPSAMAprice)
             },
            //////rfr addition
           sPattern := legGetPatternLabel ( pComponent),
           sRegistration := legGetRegistration ( pComponent ),
           sRFRCheck := lookupString ("BAB.ALL.RFRCHECK","ALL","Registration",sRegistration,"Pattern",sPattern),

           IF sRFRCheck <> "" THEN
          	 sStructure := legGetString (pComponent, "STRUCTURE"),

            IF (sRFRCheck == "IR_PRS"AND ( sStructure == "Single Murabaha" OR sStructure == "Multiple Murabaha")) THEN
            {

            	pStreams:= legGetStreams(pComponent),
                iNbStreams := streamsGetNumberOfLegsPerPhase(pStreams),
                iStream :=0,

                WHILE (iStream < iNbStreams) DO
                {
                  pStream := streamsGetStream(pStreams,0,iStream),
                  bFloating := streamIsFloating (pStream),

                   IF bFloating THEN
                   {
                       sRateConvention := streamGetRateConvention(pStream),
                       dStartDate := legGetDate(pComponent,"Start"),
                       dAdjustedMaturity := legGetDate (pComponent, "Last_Calculation_Date"),
                       sCurrency := legGetString (pComponent,"Currency2"),
                       fNbDays :=  dAdjustedMaturity-dStartDate,
                       fRateConvention := convertSToNumeric ( strSubString(sRateConvention,8,11) ),
                       fNominal := legGetNumeric (pComponent,"Nominal"),

                       IF (legIsAttributeCustomized(pComponent,"CLNG_RATE") == FALSE) THEN
                       {
                       		 // fetching estimation curve
                           pContainer := npOpen(),
                           pNew := legClone (pContainer,pComponent),
                           legOverwrite(pNew, "Sales_margin", 0.0),   
                           legCompute(pNew,"noWorkflow"),  
                           sEstCurve := legGetString(pNew,"Estimation_curve2"),
                           npClose(pContainer),

                           //fetching estimated ceiling rate
                           fEstRate := rcGetRate (sCurrency,sEstCurve,dStartDate,dAdjustedMaturity), 
                       		legSetNumeric(pComponent,"CLNG_RATE",fEstRate)
                       },

                       fCeilingRate := legGetNumeric (pComponent, "CLNG_RATE"),  

                       //Calculate ceiling profit
						fCeilingProfit := (fCeilingRate/100.0)*fNominal*(fNbDays/fRateConvention),
                       	IF (sStructure == "Single Murabaha") THEN
                       legSetNumeric(pComponent,"IS_ORIFLOW",fCeilingProfit)

                   },
				  iStream := iStream +1
                 }

               }


               ELSE IF (sRFRCheck == "BR_Murabaha" AND (sStructure == "Single Murabaha" OR sStructure == "Multiple Murabaha")) THEN
               {
                   dStartDate := legGetDate (pComponent, "Start_date"),
                   dMaturity := legGetDate (pComponent, "Maturity"),
                   fNbDays := legGetNumeric (pComponent,"Number_of_days"),
                   sRateConvention := legGetString (pComponent, "Rate_convention2"),
                   fRateConvention := convertSToNumeric ( strSubString (sRateConvention,8,11)),
                   sCurrency := legGetString (pComponent, "Currency"),
                // fetching estimation curve
            	   pContainer := npOpen(),
                   pNew := legClone (pContainer,pComponent),
                   legOverwrite(pNew, "Sales_margin", 0.0),   
                   legCompute(pNew,"noWorkflow"),  
                   sEstCurve := legGetString(pNew,"Estimation_curve2"),
                   npClose(pContainer),
                  // sEstCurve := legGetString (pComponent, "Estimation_curve2"),
                   fEstRate := rcGetRate (sCurrency, sEstCurve, dStartDate, dMaturity),
                   fNominal := legGetNumeric (pComponent, "Nominal"),

                    IF (legIsAttributeCustomized(pComponent,"CLNG_RATE") == FALSE) THEN
                                legSetNumeric(pComponent,"CLNG_RATE",fEstRate),
                    fCeilingRate := legGetNumeric (pComponent, "CLNG_RATE"),

                    fCeilingProfit := (fCeilingRate/100.0)*fNominal*(fNbDays/fRateConvention),
                   	IF (sStructure == "Single Murabaha") THEN
                   legOverwrite(pComponent,"IS_ORIFLOW",fCeilingProfit)
               }
               ,

              ///// end of rfr addition

            // BAB Addition

            //BAB addition for Price on request check
            IF legIsElementValid(pComponent,"Price_on_request") THEN
            sPriceOnRequest := legGetString(pComponent,"Price_on_request"), 
            IF sFamilyGroup == "LN_BR" AND sPriceOnRequest <> "Yes" THEN
            {
                pInitialData := legGetInitialDatas( pComponent ),  
                dMarketDataDateIRR := legGetTradingDate(pComponent),
                dStartDate := legGetDate(pComponent,"Start"),

                pContainer := npOpen(TRUE),
                pClone := npCloneLeg( pContainer,pComponent),
                //legOverwrite(pClone,"Market_Data_Private_Mode", "ON"),
                legOverwrite(pClone,"Market_Data_date", dMarketDataDateIRR),
                legOverwrite(pClone,"Flows_filter_date", dMarketDataDateIRR),
                legOverwrite(pClone,"Price_on_request","No"),                                
                pInitialData := legGetInitialDatas( pComponent ),                                                                                                                              
                legSetLocalImplied(pClone,"Rate_Margin"),
                IF (legGetString(pComponent,"Price_on_request") == "Yes") THEN
                 {
                     legCompute( pClone,"noWorkflow")
                 },

                legOverwrite(pClone, "Today_cash", "Incorporated"),
                legOverwrite( pClone,"Sales margin",0.0 ),
                legSetNumeric(pClone,"Npv",0.0),
                legCompute( pClone,"noWorkflow"),                           
                fNpvMargin1 := legGetNumeric(pClone,"Rate_Margin"),
                sEstCurve := legGetString(pClone,"Estimation_curve"),
                npClose(pContainer),
                ///rfr addition

				sRegistration := legGetRegistration ( pComponent ),
				sRFRCheck := lookupString ("BAB.ALL.RFRCHECK","ALL","Registration",sRegistration,"Pattern",sPattern),

				IF (sRFRCheck <> "") THEN
					sStructure := legGetString (pComponent, "STRUCTURE"),

					IF ((sRFRCheck == "LB_LTM" OR sRFRCheck == "LB_Murabaha" ) AND (sStructure == "Single Murabaha" OR sStructure == "Multiple Murabaha")) THEN
						{

                            dStartDate := legGetDate (pComponent, "Start"),
                            dAdjustedMaturity := legGetDate (pComponent, "Last_Calculation_Date"),
                            fNbDays := legGetNumeric (pComponent,"Number_of_days"),
                            sRateConvention := legGetString (pComponent, "Rate_convention"),
                            fRateConvention := convertSToNumeric ( strSubString (sRateConvention,8,11)),
                            sCurrency := legGetString (pComponent, "Nominal_unit"),
                            fNominal := legGetNumeric (pComponent, "Nominal"),
                            fEstRate := rcGetRate (sCurrency,sEstCurve,dStartDate,dAdjustedMaturity),

					IF (legIsAttributeCustomized(pComponent,"CLNG_RATE") == FALSE) THEN
                        legSetNumeric(pComponent,"CLNG_RATE",fEstRate),
                        fCeilingRate := legGetNumeric (pComponent, "CLNG_RATE"),

                        fCeilingProfit := (fCeilingRate/100.0)*fNominal*(fNbDays/fRateConvention),
                        IF (sStructure == "Single Murabaha") THEN
                        legOverwrite(pComponent,"IS_ORIFLOW",fCeilingProfit)
						},


				////end of rfr addition

                //Only set Benchmark rate when it's different from an already set Benchmark rate
                IF ( initialdatasGetNumeric(pInitialData, "Benchmark rate") <> fNpvMargin1 ) THEN
                {
                	initialdatasSetNumeric(pInitialData,"Benchmark rate",fNpvMargin1)
                },               
                // Set the Benchmark rate on the deal ticket
                IF (legGetNumeric(pComponent,"BNCH_RATE") <> fNpvMargin1) THEN
                {
                	legSetNumeric(pComponent,"BNCH_RATE",fNpvMargin1)
                }

             }, 



             //BAB Addition - Tag deals eligible for WHT on profit
             IF (sTypology == "Wakala Borrowing" OR sTypology == "Murabaha Borrowing" OR sTypology == "Wakala Borrowing CFC" OR sTypology == "CD Issuance") THEN
            {
                dTradeDate := legGetDate(pComponent,"Trading_Date"), 
                dMaturityDate:=legGetDate(pComponent,"Maturity"),
                fNbOfDays := dMaturityDate - dTradeDate,
                fLimitDays := 90.0,

                sCounterparty := legGetString( pComponent,"Counterpart" ),
                sCtpCountry := ctpGetCountry(sCounterparty) ,

                IF ( fNbOfDays > fLimitDays AND sCtpCountry <> "SA" ) THEN
				legSetString(pComponent, "PROFIT_WHT","Yes")
                ELSE
                legSetString(pComponent, "PROFIT_WHT","No")

             },

             //End of BAB Addition - Tag deals eligible for WHT on profit


             // Block copied from FInit-ALL to cater for VAMODE logic for Islamic
             // Set VAMODE to the relevant value for Sales profiles, keep None (Default) otherwise 
             sVAModeField := "VAMODE",  
             IF ( legIsElementValid( pComponent, sVAModeField ) ) THEN
            {
                IF ( legGetString(pComponent, "Internal") == "Yes" ) THEN
                    legSetString(pComponent, sVAModeField, "None")
                ELSE
                {
					sUserProfile := lookupString( "MX.ALL.UserGroupProfile","ALL","USER_GROUP",sysGetGroup() ),
                    IF ( sUserProfile <> "Sales" ) THEN
                    	legSetString(pComponent, sVAModeField, "None")
                    ELSE
                    	legSetString(pComponent, sVAModeField, "Keep in Sales portfolio")
                }
            },  

			iComponent := iComponent + 1
		},

           // For Sales margin mode 'Keep in Sales portfolio', automatically set Back to Back = Yes - Except for FXMM Packages where we set Independent margins = Yes
    sLegRegistration := legGetRegistrationLabel( pLeg ),
	pMainComponent := legGetMainComponent( pLeg ),    
    IF ( sLegRegistration <> "mxContractFxIOUTRIGHT" AND sLegRegistration <> "mxContractFxISPLIT" AND sLegRegistration <> "mxContractFxISPLITSWAP" AND sLegRegistration <> "mxContractFxIFUNDINGOUTRIGHT" AND sLegRegistration <> "mxContractFxIFUNDINGSWAP" ) THEN
    {
    	IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
        {
        	IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
            {
            	/*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), TRUE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
                legSetFOPIsBackToBack(pMainComponent, TRUE)*/
                IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                	legSetString(pMainComponent,"Back to back","Yes")                
            }
            ELSE
            {
 				/*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), FALSE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
				legSetFOPIsBackToBack(pMainComponent, FALSE)*/
                IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                	legSetString(pMainComponent,"Back to back","No")                  
            }
       	}
    }
    ELSE
    {
		IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
        {
        	IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
        		legSetString(pLeg, "Independent margins", "Yes")
            ELSE
	            legSetString(pLeg, "Independent margins", "No")
       	}    
    }




	}
};

// mx.preTrade.completion.Orders.ALL.CheckMsg

/*
MXpress OMS requirements for handling error/warning messages

Version 1.2
Applied MSL best practices

Version 1.1
- Amended to remove the DIST_MSG UDF and use legAddMessage(pointer ,message text ,field, error code, error level) to attach warning messages to legs.
- Bug fix in case of public contract

Version  1.0
Step 1: Get the right pointers for the components and the leg
	Two special cases are taken into account: 
		- The package allocation in case of a Block trade/order, the Leg is the first contract of the Block
		- The STB Contract, the Component is the first leg of the contract
Step 2: Handle the spefic behaviour of the Limit and Stop loss orders
		The order type is stored in the 'Order_template" field of the current order, it will serve as a condition for this step
Step 3: Read the error code pushed in messages by the formula mx.preTrade.completion.Orders.Closing.SanityCheck
*/

{
	/////////////////////////////////////////////////
	///  Step 1: Get the right pointers for the components and the leg
	///		Two special cases are taken into account: 
	///			- The package allocation in case of a Block trade/order, the Leg is the first contract of the Block
	///			- The STB Contract, the Component is the first leg of the contract
	/////////////////////////////////////////////////
	pLeg := This,
	pFirstContract := legGetContractAt( pLeg, 0 ),

	IF legGetRegistrationLabel( pLeg ) == "mxContractIPACKAGE_ALLOCATION" THEN 
		pComponent := pFirstContract
	ELSE 
		pComponent := This,

	IF legGetRegistrationLabel( pComponent ) == "mxContractStbICONTRACT" THEN 
		pComponent := legGetComponentAt( This, 0 )
	ELSE 
		pComponent := pFirstContract,

	/////////////////////////////////////////////////
	///  Step 2: Handle the spefic behaviour of the Limit and Stop loss orders
	/// 	The order type is stored in the 'Order_template" field of the current order, it will serve as a condition for this step
	///		Handle the order warning/error messages that were raised by mx.preTrade.completion.Orders.ALL.Pricing.OrdTemplate during pricing
	/////////////////////////////////////////////////
	pAllMessages := legGetMessages( pComponent ),

	// Check that we are in an insertion context    
	IF ( properties.Get( "mx.preTrade.action" ) <> "MOD" ) THEN
	{
		bIsInBookingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ), "B_" ),
		iMsg := 0,
		iNbMsgSanity := messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Odr-" ),           
		WHILE ( iMsg < iNbMsgSanity ) DO
		{
			pMessage := messagesGetMessageFromCodeAt( pAllMessages,"Sane-Odr-",iMsg ),
			IF ( bIsInBookingSequence ) THEN
				ThrowError( pComponent,messageGetText( pMessage ),messageGetField( pMessage ) )
			ELSE
			{
				ThrowLowPriorityWarning( pComponent,messageGetText( pMessage ),messageGetField( pMessage ) ),
				legSetCellColorAsError( pComponent,messageGetField( pMessage ) )
			},
			iMsg := iMsg + 1
		}
	}
};

// mx.preTrade.routing.Orders.ALL.TradePurpose

/*
MXpress 
Routing formula on the Trade Purpose

Version  1.0
The only trade purposes handled are:
	- Trade
	- Order
*/

{
	pLeg := NPD_HDL_THIS,
	sOutput := "Trade",

	sTradePurpose := legGetString( pLeg,"Trade purpose" ),
	IF ( sTradePurpose == "Order" ) THEN
		sOutput := "Order"
};

// mx.Order event.completion.Closing.Allocation

/*
MXpress OMS requirements for handling allocation on block order execution. 

Version 1.2
Applied MSL best practices

Version 1.1

Before applying the allocation algorithm, the system checks if the block quantity is impacted. It is not applied if the quantity is adjusted at leg level
The system assigns the contracts priorities based on the ascending order of the allocation percentage for each of them 
After Min piece allocation, the system recalculates fair allocation of each contract for Min Incr allocation. It is not on a prorate basis, but rather depends on the 
new theoretical remaining amount of the contract, if any (following the allocation of Min piece).

If after Min increment allocation, there is still order execution quantity to allocate, the system checks if this remaining quantity is a multiple of the Min Increment
If yes
	The system allocates Min increments to the contracts following a priority rule, regardless of the remaining quantity per contract
Else
	The system does not allocate the remaning quantity
In case the user inputs an order execution quantity less than the Min piece, the system allocates as many Min Increments as possible to the highest priority contract
If not all the order execution quantity could be allocated, the system notifies the user by setting the quantity cells of the contracts to red


Version 1.0

Note:
This algorithm performs fair allocation of executed quantity across allocations with respect to min piece and min increment as defined
in security definition for Bonds or as a minimum allocation value defaulted to 1 that can be overwritten by currency / product in 
table MX.ORD.AllocationRule   

The system first checks if minimum piece can be allocated to each allocation 

If yes
	The system allocate min piece to all remaining allocation as long as the fair allocation (prorate basis allocation) is not too far 
from Minimum piece. In order to do that the system check that the ratio between fair allocation and  Min piece is above a given 
threshold defaulted to 0.5 in current rule implementation
	If after allocating Min piece there is still order execution quantity to allocate, the system proceed with Min increment 
following the same rule as for Min piece.

	If after allocating Min increment piece there is still order execution quantity to allocate, the system proceed with the residual 
quantity following on a priority rule, based on order remaining quantity to be executed for each allocation. 
The highest priority receive as much as possible than the system iterate with the next priority until no executed quantity is left.

If no 
	The system allocates the residual quantity based on a priority rule, based on order remaining quantity to be executed for each 
allocation. The highest priority receive as much as possible than the system iterate with the next priority until no executed 
quantity is left.
*/

{
	// Event characteristics
	pEvent := This,
	sAllocationRule := "No",
	sAllocationFlag := "No",
	// Executed order
	pOrdBlock := mx.order.event.Event.GetTargetOrderUnderlyingBO( pEvent ),

	// Quantity field
	pOrder := legGetContractAt( pOrdBlock,0 ),	// There is at least one order
	sQuantityField := legGetContractOrderConfigQuantityField( pOrder ),
	sUnitField := legGetContractOrderConfigQuantityUnitField( pOrder ),
	IF ( sUnitField <> "" ) THEN 
		sCurrency := legGetString( pOrder, sUnitField ),

	// Generated contract
	pCntVOB := mx.order.event.Event.GetVersionBOAt( pEvent,0 ),
	pCntBlock := evtVersionedBOGetNew( pCntVOB ),
	iNbContracts := legGetNumberOfContracts( pCntBlock ),

	sRegistration := legGetRegistration(pOrder),

	// Retrieve the parameter to be used in allocation algorithm
	pAllocResults := lookupResults( "MX.ORD.AllocationRule","ALL",
									"Registration",sRegistration,
									"Currency",sCurrency ),
	iNbResults := lookupResultsGetNumberOfLines( pAllocResults ),
	IF ( iNbResults <> 1 ) THEN 
		ThrowError("No configuration has been found for allocation algorithm, please check MX.ORD.AllocationRule table","")
	ELSE
	{
		sAllocationRule := lookupResultsGetString( pAllocResults,0,0 ),
		sDefaultMin := lookupResultsGetString( pAllocResults,0,1 ),
		fMinPiece := lookupResultsGetNumeric( pAllocResults,0,2 ),
		fMinIncr := lookupResultsGetNumeric( pAllocResults,0,3 )
	},

	// If AllocationRule is Yes, check if manual modification done in the Quantity
	// In that case the Allocation algorithm shall not be reapplied
	IF ( sAllocationRule == "Yes" ) THEN
	{
		// Case quantity is modified from broadcaster --> recalculate Allocation
		// Total quantity is different from prev total quantity 
		// and all % ratios per leg are the same as the old ones

		iContract := 0,
		fNewQuantity := 0,
		fOldQuantity := 0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			fNewQuantity := fNewQuantity + legGetNumeric( pContract,sQuantityField ),
			fOldQuantity := fOldQuantity + legGetNumeric( pContract,"pf_leg_quantity" ),

			iContract := iContract + 1
		},

		iContract := 0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			sIsTradable := legGetString( pContract,"pf_Allocation" ),
			IF ( sIsTradable == "YES" ) THEN
				legSetCellColorAsError(  pContract,sQuantityField ),

			iContract := iContract + 1
		},

		iContract := 0,
		sRatioChange := "No",
		fLegQuantity := 0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			fLegQuantity := legGetNumeric( pContract,sQuantityField ),
			fRatio := legGetNumeric( pContract,"pf_leg_ratio" ),
			fRatioNew := rounddefault( fLegQuantity / fNewQuantity, 3),
			IF ( fRatio <> fRatioNew ) THEN
				sRatioChange := "Yes",

			iContract := iContract + 1
		},

		IF ( fOldQuantity == 0.00 ) THEN // detect first allocation
			sAllocationFlag := "Yes"
		ELSE IF ( ( fNewQuantity <> fOldQuantity ) AND ( sRatioChange == "No" ) ) THEN  // detect global qtty has changed
			sAllocationFlag := "Yes",

		IF ( sAllocationFlag == "No" ) THEN
		{
			// Case individual leg quantity is modified --> do not recalculate Allocation
			iContract := 0,
			WHILE ( iContract < iNbContracts ) DO
			{
				pContract := legGetContractAt( pCntBlock,iContract ),
				blegIsCustomized := legIsAttributeCustomized(pContract,sQuantityField),
				IF ( blegIsCustomized == TRUE ) THEN 
					sAllocationFlag := "No",

				iContract := iContract + 1
			}
		}
	},// end if sAllocationRule

	// If no allocation rule is applied, native behaviour is kept, order is executed on prorata basis
	// otherwise we apply a "fair" allocation algorithm
	// If we have only one generated contract, no need to perform any kind of allocation
	IF ( ( sAllocationFlag == "Yes" ) AND ( sAllocationRule == "Yes" ) AND ( iNbContracts > 1 ) ) THEN
	{
		iContract := 0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			legSetString ( pContract,"pf_Allocation","" ),

			iContract := iContract + 1
		},

		// If no min piece / increment have been defined we retrieve default one
		IF ( sDefaultMin == "Yes" ) THEN 
		{
			// Some registration have Min piece and min increment defined         
			IF ( sRegistration == "Bonds" ) THEN 
			{
				fMinPiece := legGetNumeric( pOrder,"Minimum piece" ),
				fMinIncr := legGetNumeric( pOrder,"Minimum increment" ),
				fLotSize := legGetNumeric( pOrder,"Lot_size" )
			}
			ELSE IF ( sRegistration == "Equities" ) THEN
			{
				sInstrument := legGetString( pOrder,"Instrument" ),
				sMarket := legGetString( pOrder,"Market" ),
				fMinIncr := securityGetBoardLot( sInstrument,sMarket ),
				fMinPiece := fMinIncr
			}
			ELSE
			{
				// Default values for all other products
				fMinPiece := 1,
				fMinIncr := 1
			},

			// In order to have one single logic whenever the execution field is quantity we have to convert 
			// the amount min piece and increment into quantity
			// Quantity is only relevant for listed product and is always named "Quantity"
			IF ( ( sQuantityField == "Quantity" ) AND ( sRegistration == "Bonds" ) ) THEN
			{
				fMinPiece := fMinPiece / fLotSize,
				fMinIncr := fMinIncr / fLotSize
			}
		},

		// In order to avoid issue related to data quality, if min piece and min increment are not defined (equal to 0), warn user and use 1
		IF ( fMinPiece == 0.0 AND sRegistration <> "Equities" ) THEN
		{
			fMinPiece := 1.0,
			ThrowLowPriorityWarning( "Min piece is not correctly defined, please correct the configuration","" )
		},

		IF ( fMinIncr > fMinPiece AND sRegistration == "Equities" ) THEN
		{
			fMinPiece := fMinIncr
		},

		IF ( fMinIncr == 0.0 ) THEN 
		{
			fMinIncr := 1.0,
			ThrowLowPriorityWarning( "Min piece is not correctly defined, please correct the configuration","" )
		},

		fRemainingAmountTotal := 0.0, // Initialize amount that can be executed
		fRemainingAmount := 0.0,
		fFairAllocation := 0.0, // Fair allocation that gives each allocation of the block order the executed amount on prorata basis
		fRankingValue := 0.0, // Value used to rank order in order to have a priority allocate what can't be "fairly" allocated
		fThreshold := 0.5, // This threshold define when the allocated quantity (taking into account minimum) should be considered too far from fair value  
		fExecutedAmount := 0.0,

		fEligibleAllocation := 0.0,
		fPostAllocRemainingAmountTotal := 0.0,

		// Define an array where we store allocated amounts
		pAllocationArray := arrayNew(),
		arrayDefinitionSetNumeric( pAllocationArray,"RemainingAmount",FALSE ),	// Original remaining Amount
		arrayDefinitionSetNumeric( pAllocationArray,"MinPiece",FALSE ),	// MinPiece: number of min piece
		arrayDefinitionSetNumeric( pAllocationArray,"MinIncr",FALSE ),	// MinIncr: number of minimal incrementpAllocationArray
		arrayDefinitionSetNumeric( pAllocationArray,"RankingValue",FALSE ),
		arrayDefinitionSetInteger( pAllocationArray,"Order",FALSE ),

		// Execution quantity
		fInitialExecutedQuantity := mx.order.event.Event.GetExecutedQuantity( pEvent ),
		fResidualExecutedQuantity := fInitialExecutedQuantity,

		// Start Loop on contracts
		// Initialize array content
		iContract := 0,
		fRemAmount := 0.0,
		fTotalRemAmount := 0.0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			pOrder := legGetContractAt ( pOrdBlock,iContract ),
			fRemAmount := mx.order.event.Event.GetContractRemainingQuantity( pEvent,pContract ),
			fTotalRemAmount := fTotalRemAmount + fRemAmount,

			iContract := iContract + 1
		},

		iContract := 0,
		fRemAmount := 0.0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),

			// Get Outstanding order qty / amount by allocation
			pOrder := legGetContractAt (pOrdBlock,iContract ),
			fRemAmount :=mx.order.event.Event.GetContractRemainingQuantity( pEvent,pContract ),
			fRemainingAmount := fInitialExecutedQuantity * (fRemAmount/fTotalRemAmount),
			// By default we use remaining amount as priority criteria
			fRankingValue := fRemainingAmount,

			pElement := arrayAddElement( pAllocationArray ),
			arrayElementSetNumeric( pElement,"RemainingAmount",fRemainingAmount ),
			arrayElementSetNumeric( pElement,"MinPiece",0.0 ),
			arrayElementSetNumeric( pElement,"MinIncr",0.0 ),
			arrayElementSetNumeric( pElement,"RankingValue",fRankingValue ),
			arrayElementSetInteger( pElement,"Order",-1 ),

			fRemainingAmountTotal := fRemainingAmountTotal + fRemainingAmount,

			IF ( fRemainingAmount >= fMinPiece ) THEN
			{
				fEligibleAllocation := fEligibleAllocation + 1.0
			},
			iContract := iContract + 1
		},

		iContract := 1,
		pElement := arrayGetElement( pAllocationArray,0 ),
		fCurrentMaxRanking := arrayElementGetNumeric( pElement,"RankingValue" ),

		//get the current max ranking as the biggest remaining amount among the contracts
		WHILE ( iContract < iNbContracts ) DO
		{
			pElement := arrayGetElement( pAllocationArray,iContract ),
			fRemainingAmount := arrayElementGetNumeric( pElement,"RankingValue" ),
			fCurrentMaxRanking := MAX( fCurrentMaxRanking,fRemainingAmount ),

			iContract := iContract + 1
		},

		iContract := 0,
		iElement := 0,
		iOrder := 0,
		// Define the priority position for each allocation
		WHILE ( iContract < iNbContracts ) DO 
		{
			iContractMax := 0,
			// Loop on all allocation in order to fine the biggest not already sorted
			WHILE ( iContractMax < iNbContracts ) DO
			{
				pElement := arrayGetElement( pAllocationArray,iContractMax ),
				fCurrentRanking := arrayElementGetNumeric( pElement,"RankingValue" ),
				iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),
				IF ( ( fCurrentRanking >= fCurrentMaxRanking ) AND ( iCurrentOrder == -1 ) ) THEN
				{
					// This allocation is smaller than what has been already order but bigger than other ones
					iElement := iContractMax
				},
				iContractMax := iContractMax + 1
			},

			pElement := arrayGetElement( pAllocationArray,iElement ),
			arrayElementSetInteger( pElement,"Order",iOrder ),

			fCurrentMaxRanking := 0. ,
			iContractCount := 0,
			fRemainingAmountComparable := 0, 

			//Recalculate the current max Ranking as the biggest remaining amount among contracts excluding those that have already been ranked  
			WHILE ( iContractCount < iNbContracts ) DO  
			{
				pElement := arrayGetElement( pAllocationArray,iContractCount ),
				iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),

				IF ( iCurrentOrder == -1 ) THEN
					fRemainingAmountComparable := arrayElementGetNumeric( pElement,"RankingValue" ),

				fCurrentMaxRanking := MAX( fCurrentMaxRanking,fRemainingAmountComparable ),
				iContractCount := iContractCount + 1
			},
			iOrder := iOrder + 1,
			iContract := iContract + 1
		},

		fRemainingExecutedQuantity := 0.0,
		// Can we give each fund the minimum amount (min piece)
		IF ( fInitialExecutedQuantity >= fMinPiece) THEN 
		{
			iContract := 0,
			fRemainingEligibleAllocation := 0.0,
			fRemainingExecutedQuantity := fInitialExecutedQuantity,
			// Allocate min piece to each fund

			iPosition := 0,
			WHILE ( iPosition < iNbContracts ) DO 
			{
				iContract := 0,
				WHILE ( iContract < iNbContracts ) DO 
				{
					pElement := arrayGetElement( pAllocationArray,iContract ),
					iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),
					IF ( iCurrentOrder == iPosition ) THEN
					{
						fRemainingAmount := arrayElementGetNumeric( pElement,"RemainingAmount" ),

						// Compute the theoretical fair value for each allocation
						fFairAllocation := fInitialExecutedQuantity * fRemainingAmount / fRemainingAmountTotal, 

						// If value to be allocated is too far from fair value, do not allocate anything
						IF ( ( fFairAllocation / fMinPiece ) >= fThreshold AND (fRemainingExecutedQuantity >= fMinPiece)) THEN 
						{
							arrayElementSetNumeric( pElement,"MinPiece",fMinPiece ),
							// Update remaining executed quatity 

							fRemainingExecutedQuantity := fRemainingExecutedQuantity - fMinPiece,
							// Store the number of fund that will be part of the execution  
							fRemainingEligibleAllocation := fRemainingEligibleAllocation + 1.0
						}
					},
					iContract := iContract + 1
				},
				iPosition := iPosition + 1
			}
		},

		// Now that minimum piece is allocated, proceed with the remaining executed amount
		// Can we give each fund the minimum amount (min increment)
		fResidualExecutedQuantity := fRemainingExecutedQuantity,
		fResidualExecutedQuantityToAllocate := fResidualExecutedQuantity,
		fTotalRealRemaining := 0.0,
		IF ( fRemainingExecutedQuantity >= fMinIncr ) THEN
		{
			iContract := 0,
			iNumberOfRemainingFunds := 0,
			// Get the theoretical remaining amount to allocate per contract after the Min piece allocation, if any
			//Calculate the total theoretical remaining amount as the sum of these individual amounts
			//This is especially useful in the case where after Min piece allocation, some contracts were allocated more than their theoretical fair allocation, others less, 
			//and hence the fair allocation percentages for all contracts should be recalculated accordingly
			// as the theoretical remaining amount of the contract (when greater than 0) over the total
			WHILE ( iContract < iNbContracts ) DO 
			{
				pElement := arrayGetElement( pAllocationArray,iContract ),
				fExecutedAmount := arrayElementGetNumeric( pElement,"MinPiece" ),
				fRemainingAmount := arrayElementGetNumeric( pElement,"RemainingAmount" ),

				IF ( fRemainingAmount - fExecutedAmount > 0.0 ) THEN
				{
					fRealRemaining := fRemainingAmount - fExecutedAmount,
					fTotalRealRemaining := fTotalRealRemaining + fRealRemaining
				},
				iContract := iContract + 1
			},

			iContract := 0,
			WHILE ( iContract < iNbContracts ) DO 
			{
				fRealRemaining := 0.0,
				pElement := arrayGetElement( pAllocationArray,iContract ),
				fExecutedAmount := arrayElementGetNumeric( pElement,"MinPiece" ),
				fRemainingAmount := arrayElementGetNumeric( pElement,"RemainingAmount" ),
				IF ( fRemainingAmount - fExecutedAmount > 0.0 ) THEN
				fRealRemaining := fRemainingAmount - fExecutedAmount,
				fFairAllocation := fResidualExecutedQuantityToAllocate * (fRealRemaining / fTotalRealRemaining),

				// If value to be allocated is too far from fair value, do not allocate anything
				IF ( ( fFairAllocation / fMinIncr ) >= fThreshold AND fExecutedAmount > 0. ) THEN 
				{
					arrayElementSetNumeric( pElement,"MinIncr",rounddefault( fFairAllocation / fMinIncr,0 ) * fMinIncr ),
					fResidualExecutedQuantity := fResidualExecutedQuantity - rounddefault( fFairAllocation / fMinIncr,0 ) * fMinIncr
				},
				iContract := iContract + 1
			}
		},

		// In any case, if there is still  allocate Min piece and Min increment based on priority when relevant
		// This part is common since as long as this was not possible to allcoate Min Piece initially it is also not possible
		// after allocation the fair amount to each allocation.
		iPosition := 0,
		WHILE ( iPosition < iNbContracts ) DO 
		{
			iContractMax := 0,
			IF ( ( fResidualExecutedQuantity > 0.0 ) ) THEN 
			{
				// Look for the element with priority "iPosition"
				WHILE ( iContractMax < iNbContracts ) DO 
				{
					pElement := arrayGetElement( pAllocationArray,iContractMax ),
					iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),
					IF ( iCurrentOrder == iPosition ) THEN
					{
						// First compute the remaining amount to be executed on this allocation
						fCurrentMinPiece := arrayElementGetNumeric( pElement,"MinPiece" ),
						fCurrentMinIncrement := arrayElementGetNumeric( pElement,"MinIncr" ),
						fExecutedAmount := fCurrentMinPiece + fCurrentMinIncrement,
						fRemainingAmount := arrayElementGetNumeric( pElement,"RemainingAmount" ),
						fRemainingAmount := fRemainingAmount - fExecutedAmount,

						// First check if we can add min increment
						IF ( ( fCurrentMinPiece == 0.0 ) AND ( fRemainingAmount >= fMinPiece ) AND ( fResidualExecutedQuantity >= fMinPiece )) THEN
						{
							arrayElementSetNumeric( pElement,"MinPiece",fMinPiece ), 
							fCurrentMinPiece := fMinPiece,
							fResidualExecutedQuantity := fResidualExecutedQuantity - fMinPiece
						},
						// Then allocate the maximum number of min piece possible
						IF ( fCurrentMinPiece > 0.0 ) THEN 
						{
							IF ( fRemainingAmount > fResidualExecutedQuantity ) THEN 
							{
								// Everything goes to this allocation
								arrayElementSetNumeric( pElement,"MinIncr",fCurrentMinIncrement + rounddefault( fResidualExecutedQuantity / fMinIncr,0 ) * fMinIncr ),
								fResidualExecutedQuantity := fResidualExecutedQuantity - rounddefault( fResidualExecutedQuantity / fMinIncr,0 ) * fMinIncr
							}
							ELSE IF ( fRemainingAmount > 0. ) THEN
							{
								// We allocate as much as possible to this allocation
								arrayElementSetNumeric( pElement,"MinIncr",fCurrentMinIncrement + rounddefault( fRemainingAmount / fMinIncr,0 ) * fMinIncr),
								fResidualExecutedQuantity := fResidualExecutedQuantity - rounddefault( fRemainingAmount / fMinIncr,0 ) * fMinIncr
							}
						}
					},
					iContractMax := iContractMax + 1
				}
			},
			iPosition := iPosition + 1
		},

		// While there is still Min increment to allocate, allocate Min increment based on priority 
		// This part is useful in the case where the total remaining quantity to allocate is a multiple of the Min incr, but the 
		// individual remaining quantity to allocate per contract is not, meaning nothing got allocated in the previous part
		WHILE ( rounddefault (fResidualExecutedQuantity/fMinIncr, 0) >= 1.) DO
		{
			iPosition := 0,

			WHILE ( iPosition < iNbContracts ) DO 
			{
				iContractMax := 0,
				// Look for the element with priority "iPosition"
				WHILE ( iContractMax < iNbContracts AND rounddefault (fResidualExecutedQuantity/fMinIncr, 0) >= 1.) DO 
				{
					pElement := arrayGetElement( pAllocationArray,iContractMax ),
					iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),
					fCurrentMinIncrement := arrayElementGetNumeric( pElement,"MinIncr" ),
					fCurrentMinPiece := arrayElementGetNumeric( pElement,"MinPiece" ),
					IF ( iCurrentOrder == iPosition AND fCurrentMinPiece > 0.0 ) THEN
					{
						arrayElementSetNumeric( pElement,"MinIncr",fCurrentMinIncrement + fMinIncr),
						fResidualExecutedQuantity := fResidualExecutedQuantity - fMinIncr
					},
					iContractMax := iContractMax + 1
				},
				iPosition := iPosition + 1
			}
		},

		// This part is for handling the case where the user input a quantity less than the min piece in the broadcaster
		// Allocate as many Min Increments as possible to the highest priority contract
		IF ( fInitialExecutedQuantity < fMinPiece) THEN 
		{
			iContract := 0,
			iPosition := 0,
			fResidualExecutedQuantity := fInitialExecutedQuantity, 
			WHILE ( iContract < iNbContracts ) DO 
			{
				pElement := arrayGetElement( pAllocationArray,iContract ),
				iCurrentOrder := arrayElementGetInteger( pElement,"Order" ),
				IF ( iCurrentOrder == iPosition ) THEN
				{
					arrayElementSetNumeric( pElement,"MinIncr", rounddefault( fInitialExecutedQuantity / fMinIncr,0 ) * fMinIncr),
					fResidualExecutedQuantity := fResidualExecutedQuantity - rounddefault( fInitialExecutedQuantity / fMinIncr,0 ) * fMinIncr
				},
				iContract := iContract + 1
			}
		},

		IF ( fResidualExecutedQuantity > 0.0 AND fResidualExecutedQuantity < fMinIncr ) THEN
		{
			iContract := 0,    
			WHILE ( iContract < iNbContracts ) DO 
			{
				pContract := legGetContractAt( pCntBlock,iContract ),
				legSetString ( pContract,"pf_Allocation","YES" ),
				legSetCellColorAsError( pContract,sQuantityField ),
				iContract := iContract + 1
			},
			ThrowWarning( "Part of the executed quantity can't be allocated automatically","Reallocate remaining quantity manually" )
		},

		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			sIsTradable := legGetString ( pContract,"pf_Allocation" ),
			iContract := iContract + 1
		},

		// Proceed with the allocation given by the algorithm
		iContract := 0,
		WHILE ( iContract < iNbContracts ) DO 
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			pElement := arrayGetElement( pAllocationArray,iContract ),

			fCurrentMinPiece := arrayElementGetNumeric( pElement,"MinPiece" ),
			fCurrentMinIncrement := arrayElementGetNumeric( pElement,"MinIncr" ),
			fExecutedAmount := fCurrentMinPiece + fCurrentMinIncrement,

			// For all products but securities we can set the amount
			legOverwrite( pContract,sQuantityField,fExecutedAmount ),
			legCompute( pContract,"noWorkflow" ),

			iContract := iContract + 1
		}
	},

	// Recalculate of the new total quantity after each allocation
	// This is useful in the cases where the allocation algorithm changes the original broadcaster quantity to allocate input by the user (to respect Min piece/Min Incr)
	// Hence, the value stored in pf_legratio for each contract should be calculated based on this new quantity
	IF ( sAllocationRule == "Yes" ) THEN
	{
		iContract := 0,
		fNewQuantity := 0.0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			fNewQuantity := fNewQuantity+ legGetNumeric( pContract, sQuantityField ) ,
			iContract := iContract + 1
		}
	},

	IF ( sAllocationRule == "Yes" ) THEN
	{
		iContract := 0,
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pCntBlock,iContract ),
			legOverwrite( pContract,"pf_leg_quantity",legGetNumeric( pContract,sQuantityField ) ),
			legOverwrite( pContract,"pf_leg_ratio",rounddefault( legGetNumeric( pContract,sQuantityField ) / fNewQuantity,3 ) ),
			iContract := iContract + 1
		}
	}
};

