// mx.preTrade.routing.FXD.Booking.Rout-Hedge

/*
MXpress
FXD Routing rule for hedging task

Version 1.1
Applied MXpress scripted-rules conventions

Version  1.0

Notes:
Thre are three outputs of this rule
	1. NoHedge -- No hedge is required 
	2. ShowHedge --  Hedge is required,  show the hedge legs
	3. HideHedge - Hedge is required, hide hedge legs when doing the booking
*/

{
	// Fields Initialization/Reset
	sOutput := "NoHedge",
	pFirstCurrLeg := pNULL, 
	iFirstCurrLeg := 0,
	iNumComponents := legGetNumberOfComponents( NPD_HDL_THIS ),
	sFamily := "",
	sHedgeType := "",

	WHILE ( iFirstCurrLeg < iNumComponents ) DO
	{
		pComponent := legGetComponentAt( NPD_HDL_THIS,iFirstCurrLeg ),
		sFamily := legGetProductFamily( pComponent ),
		IF ( sFamily == "CURR" ) THEN
		{
			pFirstCurrLeg := pComponent,
			iFirstCurrLeg := iNumComponents	// Once the first FX / FXD leg is found, get out of the loop
		},
		iFirstCurrLeg := iFirstCurrLeg + 1
	},

	IF ( pFirstCurrLeg <> pNULL ) THEN
	{
		sHedgeType := legGetString( pFirstCurrLeg,"Hedge_type" ),
		IF ( sHedgeType == "No Hedge" ) THEN
			sOutput := "NoHedge"
		ELSE
		{
			//The udf SHOW_TICKET is not available 
			//           sShowTicket:=legGetString(pFirstCurrLeg,"SHOW_TICKT"),
			//          IF sShowTicket =="Yes" THEN
			//              sOutput :="ShowHedge"
			//          ELSE
			sOutput := "HideHedge"
		}
	}
};

// mx.preTrade.routing.FXD.Booking.Rout-Spread

/*
MXpress
FXD Routing for Bid/Ask calibration - Only execute B/A calibration when no exotics are present in the structure

Version 1.2
Amended to prevent reset to ATM of the smile volatility for a strategy of vanillas toggled from bid/ask to mid.

Version 1.1
Applied MXpress scripted-rules conventions

Version  1.0

Notes: Routing rules:
	Output1 - apply b/a calibration
	Output2 - do not apply b/a calibration
*/

{
	//Initialize the parameters for structure scan
	iLeg := 0,
	iNumLegs := legGetNumberOfComponents( NPD_HDL_THIS ),

	//scan all legs and check the existence of not-vanilla currency option
	sOutput := "Output1", //default output is set to Output1

	WHILE ( iLeg < iNumLegs ) DO
	{
		sRegistration := "Vanilla",

		pLeg := legGetComponentAt( NPD_HDL_THIS,iLeg ),
		bNonVanillaSMP := ( legGetProductLabel( pLeg ) == sRegistration ) AND ( legGetString( pLeg,"Payout type" ) <> "Standard" ),
		IF ( ( legGetProductLabel( pLeg ) <> sRegistration ) OR ( bNonVanillaSMP ) ) THEN // update this formula when the function legGetRegistration is available
		{
			sOutput := "Output2",
			iLeg := iNumLegs
		},
		iLeg := iLeg + 1
	}
};

// public.preTrade.completion.CRD.Closing.PAlloc-Demo

/*
MXpress-Demo
Portfolio allocation rule

Warning: This is not the standard MXpress-Foundation portfolio allocation rule but rather a demo portfolio allocation rule. Assumptions are made related to the 
existence of the MXpress-Demo Global Operating Model. This MXpress-Demo Global Operating Model is not part of the standard MXpress-Foundation environment.

Used algorithm:
If the leg is initialised and a portfolio is requested
	Loop on all contracts
		Depending on the registration, determine the trader portfolio
		Depending on whether the contract is back to back, determine the sale portfolio
		Depending on whether the contract is internal or not and/or is back to back or not, initializs the portfolio, counterpart and btbportfolio parameters accordingly
		Loop on all components to set portfolio, counterpart and BTB porfolio fields accordingly
End if

Version 1.1
Retrieve user from Source trader and group from MX.ALL.UserProfile in case of trade import

Version 1.0
The purpose of this rule is to allocate a portfolio to each financial contract component
This rule is specific for CRD products used by FXMM: Asset Swap
The lead currency is US dollar.

This rules handles standard external contracts,internal contracts and also contracts that will be mirrored in the mirroring task
For external contracts, the rule sets the unique portfolio
For contracts that will be mirrored, the rule fills in the variable that will be used in the mirroring task

This rule uses a Look-Up Table (LUT):
( MX.ALL.PAllocIn, ALL ) contains the name of instrument for each registration
( DEMO.FXMM.Entit, ALL ) contains the entity of user group
( DEMO.FXMM.PtfHV, ALL ) contains the portfolio assignment for HVA packages
*/

{
	pLeg := This,

	IF ( legIsInitialized( pLeg ) ) THEN
	{
		// Field Initialization/Reset
		pMainComponent := legGetMainComponent( pLeg ),
		pMainContract := legGetFatherContract( pMainComponent ),
		sSourceModule := legGetSourceModule( pMainContract ),
		sPublishingSystem := legGetPublishingSystem( pMainContract ),
		bPAlloc := FALSE,
		sEntity := "",
		iNbContracts := 0,
		iContract := 0,
		sRegistration := "",
		sPrefix := "",
		sInstrumentField := "",
		sCore := "",
		sTraderPortfolio := "",
		bIsContractBTB := FALSE,
		sUser := "",
		sUserGroup := "",
		sSalePortfolio := "",
		sBORegistration := "",
		sInternal := "",
		bIsContractInternal := FALSE,
		sPortfolio := "",
		sCounterpart := "",
		sBTBPortfolio := "",
		iComponent := 0,
		iNbComponents := 0,

		// The portfolio allocation is required under specific conditions:
		// - Newly inserted contracts have to be processed by the rule,
		// - Contracts generated by a Cancel & Reissue event should not be processed,
		// - Contracts generated by a sellown procedure should not be processed
		// - Contracts generated by a rollover procedure should not be processed
		// - Contracts generated by a fixing procedured should not br processed
		// - Contracts generated by a duplication should not be processed
		// - Since in all 5 previous cases,a portfolio had aleady been allocated
		bPAlloc := ( ( sPublishingSystem == "MX" ) 
					AND ( properties.Get( "mx.preTrade.BO.source" ) == "" )
					AND ( sSourceModule <> "mx.sellDown" )
					AND ( sSourceModule <> "mx.rollover" )
					AND ( sSourceModule <>"mx.fixing" )
					AND ( properties.Get( "mx.preTrade.action" )<>"MOD" )
					AND ( properties.Get( "mx.preTrade.action.context" ) <> "DUP" ) ),

		IF ( bPAlloc ) THEN
		{
			// Waiting for groups creation, entity is hard coded
			// Assumptions: there is equivalence between group and entity.
			// So thanks to lookup table( xx,ALL ), it is possible to obtain entity
			// sUserGroup := sysGetGroup(),
			// sEntity := lookupString( "xx","ALL","USER_GROUP",sUserGroup ),
			sEntity := "LN",

			iNbContracts := legGetNumberOfContracts( pLeg ),
			iContract := 0,

			// This loops on all contracts when the higher-level object is a Package
			WHILE ( iContract < iNbContracts ) DO 
			{
				pContract := legGetContractAt( pLeg,iContract ),
				pComponent := legGetMainComponent( pContract ),//Required for the utility  MX.ALL.FCCLabel,LUT. See details below

				sRegistration := legGetRegistration( pComponent ),

				// To define sTraderPortfolio
				IF ( sRegistration == "Asset swaps") THEN
				{
					sPrefix := "MMA",

					// Another LUT is used to determine the Instrument field for each registration ( product type )
					sInstrumentField := lookupString( "MX.ALL.PAllocIn","ALL",
														"Registration",sRegistration ),
					sCore := legGetString( pContract,sInstrumentField ),

					sTraderPortfolio := sPrefix + "_" + sCore + "_" + sEntity,

					// To define sSalePortfolio
					bIsContractBTB := legGetFOPIsBackToBack( pContract ),//Tells whether the current contract will be mirrored in the mirroring task
					IF ( bIsContractBTB ) THEN
					{
                        IF ( strStartsWith(sSourceModule , "mx" ) ) THEN
                        {
                            sUser := sysGetUser(),
                            sUserGroup := sysGetGroup()
                        }
                        ELSE
                        {
                            sUser := legGetString( pComponent, "Source trader"),
                            sUserGroup := "",
                            pUserProfile := lookupResults( "MX.ALL.UserProfile","ALL","User",sUser),
                            IF ( NOT ( isNull(pUserProfile) ) ) THEN
                                sUserGroup := lookupResultsGetString(pUserProfile,0,1)
                        },
        				// A LUT is used to determine the portfolio depending user name and/or user group
						sSalePortfolio := lookupString( "DEMO.FXMM.PtfHV","ALL",
														"USER_GROUP",sUserGroup,
														"User",sUser )
					},

					sBORegistration := legGetRegistrationLabel( pContract ),
					IF ( sBORegistration == "mxContractStbICONTRACT" ) THEN
						sInternal := legGetString( pComponent,"Internal" )//If the current contract is STB contract, get the internal information from main component.
					ELSE
						sInternal := legGetString( pContract,"Internal" ),//Checks whether the current contract is internal or not
					bIsContractInternal := ( sInternal == "Yes" ),//Tells whether the current contract is internal or not
					sPortfolio := "",// Unique porfolio for external contracts and the source portfolio for internal contracts
					sCounterpart := "",// Destination portfolio for internal contracts
					sBTBPortfolio := "",// Destination portfolio for mirrored contracts generated in the mirroring task
					IF ( bIsContractInternal ) THEN
					{
						IF ( sTraderPortfolio <> "" ) THEN
							sCounterpart := sTraderPortfolio,

						IF ( sSalePortfolio <> "" ) THEN
							sPortfolio := sSalePortfolio
					}
					ELSE IF ( bIsContractBTB ) THEN
					{
						IF ( sTraderPortfolio <> "" ) THEN
							sBTBPortfolio := sTraderPortfolio,

						IF ( sSalePortfolio <> "" ) THEN
							sPortfolio := sSalePortfolio
					}
					ELSE
					{
						IF ( sSalePortfolio <> "" ) THEN
						{
							sPortfolio := sTraderPortfolio,
							sCounterpart := sSalePortfolio
						}
						ELSE
							sPortfolio := sTraderPortfolio
					},

					// Loop on components: propagate the contract portfolio to all components
					iComponent := 0,
					iNbComponents := legGetNumberOfComponents( pContract ),
					WHILE ( iComponent < iNbComponents ) DO
					{
						pComponent := legGetComponentAt( pContract,iComponent ),
						// This sets the unique portfolio for external components and the source portfolio for internal components
						legSetString( pComponent,"Portfolio",sPortfolio ),
						// This sets the destination portfolio for internal components
						IF ( bIsContractInternal ) THEN
							legSetString( pComponent,"Counterpart",sCounterpart ),
						iComponent := iComponent + 1
					},
					// This sets the mirror portfolio for contracts that will be mirrored
					// This will be used in the mirroring task
					IF ( bIsContractBTB ) THEN
						legSetFOPInternalPortfolio( pContract,sBTBPortfolio )
				},

				iContract := iContract + 1
			}
		}
	}
};

// public.preTrade.completion.FXMM.Initialization.LegF

/*
MXpress
Leg Freeze rule for FX/MM products

Version 1.1
Applied MSL best practices

Version 1.0
The purpose of this rule is (upon the modification of a contract or a package) to
-Freeze the matured leg of partially matured contracts and packages
-Apply automatically the relevant Market Operation (Cancel & Reissue or Restructure)
*/

{
	pLeg := This,

	//Should the Leg Freeze be considered ?
	bIsNeeded := ( properties.Get( "mx.preTrade.action") == "MOD" ) //Modification
			OR ( properties.Get( "mx.preTrade.BO.source.class" ) == "mxContractEventICANCEL_REISSUE" ) //Cancel & Reissue
			OR ( properties.Get( "mx.preTrade.BO.source.class" ) == "mxContractEventIRESTRUCTURE" ), //Restructure

	IF ( bIsNeeded ) THEN
	{
		pMainComponent := legGetMainComponent( pLeg ),
		pPackage := legGetFatherPackage( pMainComponent ),
		pContract := legGetFatherContract( pMainComponent ),
		bPartiallyExpired := FALSE, //Variable Initialization

		iNbComponents := legGetNumberOfComponents( pLeg ),
		iComponent := 0,
		// Only considering contracts and packages composed of more than one component ...
		//... (The target being a partially matured contract/package)
		IF ( iNbComponents > 1 ) THEN
		{
			WHILE ( iComponent < iNbComponents ) DO
			{
				pComponent := legGetComponentAt( pLeg,iComponent ),
				dMaturity := legGetDate( pComponent,"Maturity" ),
				sPortfolio := legGetString( pComponent, "Portfolio" ),
				sEntity := ptfGetLegalEntity( sPortfolio ),
				bLateTrading := entityGetProcessingDate( sEntity ) == sysGetTradingDate(),
				//In a late-trading context, if the maturity of the FCC is smaller than or equal to the FO Desk date then ...
				// ... the component should be frozen and the operation should be a Restructure else it should be a Cancel & Reissue
				//In a non late-trading context, if the maturity of the FCC is smaller than the FO Desk date then ...
				// ... the component should be frozen and the operation should be a Restructure else it should be a Cancel & Reissue
				bLegFreezeRequested := ( bLateTrading AND dMaturity <= sysGetTradingDate() ) 
								OR ( NOT bLateTrading AND dMaturity < sysGetTradingDate() ),
				IF ( bLegFreezeRequested ) THEN
				{
					legFreeze( pComponent ), //This does the Leg Freeze
					//Will be used to set the modification mode for the Contract & the Package
					//The contract/package is partially expired if ...
					// ... either the current component or a component scanned previously is partially expired
					bPartiallyExpired := TRUE OR bPartiallyExpired 
				},
				iComponent := iComponent + 1
			}
		},

		IF ( bPartiallyExpired ) THEN
		{
			legSetString( pPackage,"Modification mode","Restructure" ),
			legSetString( pContract,"Modification mode","Restructure" )
		}
		ELSE
		{
			legSetString( pPackage,"Modification mode","Cancel and reissue" ),
			legSetString( pContract,"Modification mode","Cancel and reissue" )
		}
	}
};

// mx.preTrade.completion.HYBRID.Closing.FCpl

/*
MXpress
Specific Fields completion Closing sequence for Hybrid structures

Version 1.1
Applied MSL best practices

Version 1.0
Initialization
*/

{
	pContract := This,
	sAction := properties.Get( "mx.preTrade.action" ),

	IF ( sAction == "INS" ) THEN
	{
		sRegistration := legGetRegistration( pContract ),

		IF ( ( sRegistration == "Dual Cur Deposit" ) OR ( sRegistration == "Range Cur Deposit" ) ) THEN
		{
			sSolvingMode := legGetString( pContract,"Solving mode" ),
			IF ( sSolvingMode == "No solving" ) THEN
				npResetGlobalImplied( ),

			pLoanDeposit := legGetComponentAt( pContract,0 ),
			pOption := legGetComponentAt( pContract,1 ),
			sInstrument := legGetString( pOption, "Instrument" ),
			legSetString( pLoanDeposit,"Risk_section",sInstrument ),
			legSetNumeric( pOption, "Flat_settlement",0.0 )
		}
	}
};

// mx.preTrade.completion.ALL.Pricing.FInit-ALL

/*
MXpress
Field initialization for all asset classes

Version 1.5
Remove sync of market data date with trading date

Version 1.4
Initialise VAMODE: by default we set "None" for Trader profile and "Keep in Trader portoflio" for Sales profile
but it can be amended at implementation time

Version 1.3
Update check on market data date condition
Add logic to populate CLIENT_IND Client Trade Indicator
Add logic to take into account VAMODE Sales income mode

Version 1.2
Add Fixed Recovery CDS case for the npv implied set

Version 1.1
Amended to exclude reloaded trades

Version 1.0
The purpose of this rule is to ensure the market data date is the same as the trading date
*/

{
	pLeg := This,
    pMainComponent := legGetMainComponent( pLeg ),
    pMainContract := legGetFatherContract( pMainComponent ),
    sSourceModule := legGetSourceModule( pMainContract ),
    sPublishingSystem := legGetPublishingSystem( pMainContract ),
    sLegTypology := legGetString(pMainComponent,"Typology"),

    //BAB-Dual Currency Depo- Strategy
    sUserGroup := sysGetGroup(),
    sTitle := legGetTitle(legGetFatherPackage(legGetComponentAt (This,0))),
    IF (sTitle == "Dual Currency Depo") THEN 
        IF NOT(sUserGroup == "FO_SALES" OR sUserGroup == "CS_DMG" OR sUserGroup=="SALES_DR" OR sUserGroup == "SALES_JR" OR sUserGroup == "SALES_SR" OR sUserGroup ==  "SALES_UMG") THEN
            trcPushError("Error:","Dual Currency Depo cannot be booked from this group"),
    //End


    // Populate CLIENT_IND Client Trade Indicator and VAMODE Sales income management mode
    // Set CLIENT_IND to Y if the component is External and if the Counterpart is of type CLIENT, CUSTOMER, BRANCH or CORPORATE
    // Set VAMODE to the relevant value for Sales profiles, keep None (Default) otherwise
    bInitialiseSalesInfo := ( ( sPublishingSystem == "MX") 
            AND ( properties.Get( "mx.preTrade.BO.source") == "" )
            AND ( sSourceModule <> "mx.sellDown" )
            AND ( sSourceModule <> "mx.rollover" )
			AND ( sSourceModule <> "mx.futureFlowSellDow" )            
            AND ( sSourceModule <>"mx.fixing" )
            AND ( sLegTypology <> "Murabaha Commodity" )
            AND ( properties.Get( "mx.preTrade.action" ) <> "MOD" )
            AND ( properties.Get( "mx.preTrade.action.context" ) <> "DUP" ) 
            AND ( properties.Get( "mx.preTrade.pricing.source") <> "TRADE") ),    
    IF ( bInitialiseSalesInfo ) THEN
    {
        iComponent := 0,
        iNbComponents := legGetNumberOfComponents( pLeg ),
        WHILE ( iComponent < iNbComponents ) DO
        {
            pComponent := legGetComponentAt( pLeg, iComponent ),   
            sClientIndField := "CLIENT_IND",

            //BAB addition to set the nature to generator driven
            sRegistration := legGetRegistration( pComponent ),
            IF sRegistration == "Loans/Deposits" AND legIsInitialized(pComponent) == FALSE THEN
            {
            	legSetString(pComponent,"Nature","Generator driven")
            },
            //end of BAB addition

            //BAB addition for the Counterparty full name, same logic exists in rule "BABBooking"
            sCTP := legGetString(pComponent,"Counterpart"),
            sCTPFullName := ctpGetFullName(sCTP),
            legOverwrite(pComponent,"CPTY_NAME",sCTPFullName),

			//BAB addition regarding the CR for Commodities auto filling
            sTypology := legGetTypology(pComponent),
             bEvent := properties.Get("mx.preTrade.BO.source.class") <> "mxContractEventICANCEL_REISSUE", 
                sUsage := legGetString(pComponent,"Usage"), 

                IF bEvent
                AND ((sTypology == "Murabaha Borrowing" AND sUsage == "BA") 
                    OR (sTypology == "Murabaha Placement" AND sUsage == "DI") 
                    OR (sTypology == "CD Issuance" AND sUsage == "Murabaha BA")
                    OR (sTypology == "LTM" AND sUsage == "DI") 
                    OR (sTypology == "LTM Range" AND sUsage == "DI") 
                    OR (sTypology == "LTM Callable" AND sUsage == "DI") 
                    OR (sTypology == "LTM CapFloorCollar" AND sUsage == "DI") 
                    OR (sTypology == "LTM Range Callable" AND sUsage == "DI")) THEN 
                { 
                    legSetString(pComponent,"IS_BROKER1","DUMMY BROKER 1"), 
                    legSetString(pComponent,"IS_BROKER2","DUMMY BROKER 2") 
                } 

                ELSE IF (legIsElementValid(pComponent,"IS_BROKER1") == TRUE AND bEvent) THEN 
                { 
                    legSetString(pComponent,"IS_BROKER1",""), 
                    legSetString(pComponent,"IS_BROKER2","") 
                },



            /*
            //BAB addition- Back office requirement
            IF sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "Wakala Borrowing" OR sTypology == "Wakala Placement" THEN
            {

                pStreamsBO := legGetStreams(pComponent),
                pStreamBO := streamsGetStream(pStreamsBO,0,0),
                fFinalInterestFlow := legGetNumeric(pComponent,"Final_interest_flow"),
                fFinalCapitalFLow := streamGetLastCapitalFlow(pStreamBO),
                fMaturityAmount := fFinalInterestFlow + fFinalCapitalFLow,
                legSetNumeric(pComponent,"MAT_AMNT",fMaturityAmount)
            },
              */

            //BAB addition for the sales margin amount calculation
            sTypology := legGetTypology(pComponent),
            IF sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "PRS" 
            OR sTypology == "PRS Range" OR sTypology == "PRS CapFloorCollar" OR sTypology == "PRS Inverse Floater" OR sTypology == "Depo Callable" THEN
            {
        		//Check if the flows are customized
            	 IF strCONTAIN (legGetString( pComponent, "Customized Flows" ), "Y") THEN
                 {
					//Clone the component
                    pContainer := npOpen(),
                    pClone := npCloneLeg( pContainer,pComponent),
                    fsalesmargin := legGetNumeric(pComponent,"Sales_margin"),
                    legOverwrite( pClone,"Sales margin",0.0 ),
                    pStreams := legGetStreams(pClone),

                    iPhase := 0,
                    iNumberOfPhases := streamsGetNumberOfPhases(pStreams),
                    WHILE ( iPhase < iNumberOfPhases ) DO
                    {
                        pFirstLegStream := streamsGetStream(pStreams,iPhase,0),
                        bFloating := streamIsFloating( pFirstLegStream ),
		//Only done for fixed rate
                        IF NOT ( bFloating ) THEN
                        {
                            iPeriod := 0,
                            fFlow2 := 0.0,
                            iNbPeriods := streamGetNumberOfPeriods(pFirstLegStream),

                            WHILE ( iPeriod < iNbPeriods ) DO
                            {
                                fFirstLegPeriodRate := streamGetPeriodRate(pFirstLegStream,iPeriod),
                                fNewRate := fsalesmargin,
                                streamSetPeriodRate(pStreams, pFirstLegStream, iPeriod, fNewRate),
                                iPeriod := iPeriod + 1
                            },

                            //Do not include the Capital exchange for LNBR products to have the Sales margin as the Npv for the clone
                            IF sTypology ==  "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "Depo Callable" THEN
                            {
                                legSetString(pClone,"Initial_Capital","No Exchange"),
                                legSetString(pClone,"Final_Capital","No Exchange"),
                                legSetString(pClone,"Intermediate_Capital","No Exchange")
                            },

                            legSetLocalImplied(pClone,"Npv"),
                            legCompute( pClone,"noWorkflow"),
                            fBpv := legGetNumeric(pClone,"Bpv"),

                            //New Sales margin calculation
                            IF sTypology == "PRS" OR sTypology == "PRS Range" OR sTypology == "PRS CapFloorCollar" OR sTypology == "PRS Inverse Floater"  THEN
                            {
                                fNewSalesmargin:= abs(legGetNumeric(pClone,"Leg_NPV"))
                            }
                            ELSE
                            {
                                fNewSalesmargin := abs(legGetNumeric(pClone,"Npv"))
                            }



                        },

                        iPhase := iPhase +1

                    }, 
                    //Set the Sales margin in the New UDF field
                    sSalesMarginUnit := legGetString(pComponent,"Nominal_unit"),
                    legOverwrite(pComponent,"SALES_MG_C",sSalesMarginUnit),
                    legOverwrite(pComponent,"SALES_MG",fNewSalesmargin)  
                },
                npClose(pContainer)
            },

            IF ( legIsElementValid( pComponent, sClientIndField ) ) THEN
            {
                IF ( legGetString(pComponent, "Internal") == "Yes" ) THEN
                    legSetString(pComponent, sClientIndField, "N")
                ELSE
                {
                    sCounterpart := legGetString(pComponent, "Counterpart"),
                    IF ( ctpIsBusinessActivityChecked(sCounterpart, "CLIENT")
                        OR ctpIsBusinessActivityChecked(sCounterpart, "CUSTOMER")
                        OR ctpIsBusinessActivityChecked(sCounterpart, "BRANCH")
                        OR ctpIsBusinessActivityChecked(sCounterpart, "CORPORATE") ) THEN
                        legSetString(pComponent, sClientIndField, "Y")            
                    ELSE
                        legSetString(pComponent, sClientIndField, "N")
                }
            },
			sVAModeField := "VAMODE",
 			sPricingContext := properties.Get("mx.preTrade.pricing.context"),
            IF ( legIsElementValid( pComponent, sVAModeField ) ) THEN
            {
                IF ( legGetString(pComponent, "Internal") == "Yes" ) THEN
                {
                    legSetString(pComponent, sVAModeField, "None")
                  }
                ELSE
                {
					sUserProfile := lookupString( "MX.ALL.UserGroupProfile","ALL","USER_GROUP",sysGetGroup() ),
                    IF ( sUserProfile <> "Sales" AND sPricingContext <> "MAIL") THEN
                    	legSetString(pComponent, sVAModeField, "None")
                    ELSE
                    {
                    	IF (sUserProfile == "Sales")  THEN legSetString(pComponent, sVAModeField, "Keep in Sales portfolio"),


                        // BAB addition for the Bank Note
                        sTypology := legGetString(pComponent,"Typology"),
                        IF sTypology == "Banknotes" OR sTypology == "Banknotes Credit" THEN 
                        {
                            fSpot := legGetNumeric(pComponent,"Spot"),
                            sCurr1 := legGetString(pComponent,"Den_unit"),
                            sCurr2 := legGetString(pComponent,"Num_unit"),

                            //BAB addition to switch the USN currency as the banknote currency if it is inputted as the other quantity currency. USN should only be used as BN currency against USD
                            sOtherQuantityCurr := legGetString(pComponent, "Other_quantity_currency"),
                            IF sOtherQuantityCurr == "USN" THEN
                            {
							legOverwrite(pComponent,"BANK_NOTE","USN"),
                                ThrowWarning("Bank Note Currency","USN should be the Bank note currency and not the other quantity currency")

                            },


                            //For Mono-currency XXY/XXN banknotes
                            //First two letters are the same AND Third letter is N or O
                            IF ( 	(strSubString(sCurr1, 0, 2) == strSubString(sCurr2, 0, 2)) ) 
                            AND ((strSubString(sCurr1, 2, 3) == "N") OR (strSubString(sCurr2, 2, 3) == "N") OR (strSubString(sCurr1, 2, 3) == "O") OR (strSubString(sCurr2, 2, 3) == "O") ) 
                            THEN
                            {
                            	legSetString(pComponent, sVAModeField, "None"), //No Sales Margin

                                //Price should always be 1.0 for monocurrency banknotes
                                legOverwrite(pComponent,"Forward",1.0)

                            }
                            ELSE
                            {
                            	legSetString(pComponent, sVAModeField, "Keep in Sales portfolio")
                            }
                         }


                    }      
                },

            //BAB addition for Product Code of DCD
            pStrip:= legGetFatherPackage(This),
            sTitle := legGetTitle(pStrip),
            IF sTitle == "Dual Currency Depo" THEN
            legOverwrite(pComponent,"STRTG_LBL",sTitle)
            //end of BAB addition

            },  

            // Add WHT Chargeable field
          	sTypology := legGetString(pComponent,"Typology"),
            IF sTypology == "Sukuk Issuance" OR sTypology == "Wakala Borrowing" OR sTypology == "Wakala Borrowing CFC" OR sTypology == "CD Issuance" THEN
          	{
                sCounterpart:= legGetString(pComponent,"Counterpart"),
                sWHTChargeable := ctpGetUdfString(sCounterpart,"WHT_CHARG"),

                IF sWHTChargeable <> "" THEN
                legOverwrite(pComponent,"WHT_CHARG",sWHTChargeable)
               ELSE
               {
               IF legGetLastInputField( pComponent ) == "Counterpart" THEN
               ThrowError("Please specify if the WHT should be chargeable to this specific counterpart",sMessage)
               }
            },

            iComponent := iComponent + 1
        }
    },

    // For Sales margin mode 'Keep in Sales portfolio', automatically set Back to Back = Yes - Except for FXMM Packages where we set Independent margins = Yes
    sLegRegistration := legGetRegistrationLabel( pLeg ),
	pMainComponent := legGetMainComponent( pLeg ),    
    IF ( sLegRegistration <> "mxContractFxIOUTRIGHT" AND sLegRegistration <> "mxContractFxISPLIT" AND sLegRegistration <> "mxContractFxISPLITSWAP" AND sLegRegistration <> "mxContractFxIFUNDINGOUTRIGHT" AND sLegRegistration <> "mxContractFxIFUNDINGSWAP" ) THEN
    {
    	IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
        {
        	IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
            {
            	/*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), TRUE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
                legSetFOPIsBackToBack(pMainComponent, TRUE)*/
                IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                	legSetString(pMainComponent,"Back to back","Yes")                
            }
            ELSE
            {
 				/*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), FALSE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
				legSetFOPIsBackToBack(pMainComponent, FALSE)*/
                IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                	legSetString(pMainComponent,"Back to back","No")                  
            }
       	}
    }
    ELSE
    {
		IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
        {
        	IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
        		legSetString(pLeg, "Independent margins", "Yes")
            ELSE
	            legSetString(pLeg, "Independent margins", "No")
       	}    
    },
    IF sysGetRFQRole()=="REQUESTER" THEN

                IF legGetRegistration(pLeg) == "Spot-Forward" THEN //Spot-Forward
                {
                    fPrice := legGetNumeric(pComponent,"pf_RFQ_TraderPrice"),
                    IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPrice <> legGetNumeric(pComponent,"Forward") ) THEN
                        legOverwrite(pComponent,"Forward", fPrice)           
                }

               ELSE IF  legGetRegistration(pLeg) == "Split Package" THEN //Spit-package

               {
                pFirstComponent := legGetComponentAt(pLeg,0),
				fPrice := legGetNumeric(pFirstComponent,"pf_RFQ_TraderPrice"),
                    IF ( legGetString( pFirstComponent,"pf_RFQ_Provider" ) <> "" AND fPrice <> legGetNumeric(pFirstComponent,"Forward") ) THEN
                        legOverwrite(pFirstComponent,"Forward", fPrice)           
               }

               ELSE IF  legGetRegistration(pLeg) == "Bonds" THEN //Sukuk

               {

               	fPrice := legGetNumeric(pComponent,"pf_RFQ_TraderPrice"),
                    IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPrice <> legGetNumeric(pComponent,"Settlement_price") ) THEN
                        legOverwrite(pComponent,"Settlement_price", fPrice)           
               }
                ELSE IF  legGetRegistration(pLeg) == "Loans/Deposits" THEN //Wakala

               {

               	fPrice := legGetNumeric(pComponent,"pf_RFQ_TraderPrice"),
                    IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPrice <> legGetNumeric(pComponent,"Rate_Margin") ) THEN
                        legOverwrite(pComponent,"Rate_Margin", fPrice)           
               }

               ELSE IF legGetRegistration(pLeg) == "FX swap" THEN //FX Swap
                	{
                        	pFirstComponent := legGetComponentAt(pLeg,0),
                    		pSecondComponent := legGetComponentAt(pLeg,1),


                        	fPricenear := legGetNumeric(pFirstComponent,"pf_RFQ_TraderPrice_Near"),
                            fPricefar  := legGetNumeric(pSecondComponent,"pf_RFQ_TraderPrice_Far"),
                            fPricenearinitial:= legGetNumeric(pFirstComponent,"Forward"),
                            fPricefarinitial:= legGetNumeric(pSecondComponent,"Forward"),


                             IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPricenear <> fPricenearinitial ) THEN
                             	legOverwrite(pFirstComponent,"Forward",fPricenear),

                             IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPricefar <> fPricefarinitial ) THEN
                             	legOverwrite(pSecondComponent,"Forward",fPricefar)

                    }

                     ELSE IF legGetRegistration(pLeg) == "Split Forex Swap Package" THEN //FX Swap Split
					{
                        	pFirstComponent := legGetComponentAt(pLeg,0),
                    		pFourthComponent := legGetComponentAt(pLeg,3),


                        	fPricenear := legGetNumeric(pFirstComponent,"pf_RFQ_TraderPrice_Near"),
                            fPricefar  := legGetNumeric(pFourthComponent,"pf_RFQ_TraderPrice_Far"),
                            fPricenearinitial:= legGetNumeric(pFirstComponent,"Forward"),
                            fPricefarinitial:= legGetNumeric(pFourthComponent,"Forward"),


                             IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPricenear <> fPricenearinitial ) THEN
                             	legOverwrite(pFirstComponent,"Forward",fPricenear),

                             IF ( legGetString( pComponent,"pf_RFQ_Provider" ) <> "" AND fPricefar <> fPricefarinitial ) THEN
                             	legOverwrite(pFourthComponent,"Forward",fPricefar)

                    }



};

// mx.preTrade.completion.ALL.ALL.CheckMsg

/*
MXpress Specific completion

Version 1.4
Remove a specific check for Funding swaps as funding packages checks are now done by the Common Sanity Checks 

Version 1.3
Use sysGetRFQRole rather than sysGetRole (Deprecated)

Version 1.2
- Set Tradability status at strategy/structure level
- Block Book action buttons in relevant case

Version 1.1
- Applied MSL best practices
- Replacement of DIST_USER1 by pf_RFQ_Requester, DIST_USER2 by pf_RFQ_Provider, DIST_STAT by pf_TradabilityStatus
- Replacement of SND (sender) by REQ (requester) and RCV (receiver) by PRV (provider)

Version 1.0

Notes:
This rule interprets the messages generated in Sanity and Tradability checks.
It provides information to the user (field coloring, message, pop-up).
It also computed tradability status and prevents user to book if required.

The rules runs both in closing and booking sequence.

	Step 1: Browse sanity checks
	Step 2: Browse tradability checks
	Step 3: Compute and display status
		Tradable: No sanity or tradability errors
		Requires confirmation: Tradability To Confirm errors in a Sales session, before confirmation by Trader
		Not tradable: Sanity/Tradability errors that must be solved to proceed
		Confirmed: Sales session after confirmation by Trader
Note:
Sanity checks are independant from the user and the context (RFQ, Confirmed RFQ, ...).
Tradability checks errors prevent users to book. But TradabilityToConfirm errors only prevent Sales (Requester) to book and can be confirmed or booked by a Trader (Provider).
*/

{
	pLeg := This,
	IF ( legIsInitialized( pLeg ) ) THEN
	{
		sGlobalStatus := "Tradable",
		sTradabilityStatusColor := "",
		bIsInBookingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ), "B_" ),
		sIsCommunicationActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","Communication" ) ),
		IF ( ( sIsCommunicationActive <> "YES" ) AND ( sIsCommunicationActive <> "NO" ) ) THEN
			ThrowError( pLeg,"Error in MX.ALL.GParam","Wrong returned value for Key 1 = Communication" ),
		pLeg0 := legGetComponentAt( pLeg,0 ),
		sBORegistration := legGetRegistrationLabel( pLeg ),
		bIsRequester := ( sysGetRFQRole() == "REQUESTER" OR sysGetRFQRole() == "ROBOT"),
        IF ( legIsElementValid(pLeg0,"pf_RFQ_Provider") ) THEN
			bIsRequester_ConfirmedRFQ := ( bIsRequester AND legGetString( pLeg0,"pf_RFQ_Provider" ) <> "" )
        ELSE
	        bIsRequester_ConfirmedRFQ := FALSE,
        bIsProvider := sysGetRFQRole() == "PROVIDER",             
        IF ( legIsElementValid(pLeg0,"pf_RFQ_Requester") ) THEN
			bIsProvider_OpenRFQ := ( bIsProvider AND legGetString( pLeg0,"pf_RFQ_Requester" ) <> "" )
        ELSE
        	bIsProvider_OpenRFQ := FALSE,
		bSanityError := FALSE,
		bTradabilityError := FALSE,
		bTradabilityToConfirmError := FALSE,
		iCount := 0,
		iNbLegs := legGetNumberOfComponents( pLeg ),
		iMsg := 0,
		WHILE ( iCount < iNbLegs ) DO
		{
			pComponent := legGetComponentAt( pLeg, iCount ),
			pAllMessages := legGetMessages( pComponent ),

			iNbMsgSanity := messagesGetNbOfMessagesFromCode( pAllMessages, "Sane-" ),
			// Browse sanity checks
			WHILE ( iMsg < iNbMsgSanity ) DO
			{
				pMessage := messagesGetMessageFromCodeAt( pAllMessages,"Sane-",iMsg ),
				IF ( ( messageGetLevel( pMessage ) == messageSysGetWarningLabel( ) ) ) THEN
				{
					// Sends a simple warning message to the user
					ThrowLowPriorityWarning( pComponent,"Sanity warning: " + messageGetText( pMessage ),messageGetField( pMessage ) )
				}
				ELSE IF ( ( messageGetLevel( pMessage ) == messageSysGetErrorLabel( ) ) ) THEN
				{
					sCode := messageGetCode( pMessage ),
					IF ( sCode == "Sane-PSpot-" ) OR ( sCode == "Sane-PCur1-" ) OR ( sCode == "Sane-PCur2-" ) THEN
					{
						// Sends a warning message to the user
						// If in the booking sequence use ThrowError to prevent trade booking
						IF ( bIsInBookingSequence ) THEN
							ThrowError( pComponent,"Sanity error: " + messageGetText( pMessage ),messageGetField( pMessage ) )
						ELSE
						{
							ThrowLowPriorityWarning( pComponent,"Sanity error: " + messageGetText( pMessage ),messageGetField( pMessage ) ),
							legSetCellColorAsError( pLeg,messageGetField( pMessage ) )
						}
					}
					ELSE IF NOT ( strStartsWith( sCode, "Sane-Intrusive-" ) ) THEN
					{
						// Sends a warning message to the user
						// If in the booking sequence use ThrowError to prevent trade booking
						IF ( bIsInBookingSequence ) THEN
							ThrowError( pComponent,"Sanity error: " + messageGetText( pMessage ),messageGetField( pMessage ) )
						ELSE
						{
							ThrowLowPriorityWarning( pComponent,"Sanity error: " + messageGetText( pMessage ),messageGetField( pMessage ) ),
							 //BAB Addition-To remove warning for breach messages
                             IF legIsElementValid(pComponent,messageGetField( pMessage ) ) THEN 
							IF (NOT(strCONTAIN(sCode,"Breach"))) THEN legSetCellColorAsError( pComponent,messageGetField( pMessage ) )
						}
					}
					ELSE
					{
						// Sends an intrusive error message to the user, popping-up until the user changes the trade to comply with the check
						ThrowError( pComponent,"Sanity error: " + messageGetText( pMessage ),messageGetField( pMessage ) )
					},
					bSanityError := TRUE
				},
				iMsg := iMsg + 1
			},

			// Browse tradability checks
			iMsg := 0,
			iNbMsgTradability := messagesGetNbOfMessagesFromCode( pAllMessages,"Tradability-" ),
			WHILE ( iMsg < iNbMsgTradability ) DO
			{
				pMessage := messagesGetMessageFromCodeAt( pAllMessages,"Tradability-",iMsg ),
				IF ( messageGetLevel( pMessage ) == messageSysGetWarningLabel() ) THEN
					// Sends a simple warning message to the user
					ThrowLowPriorityWarning( pComponent,"Tradability warning: " + messageGetText( pMessage ),messageGetField( pMessage ) )
				ELSE IF ( messageGetLevel( pMessage ) == messageSysGetErrorLabel() ) THEN
				{
					sCode := messageGetCode( pMessage ),
					// Sends a warning message to the user
					// If in the booking sequence use ThrowError to prevent trade booking
					IF ( bIsInBookingSequence ) THEN
						ThrowError( pComponent,"Tradability error: " + messageGetText( pMessage ),messageGetField( pMessage ) )
					ELSE
					{
						ThrowLowPriorityWarning( pComponent,"Tradability error: " + messageGetText( pMessage ),messageGetField( pMessage ) ),
						//BAB Addition-To remove warning for breach messages
						IF (NOT(strCONTAIN(sCode,"Breach"))) THEN legSetCellColorAsError( pComponent,messageGetField( pMessage ) )
					},
					bTradabilityError := TRUE
				},
				iMsg := iMsg + 1
			},
			// Run Tradability To Confirm checks only if trade is globally Tradable.
			IF NOT ( bTradabilityError ) THEN
			{
				iMsg := 0,
				iNbMsgTradability := messagesGetNbOfMessagesFromCode( pAllMessages,"TradabilityToConfirm-" ),
				WHILE ( iMsg < iNbMsgTradability ) DO
				{
					pMessage := messagesGetMessageFromCodeAt( pAllMessages,"TradabilityToConfirm-",iMsg ),
					sCode := messageGetCode( pMessage ),
					IF ( NOT ( bIsRequester ) OR ( bIsRequester_ConfirmedRFQ ) ) THEN
						// Sends a simple warning message to the user
						ThrowLowPriorityWarning( pComponent,"Tradability warning: " + messageGetText( pMessage ),messageGetField( pMessage ) )
					ELSE
					{
						// Sends a warning message to the user
						// If in the booking sequence use ThrowError to prevent trade booking
						IF ( bIsInBookingSequence ) THEN
							ThrowError( pComponent,"Tradability error: " + messageGetText( pMessage ),messageGetField( pMessage ) )
						ELSE
						{
							ThrowLowPriorityWarning( pComponent,"Tradability error: " + messageGetText( pMessage ),messageGetField( pMessage ) ),
							IF (NOT(strCONTAIN(sCode,"Breach"))) THEN legSetCellColorAsError( pComponent,messageGetField( pMessage ) )
						},
						bTradabilityToConfirmError := TRUE
					},
					iMsg := iMsg + 1
				}
			},
			iCount := iCount + 1
		},
		// Compute Tradability status based an sanity and tradability messages and also on type of user and setp in the RFQ workflow
		IF ( ( bSanityError ) OR ( bTradabilityError ) )THEN
		{
			sGlobalStatus := "Not tradable",
			sTradabilityStatusColor := "Error"
		}
		ELSE IF NOT ( bIsRequester_ConfirmedRFQ ) AND ( bTradabilityToConfirmError ) THEN
		{
			IF ( sIsCommunicationActive == "YES" ) THEN
			{
				sGlobalStatus := "Requires confirmation",
				sTradabilityStatusColor := "Error"
			}
			ELSE
			{
				sGlobalStatus := "Not tradable",
				sTradabilityStatusColor := "Error"
			}
		}
		ELSE IF ( bIsRequester_ConfirmedRFQ ) THEN
			sGlobalStatus := "Confirmed"
		ELSE IF ( bIsProvider_OpenRFQ ) THEN
			sGlobalStatus := "Under confirmation",

		IF ( legIsElementValid( pLeg,"pf_TradabilityStatus" ) ) THEN
			legOverwrite( pLeg, "pf_TradabilityStatus", sGlobalStatus ),
		// Loop on all legs to set the same common Tradability status and cell color
		// There is a specific treatment for products with the pf_TradabilityStatus field, in particular for FXMM Packages.
		pFirstComponent := legGetFirstComponent(pLeg),
		bInProductsOfException := FALSE,
		IF ( NOT legIsElementValid( pFirstComponent,"pf_TradabilityStatus" ) ) THEN
			bInProductsOfException := TRUE,

		IF ( NOT ( bInProductsOfException ) ) THEN
		{
			iCount := 0,
			WHILE ( iCount < iNbLegs ) DO 
			{
				pComponent := legGetComponentAt( pLeg, iCount ),
				legOverwrite( pComponent, "pf_TradabilityStatus", sGlobalStatus ),
				IF ( sTradabilityStatusColor == "Error" ) THEN
					legSetCellColorAsError( pComponent,"pf_TradabilityStatus" ),
				iCount := iCount + 1
			}
		}
		ELSE
		{
			// Special treatment for FXMM packages. We look for the adequate field to set the Tradability status
			pMainComponent := legGetMainComponent( pLeg ),
			pFatherPackage := legGetFatherPackage( pMainComponent ),
			bSetStatusFromPackage := TRUE,
			sPackageStatusField := "",
			IF ( legIsElementValid( pFatherPackage,"pf_TradabilityStatus" ) ) THEN
				sPackageStatusField := "pf_TradabilityStatus"
			ELSE
				bSetStatusFromPackage := FALSE,
			IF ( bSetStatusFromPackage ) THEN
			{
				legOverwrite( pFatherPackage, sPackageStatusField, sGlobalStatus ),
				IF ( sTradabilityStatusColor == "Error" ) THEN
					legSetCellColorAsError( pFatherPackage,sPackageStatusField )
			}
		},
		// At trade/structure level (as opposed to leg/component), in case the transaction is not tradable/requires confirmation:
		// Display a generic message for user information
		// Prevents booking (with ThrowError)
		bBlockBooking := FALSE,
		sBlockBookingMessage := "",
		IF ( bSanityError AND legGetRegistrationLabel( pLeg ) <> "mxContractITRADE" ) THEN
		{
			IF ( ( bIsInBookingSequence ) ) THEN
				ThrowError( pLeg,"The transaction fails the sanity checks","See other message(s) for details" )
			ELSE
			{
				ThrowLowPriorityWarning( pLeg,"The transaction fails the sanity checks","See other message(s) for details" ),
				bBlockBooking := TRUE,
				sBlockBookingMessage := "The transaction fails the sanity checks." + endline() + "See notification(s) for details"
			}
		},
		IF ( ( bTradabilityError OR bTradabilityToConfirmError) AND ( legGetRegistrationLabel( pLeg ) <> "mxContractITRADE" ) ) THEN
		{
			IF ( sGlobalStatus == "Requires confirmation" ) THEN
				sMessage := "The transaction requires confirmation"
			ELSE
				sMessage := "The transaction is not tradable",
			IF ( bIsInBookingSequence ) THEN
				ThrowError( pLeg, sMessage,"See other message(s) for details" )
			ELSE
				ThrowLowPriorityWarning( pLeg, sMessage,"See other message(s) for details" ),
			bBlockBooking := TRUE,
			sBlockBookingMessage := sMessage + "." + endline() + "See notification(s) for details"
		},
		IF NOT ( bIsInBookingSequence ) THEN
		{
			legBlockAction( pLeg,"trd:Generate trade",sBlockBookingMessage,bBlockBooking ),
			legBlockAction( pLeg,"trd:Capture trade",sBlockBookingMessage,bBlockBooking )
		}
	}
};

// mx.preTrade.morphing.ALL.Empty

/*
MXpress
Empty rule

Version  1.0
*/

bEmpty := TRUE;

// mx.preTrade.completion.ALL.Closing.SalesMg

/* Sales Margin info converted and stored as Sales income into VAAMT and VAAMTCCY in Closing sequence

Version 1.2
- For Back to Back, attach the fee to Back to back portfolio (Trader portfolio)
- Use SALES_FEE Broker code

Version 1.1
Filter out computation of VAAMT for the trades coming from an event

Version 1.0
Computation logic runs at component level, so the native margin of each individual component is copied/converted into the Sales income (VAAMT UDF) of each individual component.
So, the trade margin is assumed to be held into the individual components of a structure.
e.g. Risk Reversal margin assumed on FX Vanillas native margin(s), Dual Currency Deposit assmed expected on Loan/Depo and/or FX Vanilla native margin(s) (Not the case for the moment).

Note: It is possible to activate extra logic at the end of the rule to create an InternalFee Broker fee holding the VAAMT/VAAMTCCY information, so that the margin has a P&L/Risk impact.

*/

{
	pLeg := This,
	sAction := properties.Get( "mx.preTrade.action" ),
	sEvaluationActive := properties.Get( "mx.preTrade.evaluation.active" ), // Use sEvaluationActive == "YES" in case leg must be in Pricing context to get relevant native Sales margin values
	sIsInsertTradeTicketDisplay := properties.Get( "mx.preTrade.insertTradeTicketDisplay" ), // Use sIsInsertTradeTicketDisplay == "YES" for Generate trade intermediary ticket screen context
	sBOSource := properties.Get( "mx.preTrade.BO.source" ), // sBOSource <> "mxContractEventIEVENT" to apply logic only for new trades
	sBOClass := properties.Get( "mx.preTrade.BO.source.class" ), // sBOClass to use to filter out events if need be (e.g. sBOClass <> "mxContractEventICANCEL_REISSUE")
	IF ( sAction == "INS" ) THEN
	{
		dTradingDate := legGetDate( pLeg,"Trading_Date" ),

		iNbComponents := legGetNumberOfComponents( pLeg ),
		iComponent := 0,
		WHILE ( iComponent < iNbComponents ) DO
		{
			pComponent := legGetComponentAt( pLeg,iComponent ),
			sRegistration:=legGetRegistration( pComponent ),
			fSalesIncomeAmt := 0.0,
			sSalesIncomeCur := "",
			sInternal := legGetString( pComponent,"Internal" ),

            //Added for the VAAMT - When in Booking Sequence - Manual booking or Import
            bIsInBookingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ), "B_" ),
            bImportTrade:= FALSE,

            //BAB addition for BackToBack, copied from rule "mx.preTrade.completion.ALL.Pricing.FInit-ALL"
            //For Imported deals, to set Back to back to yes and Sales margin handling for deals from Sales type groups





            //Get Source module
            pMainComponent := legGetMainComponent( pLeg ),
    		pMainContract := legGetFatherContract( pMainComponent ),
    		sSourceModule := legGetSourceModule( pMainContract ),

            IF (   sSourceModule == "FXT"
            	OR sSourceModule == "Migration"
                OR sSourceModule == "T24.FX"
                OR sSourceModule == "T24.MM"
                OR sSourceModule == "T24.NOSTRO"
               )
            THEN
            {

                sVAModeField := "VAMODE",            
                IF ( legIsElementValid( pComponent, sVAModeField ) ) THEN
                {
                    IF ( legGetString(pComponent, "Internal") == "Yes" ) THEN
                    {
                        legSetString(pComponent, sVAModeField, "None")
                      }
                    ELSE
                    {
                        sUserProfile := lookupString( "MX.ALL.UserGroupProfile","ALL","USER_GROUP",sysGetGroup() ),
                        IF ( sUserProfile <> "Sales" ) THEN
                            legSetString(pComponent, sVAModeField, "None")
                        ELSE
                        {
                            legSetString(pComponent, sVAModeField, "Keep in Sales portfolio"),

                            // BAB addition for the Bank Note
                    sTypology := legGetString(pComponent,"Typology"),
                    IF sTypology == "Banknotes" OR sTypology == "Banknotes Credit" THEN 
                    {
                    fSpot := legGetNumeric(pComponent,"Spot"),
                    sCurr1 := legGetString(pComponent,"Den_unit"),
                    sCurr2 := legGetString(pComponent,"Num_unit"),


                    IF ((strSubString(sCurr1, 0, 2) == strSubString(sCurr2, 0, 2))) AND ((strSubString(sCurr1, 2, 3) == "N") OR (strSubString(sCurr2, 2, 3) == "N") OR (strSubString(sCurr1, 2, 3) == "O") OR (strSubString(sCurr2, 2, 3) == "O"))    THEN
                    {
                    legSetString(pComponent, sVAModeField, "None")
                    }
                    ELSE
                    {
                    legSetString(pComponent, sVAModeField, "Keep in Sales portfolio")
                    }
                    }
                    }      
                    }
                },

                // For Sales margin mode 'Keep in Sales portfolio', automatically set Back to Back = Yes - Except for FXMM Packages where we set Independent margins = Yes
                sLegRegistration := legGetRegistrationLabel( pLeg ),
                pMainComponent := legGetMainComponent( pLeg ),    
                IF ( sLegRegistration <> "mxContractFxIOUTRIGHT" AND sLegRegistration <> "mxContractFxISPLIT" AND sLegRegistration <> "mxContractFxISPLITSWAP" AND sLegRegistration <> "mxContractFxIFUNDINGOUTRIGHT" AND sLegRegistration <> "mxContractFxIFUNDINGSWAP" ) THEN
                {
                    IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
                    {
                        IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
                        {
                            /*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), TRUE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
                            legSetFOPIsBackToBack(pMainComponent, TRUE)*/
                            IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                                legSetString(pMainComponent,"Back to back","Yes")                
                        }
                        ELSE
                        {
                            /*legSetFOPIsBackToBack(legGetContractAt(pLeg, 0), FALSE), // For FX Swap (for example) SetFOPIsBackToBack works at Contract level and not component level
                            legSetFOPIsBackToBack(pMainComponent, FALSE)*/
                            IF ( legIsElementValid(pMainComponent,"Back to back") ) THEN
                                legSetString(pMainComponent,"Back to back","No")                  
                        }
                    }
                }
                ELSE
                {
                    IF ( legIsElementValid(pMainComponent,"VAMODE") ) THEN
                    {
                        IF ( legGetString(pMainComponent,"VAMODE") == "Keep in Sales portfolio" ) THEN
                            legSetString(pLeg, "Independent margins", "Yes")
                        ELSE
                            legSetString(pLeg, "Independent margins", "No")
                    }    
                }
            },
            //End of BAB BackToBack addition

			IF ( sInternal <> "Yes" ) THEN
			{
                sVAAMTField := "VAAMT",
				sVAAMTCCYField := "VAAMTCCY",
                IF ( legIsElementValid( pComponent, sVAAMTField ) ) THEN
				{
                    // Only compute VAAMT from Native Sales margin in case of new trade insertion or Event specifically tagged (pf_Sales_margin_Event_Compute==Y)
                    bSalesMarginEventCompute := FALSE,
                    IF ( legIsElementValid(pComponent,"pf_Sales_margin_Event_Compute") ) THEN
	                    IF ( legGetString(pComponent,"pf_Sales_margin_Event_Compute")=="Y" ) THEN
    	                bSalesMarginEventCompute := TRUE,
                    IF ( sBOSource <> "mxContractEventIEVENT" OR (sBOSource == "mxContractEventIEVENT" AND bSalesMarginEventCompute ) ) THEN
                    {
						//////////////////////////
						// Retrieve native Sales Margin: Amount, Currency and Date 
						//////////////////////////
						bNativeSalesMarginAvailable := FALSE,
						// Retrieve Amount
                        sCriteria2 := "",
						IF ( legIsElementValid(pComponent,"Ratio") ) THEN
							sCriteria2 := legGetString(pComponent,"Ratio"), // Only useful for EQD deals - Sales margin computed when Ratio = No
                        IF ( legGetPatternLabel( pComponent ) == "Callable Forward FXD" ) THEN
                        	sCriteria2 := "Callable Forward FXD",
						pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","Amount", "Criteria 2", sCriteria2 ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							bNativeSalesMarginAvailable := TRUE,
							iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sNativeSalesMarginAmountField := lookupResultsGetString( pFieldResult,0,1 ),
							sNativeSalesMarginAmountField2 := lookupResultsGetString( pFieldResult,0,2 ),
							IF ( sNativeSalesMarginAmountField2 == ""  AND sRegistration <> "Bonds" ) THEN // Generic case
                            {
                             //BAB Addition to compute the sales margin in pricing when importing trades or Manually booking- only booking sequence passes and there is no pricing
                             //To avoid setting a zero VAAMT when it is non-zero, as this will lock VAAMT
                             IF sSourceModule <> "mx" THEN
                                bImportTrade := TRUE,

                             //When in Booking Sequence - Manual booking or Import - Price the deal and retrieve native sales margin
                             IF bImportTrade == TRUE OR bIsInBookingSequence == TRUE THEN
                             {
                                    pContainer := npOpen( TRUE ),
									pClone := npCloneLeg( pContainer,pComponent ),
									legCompute( pClone,"noWorkflow" ),

                                    //For Migration deals, use the native field without the native discount effect of Sales_margin_amount
                                    //No market data to price and discount as of trade date
                                    IF ( sSourceModule == "Migration" AND sRegistration == "Loans/Deposits" ) THEN
                                    fNativeSalesMarginAmount := legGetNumeric( pClone,sNativeSalesMarginAmountField + "__Loan_") //Get the absolute non-discounted sales margin
                                    ELSE
                                    fNativeSalesMarginAmount := legGetNumeric( pClone,sNativeSalesMarginAmountField ), //Get the discounted sales margin

                                    npClose( pContainer )
                             }
                             //Original case: When in Closing sequence
                             ELSE
								fNativeSalesMarginAmount := legGetNumeric( pComponent,sNativeSalesMarginAmountField )
                             }
                            ELSE IF (sRegistration == "Bonds" ) THEN // Sukuk case
                                fNativeSalesMarginAmount := legGetNumeric( pComponent,sNativeSalesMarginAmountField ) / 100.0 * legGetNumeric(pComponent,sNativeSalesMarginAmountField2)
							ELSE IF sNativeSalesMarginAmountField2 <> "VirtualLegComputation" THEN // Multiply Field1 and Field2
								fNativeSalesMarginAmount := legGetNumeric( pComponent,sNativeSalesMarginAmountField ) * legGetNumeric(pComponent,sNativeSalesMarginAmountField2)
							ELSE // Call Deposits or other products requiring specific computation - Use Field Name 1 = "" and Field Name 2 = "VirtualLegComputation" in lookup table MX.ALL.FieldMapping.SalesMargin
							{
								// Create a container with a clone of the deal
								pContainer := npOpen( TRUE ),
								pClone := npCloneLeg( pContainer,pComponent ),
								// Set clone's margin to 0
								legOverwrite( pClone,"Sales margin",0.0 ),
								legCompute( pClone,"noWorkflow" ),
								// Calculate the NPV generated by the margin in the original deal (i.e. NPV(with margin) - NPV (without margin) )
								fNativeSalesMarginAmount := legGetNumeric( pComponent,"Npv" ) - legGetNumeric( pClone,"Npv" ),
								npClose( pContainer )
							}
						},
						// Retrieve Currency
						pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","Currency","Criteria 2", sCriteria2 ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sNativeSalesMarginCurrencyField := lookupResultsGetString( pFieldResult,0,1 ),
							sNativeSalesMarginCurrency := legGetString( pComponent,sNativeSalesMarginCurrencyField )
						},
						// Retrieve Date
						pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","Date","Criteria 2", sCriteria2 ),
						IF ( NOT isNull( pFieldResult ) ) THEN
						{
							iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sNativeSalesMarginDateField := lookupResultsGetString( pFieldResult,0,1 ),
							dNativeSalesMarginDate := legGetDate( pComponent,sNativeSalesMarginDateField )
						},

						IF ( bNativeSalesMarginAvailable ) THEN
						{
							// Retrieve the VAAMT Sales Margin currency
							sSalesIncomeCur := legGetString( pComponent, sVAAMTCCYField ),
                            IF ( legGetString( pComponent, "Back to back" ) <> "Yes" ) THEN
								sPortfolio := legGetString( pComponent,"Portfolio" )
                            ELSE
	                            sPortfolio := legGetString( pComponent,"Back to back portfolio" ),
							//Below commented out since Margin currency should always be SAR
                            /* IF ( legGetLastInputField(pComponent) == "Portfolio" OR legGetLastInputField(pComponent) == "Back to back portfolio" OR sSalesIncomeCur == "" ) THEN
							{
								sSalesIncomeCur := ptfGetEntityCurrency( sPortfolio ), // Note that MX.ALL.SalesMarginPtf table may be used as an alternate to specify sales margin currency
								legOverwrite( pComponent,sVAAMTCCYField,sSalesIncomeCur ),
								legOverwrite( pComponent,sVAAMTField,0.0 ) // Reset any manual customisation of the sales margin
							}, */

                            //BAB addition - Margin currency should always be in SAR
                            sSalesIncomeCur := "SAR",
                            legOverwrite( pComponent,sVAAMTCCYField,sSalesIncomeCur ),

							//////////////////////////
							// If necessary, convert/discount native Sales margin into expected currency
							//////////////////////////
							dSalesIncomeDate := dTradingDate,
							pInitialData := legGetInitialDatas( pComponent ),
							initialdatasSetDate( pInitialData,"Sales margin calc. date",dSalesIncomeDate ),

                            //BAB Addition to avoid crash on Mono-currency bank note HVA
                            IF legIsElementValid(pComponent,"Den_nominal") THEN
                            fDenNominal := legGetNumeric(pComponent,"Den_nominal")
                            ELSE				//Set it to a non-zero number to keep original logic
                            fDenNominal := 1.0, 

							IF ( sSalesIncomeCur == sNativeSalesMarginCurrency ) THEN
								fFXRate := 1.0
							ELSE IF ( sSalesIncomeCur <> "" AND fDenNominal <> 0.0 ) THEN //BAB Addition: check Den_nominal
							{
								//BAB addition: Get the rate to be used to convert from FCY margin currency to SAR margin currency
                                //Specific case: FX deal with USD/SAR instrument --> use deal rate as default
                                IF (sRegistration == "Spot-Forward" OR sRegistration == "Forex-Swap Leg" ) AND legGetString(pComponent,"Instrument") == "USD/SAR" THEN
                                	fFXRate := legGetNumeric(pComponent,"Forward")
                                //Case: everything else --> use market rate (OTB), Get the forward rate between the entity currency(numerator) and the sales margin currency(denumerator)
                                ELSE
                                {
                                	//Addition by Roy J, originally cuGetFxForwardRate gets executed only. To be enhanced to pass only for Sales deals

                                    //Avoid crash with cugetfxforwardrate when executed but CCY1/sSalesIncomeCur or sSalesIncomeCur/CCY2 currency pair does not exist in the system	
                                	//Check if currency pair used for Sales margin conversion exists in the system, otherwise throw an error to avoid crashes with cugetfxforwardrate
                                        //Get currency pair, this function always returns a value
                                        sCurrencyPair := fxGetCurrencyPair(sSalesIncomeCur,sNativeSalesMarginCurrency),

                                        //These will only return a value if the sCurrencyPair exists
                                        sCcyBase 		:= fxCntGetBase(sCurrencyPair),
                                        sCcyUnderlying 	:= fxCntGetUnderlying(sCurrencyPair),

                                        IF ( sCcyBase =="" OR sCcyUnderlying =="" ) THEN
                                        bCcyPairExists := FALSE
                                        ELSE
                                        bCcyPairExists := TRUE,

                                        IF bCcyPairExists == TRUE THEN //Only execute if currency pair exists
                                		fFXRate := cuGetFxForwardRate( sSalesIncomeCur,sNativeSalesMarginCurrency, dNativeSalesMarginDate )
                                        ELSE //Default to 1.0
                                        fFXRate := 1.0
                                },


                                //Get and set currency pair used for conversion and conversion rate into the relevant UDFs
                                sCurrencyPair := fxGetCurrencyPair(sSalesIncomeCur,sNativeSalesMarginCurrency),                                  
                                IF legIsElementValid(pComponent, "MRG_FX_CCY") THEN
								legOverwrite(pComponent,"MRG_FX_CCY",sCurrencyPair),

                                IF legIsElementValid(pComponent, "MRG_FX_RT") THEN
                                legSetNumeric(pComponent,"MRG_FX_RT",fFXRate), 
                                //Set as this is user-editable

                                //get the fxrate from the UDF
                                IF legIsElementValid(pComponent, "MRG_FX_RT") THEN
                                fFXRate := legGetNumeric(pComponent,"MRG_FX_RT"),  

                                //Set initial data
                                initialdatasSetString( pInitialData,"Sales margin conv. rate quot", sNativeSalesMarginCurrency + "-" + sSalesIncomeCur ),
                                initialdatasSetNumeric( pInitialData,"Sales margin conv. rate",fFXRate )

							},
                            IF ( dSalesIncomeDate == dNativeSalesMarginDate ) THEN
                            	fDiscount := 1.0
                            ELSE IF ( sSalesIncomeCur <> "" ) THEN
                            {
	                            // Get the discount rate between sales margin date and sales income date
                                // rcGetDiscount function can be used alternatively if the discount curve is known for the currency
	                            pContainer := npOpen(),
    		                    pVirtualLoan := legAddComponent(pContainer,"mxContractISINGLE","Loans/Deposits","Loan/Deposit"),	
                                legOverwrite(pVirtualLoan, "Instrument", sSalesIncomeCur),
                                legOverwrite(pVirtualLoan, "Nominal", 100.0),
                                legOverwrite(pVirtualLoan, "Start", dSalesIncomeDate),
                                legOverwrite(pVirtualLoan, "Maturity", dNativeSalesMarginDate),
                                legOverwrite(pVirtualLoan, "Single period", "Yes"),
                                legCompute(pVirtualLoan,"noworkflow"),
                                fDiscount := legGetNumeric(pVirtualLoan, "Repayment") / 100.0,
								npClose(pContainer),                    
                                initialdatasSetNumeric( pInitialData,"Sales margin disc. rate",fDiscount)
                            },

                            //BAB addition to turn off Sales margin discounting. Comment out to re-activate salesmargin discounting
                            fDiscount := 1.0,
                            initialdatasSetNumeric( pInitialData,"Sales margin disc. rate",fDiscount), //Added to overwrite above line 266 as per Samir 

                            //BAB addition to take into consideration the customized flows in the sales margin amount
                            sTypology := legGetTypology	(pComponent),
        					IF sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "PRS" 
           						OR sTypology == "PRS Range" OR sTypology == "PRS CapFloorCollar" OR sTypology == "PRS Inverse Floater" OR sTypology == "Depo Callable" THEN
            				{
            	 				IF strCONTAIN (legGetString(pComponent, "Customized Flows" ), "Y") THEN
                 				{
                                	fNativeSalesMarginAmount := legGetNumeric(pComponent,"SALES_MG")
                                }
                            },

                            fSalesIncomeAmt := roundnearest( fNativeSalesMarginAmount / fDiscount * fFXRate,0 ),

							// Set VAAMT UDF with Sales Margin amount
							legSetNumeric( pComponent,sVAAMTField,fSalesIncomeAmt )
						}
					},

					fSalesIncomeAmt := legGetNumeric( pComponent,sVAAMTField ), // Retrieve VAAMT whether it was just set or is coming from previous deal version in case of event
					//////////////////////////
					// Capture the Sales Margin as an InternalFee Broker fee - By default, only packaged for FXD. originally managed by FXD.Closing.BrkFees-ALL rule
					//////////////////////////
                    sSalesMarginMode := "None",
                    IF ( legIsElementValid( pComponent, "VAMODE" ) ) THEN
                    	sSalesMarginMode := legGetString(pComponent, "VAMODE"),
                    pResults := lookupResults( "MX.ALL.SalesMarginPtf","ALL","USER_GROUP",sysGetGroup( ) ),
                    IF ( NOT ( isNull( pResults) ) ) THEN
                        sDestinationPortfolio := lookupResultsGetString( pResults,0,0 ),                    
                    IF (sSalesMarginMode == "Transfer to Sales portfolio") THEN
                    {
						IF ( ABS( fSalesIncomeAmt ) > 0.001 ) THEN
						{
							dFlowValueDate := sysGetTradingDate(),
							pBrokerFlows := legGetBrokerFlows( pComponent ),
							// Get the pointer of last broker flow whose type is "InternalFee".
							iFlowCount := 0,
							pBrokerFlow := pNULL,
							iNumBrkFlows := brkFlowsGetNumberOfFlows( pBrokerFlows ),
							WHILE ( iFlowCount < iNumBrkFlows ) DO
							{
								pFlow := brkFlowsGetAt( pBrokerFlows,iFlowCount ),
								IF ( brkFlowGetType( pFlow ) == "InternalFee" ) THEN
								{
									pBrokerFlow := pFlow,
									iFlowCount := iNumBrkFlows
								},
								iFlowCount := iFlowCount + 1
							},
							// If no broker flow of type "InternalFee" is found, add one.
							IF ( isNull( pBrokerFlow ) ) THEN
								pBrokerFlow := brkFlowsAdd( pBrokerFlows ),
							brkFlowSetType( pBrokerFlow,"InternalFee" ),
							brkFlowSetSource( pBrokerFlow,sPortfolio),
							brkFlowSetDestination( pBrokerFlow,sDestinationPortfolio ),
							brkFlowSetValueDate( pBrokerFlow,dFlowValueDate ),
							brkFlowSetCode( pBrokerFlow,"SALES_FEE" ),                            
							brkFlowSetCurrency( pBrokerFlow,sSalesIncomeCur ),
							brkFlowSetFee( pBrokerFlow,fSalesIncomeAmt )
						}
						ELSE
						{
							pBrokerFlows := legGetBrokerFlows( pComponent ),
							// Remove broker flow whose type is "InternalFee" and code "SALES_FEE"
							iFlowCount := brkFlowsGetNumberOfFlows( pBrokerFlows ) - 1,
							WHILE ( iFlowCount >= 0 ) DO
							{
								pFlow := brkFlowsGetAt( pBrokerFlows,iFlowCount ),
								IF ( ( brkFlowGetType( pFlow ) == "InternalFee" ) AND ( brkFlowGetCode( pFlow ) == "SALES_FEE" ) ) THEN
									 brkFlowsRemove( pBrokerFlows,pFlow ),
								iFlowCount := iFlowCount - 1
							}
						}
					}
                    ELSE
                    {
                        pBrokerFlows := legGetBrokerFlows( pComponent ),
                        // Remove broker flow whose type is "InternalFee" and code "SALES_FEE"
                        iFlowCount := brkFlowsGetNumberOfFlows( pBrokerFlows ) - 1,
                        WHILE ( iFlowCount >= 0 ) DO
                        {
                            pFlow := brkFlowsGetAt( pBrokerFlows,iFlowCount ),
                            IF ( ( brkFlowGetType( pFlow ) == "InternalFee" ) AND ( brkFlowGetCode( pFlow ) == "SALES_FEE" ) ) THEN
                            	brkFlowsRemove( pBrokerFlows,pFlow ),
                            iFlowCount := iFlowCount - 1
                        }
                    }                    
				} 
			},

			iComponent := iComponent + 1
		}

	}
};

// mx.preTrade.completion._Functions.IRD.ClearingBusinessDayPerLeg

/*
Version 1.0
*/

{
	sContext := getArgAsString( 0 ),
	sTypology := getArgAsString( 1 ),
	sBDConvention := getArgAsString( 2 ),
	iBDCcount := 0,
	sBDCnumber := "",
	iBDC := 0,
	iBDCtot := 0,
	sBDC := "",
	sClearingEligibilityBDC := "",
	sNotEligibleReasonBDC := "",

	pBDConvention := lookupResults( "MX.IRD.ClearingDayConvention",sContext,"Typology",sTypology ),
	IF ( NOT isNull( pBDConvention ) ) THEN
	{
		iBDCcount := 0,
		sBDCnumber := lookupResultsGetString( pBDConvention,0,iBDCcount ),
		WHILE ( sBDCnumber <> "" ) DO
		{
			iBDCcount := iBDCcount + 1,
			sBDCnumber := lookupResultsGetString( pBDConvention,0,iBDCcount )
		},

		iBDC := 0,
		iBDCtot := iBDCcount,
		WHILE ( iBDC < iBDCtot ) DO
		{
			sBDC := lookupResultsGetString( pBDConvention,0,iBDC ),
			IF ( strContain( sBDConvention, sBDC ) == TRUE ) THEN
			{
				sClearingEligibilityBDC := "Business Day Convention",
				iBDC := iBDCtot
			}
			ELSE
				iBDC := iBDC + 1
		}
	},
	IF ( strContain( sClearingEligibilityBDC,"Business Day Convention" ) == FALSE ) THEN
		sNotEligibleReasonBDC := "#Business Day Convention ",

	setReturnValue( sNotEligibleReasonBDC )
};

/* The aim of this rule is to add the fees inserted at trade level to the cost in the liquidation
*/

{
	// Get a pointer on the trade being inserted + all of it deliverables
	pPackage := This,
	pAllFlows := mx.deliverable.Package.GetFlows( pPackage ),

  	// Reset Fields
	sComponentFamily := "",
	sComponentGroup := "",
	sComponentType := "",
    sSourceAccountingSection := "",   
	bIsEligible := FALSE,
	sSourcePortfolio := "",
	sBuySell := "",
	sInstrument := "",
	sInstrumentCurrency := "",
	sSettlementCurrency := "",
	fCapFactor := 0.0,
	fInitialCleanPrice := 0.0,
	fInitialNominal := 0.0,
	iFee := 0,
	fBrokerageFees := 0.0,
	sFeeCode := "",
	sFeeType := "",
	sFeeCurrency := "",
	sFeeSource := "",
	sFeeDestination := "",
	fFeeAmount := 0.0,
	fFxRate := 0.0,
	fFeeAmount := 0.0,
    iLiqFlows := 0,
    dSysDate := sysGetFODeskDate(),

    // Get a Pointer on the liquidation flow
    pLiqFlows := mx.system.collection.GetFilterByElementClass( pAllFlows,"mx.deliverable.Position"),
    iFlow := 0,
    iLiqFlows := mx.system.collection.GetLength(pLiqFlows),

    WHILE (iFlow < iLiqFlows) DO 
    {

		pLiqFlow := mx.system.collection.GetElementAt( pLiqFlows,iFlow),
	    // Get pointer on the producer of this liquidation flow
	    pComponent := mx.deliverable.Position.GetComponent(pLiqFlow),

	    // Check if producer is valid before proceeding
	    IF (NOT isNull(pComponent)) THEN 
        {
        	// Liquidation Flow will be destroyed if it is not a Bond
	        sProductGroup := legGetProductGroup(pComponent),         

			// The following is to avoid having exception on some Products                                        
	        IF (sProductGroup == "BOND") THEN {

	            // Check Eligiblity for Fees Incorporation in Cost              
				sSourceAccountingSection := legGetString(pComponent,"Source_section"),
                sBuySell := legGetString(pComponent,"Buy_Sell"),
	           	bIsEligible :=  (sSourceAccountingSection == "Issuance" AND sBuySell == "Sell") ,

		        IF (bIsEligible) THEN 
                {

					fNewCleanPrice := legGetNumeric(pComponent,"LIQ_CP"),
					mx.deliverable.Position.SetInstrumentCleanPrice(pLiqFlow, fNewCleanPrice)

	    	    }                            
	        }
            // If it is not a bond than the liquidation flow will be destroyed
		},
      iFlow := iFlow + 1  
    }
 };

// mx.preTrade.completion._Functions.IRD.ClearingFloatDayCountPerLeg

/*
Version 1.0
*/

{
	sContext := getArgAsString( 0 ),
	sLeg := getArgAsString( 1 ),
	sCurrency := getArgAsString( 2 ),
	sTypology := getArgAsString( 3 ),
	sRateConv := getArgAsString( 4 ),
	pFloatDay := pNULL,
	iFDCCount := 0,
	sFDCCountNumb := "",
	iFloat := 0,
	iFloatDay := 0,
	sFloat := "",
	sClearingEligibilityFlDC := "",
	sNotEligibleReasonFlDC := "",

	pFloatDay := lookupResults( "MX.IRD.ClearingFloatDayCount",sContext,
								"Clearing Eligible CCYs",sCurrency,
								"Typology",sTypology ),
	IF ( NOT isNull( pFloatDay ) ) THEN
	{
		iFDCCount := 0,
		sFDCCountNumb := lookupResultsGetString( pFloatDay,0,iFDCCount ),
		WHILE ( sFDCCountNumb <> "" ) DO
		{
			iFDCCount := iFDCCount + 1,
			sFDCCountNumb := lookupResultsGetString( pFloatDay,0,iFDCCount )
		},
		iFloat := 0,
		iFloatDay := iFDCCount,
		WHILE ( iFloat < iFloatDay ) DO
		{
			sFloat := lookupResultsGetString( pFloatDay,0,iFloat ),
			IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) OR ( sTypology == "FRA" ) ) THEN
			{
				IF ( strContain( sRateConv,sFloat ) == TRUE ) THEN
				{
					sClearingEligibilityFlDC := "Floating Day Count",
					iFloat := iFloatDay + 1
				}
				ELSE
					iFloat := iFloat + 1
			}
			ELSE IF ( sTypology == "ZC Inflation Swap" ) THEN
			{
				IF ( sLeg == "Floating" ) THEN
				{
					IF ( strContain( sRateConv,sFloat ) == TRUE ) THEN
					{
						sClearingEligibilityFlDC := "Floating Day Count",
						iFloat := iFloatDay + 1
					}
					ELSE
						iFloat := iFloat + 1
				}
			}
		}
	},
	IF ( strContain( sClearingEligibilityFlDC,"Floating Day Count" ) == FALSE ) THEN
		sNotEligibleReasonFlDC := "#Floating Day Count ",

	setReturnValue( sNotEligibleReasonFlDC )
};

// mx.preTrade.completion.ALL.Closing.Customizations

/*
MXpress
To allow client to put their own customizations

Version  1.0
*/

{
    pLeg := This,
    pMainComponent := legGetMainComponent(pLeg),
    sRegistration := legGetRegistration(pMainComponent),
                sTypology := legGetTypology(pMainComponent),
    IF (sTypology== "Banknotes" OR sTypology== "Banknotes Credit") THEN
