    legSetString(pLeg, "SWIFT_NET", sSwiftNet)
	}
};

// mx.msl.Deliverable.completion.ALL.SplitThreshold

/*MXpress
If there is one flow issued fitting the criteria which determined a Threshold,
this flow should be split with the amount determined in threshold 2,
as many times as needed to have every split amount equal to an amount below the first Threshold

This applies for cash flows and for security flows
In case of delivery versus payment, we split the security flows according to the threshold specified,
and we split the linked cash flows proportionnaly

Used algorithm:
If Threshold is set in lookup MX.ALL.DlvThreshold
	Loop on the payments generated by the contract
		IF Payment exceeds the first threshold
			Duplicate payment 
			Loop until the total amount of the split payments reaches the payment amount
				Split equal threshold 2 while the total split number is reached the last split payment is equal to total amount less the total splits amount
				Add the splits to the new collection
			End loop
		Else
			Add the payment to the new collection
		End if
	End loop
	Replace the payments in the original collection by the new ones
End if

Version 1.0
Initialization

NOTE : splitting the resulting flow while doing a netting is not possible
This would lead to a n-to-n netting event, whereas code assumes netting is n-to-1
If necessary, the split must be done after the netting, in a second and separate event.
*/

{
	//pointer intialization of the object, point the range of payments generated
	pPackage:=This,
	//pointer intialization, point all flows of the range previously set
	pFlows := mx.deliverable.Package.GetFlows( pPackage ),
	// For Deliverable issued by Event on Deliverables
	IF ( isNull( pFlows ) ) THEN
		pFlows := mx.deliverable.event.Event.GetBOs( pPackage ),

    //Split done
    bSplitDone := FALSE,

	//Count the number of flow in the range
	iNbOfFlows := mx.system.collection.GetLength( pFlows ),

	iFlow := iNbOfFlows,
	//Create a new collection
	pSplitFlows := mx.system.collection.New( 1 ),
	// Loop to scan all payment of the range
	WHILE ( iFlow > 0 ) DO
	{
		// Take iFlows-1 because the the first flow begins at 0 
		pFlow := mx.system.collection.GetElementAt( pFlows,iFlow - 1 ),
		bKeepFlow := FALSE,

		// Cash deliverables
		IF (mx.system.object.IsInstanceOf( pFlow,"mx.deliverable.Cash" )) THEN 
		{
			// look for the typology
            pTypology := mx.deliverable.Cash.GetTradeTypology(pFlow),
            sTypology := mx.statics.Typology.GetLabel(pTypology),

			// Look for the currency 
			pCurrency := mx.deliverable.Cash.GetCurrency( pFlow ),
			sCurrency := mx.statics.fx.CurrencyDefinition.GetCurrencyLabel( pCurrency ),
			// look for Beneficiary Party
			pBeneficiaryParty := mx.deliverable.Cash.GetBeneficiaryParty( pFlow ),
			sBeneficiaryParty := mx.statics.organization.Party.GetPartyName( pBeneficiaryParty ),
			// look for Beneficiary Country
			pBeneficiaryCountry := mx.statics.organization.Party.GetCountry( pBeneficiaryParty ),
			sBeneficiaryCountry := mx.statics.organization.CountryDefinition.GetDescription( pBeneficiaryCountry ),
			// look for the Transaction Direction (payment or receive) 
			iSendReceive := mx.deliverable.Cash.GetSendReceive( pFlow ),
			IF ( iSendReceive == 2 ) THEN
				sSendReceive:= "R"
			ELSE
				sSendReceive:= "S",
			// look for Settlement Method
			pSettlementMethod := mx.deliverable.Cash.GetSettlementMethod(pFlow),
			sSettlementMethod := mx.statics.SettlementMethod.GetLabel(pSettlementMethod),

			// Initialisation of thresholds
			fThreshold := 0.0,
			fThreshold2 := 0.0,
			// Get the thresholds from ( "MX.ALL.DlvThreshold","ALL" ) Lookup table
			// according to the typology, currency, beneficiary party, beneficiary country, send receive of the contract
			pResults := lookupResults( "MX.ALL.DlvThreshold","ALL",
									"Deliverable Type","Cash",
									"Typology",sTypology,
                                    "Direction Field",sSendReceive,
                                    "Settlement Method", sSettlementMethod,
									"Currency", sCurrency,
									"Beneficiary Country",sBeneficiaryCountry,									
									"Counterpart",sBeneficiaryParty ),

			// Check if the look up result is not empty and store them if it is the case
			IF ( NOT isNull( pResults ) ) THEN
			{
				fThreshold := lookupResultsGetNumeric( pResults,0,0 ),
				fThreshold2:= lookupResultsGetNumeric( pResults,0,1 ),
				IF    (fThreshold > 0.0)   THEN
				{
					// Get the amout of the first flow
					fAmount:= mx.deliverable.Cash.GetQuantity( pFlow ),
					// If Threshold is reached begin the split
					IF ( fAmount > fThreshold ) THEN
					{
						// Calculate number of split needed
						fNumberOfSplitDeliverables:= round( fAmount / fThreshold2,0 ),
						// Duplicate the pointer to work on it
						pClone1 := mx.deliverable.Cash.NewDuplicate(pFlow),
                        mx.deliverable.Cash.SetProducerReference(pClone1,mx.deliverable.Cash.GetProducerReference(pFlow)),
						//Loop until the total split reach the total amount
						WHILE ( fNumberOfSplitDeliverables > 0.0 ) DO
						{
							// set the amount of the split
							mx.deliverable.Cash.SetQuantity( pClone1,fThreshold2 ),
							// add the split to the collection
							mx.system.collection.AddElement( pSplitFlows,pClone1 ),
							// reevaluate the total split amount with the split previously done
							fNumberOfSplitDeliverables := fNumberOfSplitDeliverables - 1.0,
							// reinitialize the clone
							pClone1 := mx.deliverable.Cash.NewDuplicate(pFlow),
                            mx.deliverable.Cash.SetProducerReference(pClone1,mx.deliverable.Cash.GetProducerReference(pFlow))
						},
						fNumberOfSplitDeliverables:= round( fAmount / fThreshold2,0 ),
						//the last payment is  equal to total amount less the total splits amount
						fRemainingQuantity:=fAmount-fNumberOfSplitDeliverables*fThreshold2,
						IF fRemainingQuantity > 0.0 THEN
						{                
							mx.deliverable.Cash.SetQuantity( pClone1,fRemainingQuantity ),
							// add the split to the collection
							mx.system.collection.AddElement( pSplitFlows,pClone1 )
						},
                        bSplitDone := TRUE
					}
					ELSE
						bKeepFlow := TRUE       
				}
				ELSE  
					bKeepFlow := TRUE          
			}
			ELSE 
				bKeepFlow := TRUE
		}

		// Security deliverables
		ELSE IF (mx.system.object.IsInstanceOf( pFlow,"mx.deliverable.Security" )) THEN 
		{
			// look for the typology
            pTypology := mx.deliverable.Security.GetTradeTypology(pFlow),
            sTypology := mx.statics.Typology.GetLabel(pTypology),
			// look for Beneficiary Party
			pBeneficiaryParty := mx.deliverable.Security.GetBeneficiaryParty( pFlow ),
			sBeneficiaryParty := mx.statics.organization.Party.GetPartyName( pBeneficiaryParty ),
			// look for Beneficiary Country
			pBeneficiaryCountry := mx.statics.organization.Party.GetCountry( pBeneficiaryParty ),
			sBeneficiaryCountry := mx.statics.organization.CountryDefinition.GetDescription( pBeneficiaryCountry ),
			// look for the Transaction Direction (payment or receive) 
			iSendReceive := mx.deliverable.Security.GetSendReceive( pFlow ),
			IF ( iSendReceive == 2 ) THEN
				sSendReceive:= "R"
			ELSE
				sSendReceive:= "S",
			// look for Settlement Method
			pSettlementMethod := mx.deliverable.Security.GetSettlementMethod(pFlow),
			sSettlementMethod := mx.statics.SettlementMethod.GetLabel(pSettlementMethod),

			// Initialisation of thresholds
			fThreshold:= 0,
			fThreshold2:=0,

			// Get the thresholds from ( "MX.ALL.DlvThreshold","ALL" ) Lookup table
			// according to the typology, currency, beneficiary party, beneficiary country, send receive of the contract
			pResults := lookupResults( "MX.ALL.DlvThreshold","ALL",
									"Deliverable Type","Security",
									"Typology",sTypology,
                                    "Direction Field",sSendReceive,
                                    "Settlement Method", sSettlementMethod,
									"Currency", "",
									"Beneficiary Country",sBeneficiaryCountry,									
									"Counterpart",sBeneficiaryParty ),

			// Check if the look up result is not empty and store them if it is the case
			IF NOT isNull( pResults)  THEN 
			{
				fThreshold := lookupResultsGetNumeric( pResults,0,0 ),
				fThreshold2:= lookupResultsGetNumeric( pResults,0,1 ), 
				IF    (fThreshold > 0.0)   THEN
				{
					// Get the amout of the first flow
					fAmount:= mx.deliverable.Security.GetQuantity(pFlow),

					// If Threshold is reached begin the split

					IF    (fAmount > fThreshold)   THEN
					{
						// retrieve linked flows since we need to split them as accordingly
						pLinkedFlows := mx.deliverable.Security.GetLinkedFlows( pFlow ), 
						iNbOfLinkedFlows := mx.system.collection.GetLength(pLinkedFlows),

						fQuantityThreshold := ((fThreshold2 * fAmount) / fAmount),   
						fFactor := fQuantityThreshold / fAmount,
						// Calculate number of split needed
						fNumberOfSplitDeliverables:= round(fAmount / fQuantityThreshold,0),
						// Duplicate the pointer to work on it
						pClone1 :=mx.deliverable.Security.NewDuplicate(pFlow),     
                        mx.deliverable.Security.SetProducerReference(pClone1,mx.deliverable.Security.GetProducerReference(pFlow)),
						mx.system.collection.Zap(mx.deliverable.Security.GetLinkedFlows( pClone1)),

						//Loop until the total split reach the total amount
						WHILE (fNumberOfSplitDeliverables > 0.0) DO
						{
							// set the amount of the  split  
							mx.deliverable.Security.SetQuantity(pClone1,fQuantityThreshold),

							// loop through each linked flow
							iLinkedFlow := 0,
							WHILE ( iLinkedFlow < iNbOfLinkedFlows ) DO
							{
								pLinkedFlow := mx.system.collection.GetElementAt( pLinkedFlows, iLinkedFlow),
								fNewLinkedQuantity := mx.deliverable.Cash.GetQuantity(pLinkedFlow) *  fFactor,

								pCloneLinkedFlow := mx.deliverable.Cash.NewDuplicate(pLinkedFlow),
                                mx.deliverable.Cash.SetProducerReference(pCloneLinkedFlow,mx.deliverable.Cash.GetProducerReference(pLinkedFlow)),
								mx.deliverable.Cash.SetQuantity(pCloneLinkedFlow,  fNewLinkedQuantity),
								mx.system.collection.AddElement(mx.deliverable.Security.GetLinkedFlows( pClone1),pCloneLinkedFlow),
								iLinkedFlow := iLinkedFlow +1
							},

							// add the split to the collection
							mx.system.collection.AddElement(pSplitFlows,pClone1),
							// reevaluate the total split amount with the split previously done
							fNumberOfSplitDeliverables:=fNumberOfSplitDeliverables - 1.0,
							// reinitialize the clone
							pClone1 :=mx.deliverable.Security.NewDuplicate(pFlow),
                            mx.deliverable.Security.SetProducerReference(pClone1,mx.deliverable.Security.GetProducerReference(pFlow)),
							mx.system.collection.Zap(mx.deliverable.Security.GetLinkedFlows( pClone1))
						},
						fNumberOfSplitDeliverables:= round(fAmount / fQuantityThreshold,0),
						//the last payment is  equal to total amount less the total splits amount
						fRemainingQuantity:=fAmount-fNumberOfSplitDeliverables*fQuantityThreshold,               
						IF fRemainingQuantity > 0.0 THEN               
						{
							mx.deliverable.Security.SetQuantity(pClone1,fRemainingQuantity),

							// loop through each linked flow
							iLinkedFlow := 0,
							WHILE ( iLinkedFlow < iNbOfLinkedFlows ) DO
							{
								pLinkedFlow := mx.system.collection.GetElementAt( pLinkedFlows, iLinkedFlow),
								fRemainingLinkedQuantity := mx.deliverable.Cash.GetQuantity(pLinkedFlow) - ((mx.deliverable.Cash.GetQuantity(pLinkedFlow) *  fFactor) * fNumberOfSplitDeliverables),
								pCloneLinkedFlow := mx.deliverable.Cash.NewDuplicate(pLinkedFlow),
                                mx.deliverable.Cash.SetProducerReference(pCloneLinkedFlow,mx.deliverable.Cash.GetProducerReference(pLinkedFlow)),
								mx.deliverable.Cash.SetQuantity(pCloneLinkedFlow,  fRemainingLinkedQuantity),
								mx.system.collection.AddElement(mx.deliverable.Security.GetLinkedFlows( pClone1),pCloneLinkedFlow),
								iLinkedFlow := iLinkedFlow +1
							},

							// add the split to the collection
							mx.system.collection.AddElement(pSplitFlows,pClone1)
						},
                        bSplitDone := TRUE
					}
					ELSE  
						bKeepFlow := TRUE         
				}
				ELSE  
					bKeepFlow := TRUE
			}
			ELSE  
				bKeepFlow := TRUE
		}
		ELSE 	
			bKeepFlow := TRUE,

		IF( bKeepFlow ) THEN 
		{
			// the original list is going to be zapped therefore we should make sure to keep all the flow we need.
            IF (mx.system.object.IsInstanceOf( pFlow,"mx.deliverable.Cash" )) THEN {
                pClone1 :=mx.deliverable.Cash.NewDuplicate(pFlow),
                mx.deliverable.Cash.SetProducerReference(pClone1,mx.deliverable.Cash.GetProducerReference(pFlow))
                }
            ELSE IF (mx.system.object.IsInstanceOf( pFlow,"mx.deliverable.Security" )) THEN {
            	pClone1 :=mx.deliverable.Security.NewDuplicate(pFlow),
                // force the producer reference of clone and of its linked flows
                fProducerReference := mx.deliverable.Security.GetProducerReference(pFlow),
                mx.deliverable.Security.SetProducerReference(pClone1, fProducerReference),
                iLinkedFlow := 0,
				pLinkedFlows := mx.deliverable.Security.GetLinkedFlows( pClone1 ), 
				iNbOfLinkedFlows := mx.system.collection.GetLength(pLinkedFlows),
				WHILE ( iLinkedFlow < iNbOfLinkedFlows ) DO
				{
					pLinkedFlow := mx.system.collection.GetElementAt( pLinkedFlows, iLinkedFlow),
                    mx.deliverable.Cash.SetProducerReference(pLinkedFlow, fProducerReference),
                    iLinkedFlow := iLinkedFlow +1
                 }
                } 
            ELSE { 
            	pClone1 := mx.system.object.Clone(pFlow)
                },
			mx.system.collection.AddElement( pSplitFlows,pClone1 )
		},

		// Next flow
		iFlow:= iFlow - 1
	},

	IF ( bSplitDone ) THEN
    {
    	// Transfer all the flows created in the temporary list
		mx.system.collection.Zap( pFlows ),
		iNbOfFlows := mx.system.collection.GetLength( pSplitFlows ),
		iFlow := 0,
		WHILE (iFlow < iNbOfFlows) DO
		{
			pFlow := mx.system.collection.GetElementAt( pSplitFlows,iFlow ),
			mx.system.collection.AddElement( pFlows,pFlow ),
			iFlow := iFlow + 1
		}
    }
};

// mx.preTrade.completion.CRD.ALL.CollA

/*
MXpress
CRD Specific completion

Version 1.1
Use pre-trade fields "pf_CRD_CCPs_Options" or "pf_CRD_CCPs" to set the pricing counterpart. 
Remove call to LUT ( MX.CRD.CollA,ALL ) since collateral router is available in this version (based on pricing counterpart).

Version 1.0
The purpose of this scripted rule is to set a Collateral Agreement Category
This rule is designed for CRD products, it uses one Look-Up Tables ( LUT ):
( MX.CRD.CollA,ALL ) contains the collateral agreement category from registration, counterparty and one criterion ( undefined )
*/

{
	pLeg := This,
	IF ( legIsInitialized( This ) ) THEN
	{
		// Field Initialization/Reset
		iNbComponents := legGetNumberOfComponents( pLeg ),
		iComponent := 0,
		sRegistration := "",
		sListOfCollateralElligible := "Default swaps$" + 
									 "Credit index$" +
                                     "Credit index option$",
		bCollateralElligible := FALSE,
		sCounterpart := "",
		sCriteria := "",


		WHILE ( iComponent < iNbComponents ) DO
		{
			pComponent := legGetComponentAt( pLeg,iComponent ),
			sRegistration := legGetRegistration( pComponent ),

            IF (sRegistration == "Credit index option") THEN 
            {

            bCollateralElligible := strContain( sListOfCollateralElligible,sRegistration+"$" ),
			IF ( bCollateralElligible ) THEN
			{
				spf_CCPs := legGetString( pComponent,"pf_CRD_CCPs_Options" ),
                sCounterpart := legGetString( pComponent,"Counterpart" ),
				// set the value of sCriteria if needed
				// sCriteria := "",

                IF ( spf_CCPs == "1. CDSClear" ) THEN
                    legOverwrite( pComponent,"Pricing_counterpart", "CDSCLEAR")
                ELSE
                    legOverwrite( pComponent,"Pricing_counterpart", sCounterpart)   
			},
			iComponent := iComponent + 1

            }

            ELSE
            {

                bCollateralElligible := strContain( sListOfCollateralElligible,sRegistration+"$" ),
                IF ( bCollateralElligible ) THEN
                {
                    spf_CCPs := legGetString( pComponent,"pf_CRD_CCPs" ),
                    sCounterpart := legGetString( pComponent,"Counterpart" ),
                    // set the value of sCriteria if needed
                    // sCriteria := "",

                    IF ( spf_CCPs == "1. ICE Clear Credit" ) THEN
                        legOverwrite( pComponent,"Pricing_counterpart", "ICE CLEAR CREDIT")
                    ELSE IF ( spf_CCPs == "2. ICE Clear Europe" ) THEN
                        legOverwrite( pComponent,"Pricing_counterpart", "ICE CLEAR EUROPE")
                    ELSE IF ( spf_CCPs == "3. CDSClear" ) THEN
                        legOverwrite( pComponent,"Pricing_counterpart", "CDSCLEAR")
                    ELSE
                        legOverwrite( pComponent,"Pricing_counterpart", sCounterpart)   
                },
				iComponent := iComponent + 1
			}
        }

	}
};

// mx.preTrade.mirroring.ALL.ALL.Empty

/*
MXpress
Empty rule

Version  1.0
*/

bEmpty := TRUE;

// mx.msl.SiTrn.completion.ALL.Closing.SynchroSSI

/*
MXpress
Users enter Vostro SSI in deal ticket
Then the system should automatically apply the Nostro SSI depending on Settlement mode of Vostro SSI.
Nostro settlement method = Vostro settlement mode
If only Vostro SSI exists, use it
Get the SSIs Grid selected for the trade 

Used algorithm:
Loop on the number of line of the SSI grid
	Loop on the Vostro matching rules 
        	If the matching rule found is the one selected Then
            	Loop on the Nostro Rules
                	If the Vostro Settlement Method is equal to the Nostro settlement method Then
                    	Replace the Nostro selected by the Nostro rule found
                        Else
                        Let the Default Nostro SI
                     End IF
                Next Line
         End If
     Next Line
 Next Line

Version 1.0
Initialization
*/

{
	//Initialize the grid 
	pGridLine := pNull,
	//Initialize the Vostro selected reference
	fVostroSelectedReference := 0.0,
	//Initialize the Nostro selected reference
	fNostroSelectedReference := 0.0,
	//Initialize the list of matching Nostro rules
	pListOfNostroMatchingRules := pNull ,
	//Initialize the list of matching Vostro rules
	pListOfVostroMatchingRules := pNull,
	//Initialize the number of Vostro matching rule
	iNbOfVostroMatchingRules := 0,

	// Get the grid of SSIs selected for the trade
	pSIsGrid := mx.contract.ConfirmationFlows.GetSettlementInstructions( NPD_HDL_THIS ),
	// Get the number of line in this grid 
	iNbLines := settlementInstructionsGetLength( pSIsGrid ),

	//loop on every line of the grid
	iCount :=0 ,
	WHILE ( iCount < iNbLines ) DO
	{
		//Iterate through the grid lines
		pGridLine := settlementInstructionsGetSIAt( pSIsGrid,iCount ),
		// Get the selected Vostro reference
		fVostroSelectedReference := siGetVostroReference( pGridLine ),
		// Get the selected Nostro reference
		fNostroSelectedReference := siGetNostroReference( pGridLine ),
		// Get the list of the Nostro matching rules
		pListOfNostroMatchingRules := siGetNostroMatchingRules( pGridLine ),
		// Get the number of the line of the Nostro matching rules list
		iNbOfNostroMatchingRules := siRulesGetLength( pListOfNostroMatchingRules ),
		// Get the list of the Vostro matching rules
		pListOfVostroMatchingRules := siGetVostroMatchingRules( pGridLine ),
		// Get the number of the line of the Vostro matching rules list
		iNbOfVostroMatchingRules := siRulesGetLength( pListOfVostroMatchingRules ),
		// Initialize Nostro settlement method
		sNostroRuleStlMethod := "",
		// Initialize Vostro settlement method
		sVostroRuleStlMethod := "",
		// Initialize the Nostro candidate
		pSIMaxScore := pNull,
		//Initialize the Vostro rule 
		pSiVostroRule := pNull,

		// loop on the Vostro rules 
		iVostroCount := 0, 
		WHILE ( iVostroCount < iNbOfVostroMatchingRules ) DO
		{
			//Iterate through the Vostro rules 
			pSiVostroRule := siRulesGetRuleAt( pListOfVostroMatchingRules,iVostroCount ),
			// Get the Vostro settlement method
			sVostroRuleStlMethod := siRuleGetSettlementMethod( pSiVostroRule ),

			// Check the selected Vostro ref with the corresponding rules
			IF ( siRuleGetReference( pSiVostroRule ) == fVostroSelectedReference ) THEN 
			{
				// End Vostro loop when the Vostro selected found
				iVostroCount := iNbOfVostroMatchingRules,

				// Initialize the maximum scores
				fMaximumScore := 0.0,
				fDefaultMaximumScore := 0.0,
				// Initialize Nostro rule
				pSiNostroRule := pNull,
				// Initialize the score of the rule
				fScore := 0.0,
				// Initialize the line of the grid for the maximum score 
				iSiMaxScoreRuleNumber := 0,

				// Iterate through all matching Nostro rules
				//  1/ Getting the default Nostro score
				//  2/ Having same settlement method with the maximum score 

				// loop on the Nostro rules 
				iNostroCount := 0,
				WHILE ( iNostroCount < iNbOfNostroMatchingRules ) DO
				{
					//Iterate through the Nostro rules
					pSiNostroRule := siRulesGetRuleAt( pListOfNostroMatchingRules,iNostroCount ),

					// 1/ Get the score without taking into account the settlement method
					fScore := siRuleGetScore( pSiNostroRule ),
					// Get the matching score without the settlement method
					IF ( fScore > fDefaultMaximumScore ) THEN 
					{
						fDefaultMaximumScore := fScore
					},

					// 2/ Get the matching score with the settlement method 
					// Get the settlement method of the rule
					sNostroRuleStlMethod := siRuleGetSettlementMethod( pSiNostroRule ),

					// Check if the Nostro settlement method matches the Vostro Settlement Method 
					IF ( sNostroRuleStlMethod == sVostroRuleStlMethod ) THEN
					{
						IF ( fScore > fMaximumScore ) THEN 
						{
							fMaximumScore := fScore,
							iSiMaxScoreRuleNumber := iNostroCount // the Nostro count candidate   
						}
					},

					// Next line
					iNostroCount := iNostroCount + 1
				},

				// Check if matching Nostro rules having same settlement method and maximum score is found
				IF ( fMaximumScore > 0.0 ) THEN 
				{
					// Check if matching Nostro rules having same settlement method and maximum score is the default one
					IF ( fMaximumScore == fDefaultMaximumScore ) THEN 
					{
						// Set the default Nostro
						siSetDefaultNostro( pGridLine,pSIsGrid )
					}
					ELSE
					{
						// the Nostro candidate
						pSIMaxScore := siRulesGetRuleAt( pListOfNostroMatchingRules,iSiMaxScoreRuleNumber ),
						// Set the customized Nostro SI
						siSetCustomizedNostro( pGridLine,pSIsGrid,pSIMaxScore )
					}
				}
			},
			// Next line
			iVostroCount := iVostroCount + 1
		},
		// Next line
		iCount := iCount + 1
	}
};

// mx.preTrade.completion.FXMM.Booking.CtpAlloc

/*
MXpress
For Simple Cash Flow (SCF) with trade purpose in "Corporate", assign the counterparty with the issuer of the underlying secutity

Version 1.0
*/

{
	pLeg := NPD_HDL_THIS,

	// Fields Initialization
	iComponent := 0,
	iNbComponents := legGetNumberOfComponents( pLeg ),

	WHILE ( iComponent < iNbComponents ) DO
	{
		pComponent := legGetComponentAt( pLeg,iComponent ),
		sTradePurpose := legGetString( pComponent,"Trade_purpose"),
		sRegistration := legGetRegistration( pComponent ),		
		IF ( strContain( sTradePurpose,"Corporate" ) AND ( sRegistration == "Simple cash flow" ) ) THEN
		{
			sPLInstrument := legGetString( pComponent,"Pl_instrument" ),
			pSecurityData := secGetSecurityData( sPLInstrument ),
			sIssuer := securityGetIssuerLabel( pSecurityData ),
			legOverwrite( pComponent,"Counterpart",sIssuer )
		},
		iComponent := iComponent + 1
	}
};

// mx.preTrade.completion.ALL.ALL.Communication

/*
MXpress Communication module handling

Version 1.5
Use sysGetRFQRole rather than sysGetRole (Deprecated)

Version 1.4
Use Tradability status at strategy/structure level if it exists
Block RFQ initiation action buttons in relevant cases

Version 1.3
- Applied MSL best practices
- Replacement of DIST_TTL by pf_RFQ_TTL, DIST_USER1 by pf_RFQ_Requester, DIST_USER2 by pf_RFQ_Provider, DIST_STAT by pf_TradabilityStatus
- Replacement of deprecated legSetMail functions by legSetRFQ functions
- Replacement of SND (sender) by REQ (requester) and RCV (receiver) by PRV (provider)
- Truncate the mail description to 250 characters and manage FX swap description
- Store RFQ ID at Trade level (Step 7)
- Update user/fo parties management done during booking

Version 1.2
Prevent the users to complete an RFQ on a leg which is "Not Tradable", with legSetMailAsBlocked() function

Version 1.1
Truncate the mail description to 80 characters

Version  1.0
Adds an initial checks: The rule is not to be read in the trade ticket
When senders reloads an archive or a Request for quote in a box, pf_RFQ_Provider field is now reset 
	so that the tradability status is not "Confirmed" before validation.

Notes:
	Step 1: Check if the communication is active.
		The status of the communication is stored at the level of the MX.ALL.GParam lookup table. 
		The values is taken from the "Communication" input and can take for value "YES" or "NO"
	Step 2: Depending on the role of the group, fill the pf_RFQ_Requester (for sender) or pf_RFQ_Provider (for receiver) 
		with the name and the group and of the user separated by a '|' character
			In practice, when the sender send the RFQ, pf_RFQ_Requester is filled. Then, when the receiver receives the RFQ, 
			pf_RFQ_Provider is filled.
			Finally, when the receiver gets the answer the RFQ is now a Quote and is considered as confirmed. 
			Additionaly, when a sender loads an archive or a RFQ in a Notepad/Strategy, we need to set the pf_RFQ_Provider value to null 
				otherwise it would lead to an immediately "Confirmed" transaction
			The status change logic is implemented in the mx.preTrade.*.All.ChckMsg rule, where * is the asset class of the RFQ. 
	Step 3: fill the receiver group.
		When the contract is handled by a sender, when sending the RFQ, the system pushes a RFQ Recipient (just as a mailing list).
		The group are defined in a configuration session, under the Compatibility > Distribution > Settings > RFQ Recipients menu.
		This value corresponds to the the RECEIVER_GROUP field in the communication workflow
	Step 4: fill the RFQ description
		the RFQ description is taken from the small description which is stored in the DIST_DESC UDF. 
		This description is initially push by the asset/registration specific description rule.
		This value corresponds to the REQUEST_DESC field in the communication workflow
	Step 5: fill the RFQ Time To Live
		This is the time for which the RFQ will remain available at the level of the sender/receiver group.
		This values is read in the communication workflow to initialize the different timers
	Step 6: set the FO parties accordingly
    Step 7: fill RFQ Id
*/

{
	pLeg := This,
	pFirstComponent := legGetComponentAt( pLeg,0 ),
	bIsInClosingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ),"C_" ),
	/////////////////////////////////////////////////
	/// Step 1: Check if the communication is active.
	///		The status of the communication is stored at the level of the MX.ALL.GParam lookup table. 
	///		The values is taken from the "Communication" input and can take for value "YES" or "NO"
	////////////////////////////////////////////////
	sIsCommunicationActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","Communication" ) ),
	IF ( ( sIsCommunicationActive <> "YES" ) AND ( sIsCommunicationActive <> "NO" ) ) THEN 
		ThrowError( "Error in MX.ALL.GParam","wrong returned value for Key 1 = Communication" ),
    bIsProductRFQCandidate := legIsElementValid( pLeg,"pf_TradabilityStatus" ) OR legIsElementValid( pFirstComponent,"pf_TradabilityStatus" ),

	IF ( legIsInitialized( pLeg ) AND sIsCommunicationActive == "YES" AND bIsProductRFQCandidate ) THEN
	{
		IF ( bIsInClosingSequence ) THEN
		{
			// Prevent the users to complete an RFQ on a leg which is "Not Tradable"
			IF ( legIsElementValid( pLeg,"pf_TradabilityStatus" ) ) THEN
				sTradabilityStatus := legGetString( pLeg,"pf_TradabilityStatus" )
			ELSE
				sTradabilityStatus := legGetString( pFirstComponent,"pf_TradabilityStatus" ),
			bBlockRFQActions := FALSE,
			sBlockRFQActionsMessage := "",
			IF ( sTradabilityStatus == "Not tradable" ) THEN
			{
				bBlockRFQActions := TRUE,
				sBlockRFQActionsMessage := "The transaction is not tradable. RFQ initiation is not allowed." + endline() + "See notification(s) for details"
			},
			legSetRFQAsBlocked( pLeg,bBlockRFQActions ),
			legBlockAction( pLeg,"mail:Send",sBlockRFQActionsMessage,bBlockRFQActions ),
			legBlockAction( pLeg,"mail:direct Send",sBlockRFQActionsMessage,bBlockRFQActions ),

			IF ( properties.Get( "mx.preTrade.preTradeTicketDisplay" ) <> "YES" ) THEN
			{
				sBOSource := properties.Get( "mx.preTrade.BO.source.class" ),
				sEvalActive := properties.Get( "mx.preTrade.evaluation.active" ),
				sAction := properties.Get( "mx.preTrade.action" ),
				sPricingContext := properties.Get( "mx.preTrade.pricing.context" ),

				IF ( ( sBOSource == "" ) AND ( sAction == "INS" ) ) THEN
				{
					sCurrentUser := sysGetUser(),
					sCurrentGroup := sysGetGroup(),
					sCurrentGroupRole := sysGetRFQRole(),//returns the current user RFQ role label

					iComponent := 0,
					iNbComponents := legGetNumberOfComponents( pLeg ),
					// loop on all components and set the user name in udfs
					WHILE ( iComponent < iNbComponents ) DO
					{
						pComponent := legGetComponentAt( pLeg,iComponent ),

						/////////////////////////////////////////////////
						/// Step 2: Depending on the role of the group, fill the pf_RFQ_Requester (for sender) or pf_RFQ_Provider (for receiver) 
						///     with the name and the group of the user separated by a '|' character.
                        ///     Note: the | (pipe) symbol is expected by DD Formula public.distribution.communication.utils.getUserFromUserGroup to populate Requester and Provider in the workflow
						///     In practice, when the requester sends the RFQ, pf_RFQ_Requester is filled. Then, when the provider receives the RFQ, 
						///     pf_RFQ_Provider is filled.
						///     Finally, when the requester gets the answer the RFQ is now a Quote and is considered as confirmed. 
						///     Additionally, when a sender loads an archive or a RFQ in a Notepad/Strategy, we need to set the pf_RFQ_Provider value to null 
						///         otherwise it would lead to an immediately "Confirmed" transaction
						///        The status change logic is implemented in the mx.preTrade.ALL.All.CheckMsg rule
						/////////////////////////////////////////////////

						// If the group role short code is PRV, the user is a Trader and can book without confirmation. 
						// If the group role short code is REQ, the user is a Sales person and needs confirmation from the trader if the sanity check are breaking limits.
						// If the group role short code is RBT, the user is the Pricing robot, used for webbased communication. 
						// If there are no role assigned, the user is assumed to be a Trader.
						IF ( sCurrentGroupRole == "REQUESTER" ) THEN 
						{
							legOverwrite(pComponent,"pf_RFQ_Requester",sCurrentUser + "|" + sCurrentGroup ),

							// Outside the mail context, we need to make sure pf_RFQ_Provider is empty so that reloading 
							//      an Archive or an RFQ that has been previously booked / confirmed 
							//      does not lead to an immediately "Confirmed"  transaction for the Sender.
							IF ( ( sPricingContext <> "MAIL") AND ( sEvalActive == "YES" ) ) THEN
								legOverwrite( pComponent,"pf_RFQ_Provider","" )
						}
						ELSE IF ( sCurrentGroupRole == "PROVIDER" ) THEN
							legOverwrite( pComponent,"pf_RFQ_Provider",sCurrentUser + "|" + sCurrentGroup ),

						iComponent := iComponent + 1
					}
				},

				/*******************  Default Mail Routing rules   ********************/
				// by default, all the mails will be sent to mail group "Providers".
				IF ( ( sAction == "INS" )  AND ( legGetString( pFirstComponent,"pf_RFQ_Provider" ) == "" ) )  THEN 
				{
					/////////////////////////////////////////////////
					/// Step 3: fill the receiver group.
					///     When the contract is handled by a sender, when sending the RFQ, the system pushes a receiver group (just as a mailing list).
					///     The group are defined in a configuration session, under the Compatibility > Distribution > Settings > Distribution Groups menu.
					/////////////////////////////////////////////////
					// legSetRFQRecipient( pLeg,"Providers" ),
					// RFQ 
                    // BAB RFQ addition                     
                     sPattern := legGetPatternLabel(pLeg),
                     sRegistration := legGetRegistration(pLeg),
                     IF sRegistration == "FX swap" THEN
                        sTypology := "FX Swap"
                    ELSE IF sPattern == "Depo CapFloorCollar" THEN
                        sTypology := legGetString(pLeg,"Typology")
                     ELSE
                        sTypology := legGetTypology(pLeg),

                    IF sTypology == "Split Time Opt" OR sTypology == "Split Spot" OR sTypology == "Split Outright" OR sTypology == "Spot" OR sTypology == "FX Waad" OR sTypology == "Split FX Swap" OR sTypology == "FX Murabaha" OR sTypology == "Time Option" OR sTypology == "FX Swap" OR sTypology == "Banknotes" OR sTypology == "Banknotes Credit"   THEN
                    legSetRFQRecipient( pLeg,"PROVIDERS_FX" )
                    ELSE IF sTypology == "Sukuk" THEN
                    legSetRFQRecipient( pLeg,"PROVIDERS_INV" )
                    ELSE IF sTypology == "Wakala Borrowing" OR sTypology == "Murabaha Borrowing" OR sTypology == "Depo CapFloorCollar"  OR sTypology == "CD Issuance" THEN
                    legSetRFQRecipient(pLeg,"PROVIDERS_MM"),

                   //BAB addition: RFQ eligibility check
					pResult := lookupResults( "BAB.ALL.RFQEligibility","ALL","Registration",sRegistration,"Typology",sTypology),
                    sRFQIsEligible := lookupResultsGetString(pResult,0,0),

                    IF NOT bBlockRFQActions THEN  //If Deal is "Tradable", RFQ is not blocked by default
                    {

                        IF 	sRFQIsEligible <> "Yes" THEN
                            legBlockAction(pLeg,"mail:direct Send","This product is not eligible for RFQ",TRUE)
                        ELSE 
                            legBlockAction(pLeg,"mail:direct Send","This product is not eligible for RFQ",FALSE)
                    },           
                     //BAB: End of RFQ eligibility check



					/////////////////////////////////////////////////
					/// Step 4: fill the RFQ description
					///     the RFQ description is taken from the small description which is stored in the DIST_DESC UDF. 
					///     This description is initially push by the asset/registration specific description rule.
					///     This value corresponds to the REQUEST_DESC field in the communication workflow
					///     FX Swap case: aggregate near and far leg individual descriptions
					/////////////////////////////////////////////////
					IF ( legGetRegistration( pLeg ) <> "FX swap" ) THEN
						legSetRFQDescription( pLeg, strSubString( legGetString( pFirstComponent,"DIST_DESC" ),0,250 ) )
					ELSE
					{
						sDesc := strSubString( legGetString( pFirstComponent,"DIST_DESC" ),0,124 ) + ", ",
						sDesc := sDesc + strSubString( legGetString( legGetComponentAt(pLeg, 1),"DIST_DESC" ),0,124 ),
						legSetRFQDescription( pLeg, sDesc)
					}
				},

				/////////////////////////////////////////////////
				/// Step 5: fill the RFQ Time To Live
				///     This is the time for which the RFQ will remain available at the level of the sender/receiver group
				///     This values is read in the communication workflow to initialize the different timers
				/////////////////////////////////////////////////
				pFirstContract := legGetContractAt( pLeg,0 ),
				IF ( legIsElementValid( pFirstContract,"pf_RFQ_TTL") ) THEN
					legSetNumeric( pFirstContract,"pf_RFQ_TTL",1800.0 )
			}
		},

		/////////////////////////////////////////////////
		/// Step 6: Set the FO parties to keep tracks of pf_RFQ_Requester and pf_RFQ_Provider for audit
		/// For each contract of the transaction, store the group name and user name of the RFQ requester and of the provider in the front office parties.
		/// For RFQ booked by Robot, replace the robot user by the Receiver user at Trade level
		/////////////////////////////////////////////////
		iContract := 0,
		iNbContracts := legGetNumberOfContracts( pLeg ),
		WHILE ( iContract < iNbContracts ) DO
		{
			pContract := legGetContractAt( pLeg,iContract ),
			pFirstComponent := legGetComponentAt( pLeg,0 ),
			iCurrentContractNbComponents := legGetNumberOfComponents( pContract ),
			sRequester := legGetString( pFirstComponent,"pf_RFQ_Requester" ),
			sProvider := legGetString( pFirstComponent,"pf_RFQ_Provider" ),
			IF ( sRequester <> "" ) THEN
			{
				sRequesterUser := strToken( sRequester,"|",0 ),
				sRequesterGroup := strToken( sRequester,"|",1 ),
				legSetFOPPartyGroup( pContract,"REQ",sRequesterGroup ),
				legSetFOPPartyUser( pContract,"REQ",sRequesterUser )
			},
			IF ( sProvider <> "" ) THEN
			{
				sProviderUser := strToken( sProvider,"|",0 ),
				sProviderGroup := strToken( sProvider,"|",1 ),
				legSetFOPPartyGroup( pContract,"PRV",sProviderGroup ),
				legSetFOPPartyUser( pContract,"PRV",sProviderUser )
			},
			IF ( sysGetRFQRole() == "ROBOT" ) THEN
			{
				legSetFOPPartyGroup( pContract,"RBT",sysGetGroup( ) ),
				legSetFOPPartyUser( pContract,"RBT",sysGetUser( ) ),
				IF ( sProvider <> "" ) THEN
				{
					sProviderUser := strToken( sProvider,"|",0 ),
					iCurrentContractComponent := 0,
					WHILE ( iCurrentContractComponent < iCurrentContractNbComponents ) DO
					{
						legOverwrite( legGetComponentAt( pContract,iCurrentContractComponent ),"Source trader",sProviderUser ),
						iCurrentContractComponent := iCurrentContractComponent + 1
					}
				}
			},
			iContract := iContract + 1
		},

		///////////////////////////////////////////////
		// Step 7: Store RFQ_ID at Trade level - If UDF exists
		///////////////////////////////////////////////
		fRFQId := legGetRFQId( pLeg ),
		IF ( fRFQId > 0.0 ) THEN
		{
			iComponent := 0,
			iNumComponents := legGetNumberOfComponents( pLeg ),
			WHILE ( iComponent < iNumComponents ) DO
			{
				pComponent := legGetComponentAt( pLeg,iComponent ),
				IF ( legIsElementValid( pComponent,"RFQ_ID" ) ) THEN
					legOverwrite(pComponent, "RFQ_ID", fRFQId),
				iComponent := iComponent + 1
			}
		}

	}
	ELSE IF ( ( sIsCommunicationActive <> "YES" ) AND ( bIsInClosingSequence ) ) THEN
	{
		legBlockAction( pLeg,"mail:Send","RFQ feature is not enabled",TRUE ),
		legBlockAction( pLeg,"mail:direct Send","RFQ feature is not enabled",TRUE )
	},
    //BAB RFQ addition 
        //Storing the value of the fields

        	//For PROVIDER
            IF sysGetRFQRole() == "PROVIDER" AND properties.Get("mx.preTrade.evaluation.active") == "YES" AND properties.Get("mx.preTrade.pricing.context") == "MAIL" THEN
            {
            	IF legGetRegistration(pLeg) == "Spot-Forward" THEN
                {	
                	fPrice := legGetNumeric(pComponent,"Forward"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice",fPrice)                                                          
                }
               ELSE IF legGetRegistration(pLeg) == "Split Package" THEN
                {	

                	fPrice := legGetNumeric(pFirstComponent,"Forward"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice",fPrice)                                                          
                }
			   ELSE IF legGetRegistration(pLeg) == "Bonds" THEN
                {	

                	fPrice := legGetNumeric(pComponent,"Settlement_price"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice",fPrice)                                                          
                }
			   ELSE IF legGetRegistration(pLeg) == "Loans/Deposits" THEN
                {	

                	fPrice := legGetNumeric(pComponent,"Rate_Margin"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice",fPrice)                                                          
                }

                ELSE IF legGetRegistration(pLeg) == "FX swap" THEN
                {	
                	pFirstComponent := legGetComponentAt(pLeg,0),
                    pSecondComponent := legGetComponentAt(pLeg,1),

                	fPricenear := legGetNumeric(pFirstComponent,"Forward"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice_Near",fPricenear), 

                    fPricefar := legGetNumeric(pSecondComponent,"Forward"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice_Far",fPricefar)
                }

               ELSE IF legGetRegistration(pLeg) == "Split Forex Swap Package" THEN
                {	
                	pFirstComponent := legGetComponentAt(pLeg,0),                    
                    pFourthComponent := legGetComponentAt(pLeg,3),                                  
                	fPricenear := legGetNumeric(pFirstComponent,"Forward"),            
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice_Near",fPricenear), 

                    fPricefar := legGetNumeric(pFourthComponent,"Forward"),
                	legOverwrite(pComponent,"pf_RFQ_TraderPrice_Far",fPricefar)
				}



            }

	  //End of BAB RFQ addition


};

// mx.preTrade.completion.ALL.Booking.DirectMethod

/*
MXpress

Version  1.0
The goal of this rule is to check whether or not the deal can be inserted by the current group after a direct modification on the trade 
It will issue an error message if the sanity check is activated and the transaction is not sane.

	Step 1: checks the current statuses for the sanity check clauses in the MX.ALL.GParam lookup table.
		SanityCheckMandatory.DirectMod : Assess whether or not the sanity check are activated.
			When set to YES, the sanity check will prevent the deal from being booked.
			When set to NO, the sanity check will be only indicative
	Step 2: The rule will check if the direct modification on the trade is done by the same group which booked it. If the group is different
        an error message will be throwed.
*/

{
	IF ( legIsInitialized( NPD_HDL_THIS ) ) THEN
	{   
        /////////////////////////////////////////////////
		/// Step 1: checks the current statuses for the sanity clauses in the MX.ALL.GParam lookup table.
		///     SanityCheckMandatory.DirectMod : Assess whether or not the sanity check are activated. 
		///     	When set to YES, the sanity check will prevent the deal from being booked.
		///         When set to NO, the sanity check will be only indicative
		////////////////////////////////////////////////
		sIsSanityCheckMandatory := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","SanityCheckMandatory.DirectMod" ) ),
		IF ( ( sIsSanityCheckMandatory <> "YES" ) AND ( sIsSanityCheckMandatory <> "NO" ) ) THEN 
			ThrowError( "Error", "Value in lookup table MX.ALL.GParam should be YES or NO for SanityCheckMandatory.DirectMod" ),

		/////////////////////////////////////////////////
		/// Step 2 : checks if the direct modification on the trade is done by the same group which booked it. 
		///     If the group is different a message will be throwed depending on the sanity check value (error or warning).
		/////////////////////////////////////////////////
		pMainComponent := legGetMainComponent( NPD_HDL_THIS ),
		sClass := properties.Get( "mx.preTrade.BO.source.class" ),
		sAction := properties.Get( "mx.preTrade.action" ),
		sGroup := sysGetGroup(),
		sInitGroup := legGetFOPInitiatorGroup(pMainComponent),        
		IF ( ( sClass == "" ) AND ( sAction == "MOD" ) AND ( sGroup <> sInitGroup ) ) THEN
		{
			IF ( sIsSanityCheckMandatory == "YES" ) THEN
				ThrowError( "Could not perform the modification", "Group not allowed to do a direct modification. It should be done with " + sInitGroup + " group" )
			ELSE
				ThrowWarning( "Warning", "Direct Modification on this trade should be done by using " + sInitGroup + " group" )
		}
	}
};

{
pSec:=This,



sLabel:=mx.statics.securities.SecurityHeader.GetLabel(pSec),

sType := mx.statics.securities.SecurityHeader.GetSecurityGroup(pSec),

sDisplayLabel:= mx.statics.securities.SecurityHeader.GetDisplayLabel(pSec),

pSecUDF:=mx.statics.securities.SecurityHeader.GetUDF(pSec) ,

IF sType == "Equity" THEN
{

sInvestType:=udfGetString(pSecUDF,"INV_TYPE"),
sIssuer :=mx.statics.securities.SecurityHeader.GetIssuer(pSec),

IF sInvestType == "" THEN
{
ThrowError("Error","Missing Investement Type field in the user definable fields of the security.")
},

IF sIssuer == "" THEN
{
ThrowError("Error","Missing Issuer field in the Equity properties of the security.")
},



pEquityProductCode := lookupResults("BAB.ALL.EquityProductCode","ALL","Investement Type",sInvestType),

   IF ( NOT isNull( pEquityProductCode ) ) THEN
       {
       sEqProductCode := lookupResultsGetString( pEquityProductCode,0,0),
       udfOverwriteString(pSecUDF,"EQ_CODE",sEqProductCode)    
       }
       ELSE //Keep empty
       {
       udfOverwriteString(pSecUDF,"EQ_CODE","")
       }
            // end of brk2 code


},
IF sType == "Bond" THEN
{
sSukukType := mx.statics.securities.SecurityHeader.GetValueLabelForProperty(pSec,"Sukuk"),
sCouponType := mx.statics.securities.SecurityHeader.GetValueLabelForProperty(pSec,"Coupon"),
sIssuer :=mx.statics.securities.SecurityHeader.GetIssuer(pSec),
sSukukFund := mx.statics.securities.SecurityHeader.GetValueLabelForProperty(pSec,"Sukuk Fund"),

IF sSukukType == "" THEN
{
ThrowError("Error","Missing Sukuk Type field in the bond properties of the security.")
},

IF sCouponType == "" THEN
{
ThrowError("Error","Missing Coupon Type field in the bond properties of the security.")
},

IF sIssuer == "" THEN
{
ThrowError("Error","Missing Issuer field in the bond properties of the security.")
}, 

IF sSukukFund == "" THEN
{
ThrowError("Error","Missing Sukuk Fund field in the bond properties of the security.")
},



pBondProductCode := lookupResults("BAB.ALL.BondProductCode","ALL","Sukuk",sSukukType,"Coupon",sCouponType,"Issuer",sIssuer,"Sukuk Fund",sSukukFund),

   IF ( NOT isNull( pBondProductCode ) ) THEN
       {
       sBdProductCode := lookupResultsGetString( pBondProductCode,0,0),
       udfOverwriteString(pSecUDF,"BOND_CODE",sBdProductCode)    
       }
       ELSE //Keep empty
       {
       udfOverwriteString(pSecUDF,"BOND_CODE","")
       }
            // end of brk2 code


}
};

