    sSourceClass:= properties.Get(pComponent,"mx.preTrade.BO.source.class"),
	properties.Get(pComponent,"mx.preTrade.BO.source"),
	properties.Get(pComponent,"mx.preTrade.BO.class"),
	properties.Get(pComponent,"mx.preTrade.action"),
		iFlow := 0,
		iNbFlows := mx.system.collection.GetLength( pFlows ),
		WHILE ( iFlow < iNbFlows ) DO
		{
			pFlow := mx.system.collection.GetElementAt( pFlows,iFlow ),

    pFather := legGetFatherContract (pComponent),



    fLogicalPackageID := legGetLogicalPackageId(pFather),
    mx.deliverable.Cash.SetLogicalPackageID(pFlow,fLogicalPackageID),


 //Offsetting event handling   

IF ((sSourceClass ==  "mxContractEventFxIEARLY_TAKEUP_OFFSETTING") OR (sSourceClass == "mxContractEventFxIEXTENSION_OFFSETTING")) 
THEN
{
     fContractRootID:=legGetContractCreatorOriginReference(pFather),
    mx.deliverable.Cash.SetRootContractID(pFlow,fContractRootID)
    }
    ELSE 
    {
     mx.deliverable.Cash.SetRootContractID(pFlow,fContractID)
    },


    iFlow := iFlow + 1
		}
        };

 {

	pPackage := This,
