    sProducerClassId := mx.deliverable.Cash.GetProducerClassId(pCashFlow),
    sProdClassLabel := mx.deliverable.Cash.GetFunctionalProducerDctClassLabel(pCashFlow),
    fProdRef := mx.deliverable.Cash.GetFunctionalProducerReference(pCashFlow), 

    //Added below in case of bond issuance
    IF NOT(isNull(pSecFlow))
    THEN
    {
    	sProducerClassId := mx.deliverable.Security.GetProducerClassId(pSecFlow),
    	sProdClassLabel := mx.deliverable.Security.GetFunctionalProducerDctClassLabel(pSecFlow),
    	fProdRef := mx.deliverable.Security.GetFunctionalProducerReference(pSecFlow)
        },


   	iFlow := 0,
	iNbFlows := mx.system.collection.GetLength( pFlows ),


   //Check if deliverable is generated from a corporate action 

   s_CONTRACT_TYPES:="McVJg51253/1.394/1.238/1.526/MSqHl39229/MbIDt59176/",

		WHILE ( iFlow < iNbFlows ) DO
        {  		
     	    pFlow :=  mx.system.collection.GetElementAt(pFlows, iFlow),
            bCash := mx.system.object.IsInstanceOf(pFlow,"mx.deliverable.Cash"),
    		bSec := mx.system.object.IsInstanceOf( pFlow,"mx.deliverable.Security" ),

            IF bCash
            THEN
            {
           		pCashFlow := mx.system.collection.GetElementAt( pFlows,iFlow ),
				sProducerClassId := mx.deliverable.Cash.GetProducerClassId(pCashFlow),
				sProdClassLabel := mx.deliverable.Cash.GetFunctionalProducerDctClassLabel(pCashFlow),
				fProdRef := mx.deliverable.Cash.GetFunctionalProducerReference(pCashFlow)
            }
            ELSE
            {
            	pSecFlow := mx.system.collection.GetElementAt( pFlows,iFlow ),
            	sProducerClassId := mx.deliverable.Security.GetProducerClassId(pSecFlow),
				sProdClassLabel := mx.deliverable.Security.GetFunctionalProducerDctClassLabel(pSecFlow),
				fProdRef := mx.deliverable.Security.GetFunctionalProducerReference(pSecFlow)
                },

            // If the producer is not a contract, we assume it is a CA
			IF NOT strCONTAIN(s_CONTRACT_TYPES, sProducerClassId +"/") THEN 
            {
            	bIsCAExecution:= (sProducerClassId == "MbLCx52750"), //corporate action execution
                IF bIsCAExecution THEN
                {

                 IF (sProdClassLabel == "Coupon payment" OR sProdClassLabel == "Partial redemption" OR sProdClassLabel == "Final redemption") THEN
                            { 
                            sSecurityType := "Bond",
                            sCA := "Bond CA"
                            }
                  ELSE IF (sProdClassLabel == "Cash dividend" OR sProdClassLabel == "Bonus issue" OR sProdClassLabel == "Stock dividend" OR sProdClassLabel == "Split" OR sProdClassLabel == "Reverse split" OR sProdClassLabel == "Spin-off" OR sProdClassLabel == "Right exercise" OR sProdClassLabel == "Right distribution" OR sProdClassLabel == "Merger" OR sProdClassLabel == "Exchange offer" OR sProdClassLabel == "Dividend reinvestment") THEN
                   { 
                            sSecurityType := "Equity",
                            sCA := "Equity CA"
                            },

                 // Block for Cash Deliverables
                    IF bCash
                    THEN
                    {     
                            IF (sCA == "Bond CA" OR sCA == "Equity CA") THEN
                            {
                                pLegalEntity := mx.deliverable.Cash.GetBeneficiaryParty(pCashFlow),
                                mx.deliverable.Security.SetLegalEntity(pSecFlow,pLegalEntity),

                                 //Set Portfolio, Accounting Entity, Closing Entity

                                pAccount :=  mx.deliverable.Cash.GetOriginatingAccount(pCashFlow),
                                sAccountLabel :=  mx.account.Depot.GetLabel(pAccount),



                                pResults := lookupResults( "BAB.ALL.CA.PortfolioAssignment","ALL", "Bond Label"), // JA Add security type

                                IF ( NOT isNull( pResults ) ) THEN
                                {
                                    sPortfolio := lookupResultsGetString( pResults,0,0)
                            //       sClosingEntity := lookupResultsGetString( pResults,0,1)
                                },

                                //hardcoding portfolio name
                                sPortfolio := "INV_EQ_ETF",
                                pPortfolio := mx.system.object.PushByLabel("mx.statics.organization.Portfolio",sPortfolio),
                                mx.deliverable.Cash.SetPortfolio(pCashFlow, pPortfolio),
                                pEntity := mx.statics.organization.Portfolio.GetClosingEntity(pPortfolio),



                      //          pEntity := mx.system.object.PushByLabel("mx.statics.organization.Entity",sClosingEntity),
                                mx.deliverable.Cash.SetEntity(pCashFlow,pEntity)

                                //End Set Closing Entity, Portfolio 

                             }
          			//End block for Cash Deliverables

                   }

                  ELSE
                    { 

                       IF (sCA == "Bond CA" OR sCA == "Equity CA") THEN
                            {
                                 pLegalEntity := mx.deliverable.Security.GetBeneficiaryParty(pSecFlow),
                                 mx.deliverable.Security.SetLegalEntity(pSecFlow,pLegalEntity),

                                  //Set Portfolio, Accounting Entity, Closing Entity

                                  pAccount :=  mx.deliverable.Security.GetOriginatingAccount(pSecFlow),
                                  sAccountLabel :=  mx.account.Depot.GetLabel(pAccount),



                                  pResults := lookupResults( "BAB.ALL.CA.PortfolioAssignment","ALL", "Bond Label"),

                                   IF ( NOT isNull( pResults ) ) THEN
                                            {
                                                sPortfolio := lookupResultsGetString( pResults,0,0)
                                           //     sClosingEntity := lookupResultsGetString( pResults,0,1)
                                            },

                                               //hardcoding portfolio name
                                sPortfolio := "INV_SUK_LCY_AFS",

                                    pPortfolio := mx.system.object.PushByLabel("mx.statics.organization.Portfolio",sPortfolio),
                                    mx.deliverable.Security.SetPortfolio(pSecFlow, pPortfolio),
                                    pEntity := mx.statics.organization.Portfolio.GetClosingEntity(pPortfolio),

                             //       pEntity := mx.system.object.PushByLabel("mx.statics.organization.Entity",sClosingEntity),
                                    mx.deliverable.Security.SetEntity(pSecFlow,pEntity)

                                  //End Set Closing Entity, Portfolio 

                     }


                    }

                  }


               },
           iFlow := iFlow + 1

          }
  };

// mx.completion.FXMM.Closing.XTP_Threshold

/* MXpress

v1.0
The rule below performs threshold check for a certain scope of source modules.
If amount < decimal precision or amount < threshold defined in LookUp table then the leg will be excluded.
*/
{
	pLeg := This,
	sSourceModule := legGetSourceModule( legGetFatherContract( legGetMainComponent( pLeg ) ) ),

	IF ( ( sSourceModule == "mx.rollover" )
	OR ( sSourceModule == "mx.prefunding" ) ) THEN
	{
		iNbComponents := legGetNumberOfComponents( pLeg ),
		iComponent := 0,
		WHILE ( iComponent < iNbComponents ) DO
		{
			pComponent := legGetComponentAt( pLeg,iComponent ),
			sFamily := legGetProductFamily( pComponent ),
			IF ( sFamily == "CURR" ) THEN
			{
				sDenominator := legGetString( pComponent,"Den unit" ),
				fPrecisionDen := fxCurrencyGetPrecision( sDenominator ),
				fPositionThresholdDen := lookupNumeric( "MX.FXMM.XTP.Threshold","ALL","Currency",sDenominator,"Source Module",sSourceModule ),

				sNumenator := legGetString( pComponent,"Num unit" ),
				fPrecisionNum := fxCurrencyGetPrecision( sNumenator ),
				fPositionThresholdNum := lookupNumeric( "MX.FXMM.XTP.Threshold","ALL","Currency",sNumenator,"Source Module",sSourceModule ),

				fPositionDen := legGetNumeric( pComponent,"Den nominal" ),
				fPositionNum := legGetNumeric( pComponent,"Num nominal" ),
                IF ( fPositionDen > 0.0 AND fPositionNum > 0.0
				AND ( ( ( fPositionThresholdNum > 0.0) AND( fPositionThresholdNum > fPositionNum ) ) OR ( fPositionNum < fPrecisionNum ) )
				AND ( ( ( fPositionThresholdDen > 0.0 ) AND( fPositionThresholdDen > fPositionDen ) ) OR ( fPositionDen < fPrecisionDen ) ) ) THEN
				{
					legOverwrite( pLeg,"Exclude_leg","Yes" ),
					iComponent := iNbComponents
				}
				ELSE
				{
					legOverwrite( pComponent,"Exclude_leg","No" )
				}
			}
			ELSE
			{
				IF ( sFamily == "SCF" ) THEN
				{
					sPositionCur := legGetString( pComponent,"Instrument" ),
					fPosition := legGetNumeric( pComponent,"Nominal" )
				},

				IF ( sFamily == "IRD" ) THEN
				{
					sPositionCur := legGetString( pComponent,"Nominal_unit" ),
					fPosition := legGetNumeric( pComponent,"Nominal" )
				},

				fPositionThreshold := lookupNumeric( "MX.FXMM.XTP.Threshold","ALL","Currency",sPositionCur,"Source Module",sSourceModule ),

				fPrecision := fxCurrencyGetPrecision( sPositionCur ),
                IF ( ( fPosition > 0.0 )
				    AND ( ( ( fPositionThreshold > 0.0 ) AND( fPositionThreshold > fPosition ) ) OR ( fPosition < fPrecision ) ) ) THEN
				{
					legOverwrite( pLeg,"Exclude_leg","Yes" ),
					iComponent := iNbComponents
				}
				ELSE
				{
					legOverwrite( pComponent,"Exclude_leg","No" )
				}
			},
			iComponent := iComponent + 1
		}
	}
};

// mx.preTrade.completion.FXD.Booking.SalesMg-Settlement

/*
MXpress
FXD Sales Margin and Settlement Booking

Version 1.5
Add FXD Settlement Split for Strategies at booking
Rename the rule SalesMg-Settlement. It was SalesMg-Book beforehand

Version 1.4
Applied MSL best practices

Version 1.3
Use pf_Sales_margin_Book and pf_Sales_margin_amt_Book instead of LCL_MARGIN, MARGN_AMNT, MARGN_RATE UDFs

Version 1.2
Use the legGetRegistration function instead the ( MX.ALL.FCCLabel,ALL ) LUT

Version 1.1
Applied MXpress scripted-rules conventions

Version 1.0

Notes: Sales margin rule
	- Sales margin is copied from the pre-trade field into the Sales_margin field for booking
	- The Flat_settlement customization is kept if any.
*/

{
	//Fields initialization/Reset
	pLeg := This,
	sBOSource := properties.Get( "mx.preTrade.BO.source.class" ),
	sAction := properties.Get( "mx.preTrade.action" ),
	iCount := 0,
	iNbLegs := 0,
	sFamily := "",
	sGroup := "",
	sRegistration := "",
	fMargin := 0.0,
	fMarginAmt := 0.0,
	fFlatSettl := 0.0,

	IF ( ( sBOSource == "" ) AND ( sAction == "INS" ) ) THEN 
	{
		iCount := 0, 
		iNbLegs := legGetNumberOfComponents( pLeg ), 
		// Loop on the FCC independently from the structure of "This" 
		WHILE ( iCount < iNbLegs ) DO
		{
			pComponent := legGetComponentAt( pLeg,iCount ),
			sFamily := legGetProductFamily( pComponent ),
			sGroup := legGetProductGroup( pComponent ),
			sRegistration := legGetRegistration( pComponent ),
			IF ( ( sFamily == "CURR" ) AND ( sGroup == "OPT" ) ) THEN 
			{
				// get the sales margin information from UDFs. These values are stored in closing sequence
				fMargin := legGetNumeric( pComponent,"pf_Sales_margin_Book" ),
				fMarginAmt := legGetNumeric( pComponent,"pf_Sales_margin_amt_Book" ),

				// If total sales margin amout is zero, no need to handle the margin
				IF ( fMarginAmt > 0.0 ) THEN
				{ 
					//Get the Flat settlement, it's because of a bug that the flat settlement will be modified when the sales margin is reset
					fFlatSettl := legGetNumeric( pComponent,"Flat_settlement" ),

					//reinject the margin to native fields
					legOverwrite( pComponent,"Sales_margin",fMargin ),
					legOverwrite( pComponent,"Sales_margin_amt",fMarginAmt ),
					// Rest the "Sales margin custom" to zero for FX Simple Option
					IF ( sRegistration == "Simple Option" ) THEN
					{
						legOverwrite( pComponent,"Sales_margin_custom",0.0 ),
						legOverwrite( pComponent,"Sales_margin_custom_amt",0.0 )
					},
					//put back the flat settlement
					legOverwrite( pComponent,"Flat_settlement",fFlatSettl )
				}
			},
			iCount := iCount + 1
		},

		iCount := 0, 
		iNbLegs := legGetNumberOfComponents( pLeg ),
		sFIRSTLEG := "On first leg",
		sFIRSTLEGDIR := "On first direction leg",
		sEVEN := "Even",
		// pf_SettlementSplitFXD considered at top overal structure level - pf_SettlementSplitFXD is not expected and should not be setup at component level 
		IF ( legIsElementValid( pLeg,"pf_SettlementSplitFXD" ) ) THEN
		{
			sSplit := legGetString( pLeg,"pf_SettlementSplitFXD" )
		},
		IF ( ( sSplit == sFIRSTLEG ) OR ( sSplit == sFIRSTLEGDIR ) OR ( sSplit == sEVEN ) ) THEN
		{
			bChangeSplit := TRUE,
			fTotalPremiumFXD := 0.0,
			sPremiumCurrency := "",
			dPremiumDate :=  toDate(""),
			fNbLegsFXD := 0.0,
			WHILE ( iCount < iNbLegs AND bChangeSplit) DO
			{
				pComponent := legGetComponentAt( pLeg,iCount ),
				sFamily := legGetProductFamily( pComponent ),
				sGroup := legGetProductGroup( pComponent ),
				sRegistration := legGetRegistration( pComponent ),
				IF ( ( sFamily == "CURR" ) AND ( sGroup == "OPT" ) ) THEN
				{
					fLegPremium := legGetNumeric( pComponent,"Flat_settlement" ),
					sLegPremiumCurrency := legGetString( pComponent,"Flat_settl_unit" ),
					dLegPremiumDate := legGetDate( pComponent,"Settl flow date" ),
					IF ( sLegPremiumCurrency <> sPremiumCurrency ) THEN
					{
						IF ( sPremiumCurrency == "" ) THEN
							sPremiumCurrency := sLegPremiumCurrency // Initialise the Premium currency if still empty
						ELSE
							bChangeSplit := FALSE // Stop the Aggregation if not all premium currencies are identical
					},
					IF ( dLegPremiumDate <> dPremiumDate ) THEN
					{
						IF ( dPremiumDate == toDate("") ) THEN
							dPremiumDate := dLegPremiumDate // Initialise the Premium date if still empty
						ELSE
							bChangeSplit := FALSE // Stop the Aggregation if not all premium dates are identical
					},
					fTotalPremiumFXD := fTotalPremiumFXD + fLegPremium,
					fNbLegsFXD := fNbLegsFXD + 1.0
				},
				iCount := iCount + 1
			},
			IF ( bChangeSplit ) THEN
			{
				iCount := 0, 
				bDoneApplyingPremiumOnFirstLeg := FALSE,
				IF ( fTotalPremiumFXD == 0.0 ) THEN
					bDoneApplyingPremiumOnFirstLeg := TRUE,
				WHILE ( iCount < iNbLegs ) DO
				{
					pComponent := legGetComponentAt( pLeg,iCount ),
					sFamily := legGetProductFamily( pComponent ),
					sGroup := legGetProductGroup( pComponent ),
					sRegistration := legGetRegistration( pComponent ),
					IF ( ( sFamily == "CURR" ) AND ( sGroup == "OPT" ) ) THEN
					{
						IF ( sSplit == sFIRSTLEG ) THEN
						{
							IF ( NOT ( bDoneApplyingPremiumOnFirstLeg ) ) THEN
							{
								legOverwrite( pComponent,"Flat_settlement",fTotalPremiumFXD ),
								bDoneApplyingPremiumOnFirstLeg := TRUE
							}
							ELSE
								legOverwrite( pComponent,"Flat_settlement",0.0 )
						}
						ELSE IF ( sSplit == sFIRSTLEGDIR ) THEN
						{
							IF ( NOT ( bDoneApplyingPremiumOnFirstLeg ) ) THEN
							{
								IF ( ( legGetString( pComponent,"Buy/Sell" ) == "Buy" ) AND ( fTotalPremiumFXD > 0.0 ) ) THEN
								{
									legOverwrite( pComponent,"Flat_settlement",fTotalPremiumFXD ),
									bDoneApplyingPremiumOnFirstLeg := TRUE
								}
								ELSE IF ( ( legGetString( pComponent,"Buy/Sell" ) == "Sell" ) AND ( fTotalPremiumFXD < 0.0 ) ) THEN
								{
									legOverwrite( pComponent,"Flat_settlement",fTotalPremiumFXD ),
									bDoneApplyingPremiumOnFirstLeg := TRUE
								}
								ELSE
									legOverwrite( pComponent,"Flat_settlement",0.0 )
							}
							ELSE
								legOverwrite( pComponent,"Flat_settlement",0.0 )
						}
						ELSE IF ( sSplit == sEVEN ) THEN
						{
							legOverwrite( pComponent,"Flat_settlement",fTotalPremiumFXD / fNbLegsFXD )
						}
					},
					iCount := iCount + 1
				}
			}
		},

		// Round Flat settlement to the expected number of decimals
		iCount := 0,
		iNbLegs := legGetNumberOfComponents( pLeg ),
		WHILE ( iCount < iNbLegs ) DO
		{
			pComponent := legGetComponentAt( pLeg,iCount ),
			// log() is used to retrieve the number of decimals from the amount currency setting
			iNumberOfDecimals := - toInt( ln( fxCurrencyGetPrecision( legGetString( pComponent,"Flat_settl_unit" ) ) ) / ln( 10.0 ) ),
			fAmount := roundnearest( legGetNumeric( pComponent,"Flat_settlement" ),iNumberOfDecimals ),
			legOverwrite( pComponent,"Flat_settlement",fAmount ),
			iCount := iCount + 1
		}
	}
};

// mx.preTrade.completion._Functions.ALL.SanityCheckCommon

/*
MXpress Common Sanity Checks

Version 1.1
Adaptation for FX Cash Funding packages : the counterparty checks should be done on all legs of the Funding packages (swaps & outrights)

Version 1.0

Notes:
The goal of this rule is to analyze every leg/component of a transaction and check if they are sane.
When a sanity check is not fulfilled, a warning or error code is generated with legAddMessage function.
Those codes will then be analysed in mx.preTrade.completion.ALL.ALL.CheckMsg rule and error/warning messages will be pushed to user and tradability status computed accordingly.

Generic Common Sanoty Checks included by default and their code:
	For every registration, across all assets:
		- Portfolio is missing if not part of blockTrade					: "P"
		- Back to back Portfolio is missing									: "BTBP"
		- Counterparty is missing											: "C"
		- Counterparty is not allowed for this product 						: "CNA" 

If customizations of the warning/error level are necessary, in order to get the required user notification level:
For Sanity warning
	-> legAddMessage( pComponent,"<message>","<field>","Sane-<code>-",messageSysGetWarningLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark
For Sanity error
	->  legAddMessage( pComponent,"<message>","<field>","Sane-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message is accesible by clicking on exclamation mark
	Booking is prevented
For Sanity error Intrusive
	-> legAddMessage( pComponent,"<message>","<field>","Sane-Intrusive-<code>-",messageSysGetErrorLabel( ) )
	Highlight the field and an explanatory message pops up systematically. Very intrusive for the user.
	Booking is prevented
*/

{
	// Fields Initialization/Reset
	pLeg := This,
	sAsset := getArgAsString(0),
	sPattern := "",
	sRegistration := "",
	pAllMessages := pNULL,
	sIsBlockTradeActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","BlockTrade" ) ),
	sPortfolio := "",
	bIsBacktoBack := FALSE,
	sBackToBackPortfolio := "",
	sCounterpart := "",
	sProductAllowed := "",
    sBOClass := properties.Get( "mx.preTrade.BO.source.class" ),
	sTradePurpose := legGetString ( pLeg,"Trade purpose" ),
	sOrderCtpMandatory := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","OrderCounterpartyMandatory" ) ),
	sSanityCheckMandatory.ASSET := "SanityCheckMandatory." + sAsset,
	sIsSanityCheckMandatory := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1",sSanityCheckMandatory.ASSET ) ),
	IF ( ( sIsSanityCheckMandatory <> "YES" ) AND ( sIsSanityCheckMandatory <> "NO" ) ) THEN
		ThrowError( "Error in MX.ALL.GParam","Wrong returned value for Key 1 = " + sSanityCheckMandatory.ASSET + " ( should be YES or NO )" ),

	iCount := 0,
	iNbLegs := legGetNumberOfComponents( pLeg ),

	// For each of the component of the transaction, perform sanity checks
	WHILE ( iCount < iNbLegs ) DO
	{
		pComponent := legGetComponentAt( pLeg,iCount ),

		sRegistration := legGetRegistration( pComponent ),
		pAllMessages := legGetMessages( pComponent ),
		IF ( sIsBlockTradeActive <> "YES" ) THEN
			sPortfolio := legGetString( pComponent,"Portfolio" ),
		bIsBacktoBack := legGetFOPIsBackToBack( pComponent ),
		sBackToBackPortfolio := legGetString( pComponent , "Back_to_back_portfolio"),
		sCounterpart := legGetString( pComponent,"Counterpart" ),

        //BAB addition - Always re-set Payout to Borrow/Lend if it's set to Lend/Borrow and is protected
        sTypology := legGetTypology(pComponent),
        IF ( sTypology == "Murabaha Borrowing" OR sTypology == "Wakala Borrowing" OR sTypology == "RR Murabaha" OR sTypology == "RR Waad" OR sTypology == "Repo SAMA" OR sTypology == "CD Issuance")  THEN 
        {
            sPayout := legGetString(pComponent,"Payout"),
            IF ( sPayout == "Lend" ) THEN
            {
                legOverwrite (pComponent,"Payout","Borrow"),
                ThrowError ( pComponent,"Payout Lend is not allowed for this product, Payout has been reset to Borrow","Payout")
            }  
        }

        ELSE IF ( sTypology == "Murabaha Placement" OR sTypology == "Wakala Placement" OR sTypology == "DPM Murabaha" OR sTypology == "Repo Murabaha" OR sTypology == "Repo Waad" OR sTypology == "RR SAMA" 
               OR sTypology == "LTM" OR sTypology == "LTM Callable" OR sTypology == "LTM Range" OR sTypology == "LTM Range Callable" OR sTypology == "LTM CapFloorCollar")  THEN 
        {
            sPayout := legGetString(pComponent,"Payout"),
            IF ( sPayout == "Borrow" ) THEN
            {
                legOverwrite (pComponent,"Payout","Lend"),
                ThrowError ( pComponent,"Payout Borrow is not allowed for this product, Payout has been reset to Lend","Payout")
            }  
        },
         //End of BAB addidtion


		bFirstLeg := TRUE,
		IF ( ( legGetRegistrationLabel( pComponent ) == "mxContractITRADE" ) AND sAsset <> "FXMM" ) THEN
		{
			pFirstComponent := legGetFirstComponent( legGetFatherContract( pComponent ) ),
			IF ( pComponent <> pFirstComponent ) THEN 
				bFirstLeg := FALSE
		}
		ELSE IF ( sAsset == "FXMM" ) THEN
		{
			sBORegistration := legGetRegistrationLabel( pLeg ),
			// Counteparties should be checked for all legs of Funding packages
			IF ( pComponent <> legGetMainComponent( pLeg ) AND (sBORegistration <> "mxContractFxIFUNDINGSWAP" AND sBORegistration <> "mxContractFxIFUNDINGOUTRIGHT") ) THEN
				bFirstLeg := FALSE
		},
		// Empty Portfolio check
		IF ( ( sIsBlockTradeActive <> "YES" ) AND ( sPortfolio == "" ) AND ( bFirstLeg ) ) THEN
		{
			IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-P-" ) == 0 ) THEN
				legAddMessage( pComponent,"Portfolio is required","Portfolio","Sane-P-",messageSysGetErrorLabel( ) )
		},
		// Empty Back to back portfolio check
		IF ( ( bIsBacktoBack ) AND ( sBackToBackPortfolio == "" ) ) THEN
		{
			IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-BTBP-" ) == 0 ) THEN
				legAddMessage( pComponent,"Back to Back Portfolio is required","Back to back portfolio","Sane-BTBP-",messageSysGetErrorLabel( ) )
		},

        //Throw Error if no broker has been selected
         IF ((legGetRegistration(pLeg) == "Spot-Forward") AND sTypology == "Spot") AND legGetString(pComponent,"BROKER") == "" AND legGetString(pComponent,"BROKER_FEE") == "Yes" 
         AND ( sBOClass <> "mxContractEventFxIEARLY_TAKEUP_OFFSETTING" ) THEN
        {
        	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Brok" ) == 0 ) THEN
        		legAddMessage(pComponent,"Broker is empty","BROKER","Sane-Brok",messageSysGetErrorLabel( ))
        },
          IF ((legGetRegistration(pLeg) == "Split Package") AND sTypology == "Spot") AND legGetString(pComponent,"cross.BROKER") == "" AND legGetString(pComponent,"cross.BROKER_FEE") == "Yes" THEN
        {
        	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Brok" ) == 0 ) THEN
        		legAddMessage(pComponent,"Broker is empty","BROKER","Sane-Brok",messageSysGetErrorLabel( ))
        },
        // End

		IF ( ( sCounterpart == "" ) AND ( bFirstLeg ) ) THEN
		{
			// Empty Counterparty check
			IF ( ( sTradePurpose <> "Order" AND sTradePurpose <> "Draft")
			OR ( sTradePurpose == "Order" AND sOrderCtpMandatory == "YES" ) ) THEN
			{
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-C-" ) == 0 ) THEN
				{
					IF ( sIsSanityCheckMandatory == "NO" ) THEN
						legAddMessage( pComponent,"Counterparty is empty","Counterpart","Sane-C-",messageSysGetWarningLabel( ) )
					ELSE
						legAddMessage( pComponent,"Counterparty is required","Counterpart","Sane-C-",messageSysGetErrorLabel( ) )
				}
			}
		}
		ELSE IF ( bFirstLeg ) THEN
		{
			// Counterparty Not Allowed check
			sProductAllowed := lookupString( "MX.ALL.SanityProducts","ALL",
											"Counterpart",sCounterpart,
											"Registration",sRegistration,
											"Pattern",sPattern ),
			IF ( ( sProductAllowed == "No") ) THEN
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Intrusive-CNA-" ) == 0 ) THEN
					legAddMessage( pComponent,"This product cannot be traded with " + sCounterpart,"Counterpart","Sane-Intrusive-CNA-",messageSysGetErrorLabel( ) )
		},
		iCount := iCount + 1
	}
};

// mx.msl.event.completion.ALL.ALL.SalesMargin

/*
MXpress

- For a Cancel&Reissue, analyse the old and new version and decide whether to recompute Sales income (VAAMT) or not for the new version. The recomputation is either done at new trade level
in case of new maturity, new currency... or inside event rule (in case a ratio can be applied)
- For termination events (Unwind, Early terminate), if applicable, store the Event Sales income (EVT_VAAMT/ECT_VACCY) as a broker fee
- For FX Allocation, recompute Sales income (VAAMT) for the new versions.

v1.1
- Manage VAAMT_EVT Event sales income amount
- For Back to Back, attach the fee to Back to back portfolio (Trader portfolio)
- Use SALES_FEE Broker code
- Specific logic for FX Allocation and FX Exercise (Callable Take Up)

v1.0
*/

{
	//Fields initialization:
	pEvent := This,
	sEvent := properties.Get( "mx.preTrade.BO.class" ),
	IF ( sEvent == "mxContractEventICANCEL_REISSUE" ) THEN
	{
		iVersionedBO := 0,
		iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),
		WHILE ( iVersionedBO < iNbVersionedBOs ) DO
		{
			pVersionedBO := evtGetVersionedBOAt( pEvent,iVersionedBO ),
			pNew := evtVersionedBOGetNew( pVersionedBO ),
			pOld := evtVersionedBOGetOld( pVersionedBO ),
			iComponent := 0,
			iNbComponents := legGetNumberOfComponents( pNew ),
			WHILE ( iComponent < iNbComponents ) DO
			{
				pComponentNew := legGetComponentAt( pNew,iComponent ),
				pComponentOld := legGetComponentAt( pOld,iComponent ),
				sRegistration := legGetRegistration( pComponentOld ),

                sVAAMTField := "VAAMT",
				sVAAMTCCYField := "VAAMTCCY",
                IF ( legIsElementValid( pComponentNew, sVAAMTField ) ) THEN                
				{
					sRecomputeVAAMTAtTradeLevel := "N",

					// If maturity is updated, apply trade level logic
					pFieldMapMaturityResult := pNULL,
					sField := "Maturity",
					pFieldMapMaturityResult := lookupResults( "MX.ALL.FieldMapping",sField,
																"Registration",sRegistration,
																"Criteria 1","",
																"Criteria 2","",
																"Criteria 3","" ),
					IF ( NOT isNull( pFieldMapMaturityResult ) ) THEN
					{
						iLeg := toInt( lookupResultsGetNumeric( pFieldMapMaturityResult,0,0 ) ),
						sMaturityField := lookupResultsGetString( pFieldMapMaturityResult,0,1 ),
						IF ( iLeg == iComponent ) THEN
						{
							dMaturityValueOld := legGetDate( pComponentOld,sMaturityField ),
							dMaturityValueNew := legGetDate( pComponentNew,sMaturityField ),
							IF ( dMaturityValueNew <> dMaturityValueOld ) THEN
								sRecomputeVAAMTAtTradeLevel := "Y"
						}
					},

					// If portfolio entity currency changed, apply trade level logic
					IF ( ptfGetEntityCurrency( legGetString( pComponentOld,"Portfolio" ) ) <> ptfGetEntityCurrency( legGetString( pComponentNew,"Portfolio" ) ) ) THEN
						sRecomputeVAAMTAtTradeLevel := "Y"
					ELSE
					{
						pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","EventReferenceAmount" ),
						IF ( isNull( pFieldResult ) ) THEN
						{
							// If we don't have a reference amount, apply trade level logic
							sRecomputeVAAMTAtTradeLevel := "Y"
						}
						ELSE
						{
							iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
							sRefAmountField := lookupResultsGetString( pFieldResult,0,1 ),
							fNewSalesMarginAmt := legGetNumeric( pComponentNew,sRefAmountField ),
							fOldSalesMarginAmt := legGetNumeric( pComponentOld,sRefAmountField ),
							IF ( fOldSalesMarginAmt == 0.0 ) THEN
							{
								// If old reference amount is null, apply trade level logic
								sRecomputeVAAMTAtTradeLevel := "Y"
							}
							ELSE IF ( fNewSalesMarginAmt <> fOldSalesMarginAmt ) THEN
							{
								fOldVAAMT := legGetNumeric( pComponentOld,sVAAMTField ),
								IF ( fOldVAAMT == 0.0 ) THEN
								{
									// If original VAAMT was 0, apply trade level logic
									sRecomputeVAAMTAtTradeLevel := "Y"
								}
								ELSE
								{
									// Otherwise we apply a linear computation of new VAAMT from old VAAMT and ratio of old and new native margin
									sRecomputeVAAMTAtTradeLevel := "N",
									fNewVAAMT := fOldVAAMT * fNewSalesMarginAmt / fOldSalesMarginAmt,
									legSetNumeric( pComponentNew,sVAAMTField,fNewVAAMT )
								}
							}
						}
					},
					IF ( legIsElementValid( pComponentNew,"pf_Sales_margin_Event_Compute" ) ) THEN
						legSetString( pComponentNew,"pf_Sales_margin_Event_Compute",sRecomputeVAAMTAtTradeLevel )
				},
				iComponent := iComponent + 1
			},
			iVersionedBO := iVersionedBO + 1
		}
	}
	ELSE IF ( sEvent == "mxContractEventIUNWIND" OR sEvent == "mxContractEventFxIEARLY_TAKEUP_TERMINATE" OR sEvent == "mxContractEventIRESTRUCTURE") THEN
	{
		pUDFs := evtGetUserFields( pEvent ),
		iVersionedBO := 0,
		iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),
		WHILE ( iVersionedBO < iNbVersionedBOs ) DO
		{
			pVersionedBO := evtGetVersionedBOAt( pEvent,iVersionedBO ),
			pNew := evtVersionedBOGetNew( pVersionedBO ),
			pOld := evtVersionedBOGetOld( pVersionedBO ),

			pComponentOld := legGetComponentAt( pOld,0 ),
			IF ( legIsElementValid( pComponentOld, "VAAMTCCY" ) ) THEN            
				udfSetString( pUDFs,"EVT_VACCY",legGetString( pComponentOld,"VAAMTCCY" ) ),

			fEvtVAAMT := udfGetNumeric( pUDFs,"EVT_VAAMT" ),
			sEvtVAAMTCCY := udfGetString( pUDFs,"EVT_VACCY" ),           

			pComponent := legGetComponentAt( pNew,0 ),

			IF ( legIsElementValid( pComponentOld, "VAAMT_EVT" ) ) THEN            
            	legOverwrite(pComponent, "VAAMT_EVT", legGetNumeric(pComponentOld, "VAAMT_EVT") + fEvtVAAMT),

			IF ( sEvent == "mxContractEventIRESTRUCTURE" AND legIsElementValid( pComponent,"pf_Sales_margin_Event_Compute" ) ) THEN
					legSetString( pComponent,"pf_Sales_margin_Event_Compute","Y" ),                


            sSalesMarginMode := "None",
            IF ( legIsElementValid( pComponent, "VAMODE" ) ) THEN
                sSalesMarginMode := legGetString(pComponent, "VAMODE"),                
			IF (sSalesMarginMode == "Transfer to Sales portfolio") THEN
            {
				IF ( legGetString( pComponent, "Back to back" ) <> "Yes" ) THEN
					sPortfolio := legGetString( pComponent,"Portfolio" )
                ELSE
	            	sPortfolio := legGetString( pComponent,"Back to back portfolio" ),
				pResults := lookupResults( "MX.ALL.SalesMarginPtf","ALL","USER_GROUP",sysGetGroup( ) ),
				IF ( NOT ( isNull( pResults) ) ) THEN
					sDestinationPortfolio := lookupResultsGetString( pResults,0,0 ),
				// Create a new broker fee attached to the trade if applicable
				IF ( ABS ( fEvtVAAMT ) > 0.001 ) THEN
				{
					dFlowValueDate := sysGetTradingDate(),

					pBrokerFlowsOld := legGetBrokerFlows( pComponentOld ),
					iNumBrkFlowsOld := brkFlowsGetNumberOfFlows( pBrokerFlowsOld ),
					pBrokerFlows := legGetBrokerFlows( pComponent ),
					iNumBrkFlows := brkFlowsGetNumberOfFlows( pBrokerFlows ),
					IF ( iNumBrkFlows <= iNumBrkFlowsOld ) THEN
					{
						pBrokerFlow := brkFlowsAdd( pBrokerFlows )
					}
					ELSE
					{
						pBrokerFlow := brkFlowsGetAt( pBrokerFlows,iNumBrkFlows - 1 )
					},
					brkFlowSetType( pBrokerFlow,"InternalFee" ),
					brkFlowSetSource( pBrokerFlow,sPortfolio ),
					brkFlowSetDestination( pBrokerFlow,sDestinationPortfolio ),
					brkFlowSetValueDate( pBrokerFlow,dFlowValueDate ),
					brkFlowSetCode( pBrokerFlow,"SALES_FEE" ),                    
					brkFlowSetCurrency( pBrokerFlow,sEvtVAAMTCCY ),
					brkFlowSetFee( pBrokerFlow,fEvtVAAMT )
				}
				// Remove the extra broker fee in case Event VAAMT is set back to zero
				ELSE
				{
					pBrokerFlowsOld := legGetBrokerFlows( pComponentOld ),
					iNumBrkFlowsOld := brkFlowsGetNumberOfFlows( pBrokerFlowsOld ),
					pBrokerFlows := legGetBrokerFlows( pComponent ),
					iNumBrkFlows := brkFlowsGetNumberOfFlows( pBrokerFlows ),
					IF ( iNumBrkFlows > iNumBrkFlowsOld) THEN
					{
						pFlow := brkFlowsGetAt( pBrokerFlows,iNumBrkFlows-1 ),
						brkFlowsRemove( pBrokerFlows,pFlow )
					}
				}
			},
            // Synchronise unwind fees between second component and first component in back to back package, when applicable
			IF ( sEvent == "mxContractEventIUNWIND" AND ( sSalesMarginMode == "Transfer to Sales portfolio" OR sSalesMarginMode == "Keep in Trader portfolio") ) THEN
            {
				IF ( legGetString( pComponent, "Back to back" ) == "Yes" ) THEN
                {
                	iEvtFlowCount := evtGetNumberOfFlows( pEvent ),
                    IF ( iEvtFlowCount == 2 ) THEN
                    {
                    	pEvtFlow1 := evtGetFlowAt( pEvent, 0 ),
						pEvtFlow2 := evtGetFlowAt( pEvent, 1 ),
                        IF ( evtFlowGetAmount(pEvtFlow1) <> evtFlowGetAmount(pEvtFlow2) ) THEN
	                        evtFlowSetAmount(pEvtFlow2, evtFlowGetAmount(pEvtFlow1))
                    }
                }
			},            
			iVersionedBO := iVersionedBO + 1
		}
	}
	ELSE IF ( sEvent == "mxContractEventFxIEARLY_TAKEUP_MODIFY" OR sEvent == "mxContractEventFxIEARLY_TAKEUP_OFFSETTING" 
		OR sEvent == "mxContractEventFxIEXTENSION_MODIFY" OR sEvent == "mxContractEventFxIEXTENSION_OFFSETTING") THEN
	{
		iVersionedBO := 0,
		iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),
		WHILE ( iVersionedBO < iNbVersionedBOs ) DO
		{
			pVersionedBO := evtGetVersionedBOAt( pEvent,iVersionedBO ),
			pNew := evtVersionedBOGetNew( pVersionedBO ),
			iComponent := 0,
			iNbComponents := legGetNumberOfComponents( pNew ),
			WHILE ( iComponent < iNbComponents ) DO
			{
				pComponentNew := legGetComponentAt( pNew,iComponent ),
				IF ( legIsElementValid( pComponentNew,"pf_Sales_margin_Event_Compute" ) ) THEN
					legSetString( pComponentNew,"pf_Sales_margin_Event_Compute","Y" ),
				iComponent := iComponent + 1
			},
			iVersionedBO := iVersionedBO + 1
		}
	}
	ELSE IF ( sEvent == "mxContractEventFxIALLOCATION" ) THEN
	{
		iVersionedBO := 0,
		iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),
        WHILE ( iVersionedBO < iNbVersionedBOs ) DO
        {
            pVersionedBO := evtGetVersionedBOAt( pEvent,iVersionedBO ),
            pNew := evtVersionedBOGetNew( pVersionedBO ),
            IF ( iVersionedBO == 0 ) THEN
            {
            	// For the original deal, set VAAMT to 0
                pMainComponent := legGetMainComponent(pNew),
                pTradeUDFNew := legGetUserFields(legGetMainComponent( pMainComponent )),
				udfOverwriteNumeric( pTradeUDFNew,"VAAMT", 0.0)
            }
            ELSE
            {
            	// For the new deals, compute VAAMT in Trade sequence
				iComponent := 0,
				iNbComponents := legGetNumberOfComponents( pNew ),                
                WHILE ( iComponent < iNbComponents ) DO
                {
                    pComponentNew := legGetComponentAt( pNew,iComponent ),
                    IF ( legIsElementValid( pComponentNew,"pf_Sales_margin_Event_Compute" ) ) THEN
                        legSetString( pComponentNew,"pf_Sales_margin_Event_Compute","Y" ),
                    iComponent := iComponent + 1
                }
            },
            iVersionedBO := iVersionedBO + 1 
        }
    }
	ELSE IF ( sEvent == "mxContractEventFxIEXERCISE" ) THEN
	{
        iVersionedBO := 0,
        iNbVersionedBOs := evtGetNumberOfVersionedBOs( pEvent ),
        fVANewTrade := 0.0,
        fNewVAInitialTrade := 0.0,        
        WHILE ( iVersionedBO < iNbVersionedBOs ) DO
        {
            pVersionedBO := evtGetVersionedBOAt( pEvent,iVersionedBO ),
            pNew := evtVersionedBOGetNew( pVersionedBO ),
            IF ( iVersionedBO == 0 ) THEN
            {
	            pOld := evtVersionedBOGetOld(pVersionedBO ),
	            pTradeUDFOld := legGetUserFields(  legGetMainComponent( pOld) ),
                pMainComponent := legGetMainComponent(pNew),
                pTradeUDFNew := legGetUserFields(legGetMainComponent( pMainComponent )),
                sTradedUnit:=legGetString(pMainComponent,"Traded nominal unit"),
	            sEvtCcy:=evtFXMMGetString(pEvent, "Amount currency"),
	            IF (sTradedUnit==sEvtCcy) THEN {
    	            fAmount:=evtFXMMGetNumeric(pEvent, "Mktop amount"),
        	        fInitAmount:=legGetNumeric(pMainComponent,"Available traded nominal")
	            } ELSE{
    	            fAmount:=evtFXMMGetNumeric(pEvent, "Mktop amount"),
        	        fInitAmount:=legGetNumeric(pMainComponent,"Available other traded nominal")
	            },
    	        fRatio:=fAmount/fInitAmount,
        	    fVA:=udfGetNumeric(pTradeUDFOld,"VAAMT"),
            	fNewVAInitialTrade:=round(fVA*(1.0-fRatio),0),
                fVANewTrade:=round(fVA*fRatio,0),
				udfOverwriteNumeric( pTradeUDFNew,"VAAMT",fNewVAInitialTrade)
            }
            ELSE
            {
                pMainComponent := legGetMainComponent(pNew),
                pTradeUDFNew := legGetUserFields(legGetMainComponent( pMainComponent )),
            	udfOverwriteNumeric( pTradeUDFNew,"VAAMT",fVANewTrade)
            },            
            iVersionedBO := iVersionedBO + 1 
        }    
    }
};

// mx.msl.hedge.completion.ALL.LinkRealAndModelled

/*
MXpress
Hedge completion

Version 1.0
Fill automatically the "linked hedging instrument" field
*/

{
	pHedge := This,
	pHStrategy := mx.accounting.hedge.Hedge.GetStrategy( pHedge ),
	sStrategyLabel:= mx.accounting.hedge.config.Strategy.GetLabel( pHStrategy ),
	IF ( sStrategyLabel == "FV_CS_CDO_MT" ) THEN
	{
		pHedgingInstruments := mx.accounting.hedge.Hedge.GetHedgingComponents( pHedge ),
		pModelledHedgingInstruments := mx.accounting.hedge.Hedge.GetTheoreticalHedgingComponents( pHedge ),
		iHedge := 0,
		iNbHedges := mx.system.collection.GetLength( pHedgingInstruments ),
		WHILE ( iHedge < iNbHedges ) DO
		{
			pModelledHedgingInstrument := mx.system.collection.GetElementAt( pModelledHedgingInstruments,iHedge ),
			pHedgingInstrument := mx.system.collection.GetElementAt( pHedgingInstruments,iHedge ),
			fHedgingTrade := mx.accounting.hedge.Component.GetTradeOriginReference( pHedgingInstrument ),
			mx.accounting.hedge.Component.SetLinkedHedgingInstrument( pModelledHedgingInstrument,fHedgingTrade ),
			iHedge := iHedge + 1
		}
	}
};

// mx.msl.event.completion.ALL.InheritFields

/*
MXpress
Event completion in order to:
- copy needed fields (mx native fields or UDFs) during an event. Currently supported events: "exercise" and "portfolio assignment"
- remove the fees depending a specific event UDF. Currently supported events: "portfolio assignment"

Version 1.0
First version of the algorithm
*/

{
	pAllEvents := This,
	// get the action type of the event
	sAction := properties.Get( "mx.preTrade.action" ),
	sEvent := properties.Get( "mx.preTrade.BO.class" ),
	bIsBulk := mx.contract.event.IsBulkEvent( pAllEvents ),
	IF ( bIsBulk ) THEN
		iNbEvents:= mx.contract.bulkevent.GetNumberOfEvents( pEvent )
	ELSE
		iNbEvents := 1,

	WHILE ( iNbEvents > 0 ) DO
	{
		pEvent := mx.contract.bulkevent.GetEventAt( pAllEvents,iNbEvents - 1 ),
		pOld := evtVersionedBOGetOld( evtGetVersionedBOAt( pEvent,0 ) ),
		pNew := evtVersionedBOGetNew( evtGetVersionedBOAt( pEvent,0 ) ),

		// Inherit fields
		IF ( sAction <> "CNL" ) THEN
		{
			pMainContract := legGetFatherContract( pOld ),
			sSourceModule := legGetSourceModule( pMainContract ),

			iVersionedBO := 0,
			iNbVersionedBOs := evtGetNumberOfVersionedBOs( pAllEvents ),
			WHILE ( iVersionedBO < iNbVersionedBOs ) DO
			{
				pVersionedBO := evtGetVersionedBOAt( pAllEvents,iVersionedBO ),
				pNew := evtVersionedBOGetNew( pVersionedBO ),
				iComponent := 0,
				iNbComponents := legGetNumberOfComponents( pNew ),
				iNbComponentsOld := legGetNumberOfComponents( pOld ),

                sRegistrationOld := legGetRegistration( pOld ),

                IF sRegistrationOld <> "FX swap" THEN
                { 
				IF ( iNbComponents <> iNbComponentsOld ) THEN
					ThrowInformation( "inheritFields","Unexpected number of components pOld/pNew [" + toString( iNbComponentsOld ) + "/" + toString( iNbComponents ) + "]. Please check with your configurator." ),
				WHILE ( iComponent < iNbComponents ) DO
				{
					pComponentNew := legGetComponentAt( pNew,iComponent ),
					IF ( iComponent < iNbComponentsOld ) THEN
						pComponentOld := legGetComponentAt( pOld,iComponent ),

					// sample of propagation for the source module
					IF ( sSourceModule == "XXX" ) THEN
					{
						pContractNew := legGetContractAt( pNew,iComponent ),
						legSetSourceModule( pContractNew,sSourceModule )
					},

					// sample of field inheritance: only an update of the ( MX.ALL.EventInheritance,ALL ) lookup table is required
					sRegistration := legGetRegistration( pNew ),
					sComponentRegistration := legGetRegistration( pComponentNew ),
					pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event",sEvent,"Registration",sRegistration,"Component Registration",sComponentRegistration ),
					IF ( toString( pResults ) <> "0" ) THEN
					{
						iNbResults := lookupResultsGetNumberOfLines( pResults ),
						iRes := 0,
						WHILE ( iRes < iNbResults ) DO
						{
							sFieldName := lookupResultsGetString( pResults,iRes,0 ),
							// depending on type, copy from old to new
							IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
							{
								sFieldType := legGetFieldType( pComponentOld,sFieldName ),
								IF ( sFieldType == "string" ) THEN
									legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "numeric" ) THEN
									legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "date" ) THEN
									legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
								ELSE
									ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
							}
							ELSE
							{
								// specific treatment to be considered here
								ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
							},
							iRes := iRes + 1
						}
					},

					// loop in case inheritance should occured for all events
					pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event","","Registration",sRegistration,"Component Registration",sComponentRegistration ),
					IF ( toString( pResults ) <> "0" ) THEN
					{
						iNbResults := lookupResultsGetNumberOfLines( pResults ),
						iRes := 0,
						WHILE ( iRes < iNbResults ) DO
						{
							sFieldName := lookupResultsGetString( pResults,iRes,0 ),
							// depending on type, copy from old to new
							IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
							{
								sFieldType := legGetFieldType( pComponentOld,sFieldName ),
								IF ( sFieldType == "string" ) THEN
									legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "numeric" ) THEN
									legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "date" ) THEN
									legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
								ELSE
									ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
							}
							ELSE
							{
								// specific treatment to be considered here
								ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
							},
							iRes := iRes + 1
						}
					},

					 // loop in case inheritance should occured for all registrations
					pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event",sEvent,"Registration","","Component Registration","" ),
					IF ( toString( pResults ) <> "0" ) THEN
					{
						iNbResults := lookupResultsGetNumberOfLines( pResults ),
						iRes := 0,
						WHILE ( iRes < iNbResults ) DO
						{
							sFieldName := lookupResultsGetString( pResults,iRes,0 ),
							// depending on type, copy from old to new
							IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
							{
								sFieldType := legGetFieldType( pComponentOld,sFieldName ),
								IF ( sFieldType == "string" ) THEN
									legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "numeric" ) THEN
									legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
								ELSE IF ( sFieldType == "date" ) THEN
									legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
								ELSE
									ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
							}
							ELSE
							{
								// specific treatment to be considered here
								ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
							},
							iRes := iRes + 1
						}
					},

					iComponent := iComponent + 1
				},
				iVersionedBO := iVersionedBO + 1
			}
          }
		},

		// sample of removal of event flows in case of portfolio assignment event
		IF ( sEvent == "mxContractEventIPORTFOLIO_ASSIGNMENT" ) THEN
		{
			pEvtUDF := evtGetUserFields( pEvent ),
			sRemoveFee := udfGetString( pEvtUDF,"NOFEE" ),
			IF ( sRemoveFee == "Yes" ) THEN
			{
				iEvtFlowCount := evtGetNumberOfFlows( pEvent ),
				WHILE ( iEvtFlowCount > 0 ) DO
				{
					pEvtFlow := evtGetFlowAt( pEvent,iEvtFlow ),
					fAmount := evtFlowGetAmount( pEvtFlow ),
					evtRemoveFlowAt( pEvent,iEvtFlow ),
					iEvtFlowCount := iEvtFlowCount - 1
				}
			}
		},
		iNbEvents:=iNbEvents - 1
	}
};

// mx.msl.event.completion.ALL.SanityChecks

/*
MXpress
Event completion in order to:
- force the user to set a comment during an event. Currently supported events: "cancel" and "cancel and reissue"

Version 1.0
First version of the algorithm
*/

{
	pAllEvents := This,
	// get the action type of the event
	sAction := properties.Get( "mx.preTrade.action" ),
	sEvent := properties.Get( "mx.preTrade.BO.class" ),
	bIsEventCommentMandatory := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","EventCommentMandatory" ) ) == "YES",
	bIsInClosingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ), "C_" ),
	bIsBulk := mx.contract.event.IsBulkEvent( pAllEvents ),

	IF ( bIsBulk ) THEN
		iNbEvents:= mx.contract.bulkevent.GetNumberOfEvents( pAllEvents )
	ELSE
		iNbEvents := 1,

	WHILE ( iNbEvents > 0 ) DO
	{
		pEvent := mx.contract.bulkevent.GetEventAt( pAllEvents,iNbEvents - 1 ),

		//BAB addition for cancellation of BOTOFO trades
		pOld := evtVersionedBOGetOld( evtGetVersionedBOAt( pEvent,0 ) ),
		pMainContract := legGetFatherContract(pOld),
    	sTradePurpose := legGetString(pMainContract,"Trade_purpose"),
        IF sTradePurpose == "Corporate action execution" THEN
        evtSetString(pEvent,"Comment","Corporate action execution: Cancelled via BOTOFO"),
    	//End of BAB addition

		// Request a comment
		IF ( /*( bIsEventCommentMandatory )
		AND */(( sEvent == "mxContractEventICANCEL" ) 
		OR ( sEvent == "mxContractEventICANCEL_REISSUE" )
		/*OR ( sAction == "MOD" )
        OR ( sAction == "CNL")*/) ) THEN // sAction is the event insert mode: insert/modify/delete event. Should the same apply as for a Cancel/C&R on the trade?
		{
			//sCommentDefault := "Please motivate this action",
			sComment := strTrim( evtGetString( pEvent,"Comment" ) ),
			 IF ( sComment == "" ) THEN
             {
				//evtSetString( pEvent,"Comment",sCommentDefault ),
			// can be recovered afterwards in booking to block
		//	IF ( sComment == sCommentDefault ) THEN
		//	{
				IF ( bIsInClosingSequence ) THEN
					ThrowLowPriorityWarning( "Event comment is mandatory","Comment" )

				ELSE
					ThrowError( "Event comment is mandatory","Comment" )
			//}
            }
		},
		iNbEvents:=iNbEvents - 1
	}
};

// mx.preTrade.completion._Functions.ALL.LayDynCommon

/*
MXpress Common Dynamic Layout

Version 1.2
Replace sysGetRole by sysGetRFQRole

Version 1.1
Add:
 - hiding of Counterparty on Provider (Trader) side during RFQ,
 - display of RFQ Id when applicable
 - display of Event/Unwind fields when applicable

Version 1.0

Notes:
In case of multi-component contract, the required fields should be added to the field properties at contract level, as the field properties at sub-component level will be ignored here.
For example, for a Dual Cur Deposit, Loan#1.Portfolio and Vanilla#1.Portfolio are added to common_0.3.1_portfolio field property at Dual Cur Deposit level.
*/
{
	pLeg := This,
	sAsset := getArgAsString(0),    
    sContext := "",
	iContract := 0,
	iNumContracts := legGetNumberOfContracts( pLeg ),

    // Tradability information
	sIsCommunicationActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","Communication" ) ),
	sIsTradabilityCheckActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","TradabilityCheck." + sAsset ) ),   

    // Back to back information
	sIsBackToBackActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","BackToBack." + sAsset) ),    

    // Context and Block trade information
    sPricingContext := properties.Get( "mx.preTrade.pricing.context" ), // possible values are FDI, MAIL, ARCHIVE or empty string
    sTicketDisplay := properties.Get( "mx.preTrade.preTradeTicketDisplay" ),
    sAction := properties.Get( "mx.preTrade.action" ), // possible values are INS, MOD and CNL
    sBOSource := properties.Get( "mx.preTrade.BO.source" ),

    IF ( ( ( sPricingContext == "" ) AND ( sTicketDisplay == "YES" ) ) 
    OR ( ( sAction == "INS" ) AND ( sBOSource == "mxContractEventIEVENT" ) )
    OR ( sAction <> "INS" ) ) THEN
        sContext := "BOOKING"
    ELSE IF ( ( sAction == "INS" ) AND ( sBOSource <> "mxContractEventIEVENT" ) ) THEN
        sContext := "PRICING",    
	sIsBlockTradeActive := strToUpperCase( lookupString( "MX.ALL.GParam","ALL","Key 1","BlockTrade" ) ),    

    // Order information
	fOriginOrderId := legGetNumeric( pLeg,"Trade_origin_order_id" ),    

	iContract := 0,
    WHILE ( iContract < iNumContracts ) DO
    {
	    pContract := legGetContractAt( pLeg, iContract ),
        // If the Communication is active or if the Tradability check is active, we need to activate the tradability check property
        IF ( ( sIsCommunicationActive == "YES" ) OR ( sIsTradabilityCheckActive == "YES" ) ) THEN
        {
            IF ( sAsset == "COM" ) THEN
                legAddProperty( pContract,"com_5.1_tradabilityStatus" )
            ELSE IF ( sAsset == "CRD" ) THEN                
                legAddProperty( pContract,"crd_1_tradabilityStatus" )
            ELSE IF ( sAsset == "EQD" ) THEN
            {
                legAddProperty( pContract,"van_1.8.1_tradabilityStatus" ),
				legAddProperty( pContract,"exo_2.22.1_tradabilityStatus" ),
				legAddProperty( pContract,"cash_3.1.1_tradabilityStatus" )
            }
            ELSE IF ( sAsset == "FXD" ) THEN {
				legAddProperty( legGetFirstComponent( pContract ),"fxd_01.05.01_tradabilityStatus" ),
				legAddProperty( pContract,"fxd_01.05.01_tradabilityStatus" )
            }
            ELSE IF ( sAsset == "FXMM" ) THEN            
				legAddProperty( pContract,"fxmm_01.02.01_tradabilityStatus" )
            ELSE IF ( sAsset == "IRD" ) THEN
            {
				legAddProperty( pContract,"irs_5.5.1_tradabilityStatus" ),
				legAddProperty( pContract,"cf_1.10.1_tradabilityStatus" ),
				legAddProperty( pContract,"swaption_9.2.1_tradabilityStatus" ),
				legAddProperty( pContract,"fra_3.2.1_tradabilityStatus" ),
				legAddProperty( pContract,"shortFuture_8.1.1_tradabilityStatus" ),
                legAddProperty( pContract, "crd_1_tradabilityStatus")
            }
            ELSE IF ( sAsset == "SF" ) THEN
            {            
                legAddProperty( pContract,"ers_1.5_tradabilityStatus" ),
                legAddProperty( pContract,"phys_1.5_tradabilityStatus" )            
            }
        },

		// If the Back to back is active, we need to activate the back to back property
		sBackToBack := legGetString( legGetFirstComponent(pContract),"Back to back" ),
        IF ( sIsBackToBackActive == "YES" OR sBackToBack == "Yes") THEN
        {
        	// FXMM logic is kept in FXMM LayDyn rule
        	IF ( sAsset <> "FXMM" ) THEN
            {
            	legAddProperty( pContract,"common_0.2.1_backToBack" ),
                IF ( sBackToBack == "Yes" ) THEN
                {
                    legAddProperty( pContract,"common_0.2.2_backToBackDetails" ),

                    //BAB addition to take into account the customization of flows in the sales margin amount
                    sTypology := legGetTypology	(pContract),
                    IF sTypology == "PRS" OR sTypology == "PRS Range" OR sTypology == "PRS CapFloorCollar" OR sTypology == "PRS Inverse Floater"  THEN
           		 	{
            	 		IF strCONTAIN (legGetString(pContract, "Customized Flows" ), "N") THEN
                		{
                    		legAddProperty( pContract,"common_0.1.4.8_salesmgnative")
                        }
                    },

                	// Retrieve Currency
                    sRegistration := legGetRegistration( pContract ),
                    pFieldResult := lookupResults( "MX.ALL.FieldMapping","SalesMargin","Registration",sRegistration,"Criteria 1","Currency","Criteria 2", sCriteria2 ),
                    IF ( NOT isNull( pFieldResult ) ) THEN
                    {
                        iLeg := toInt( lookupResultsGetNumeric( pFieldResult,0,0 ) ),
                        sNativeSalesMarginCurrencyField := lookupResultsGetString( pFieldResult,0,1 ),
                        sNativeSalesMarginCurrency := legGetString( pContract,sNativeSalesMarginCurrencyField )
                    },
					IF sNativeSalesMarginCurrency <> "SAR" THEN
                    {
                    	legAddProperty( pContract,"common_0.6.4_SalesMarginSAR" )
                    }
                 }    

            }
        },

    	//If the block trade is active , we need to activate the block trade properties
	    IF ( ( sIsBlockTradeActive == "YES" ) AND ( sContext == "PRICING" ) ) THEN
	    {
            legAddProperty( pContract,"common_0.3.2_blocktrade" ),                        
            sBlockTrade := legGetString( pContract,"Block Trade" ),
            IF ( sBlockTrade == "No" ) THEN
                legAddProperty( pContract,"common_0.3.1_portfolio" )
            ELSE
                legAddProperty( pContract,"common_0.3.3_allocationMatrix" )
        }
	    ELSE
	    {
	        legAddProperty( pContract,"common_0.3.1_portfolio" )
        },

	    // If the Origin order id is not null, it means current trade has been issued after an order execution, we should display the order id
	    IF ( fOriginOrderId <> 0.0 ) THEN
	    {
	        legAddProperty( pContract,"common_0.1.4.2_orderId" )
        },

        // Event pricing fields
        IF (legIsElementValid(pContract,"Event type")) THEN
        {
        	IF (legGetString(pContract,"Event type") == "Unwind") THEN
            	legAddProperty( pContract, "common_0.6.2_unwindPricing" )	
        },
    	iComponent := 0,
		iNumComponents := legGetNumberOfComponents( pContract ),        
    	WHILE ( iComponent < iNumComponents ) DO
		{
        	pComponent := legGetComponentAt( pContract,iComponent ),
	        IF (legIsElementValid(pComponent,"Event type")) THEN
    	    {
        		IF (legGetString(pComponent,"Event type") == "Unwind") THEN
            		legAddProperty( pComponent, "common_0.6.2_unwindPricing" )	
	        },
        	iComponent := iComponent + 1
        },

        // Hide counterparty information from trader during RFQ process
        // Counterpart at component level, but lay dyn property is at contract level
		IF ( properties.Get("mx.preTrade.pricing.context") <> "MAIL" OR sysGetRFQRole() <> "PROVIDER" ) THEN
			legAddProperty( pContract, "common_0.6.1_counterparty" ),                

        // RFQ_ID is UDF at component level, but lay dyn property is at contract level
        IF (legIsElementValid(legGetFirstComponent(pContract),"RFQ_ID")) THEN
        {
        	IF (legGetNumeric(legGetFirstComponent(pContract),"RFQ_ID") > 0.0) THEN
            	legAddProperty( pContract, "common_0.6.3_RFQId" )	
        },        

        iContract := iContract + 1        
    }
};

// public.msl.event.completion.ALL.InheritFields

/*
MXpress
Event completion samples in order to:
- force the user to set a comment during an event. Currently supported events: "cancel" and "cancel and reissue"
- copy needed fields (mx native fields or UDFs) during an event. Currently supported events: "exercise" and "portfolio assignment"
- remove the fees depending a specific event UDF. Currently supported events: "portfolio assignment"

Version 1.0
First version of the algorithm
*/

{
	pAllEvents := This,
	// get the action type of the event
	sAction := properties.Get( "mx.preTrade.action" ),
	sEvent := properties.Get( "mx.preTrade.BO.class" ),
	bIsBulk := mx.contract.event.IsBulkEvent( pAllEvents ),
	IF ( bIsBulk ) THEN
		iNbEvents:= mx.contract.bulkevent.GetNumberOfEvents( pEvent )
	ELSE
		iNbEvents := 1,

	WHILE ( iNbEvents > 0 ) DO
	{
		pEvent := mx.contract.bulkevent.GetEventAt( pAllEvents,iNbEvents - 1 ),
		pOld := evtVersionedBOGetOld( evtGetVersionedBOAt( pEvent,0 ) ),
		pNew := evtVersionedBOGetNew( evtGetVersionedBOAt( pEvent,0 ) ),

		pOldFirstComponent := legGetMainComponent( pOld ),
		pNewFirstComponent := legGetMainComponent( pNew ),
		sCounterpart := legGetString( pOldFirstComponent,"Counterpart" ),
		sInternal := legGetString( pOldFirstComponent,"Internal" ),

		// Request a comment
		IF ( ( sEvent == "mxContractEventICANCEL" ) 
		OR ( sEvent == "mxContractEventICANCEL_REISSUE" )
		OR ( sAction == "MOD" )
		OR ( sAction == "CNL" ) ) THEN // sAction is the event insert mode: insert/modify/delete event. Should the same apply as for a Cancel/C&R on the trade?
		{
			sCommentDefault := "Please motivate this action",
			sComment := strTrim( evtGetString( pEvent,"Comment" ) ),
             IF ( sComment == "" ) THEN
             {
				//evtSetString( pEvent,"Comment",sCommentDefault ),
			// can be recovered afterwards in booking to block
			//IF ( sComment == sCommentDefault ) THEN
				ThrowLowPriorityWarning( "Event comment is mandatory","Comment" )
                }

		},

		// Inherit fields
		IF ( sAction <> "CNL" ) THEN
		{
			pMainContract := legGetFatherContract( pOld ),
			sSourceModule := legGetSourceModule( pMainContract ),

			iVersionedBO := 0,
			iNbVersionedBOs := evtGetNumberOfVersionedBOs( pAllEvents ),
			WHILE ( iVersionedBO < iNbVersionedBOs ) DO
			{
				pVersionedBO := evtGetVersionedBOAt( pAllEvents,iVersionedBO ),
				pNew := evtVersionedBOGetNew( pVersionedBO ),
				iComponent := 0,
				iNbComponents := legGetNumberOfComponents( pNew ),
				iNbComponentsOld := legGetNumberOfComponents( pOld ),
				IF ( iNbComponents <> iNbComponentsOld ) THEN
					ThrowInformation( "inheritFields","Unexpected number of components pOld/pNew [" + toString( iNbComponentsOld ) + "/" + toString( iNbComponents ) + "]. Please check with your configurator." ),
				WHILE ( iComponent < iNbComponents ) DO
				{
					pComponentNew := legGetComponentAt( pNew,iComponent ),
					IF ( iComponent < iNbComponentsOld ) THEN
						pComponentOld := legGetComponentAt( pOld,iComponent ),

					// sample of propagation for the source module
					IF ( sSourceModule == "XXX" ) THEN
					{
						pContractNew := legGetContractAt( pNew,iComponent ),
						legSetSourceModule( pContractNew,sSourceModule )
					},

					// sample of field inheritance: only an update of the ( MX.ALL.EventInheritance,ALL ) lookup table is required
					sRegistration := legGetRegistration( pNew ),
					sComponentRegistration := legGetRegistration( pComponentNew ),
                    pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event",sEvent,"Registration",sRegistration,"Component Registration",sComponentRegistration ),
                    IF ( toString( pResults ) <> "0" ) THEN
                    {
                        iNbResults := lookupResultsGetNumberOfLines( pResults ),
                        iRes := 0,
                        WHILE ( iRes < iNbResults ) DO
                        {
                            sFieldName := lookupResultsGetString( pResults,iRes,0 ),
                            // depending on type, copy from old to new
                            IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
                            {
                                sFieldType := legGetFieldType( pComponentOld,sFieldName ),
                                IF ( sFieldType == "string" ) THEN
                                    legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "numeric" ) THEN
                                    legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "date" ) THEN
                                    legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
                                ELSE
                                    ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
                            }
                            ELSE
                            {
                                // specific treatment to be considered here
                                ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
                            },
                            iRes := iRes + 1
                        }
                    },

                    // loop in case inheritance should occured for all events
                    pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event","","Registration",sRegistration,"Component Registration",sComponentRegistration ),
                    IF ( toString( pResults ) <> "0" ) THEN
                    {
                        iNbResults := lookupResultsGetNumberOfLines( pResults ),
                        iRes := 0,
                        WHILE ( iRes < iNbResults ) DO
                        {
                            sFieldName := lookupResultsGetString( pResults,iRes,0 ),
                            // depending on type, copy from old to new
                            IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
                            {
                                sFieldType := legGetFieldType( pComponentOld,sFieldName ),
                                IF ( sFieldType == "string" ) THEN
                                    legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "numeric" ) THEN
                                    legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "date" ) THEN
                                    legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
                                ELSE
                                    ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
                            }
                            ELSE
                            {
                                // specific treatment to be considered here
                                ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
                            },
                            iRes := iRes + 1
                        }
                    },

                     // loop in case inheritance should occured for all registrations
                    pResults := lookupResults( "MX.ALL.EventInheritance","ALL","Event",sEvent,"Registration","","Component Registration","" ),
                    IF ( toString( pResults ) <> "0" ) THEN
                    {
                        iNbResults := lookupResultsGetNumberOfLines( pResults ),
                        iRes := 0,
                        WHILE ( iRes < iNbResults ) DO
                        {
                            sFieldName := lookupResultsGetString( pResults,iRes,0 ),
                            // depending on type, copy from old to new
                            IF ( legIsElementValid( pComponentOld,sFieldName ) ) THEN
                            {
                                sFieldType := legGetFieldType( pComponentOld,sFieldName ),
                                IF ( sFieldType == "string" ) THEN
                                    legSetString( pComponentNew,sFieldName,legGetString( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "numeric" ) THEN
                                    legSetNumeric( pComponentNew,sFieldName,legGetNumeric( pComponentOld,sFieldName ) )
                                ELSE IF ( sFieldType == "date" ) THEN
                                    legSetDate( pComponentNew,sFieldName,legGetDate( pComponentOld,sFieldName ) )
                                ELSE
                                    ThrowWarning( pComponentNew,"Sorry, did not understand field type " + sFieldType,"eventInherit" )
                            }
                            ELSE
                            {
                                // specific treatment to be considered here
                                ThrowWarning( pComponentNew,sFieldName + " is not a valid field","eventInherit" )
                            },
                            iRes := iRes + 1
                        }
                    },

					iComponent := iComponent + 1
				},
				iVersionedBO := iVersionedBO + 1
			}
		},

		// sample of removal of event flows in case of portfolio assignment event
		IF ( sEvent == "mxContractEventIPORTFOLIO_ASSIGNMENT" ) THEN
		{
			pEvtUDF := evtGetUserFields( pEvent ),
			sRemoveFee := udfGetString( pEvtUDF,"NOFEE" ),
			IF ( sRemoveFee == "Yes" ) THEN
			{
				iEvtFlowCount := evtGetNumberOfFlows( pEvent ),
				WHILE ( iEvtFlowCount > 0 ) DO
				{
					pEvtFlow := evtGetFlowAt( pEvent,iEvtFlow ),
					fAmount := evtFlowGetAmount( pEvtFlow ),
					evtRemoveFlowAt( pEvent,iEvtFlow ),
					iEvtFlowCount := iEvtFlowCount - 1
				}
			}
		},
		iNbEvents:=iNbEvents - 1
	}
};

{

	//Initialize the grid 
	pGridLine := pNull,
	//Initialize the Vostro selected reference
	fVostroSelectedReference := 0.0,
	//Initialize the Nostro selected reference
	fNostroSelectedReference := 0.0,
	//Initialize the list of matching Nostro rules
	pListOfNostroMatchingRules := pNull ,
	//Initialize the list of matching Vostro rules
	pListOfVostroMatchingRules := pNull,
	//Initialize the number of Vostro matching rule
	iNbOfVostroMatchingRules := 0,

	// Get the grid of SSIs selected for the trade
	pSIsGrid := mx.contract.ConfirmationFlows.GetSettlementInstructions( This ),
	// Get the number of line in this grid 
	iNbLines := settlementInstructionsGetLength( pSIsGrid ),

	//loop on every line of the grid
	iCount :=0 ,
	WHILE ( iCount < iNbLines ) DO
	{

		// Get the selected Vostro reference
		fVostroSelectedReference := siGetVostroReference( pGridLine ),
		// Get the selected Nostro reference
		fNostroSelectedReference := siGetNostroReference( pGridLine ),




		// Initialize Nostro settlement method
		sNostroRuleStlMethod := "",
		// Initialize Vostro settlement method
		sVostroRuleStlMethod := "",
		// Initialize the Nostro candidate
		pSIMaxScore := pNull,
		//Initialize the Vostro rule 
		pSiVostroRule := pNull,
		//Iterate through the grid lines
		pGridLine := settlementInstructionsGetSIAt( pSIsGrid,iCount ),
		// loop on the Vostro rules 
        // Get the list of the Nostro matching rules
		pListOfNostroMatchingRules := siGetNostroMatchingRules( pGridLine ),
        // Get the list of the Vostro matching rules
		pListOfVostroMatchingRules := siGetVostroMatchingRules( pGridLine ),
        // Get the number of the line of the Nostro matching rules list
		iNbOfNostroMatchingRules := siRulesGetLength( pListOfNostroMatchingRules ),
        // Get the number of the line of the Vostro matching rules list
		iNbOfVostroMatchingRules := siRulesGetLength( pListOfVostroMatchingRules ),
        iVostroCount := 0, 

			//Iterate through the Vostro rules 
            fVostroRef := siGetVostroReference(pGridLine), 

			pVosLoopUdf := siGetVostroUserFields(pGridLine),
			// Get First Intermediary

            sVosFirstIntLoop := udfGetString(pVosLoopUdf,"INT1_LBL"),


            // Get Legal Entity
            pLeg:=mx.contract.ConfirmationFlows.GetLeg(This),
            pContract := legGetContractAt( pLeg,iContract ),
            pComponent := legGetMainComponent( pContract ),
            sSourcePortfolio := legGetString( pComponent, "Portfolio" ),
			sLegalEntity := ptfGetLegalEntity( sSourcePortfolio ),
            sUsageMurabaha:=legGetUsage(pComponent),
            iSign := siGetSign(pGridLine),
            iNature := siGetNature(pGridLine),
            fNostro := 24,

            /*IF ( iNbOfNostroMatchingRules == 0) THEN
			     {
                  ThrowError("Error","Empty Nostro SSI's. Please contract TROPS.")
                  },
            IF ( iNbOfVostroMatchingRules == 0) THEN
                 {
                  ThrowError("Error","Empty Vostro SSI's. Please contract TROPS.")
                  },*/


                 //FT NOSTRO NOSTRO
                 IF legGetTypology(pLeg) == "FT Nostro Nostro" OR legGetTypology(pLeg) == "Nostro Voucher" THEN
                 {
                  pContract:=legGetFatherContract(pLeg),
                  pTradeUDF:=legGetUserFields(pLeg),
                  sLegNumber:=udfGetString(pTradeUDF,"SCF_LEG"),
                  IF sLegNumber == "2" THEN
            	  {
                    iCount:=0,
                    iNbLines := settlementInstructionsGetLength( pSIsGrid ),
                     pGridLine := settlementInstructionsGetSIAt( pSIsGrid,0 ),
                     IF legGetTypology(pLeg) == "FT Nostro Nostro" THEN
                     {
                         sNostroSelectedReference := udfGetString(pTradeUDF,"VOSTRO_REF"),
                         sVostroSelectedReference := udfGetString(pTradeUDF,"NOSTRO_REF")
                     }
                     ELSE
                     {
                         sVostroSelectedReference := udfGetString(pTradeUDF,"VOSTRO_REF"),
                         sNostroSelectedReference := udfGetString(pTradeUDF,"NOSTRO_REF")
                     },

                        pGridLine := settlementInstructionsGetSIAt( pSIsGrid,iCount ),                
                        pListOfNostroMatchingRules := siGetNostroMatchingRules( pGridLine ),
                        pListOfVostroMatchingRules := siGetVostroMatchingRules( pGridLine ),
                        iNbNostroMatchingRules := siRulesGetLength(pListOfNostroMatchingRules), 
                        iNbVostroMatchingRules := siRulesGetLength(pListOfVostroMatchingRules), 
                        iNostroCount:=0,
                        iVostroCount:=0,

                            WHILE iNostroCount < iNbNostroMatchingRules DO
                            {
                                pSiNostroRule := siRulesGetRuleAt( pListOfNostroMatchingRules,iNostroCount ),
                                pNosUdf := siRuleGetUserFields(pSiNostroRule),
                                sSiNostroRef := udfGetString( pNosUdf,"CSNS_ACC" ), 

                                iNostroCount:= iNostroCount + 1,
                                IF sSiNostroRef == sNostroSelectedReference  THEN
                                {
                                    iNostroCount := iNbNostroMatchingRules + 1,
                                    siSetCustomizedNostro(pGridLine, pSIsGrid, pSiNostroRule)
                                }    
                            },
                            WHILE iVostroCount < iNbVostroMatchingRules DO
                            {
                                pSiVostroRule := siRulesGetRuleAt( pListOfVostroMatchingRules,iVostroCount ),
                                pVosUdf := siRuleGetUserFields(pSiVostroRule),
                                sSiVostroRef:= udfGetString( pVosUdf,"BEN_ACC" ), 

                                iVostroCount:= iVostroCount + 1,
                                IF sSiVostroRef == sVostroSelectedReference  THEN
                                {
                                    iVostroCount := iNbVostroMatchingRules + 1,
                                    siSetCustomizedVostro(pGridLine, pSIsGrid, pSiVostroRule)
                                }    
                            }
                        }
                 },      


		// Next line
		iCount := iCount + 1
	}
};

// mx.msl.event.completion.ALL.FtpIE

/*
MXpress
This rules defaults the internal counterparty in case of an inter entity FTP package.

Used algorithm
Retreives the main component of the package
IF one internal portfolio is stored THEN
	Switch the trade to Internal
    Set the internal counterparty

Version 1.0
This rules defaults the internal counterparty in case of an inter entity FTP package.

*/

{
	pEvent := This,
	pVB0 := evtGetVersionedBOAt( pEvent,0 ),
	pLeg := evtVersionedBOGetNew( pVB0 ),
	pMainComponent := legGetMainComponent( pLeg ),
    	sRegistration := legGetRegistration( pMainComponent ),
    	sFOPInternalPortfolio := legGetFOPInternalPortfolio( pMainComponent ),

    	//Tells whether the current contract is an inter-entity FTP loan
   	 bIsContractFTP_IE := FALSE,
   	 IF ( sRegistration == "Loans/Deposits" AND sFOPInternalPortfolio <> "" ) THEN
    	{
        		callPreTradeFormula( sOutput,pMainComponent,"mx.routing.FXMM.Pricing.Rout-FTP" ),
       		 bIsContractFTP_IE := sOutput == "FTP"
	},

    	IF ( bIsContractFTP_IE ) THEN
    	{
    		legSetString( pMainComponent,"Internal","Yes" ),
       	 legSetString( pMainComponent,"Counterpart",sFOPInternalPortfolio ) 
   	 }
};

// Deliverable.mx.completion.ALL.KeepTradeDateSI

/*
MXpress
Keep SI selected based on trade date on deliverable, even if the trade date SI is not valid at deliverable value Date
User should duplicate the SSI he wants to keep (the one assigned at trade date) and set its start date = previous SI end date and set its code to "TRADE DATE"


Version 1.0
*/
{
	// Initialisation
	pPackage := This,
	pFlow := pNull,
	pComponent := pNull,
	pFlows := pNull,
	iFlow := 0,
	iFlows := 0,
	bEligible := FALSE,
    sKeepTradeDateCode:="TRADE DATE",

	//Get the list of flows
	pFlows := mx.deliverable.Package.GetFlows( pPackage ),
	iFlows := mx.system.collection.GetLength( pFlows ),
	pFlow := mx.system.collection.GetElementAt( pFlows,0 ),
	pComponent := mx.deliverable.Cash.GetComponent( pFlow ),
	dTradeDate := legGetTradingDate( pComponent ),

	// to add the conditions of eligibility to this process from the trade when this behavior is required
    // IF ... THEN bEligible := TRUE

	IF ( bEligible ) THEN
	{
		WHILE( iFlow < iFlows ) DO
		{
			mx.deliverable.Cash.CheckRoute( pFlow ),
			pSSIs:= mx.deliverable.Cash.GetVostroRouteMatchingRules( pFlow ),
			iSSI := 0,
			iSSIs := siRulesGetLength( pSSIs ),
			WHILE ( iSSI<iSSIs ) DO
			{
				pSI := siRulesGetRuleAt( pSSIs,iSSI ),
				sCode := siRuleGetCode( pSI ),
				dStartDate := siRuleGetStartDate(pSI),
				IF ( ( dTradeDate < dStartDate ) AND ( sCode == sKeepTradeDateCode ) ) THEN
				{
					fSIRef := siRuleGetReference( pSI ),
					mx.deliverable.Cash.SetVostroRouteCustomized( pFlow,fSIRef )
				},		
				iSSI := iSSI + 1
			}, 
			iFlow := iFlow + 1
		}
	}
};

// mx.preTrade.completion._Functions.IRD.IRSClearingEligibility

/*
Version 1.0
*/

{
	pLeg := This,
	pComponent := legGetComponentAt( pLeg,0 ),
	sContext := getArgAsString( 0 ),

	sLeg1 := legGetString( pComponent,"Leg type" ),
	sLeg2 := legGetString( pComponent,"Leg type2" ),
	dStart := legGetDate( pComponent,"Start" ),
	sZC1 := legGetString( pComponent,"Payment Freq" ),
	sZC2 := legGetString( pComponent,"Payment Freq2" ),
	sTypology := legGetString( pComponent,"Typology" ),
	dMaturity := legGetDate( pComponent,"Maturity" ),
	sCurrency1 := legGetString( pComponent,"Currency1" ),
	sCurrency2 := legGetString( pComponent,"Currency2" ),
	sCustomizedFlows := legGetString( pComponent,"Customized Flows" ),
	sStubPeriod := legGetString( pComponent,"Stub Period" ),

	sNotEligibleReason := "",
	sNotEligibleReasonVNSIndexCCY1 := "",
	sNotEligibleReasonVNSIndexCCY2 := "",
	sNotEligibleReasonMaturity := "",
	sNotEligibleReasonFixBasis1 := "",
	sNotEligibleReasonFixBasis2 := "",
	sNotClearingEligibilityISDAFlDC1 := "", 
	sNotClearingEligibilityISDAFlDC2 := "",
	sNotEligibleReasonAddPayments := "",
	sNotEligibleReasonPayFreq1 := "",
	sNotEligibleReasonPayFreq2 := "",
	sNotEligibleReasonTenRes1 := "",
	sNotEligibleReasonTenRes2 := "",
	sNotEligibleReasonFlDC1 := "",
	sNotEligibleReasonFlDC2 := "",
	sNotEligibleReasonFixing1 := "",
	sNotEligibleReasonFixing2 := "",
	sNotEligibleReasonBDC1 := "",
	sNotEligibleReasonBDC2 := "",
	sNotEligibleReasonNot := "",
	sNotEligibleReasonStub := "",
	sNotEligibleReasonCal1 := "",
	sNotEligibleReasonCal2 := "",

	// Index Formatting. The Index label in MX is customizable, so it has to be formatted accordingly to the LUT and the CCPs.
	// If MX users wish to change MXpress index labels, they have also to modify accordingly the LUT.
	IF ( sZC1 == "Zero coupon" ) THEN
		sZeroCoupon1 := "ZC",
	IF ( sZC2 == "Zero coupon" ) THEN
		sZeroCoupon2 := "ZC",

	IF ( sLeg1 == "Floating" ) THEN
	{
		sIndex1 := legGetString( pComponent,"Index1" ),
		callPreTradeFormula( sIndex1Eligibility,pLeg,"mx.completion._Functions.IRD.ClearingFormatIndex",sContext,sCurrency1,sIndex1 ),
		IF ( sIndex1 <> sIndex1Eligibility ) THEN
		{
			sIndex1 := strToken(sIndex1Eligibility,"$",0 ),
			sClearingEligibilityIndex := strToken(sIndex1Eligibility,"$",1 ),
			sIndex1Check := legGetString( pComponent,"Index1" )
		},
		callPreTradeFormula( sNotEligibleReasonVNSIndexCCY1,pLeg,"mx.completion._Functions.IRD.IRSClearingVNSIndexCCYPerLeg",sContext,sIndex1Check,sCustomizedFlows,sZeroCoupon1,sZeroCoupon2 )
	},
	IF ( sLeg2 == "Floating" ) THEN
	{
		sIndex2 := legGetString( pComponent,"Index2" ),
		callPreTradeFormula( sIndex2Eligibility,pLeg,"mx.completion._Functions.IRD.ClearingFormatIndex",sContext,sCurrency2,sIndex2 ),
		IF ( sIndex2 <> sIndex2Eligibility ) THEN
		{
			sIndex2 := strToken(sIndex2Eligibility,"$",0 ),
			sClearingEligibilityIndex := strToken(sIndex2Eligibility,"$",1 ),
			sIndex2Check := legGetString( pComponent,"Index2" )
		},
		callPreTradeFormula( sNotEligibleReasonVNSIndexCCY2,pLeg,"mx.completion._Functions.IRD.IRSClearingVNSIndexCCYPerLeg",sContext,sIndex2Check,sCustomizedFlows,sZeroCoupon1,sZeroCoupon2 )
	},

	// Check if trade is a Basis swap. Note: different indexes can be used in each leg for certain ccys.
	sBasisSwap := "",
	IF ( ( sLeg1 == "Floating" ) AND ( sLeg2 == "Floating" ) ) THEN
	{
		IF ( sIndex1 == sIndex2 ) THEN
			sBasisSwap := "Basis1"
		ELSE
			sBasisSwap := "Basis2"
	},

	IF ( ( ( sContext == "SwapClear" ) AND ( legGetString( pComponent, "pf_NotEligibleReasonSC" ) == "" ) )
	OR ( ( sContext == "CME" ) AND ( legGetString( pComponent, "pf_NotEligibleReasonCME" ) == "" ) ) ) THEN
	{
		// Notional Amount Check
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			fNotional := legGetNumeric( pComponent,"Nominal" ),
			IF ( ( fNotional > 0.01 ) AND ( fNotional < 99999999999.99 ) ) THEN
				sClearingEligibilityNot := "Notional"
			ELSE
				sNotEligibleReasonNot := "#Notional "
		},

		// Maturity Check
		callPreTradeFormula( sNotEligibleReasonMaturityTmp,pLeg,"mx.completion._Functions.IRD.ClearingMaturity",sContext,sCurrency1,sBasisSwap,"" ),
		IF strStartsWith( sNotEligibleReasonMaturityTmp,"Not Eligible" ) THEN
		{
			IF ( sContext == "SwapClear" ) THEN
				sEligibilityCheckSC := "Not Eligible"
			ELSE IF ( sContext == "CME" ) THEN
				sEligibilityCheckCME := "Not Eligible"
		}
		ELSE
			sNotEligibleReasonMaturity := strToken(sNotEligibleReasonMaturityTmp,"$",0 ),

		// Based on the Master Agreement signed witht the counterparty, the fixed leg basis count has to be checked
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			sLegalEntity := legGetString( pComponent,"Legal Entity" ),
			sCounterparty := legGetString( pComponent,"Counterpart" ),
			pMA := agreementGetMA( dStart,"COUNTERPART",sCounterparty, "TYPOLOGY", sTypology,"LEGAL ENTITY",sLegalEntity ),
			pISDA := legGetMA( pLeg ),
			IF ( ( NOT isNull( pMA ) ) AND ( NOT isNull( pISDA ) ) ) THEN
			{
				legSetMA( pLeg, pMA ),
				sISDA := mx.statics.organization.legal.Ma.GetLabel( pMA ),

				// Fixed Leg day Count Check
				sFixDC1 := legGetString( pComponent,"Rate convention" ),
				callPreTradeFormula( sNotEligibleReasonFixBasis1,pLeg,"mx.completion._Functions.IRD.IRSClearingISDADayCountPerLeg",sContext,sISDA,sLeg1,sFixDC1 ),

				sFixDC2 := legGetString( pComponent,"Rate convention2" ),
				callPreTradeFormula( sNotEligibleReasonFixBasis2,pLeg,"mx.completion._Functions.IRD.IRSClearingISDADayCountPerLeg",sContext,sISDA,sLeg2,sFixDC2 ),

				IF ( sContext == "CME" ) THEN
				{
					// Rate day Count Check
					sRateDC1 := legGetString( pComponent,"Rate convention" ),
					callPreTradeFormula( sNotClearingEligibilityISDAFlDC1,pLeg,"mx.completion._Functions.IRD.IRSClearingISDADayCountPerLeg",sContext,sISDA,sLeg1,sRateDC1 ),

					sRateDC2 := legGetString( pComponent,"Rate convention2" ),
					callPreTradeFormula( sNotClearingEligibilityISDAFlDC2,pLeg,"mx.completion._Functions.IRD.IRSClearingISDADayCountPerLeg",sContext,sISDA,sLeg2,sRateDC2 )
				}
			}
		},

		//Check if there are Additional Flows
		IF ( sContext == "SwapClear" ) THEN
		{
			sAdditional1 := legGetString( pComponent,"Additional flows enable" ),
			IF ( sAdditional1 == "Yes" ) THEN
			{
				IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
				{
					// CCP accepts maximum 6 additional flows
					callPreTradeFormula( sNotEligibleReasonAddPayments,pLeg,"mx.completion._Functions.IRD.IRSClearingAddPayments",dStart,dMaturity,6,sCurrency1 )
				}
				ELSE IF ( sTypology == "ZC Inflation Swap" ) THEN
				{
					// CCP accepts maximum 1 additional flow
					callPreTradeFormula( sNotEligibleReasonAddPayments,pLeg,"mx.completion._Functions.IRD.IRSClearingAddPayments",dStart,dMaturity,1,sCurrency1 )
				}
			}
		},

		// Check Business day Convention
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			sBDConvention1 := legGetString( pComponent,"Calc driving schedule" ),
			sBDConvention2 := legGetString( pComponent,"Calc driving schedule2" ),
			callPreTradeFormula( sNotEligibleReasonBDC1,pLeg,"mx.completion._Functions.IRD.ClearingBusinessDayPerLeg",sContext,sTypology,sBDConvention1 ),
			callPreTradeFormula( sNotEligibleReasonBDC2,pLeg,"mx.completion._Functions.IRD.ClearingBusinessDayPerLeg",sContext,sTypology,sBDConvention2 )
		},

		// Check if fixing leg, tenor and payment frequency are in line with CCP
		IF ( legGetString ( pComponent,"Fix schedule" ) == "Equal to" ) THEN
			sFixingLag1 := "0"
		ELSE
			sFixingLag1 := legGetString ( pComponent,"Fix deduction formula" ),

		IF ( legGetString ( pComponent,"Fix schedule 2" ) == "Equal to" ) THEN
			sFixingLag2 := "0"
		ELSE
			sFixingLag2 := legGetString ( pComponent,"Fix deduction formula2" ),

		// Leg1 Check if fixing lag, tenor and payment frequency are in line with CCP
		sCalcFreq1 := legGetString ( pComponent,"Calculation Frequency" ),
		IF ( sLeg1 == "Floating" ) THEN
		{
			IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) ) THEN
			{
				// Tenor and Reset frequency Check
				// The "Floating Leg Reset Frequency" defines how often the interest rate on the floating leg is reset. 
				// For example, a value of "1M" means that the interest rate on the floating leg is reset every month.  
				// The Floating Rate Index Tenor must not be larger than the Floating Leg Reset Frequency.
				// e.g. a swap is not eligible if the Floating Rate Index Tenor (Regular Period) is 6M and the Floating Leg Reset Frequency is 1M.

				// Check if the Leg of the basis swap is OIS or BOR
				sIndTen1 := legGetString ( pComponent,"Index tenor" ),
				callPreTradeFormula( sNotEligibleReasonTenRes1,pLeg,"mx.completion._Functions.IRD.ClearingTenorResetPerLeg",sContext,sBasisSwap,sCurrency1,sIndex1,sTypology,sUsage,sIndTen1,sVNS,sCalcFreq1 ),

				// Fixing and fixing lag check
				sFixingMode1 := legGetString ( pComponent,"Fixing mode1" ),
				callPreTradeFormula( sNotEligibleReasonFixing1,pLeg,"mx.completion._Functions.IRD.IRSClearingFixingPerLeg",sContext,sCurrency1,sIndex1,sTypology,sUsage,sBasisSwap,sFixingLag1,sFixingMode1 )
			},

			// Floating Leg Day Count Check
			IF ( sContext == "SwapClear" ) THEN
			{
				sRateConv1 := legGetString ( pComponent,"Rate convention" ),
				callPreTradeFormula( sNotEligibleReasonFlDC1,pLeg,"mx.completion._Functions.IRD.ClearingFloatDayCountPerLeg",sContext,sLeg1,sCurrency1,sTypology,sRateConv1 )
			}
		},

		// Leg2 Check if fixing lag, tenor and payment frequency are in line with CCP
		sCalcFreq2 := legGetString ( pComponent,"Calculation Frequency2" ),
		IF ( sLeg2 == "Floating" ) THEN
		{
			IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) ) THEN
			{
				// Tenor and Reset frequency Check
				sIndTen2 := legGetString ( pComponent,"Index tenor2" ),
				callPreTradeFormula( sNotEligibleReasonTenRes2,pLeg,"mx.completion._Functions.IRD.ClearingTenorResetPerLeg",sContext,sBasisSwap,sCurrency2,sIndex2,sTypology,sUsage,sIndTen2,sVNS,sCalcFreq2 ),

				// Fixing and fixing lag check
				sFixingMode2 := legGetString ( pComponent,"Fixing mode2" ),
				callPreTradeFormula( sNotEligibleReasonFixing2,pLeg,"mx.completion._Functions.IRD.IRSClearingFixingPerLeg",sContext,sCurrency2,sIndex2,sTypology,sUsage,sBasisSwap,sFixingLag2,sFixingMode2 )
			},

			// Floating Leg Day Count Check
			IF ( sContext == "SwapClear" ) THEN
			{
				sRateConv2 := legGetString ( pComponent,"Rate convention2" ),
				callPreTradeFormula( sNotEligibleReasonFlDC2,pLeg,"mx.completion._Functions.IRD.ClearingFloatDayCountPerLeg",sContext,sLeg2,sCurrency2,sTypology,sRateConv2 )
			}
		},

		// Payment Frequency Check on both legs
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			sPayFreq1 := legGetString ( pComponent,"Payment Frequency" ),
			callPreTradeFormula( sNotEligibleReasonPayFreq1,pLeg,"mx.completion._Functions.IRD.IRSClearingPayFreqPerLeg",sContext,sLeg1,sTypology,sCurrency1,sBasisSwap,sZeroCoupon1,sPayFreq1,sCalcFreq1 ),

			sPayFreq2 := legGetString ( pComponent,"Payment Frequency2" ),
			callPreTradeFormula( sNotEligibleReasonPayFreq2,pLeg,"mx.completion._Functions.IRD.IRSClearingPayFreqPerLeg",sContext,sLeg2,sTypology,sCurrency2,sBasisSwap,sZeroCoupon2,sPayFreq2,sCalcFreq2 )
		},

		// Stub Check
		// CCP accepts trades where the the floating rate for the stub period is interpolated (straight line) between the two nearest floating rate index tenors.
		sStubTenors := "",
		dStart := legGetDate( pComponent,"Start" ),

		IF ( sContext == "SwapClear" ) THEN
		{
			// Different Tenors are eligible for EURIBOR trades if the first fixing is before 01-Nov-13, so with the start date strictly before 03-Nov-13
			IF ( sIndex1 == "EURIBOR" OR sIndex2 == "EURIBOR" ) THEN
			{
				IF ( convertDToNumeric( dStart ) < 20131103.00 ) THEN
				{
					IF ( ( sZeroCoupon1 == "ZC" ) OR ( sZeroCoupon2 == "ZC" ) ) THEN
						sZeroCoupon := "ZC",

					IF ( sZeroCoupon <> "" ) THEN
						sZeroCoupon := sZeroCoupon + " Nov13"
					ELSE
						sZeroCoupon := " Nov13",

					IF ( sBasisSwap <> "" ) THEN
						sBasisSwap := sBasisSwap + " Nov13"
					ELSE
						sBasisSwap := " Nov13"
				}
			}
		},
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			pStreams := legGetStreams ( pComponent ),
			pStream0 := streamsGetStream( pStreams,0,0 ),
			pStream1 := streamsGetStream( pStreams,0,1 ),
			IF ( ( NOT isNull( pStreams ) ) AND ( NOT isNull( pStream0 ) ) AND ( NOT isNull( pStream1 ) ) ) THEN
			{
				IF ( sStubPeriod == "None" ) THEN
					sClearingEligibilityStub := "Stub"
				ELSE IF ( sStubPeriod <> "None" ) THEN
				{
					IF ( sTypology == "OIS" AND sBasisSwap <> "Basis2" ) THEN
						sNotEligibleReasonStub := "#Stub ",

					IF ( sNotEligibleReasonStub == "" ) THEN
					{
						fCalcFreq1 := convertSToNumeric( sCalcFreq1 ),
						fCalcFreq2 := convertSToNumeric( sCalcFreq2 ),
						fYearDD := 365.33,
						fMonthDD := 30.0,
						fWeekDD := 7.0,

						// Maturity (necessary to compute Stub lenght)
						iMat := toInt( dMaturity - dStart ),
						fMat := convertIToNumeric( iMat ),
						IF ( ( sLeg1 == "Floating" ) AND ( sLeg2 == "Floating" ) ) THEN
						{
							fFrequencyP1 := fCalcFreq1 * fYearDD / 12.0,
							fFrequencyP2 := fCalcFreq2 * fYearDD / 12.0,
							fFrequencyP := MAX( fFrequencyP1,fFrequencyP2 )
						}
						ELSE IF ( sLeg1 == "Floating" ) THEN
							fFrequencyP := fCalcFreq1 * fYearDD / 12.0
						ELSE IF ( sLeg2 == "Floating" ) THEN
							fFrequencyP := fCalcFreq2 * fYearDD / 12.0,

						fPeriods := fMat / fFrequencyP,
						fStubP := fPeriods - round( fPeriods,0 ),
						fStubDD := fStubP * fFrequencyP,
						IF ( fStubDD < 30.0 ) THEN
						{
							fStubWW := roundnearest( fStubDD/fWeekDD,0 ),
							fStubPeriod := fStubWW / 4.0
						}
						ELSE
							fStubPeriod := roundnearest( fStubDD/fMonthDD,0 ),

						IF ( ( sLeg1 == "Floating" ) OR ( sLeg2 == "Floating" ) ) THEN
						{
							pStub01 := streamGetUpfrontBrokenPeriodFirstIndex( pStream0 ),
							pStub02 := streamGetUpfrontBrokenPeriodSecondIndex( pStream0 ),
							pStub11 := streamGetUpfrontBrokenPeriodFirstIndex( pStream1 ),
							pStub12 := streamGetUpfrontBrokenPeriodSecondIndex( pStream1 ),
							pStub03 := streamGetInArrearsBrokenPeriodFirstIndex( pStream0 ),
							pStub04 := streamGetInArrearsBrokenPeriodSecondIndex( pStream0 ),
							pStub13 := streamGetInArrearsBrokenPeriodFirstIndex( pStream1 ),
							pStub14 := streamGetInArrearsBrokenPeriodSecondIndex( pStream1 )
						},

						sStub01 := indexGetIndexLabel( pStub01 ),
						sStub02 := indexGetIndexLabel( pStub02 ),
						sStub11 := indexGetIndexLabel( pStub11 ),
						sStub12 := indexGetIndexLabel( pStub12 ),
						sStub03 := indexGetIndexLabel( pStub03 ),
						sStub04 := indexGetIndexLabel( pStub04 ),
						sStub13 := indexGetIndexLabel( pStub13 ),
						sStub14 := indexGetIndexLabel( pStub14 ),

						sIndex1Check := legGetString( pComponent,"Index1" ),
						sIndex2Check := legGetString( pComponent,"Index2" ),
						IF ( sStubPeriod == "Up front" ) THEN 
							IF ( ( sStub01 == sIndex1Check )
							OR ( sStub02 == sIndex1Check )
							OR ( sStub11 == sIndex2Check )
							OR ( sStub12 == sIndex2Check ) ) THEN
								sNotEligibleReasonStub := ""
							ELSE
								sNotEligibleReasonStub := ( "#Stub " ),

						IF ( sStubPeriod == "In arrears" ) THEN
						{
							IF ( ( sStub03 <> sIndex1Check )
							OR ( sStub04 <> sIndex1Check )
							OR ( sStub13 <> sIndex2Check )
							OR ( sStub14 <> sIndex2Check ) ) THEN
								sNotEligibleReasonStub := ""
							ELSE
								sNotEligibleReasonStub := ( "#Stub " )
						},

						IF ( ( sStubPeriod == "Both ends (forward)" )
						OR ( sStubPeriod == "Both ends (backward)" ) ) THEN
						{
							IF ( ( sStub01 <> sIndex1Check )
							OR ( sStub02 <> sIndex1Check )
							OR ( sStub11 <> sIndex2Check )
							OR ( sStub12 <> sIndex2Check )
							OR ( sStub03 <> sIndex1Check )
							OR ( sStub04 <> sIndex1Check )
							OR ( sStub13 <> sIndex2Check )
							OR ( sStub14 <> sIndex2Check ) ) THEN
								sNotEligibleReasonStub := ""
							ELSE
								sNotEligibleReasonStub := "#Stub "
						}
					},

					IF ( ( sNotEligibleReasonStub == "" ) AND ( fStubPeriod == fCalcFreq1 ) OR ( fStubPeriod == fCalcFreq2 ) ) THEN
						sClearingEligibilityStub := "Stub"
					ELSE
					{
						sBroken1 := legGetString ( pComponent,"Broken rate" ),
						callPreTradeFormula( sClearingEligibilityStubLeg1,pLeg,"mx.completion._Functions.IRD.IRSClearingStubPerLeg",sLeg1,sBroken1,sContext,sTypology,sCurrency1,sIndex1,sBasisSwap,sZeroCoupon,sStubPeriod,sStub01,sStub02,sStub03,sStub04,fStubDD,fStubPeriod,fCalcFreq1 ),

						sBroken2 := legGetString ( pComponent,"Broken rate2" ),
						callPreTradeFormula( sClearingEligibilityStubLeg2,pLeg,"mx.completion._Functions.IRD.IRSClearingStubPerLeg",sLeg2,sBroken2,sContext,sTypology,sCurrency1,sIndex2,sBasisSwap,sZeroCoupon,sStubPeriod,sStub11,sStub12,sStub13,sStub14,fStubDD,fStubPeriod,fCalcFreq2 ),

						sClearingEligibilityStub := sClearingEligibilityStubLeg1 + sClearingEligibilityStubLeg2
					}
				}
			},
			IF ( strContain( sClearingEligibilityStub,"Stub" ) == FALSE ) THEN
				sNotEligibleReasonStub := "#Stub "
		},

		// Financial Centre : holidays and payment eligible calendars
		IF ( ( sTypology == "IRS" ) OR ( sTypology == "OIS" ) )THEN
		{
			IF ( sLeg1 == "Floating" ) THEN
			{
				sPayCalendar1 := legGetString( pComponent,"Union Pay Calendar" ),
				sFixCalendar1 := legGetString( pComponent,"Union Fxg Calendar" ),
				callPreTradeFormula( sNotEligibleReasonCal1,pLeg,"mx.completion._Functions.IRD.ClearingCalendarPerLeg",sContext,sCurrency1,sIndex1,sPayCalendar1,sFixCalendar1 )
			},

			IF ( sLeg2 == "Floating" ) THEN
			{
				sPayCalendar2 := legGetString( pComponent,"Union Pay Calendar2" ),
				sFixCalendar2 := legGetString( pComponent,"Union Fxg Calendar2" ),
				callPreTradeFormula( sNotEligibleReasonCal2,pLeg,"mx.completion._Functions.IRD.ClearingCalendarPerLeg",sContext,sCurrency2,sIndex2,sPayCalendar2,sFixCalendar2 )
			}
		},

		// Final Check
		sNotEligibleReason := sNotEligibleReasonVNSIndexCCY1 + sNotEligibleReasonVNSIndexCCY2 + sNotEligibleReasonMaturity + sNotEligibleReasonFixBasis1 + sNotEligibleReasonFixBasis2 +
							sNotClearingEligibilityISDAFlDC1 + sNotClearingEligibilityISDAFlDC2 + sNotEligibleReasonAddPayments + sNotEligibleReasonPayFreq1 + sNotEligibleReasonPayFreq2 +
							sNotEligibleReasonTenRes1 + sNotEligibleReasonTenRes2 + sNotEligibleReasonFlDC1 + sNotEligibleReasonFlDC2 + sNotEligibleReasonFixing1 + sNotEligibleReasonFixing2 +
							sNotEligibleReasonBDC1 + sNotEligibleReasonBDC2 + sNotEligibleReasonNot + sNotEligibleReasonStub + sNotEligibleReasonCal1 + sNotEligibleReasonCal2,
		setReturnValue( sNotEligibleReason )
	}
};

// mx.preTrade.completion._Functions.IRD.IRSClearingFixingPerLeg

/*
Version 1.0
*/

{
	sContext := getArgAsString( 0 ),
	sCurrency := getArgAsString( 1 ),
	sIndex := getArgAsString( 2 ),
	sTypology := getArgAsString( 3 ),
	sUsage := getArgAsString( 4 ),
	sBasisSwap := getArgAsString( 5 ),
	sFixingLagLeg := getArgAsString( 6 ),
	sFixingMode := getArgAsString( 7 ),

	pFixingLag := lookupResults( "MX.IRD.ClearingFixinglag",sContext,
								 "Clearing Eligible CCYs",sCurrency,
								 "CL_EL_INDEX",sIndex ),
	sFixingLag := "",
	sClearingEligibilityFixing := "",
	sNotEligibleReasonFixing := "",

	IF ( NOT isNull( pFixingLag ) ) THEN
	{
		sFixingLag := lookupResultsGetString( pFixingLag,0,0 ),
		IF ( sContext == "SwapClear" ) THEN
		{
			IF ( ( sTypology == "OIS" ) AND ( sUsage == "Compound" ) AND ( sBasisSwap == "" ) ) THEN
				sClearingEligibilityFixing := "Fixing"
			ELSE IF ( ( sTypology == "OIS" ) AND ( sUsage == "Compound" ) AND ( sBasisSwap <> "" ) ) THEN
			{
				IF ( strContain( sIndex, "BOR" ) == TRUE ) THEN
				{
					IF ( ( strContain( sFixingLagLeg,sFixingLag ) == TRUE ) AND ( sFixingMode == "In advance" ) ) THEN
						sClearingEligibilityFixing := "Fixing"
				}
				ELSE
					sClearingEligibilityFixing := "Fixing"
			}
			ELSE IF ( sTypology == "IRS" ) THEN
			{
				IF ( ( sFixingMode == "In advance" ) AND ( strContain( sFixingLagLeg, sFixingLag ) == TRUE ) ) THEN
					sClearingEligibilityFixing := "Fixing"
			}
		}
		ELSE IF ( sContext == "CME" ) THEN
		{
			IF ( ( sTypology == "OIS" ) AND ( sUsage == "Compound" ) ) THEN
				sClearingEligibilityFixing := "Fixing"
			ELSE
			{
				IF ( sTypology == "IRS" ) THEN
				{
					IF ( ( sBasisSwap == "" ) AND ( sFixingMode == "In advance" ) AND ( strContain( sFixingLagLeg, sFixingLag ) == TRUE ) ) THEN
						sClearingEligibilityFixing := "Fixing",
					IF ( sBasisSwap <> "" AND strContain( sFixingLagLeg, sFixingLag ) == TRUE ) THEN
						sClearingEligibilityFixing := "Fixing"
				}
			}
		}
	},
	IF ( strContain( sClearingEligibilityFixing,"Fixing" ) == FALSE ) THEN
		sNotEligibleReasonFixing := "#Fixing ",

	setReturnValue( sNotEligibleReasonFixing )
};

// mx.preTrade.completion._Functions.IRD.IRSClearingSpreadPerLeg

/*
Version 1.0
*/

{
	sLeg := getArgAsString( 0 ),
	fSpread := getArgAsString( 1 ),

	sClearingEligibilitySprd := "",
	sNotEligibleReasonSprd := "",

	IF ( sLeg == "Floating" ) THEN
	{ 
		IF ( fSpread == 0.00 ) THEN
			sClearingEligibilitySprd := "Spread"
		ELSE
			sNotEligibleReasonSprd := "#Spread "
	},
	setReturnValue( sNotEligibleReasonSprd )
};

// mx.preTrade.routing.FXMM.Pricing.Rout-FTP

/*
MXpress

Router for FTP package

Version 1.1
Add sOutput as a return value

Version 1.0
The aim is to send a FTP package in the right workflow in order to handle properly the Mirroring.

*/

{
	pLeg := This,
	//Field Initialization/Reset
	sOutput := "Simple",
	pComponent := legGetMainComponent( pLeg ),
	pContract := legGetFatherContract( pComponent ),
	sContractRegistration := legGetRegistration( pContract ),

	// To know if it is a FTP
	IF ( sContractRegistration == "Loans/Deposits" ) THEN
	{
		sPortfolio:= legGetString( pContract,"Portfolio" ),
		IF ( sPortfolio <> "" ) THEN
		{
			pPortfolioUdf := ptfGetUserFields( sPortfolio ),
			sFtpPortal := udfGetString( pPortfolioUdf,"FTP_PORTAL" ),
			IF ( sFtpPortal == "Yes" ) THEN
			{
				sOutput := "FTP"
			}
		}
	},

    setReturnValue( sOutput )  
};

{
    pLeg := This,

    iNbContracts := 0,
    iNbContracts := legGetNumberOfContracts( pLeg ),
    iContract := 0,  
    pPackage := legGetFatherPackage( pLeg ),
    sPackageRegistrationLabel := legGetRegistrationLabel( pPackage ),
    bInterEntitySPV:=FALSE,
 	sSourceClass := properties.Get( "mx.preTrade.BO.source.class" ),
    sGroup:=sysGetGroup(),
  //  sSourceModule:=legGetSourceModule(pLeg),


    WHILE ( iContract < iNbContracts ) DO 
    {

        pContract := legGetContractAt( pLeg,iContract ),
        pComponent := legGetMainComponent( pContract ),
        pMainComponent := legGetMainComponent( pLeg ),
        sFamilyGroup:=legGetProductGroup(pComponent),
    	pGroupResults := lookupResults("MX.ALL.UserGroupProfile","ALL","USER_GROUP",sGroup),
		sGroupType := lookupResultsGetString(pGroupResults,0,0),
		sCounterparty := legGetString(pComponent,"Counterpart"),
        sTypology := legGetTypology(pComponent),
        sUsage:= legGetUsage(pComponent),
        sGroup := sysGetGroup(),
        sSource := "trasset",

        //Addition for BAB - for Accounting - fill Product code UDF at trade level from BAB.ALL.ProductCode.ALL LookupTable
        iNbComponent := legGetNumberOfComponents( pContract ),
        iNbComp:=0,

        //BAB addition for Dual Strategy
        sFamilyType := legGetProductFamily(pComponent),
        IF (sFamilyType == "IRD" OR sFamilyType == "CURR") THEN
        {
        sStrategyLabel := legGetString(pComponent,"STRTG_LBL")
        },

        // End of BAB addition

        WHILE (iNbComp < iNbComponent) DO
        {
        	pComponent:=legGetComponentAt(pContract,iNbComp),
            IF sFamilyType == "IRD" THEN
            {
            	sPurpose := legGetString (pComponent,"PURPOSE"),
            	pResultsProductCode := lookupResults("BAB.ALL.ProductCodes","ALL","Typology",sTypology,"Usage",sUsage,"Strategy Label",sStrategyLabel, "Deal Purpose", sPurpose)
            }
            ELSE
            	pResultsProductCode := lookupResults("BAB.ALL.ProductCodes","ALL","Typology",sTypology,"Usage",sUsage,"Strategy Label",sStrategyLabel),

            //BAB addition for the Counterparty full name, same logic exists in rule "Finit-ALL"
            sCTP := legGetString(pComponent,"Counterpart"),
            sCTPFullName := ctpGetFullName(sCTP),
            legOverwrite(pComponent,"CPTY_NAME",sCTPFullName),

            IF legIsElementValid(pComponent,"VAT_WHT") THEN
            sVATWHT := strToUpperCase(legGetString(pComponent, "VAT_WHT")),

            //Check lookup returned a result
            IF ( NOT isNull( pResultsProductCode ) ) THEN
            {
            	sProductCode := lookupResultsGetString( pResultsProductCode,0,0),
                legOverwrite(pComponent,"PROD_CODE",sProductCode)
            }
            ELSE IF (sFamilyGroup == "SCF" AND sVATWHT == "YES") THEN
            { 
            	sProductCode := legGetString(pComponent,"PROD_CODE"),
            	legOverwrite(pComponent,"PROD_CODE",sProductCode)
                }
            ELSE //keep empty

            // PROD_CODE ADDITION FOR SCF-Fees and Custodian Fee
             {
          	IF ( sTypology <> "SCF-Fees" AND sTypology <> "Custodian Fee" AND sTypology <> "Brokerage Fee") THEN
            	legOverwrite(pComponent,"PROD_CODE","")
         },

             // Add BRK_CODE to Brokerage Fees SCF deals - Addition by Fady Abdelnour
            IF sTypology== "Brokerage Fee" THEN
            {
                sBroker:= legGetString(pComponent,"Broker"),
                sBrkCode := ctpGetUdfString(sBroker,"CTP_CODE"),

                IF sBrkCode <> "" THEN
                legOverwrite(pComponent,"BRK_CODE",sBrkCode)

            },
            // End of  BRK_CODE to Brokerage Fees SCF deals           


            // Add brk1 code to master trade
            IF sFamilyGroup == "LN_BR" OR sFamilyGroup == "REPO" OR sFamilyGroup == "BOND" THEN
            {
                sBroker:= legGetString(pComponent,"IS_BROKER1"),
                sBrkCode := ctpGetUdfString(sBroker,"CTP_CODE"),

                IF sBrkCode <> "" THEN
                legOverwrite(pComponent,"BRK_CODE",sBrkCode)

            },
            // end of brk2 code

            // Add brk2 code to master trade
            IF sFamilyGroup == "LN_BR" OR sFamilyGroup == "REPO" OR sFamilyGroup == "BOND" THEN
            {
                sBrokerB:= legGetString(pComponent,"IS_BROKER2"),
                sBrkBCode := ctpGetUdfString(sBrokerB,"CTP_CODE"),

                IF sBrkBCode <> "" THEN
                legOverwrite(pComponent,"BRKB_CODE",sBrkBCode)

            },
            // end of brk2 code


      //BAB addition regarding the CR for Commodities auto filling
                   bEvent := properties.Get("mx.preTrade.BO.source.class") <> "mxContractEventICANCEL_REISSUE", 
                sUsage := legGetString(pComponent,"Usage"), 

            IF bEvent 
                AND ((sTypology == "Murabaha Borrowing" AND sUsage == "BA") 
                    OR (sTypology == "Murabaha Placement" AND sUsage == "DI") 
                    OR (sTypology == "CD Issuance" AND sUsage == "Murabaha BA")
                    OR (sTypology == "LTM" AND sUsage == "DI") 
                    OR (sTypology == "LTM Range" AND sUsage == "DI") 
                    OR (sTypology == "LTM Callable" AND sUsage == "DI") 
                    OR (sTypology == "LTM CapFloorCollar" AND sUsage == "DI") 
                    OR (sTypology == "LTM Range Callable" AND sUsage == "DI")) THEN 
                { 
                    legSetString(pComponent,"IS_BROKER1","DUMMY BROKER 1"), 
                    legSetString(pComponent,"IS_BROKER2","DUMMY BROKER 2") 
                } 

                ELSE IF (legIsElementValid(pComponent,"IS_BROKER1") == TRUE AND bEvent) THEN 
                { 
                    legSetString(pComponent,"IS_BROKER1",""), 
                    legSetString(pComponent,"IS_BROKER2","") 
                },

            // Add LPID if eligible to WHT/VAT
            IF sTypology <> "Murabaha Commodity" THEN    				// Exclude COM deals as they already have a an LPID attached
            {

    			IF legIsElementValid(pComponent,"PROFIT_WHT") THEN
            	sWHTEligible := legGetString(pComponent,"PROFIT_WHT"),	        

                pBrokerFees := legGetBrokerFlows( pComponent ),
                iNbFees := brkFlowsGetNumberOfFlows( pBrokerFees ),
                iFee := 0,

                WHILE ( iFee < iNbFees ) DO
                {
                 pFee := brkFlowsGetAt( pBrokerFees,iFee ),
                 sCode:=brkFlowGetCode(pFee),						// Left if needed to filter out Clearer fee

                 IF (brkFlowGetFee(pFee) <> 0.0) THEN
                 sBrokerFeeEligible := "Yes",
                 iFee := iFee + 1
                },


                IF sWHTEligible == "Yes" OR sBrokerFeeEligible == "Yes" THEN
                { 
                	// Added for packages to retrieve the contract ID
                    iNumberOfComponents := legGetNumberOfComponents(pLeg),

                        IF iNumberOfComponents  <> 1 THEN
                            pOriginContract := legGetContractAt(pLeg,0)
                        ELSE 
                            pOriginContract := pComponent,
                	fOriginalContractRef := legGetNumeric(pOriginContract,"Origin Reference"),

                    //Add LPID only if not existing
                    fCurrentLPID := legGetLogicalPackageId(pComponent),
                	IF fCurrentLPID == 0.0 THEN
               		legSetLogicalPackageId(pComponent, fOriginalContractRef)
                }

            },
            // end of add LPID if eligible to WHT/VAT

            //BAB addition for accounting PROD_CODE Sukuks
            IF sTypology == "Sukuk" THEN
            {
            	sInstrument := legGetString(pComponent,"Instrument"),
                sBondCode := secGetUdfString(sInstrument, "BOND_CODE"),
                legOverwrite(pComponent,"PROD_CODE",sBondCode)
            },
            //end of BAB addition

            iNbComp:= iNbComp +1
        },
        //End of Product code

       //BAB addition - Assigning Segment Code of portfolio onto the trade
       sPortfolio := legGetString(pContract,"Portfolio"),
       pPtfUDF := ptfGetUserFields(sPortfolio),
       sSegCode := udfGetString(pPtfUDF,"SEG_CODE"),
       IF sSegCode <> "" THEN
       {
          legOverwrite(pContract,"SEG_CODE",sSegCode)                 	

        },
       //End of Segment code assignment

		//Step-up rate identification for specific Murabaha Process - Only applies to fixed rate
        //Loop on all streams; check if rate period = previous rate period
        //if yes -> skip; if no --> step up period + store new rate + store period nb

        IF sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" OR sTypology == "CD Issuance" OR sTypology == "PRS" OR sTypology == "PRS Range" OR sTypology == "PRS CapFloorCollar" OR sTypology == "PRS Inverse Floater" OR sTypology == "Depo Callable" THEN
        {
        //	sIndex := legGetString( pComponent,"Index" ),
            pStreamsIndex := legGetStreams( pComponent ),
            pStreamIndex := streamsGetStream( pStreamsIndex,0,0 ),
            pIndex := streamGetIndex( pStreamIndex ),
           /* IF ( pIndex == pNull ) THEN
            sNature := "Fixed rate"
            ELSE
            sNature := "Floating rate",*/

        	iNbChanges := 0,
            sStepUpPeriod := "0",

            /*IF sTypology == "Murabaha Borrowing" OR sTypology == "Murabaha Placement" THEN
            sIsStepUp := "Yes",*/

            pStreams := legGetStreams(pContract),

            iPhase := 0,
            iNumberOfPhases := streamsGetNumberOfPhases(pStreams),

            WHILE ( iPhase < iNumberOfPhases ) DO
            {
                    pFirstLegStream := streamsGetStream(pStreams,iPhase,0),

                    IF ( streamIsFloating( pFirstLegStream ) ) THEN
                        sNatureLeg1 := "Floating"
                    ELSE
                        sNatureLeg1 := "Fixed",

                     IF sNatureLeg1 == "Fixed" THEN
                    {
                    iFirstLegPeriod := 0,
                    iFirstLegNumberOfPeriods := streamGetNumberOfPeriods(pFirstLegStream),
                    fFirstLegPeriodRateRef := streamGetPeriodRate(pFirstLegStream,0),

                    WHILE (iFirstLegPeriod < iFirstLegNumberOfPeriods) DO
                    {
                      fFirstLegPeriodRate := streamGetPeriodRate(pFirstLegStream,iFirstLegPeriod),
                      IF (fFirstLegPeriodRateRef <> fFirstLegPeriodRate) THEN
                      {
                      	iNbChanges := iNbChanges + 1,
                        fFirstLegPeriodRateRef := fFirstLegPeriodRate,
                        sFirstLegPeriod := toString(iFirstLegPeriod),
                        sStepUpPeriod := sStepUpPeriod + ";" + sFirstLegPeriod,
                        sIsStepUp := "Yes"
                      },


                        iFirstLegPeriod := iFirstLegPeriod + 1
                    }
                    },


                    pSecondLegStream := streamsGetStream(pStreams,iPhase,1),

                    IF ( streamIsFloating( pSecondLegStream ) ) THEN
                        sNatureLeg2 := "Floating"
                    ELSE
                        sNatureLeg2 := "Fixed",

                    IF sNatureLeg2 == "Fixed" THEN
                    {
                    iSecondLegPeriod := 0,
                    iSecondLegNumberOfPeriods := streamGetNumberOfPeriods(pSecondLegStream),
                    fSecondLegPeriodRateRef := streamGetPeriodRate(pSecondLegStream,0),

                    WHILE (iSecondLegPeriod < iSecondLegNumberOfPeriods) DO
                    {
                    	fSecondLegPeriodRate := streamGetPeriodRate(pSecondLegStream,iSecondLegPeriod),
                        IF (fSecondLegPeriodRateRef <> fSecondLegPeriodRate) THEN
                        {
                            iNbChanges := iNbChanges + 1,
                            fSecondLegPeriodRateRef := fSecondLegPeriodRate,
                            sSecondLegPeriod := toString(iSecondLegPeriod),
                       		sStepUpPeriod := sStepUpPeriod + ";" + sSecondLegPeriod,
                            sIsStepUp := "Yes"
                        },

                        iSecondLegPeriod := iSecondLegPeriod + 1
                    }
                    },
                    iPhase := iPhase + 1
                },





        IF sIsStepUp == "Yes" THEN
       {
          legOverwrite(pContract,"IS_STEPUP",sIsStepUp),
          legOverwrite(pContract,"SU_PERIOD",sStepUpPeriod)

        }

        },  // End of step up rate
       //Added to prevent trader from booking certain typoligies w/out filling Commodity Details


       sTypology := legGetTypology (pComponent),
       sUsage := legGetString( pComponent,"Usage" ),
       sEvent := properties.Get( "mx.preTrade.BO.class" ),


    bBrokerDetailsTypology := sTypology == "Murabaha Borrowing" 
                              OR sTypology == "LTM"
                              OR sTypology == "Murabaha Placement"
                              OR sTypology == "RR SAMA"
                              OR sTypology == "Repo SAMA"
                              OR sTypology == "RR Murabaha"
                              OR sTypology == "Repo Muabaa"
                              OR sTypology == "Repo Murabaha"
                              OR sTypology == "PRS" AND sUsage =="COM"
                              OR sTypology == "PRS CapFloorCollar"
                              OR sTypology == "PRS Range"
                              OR sTypology == "PRS Inverse Floater",

    IF (bBrokerDetailsTypology) THEN
    {
        sComName := legGetString (pComponent, "IS_COMMO"),
        sBrokerA := legGetString (pComponent, "IS_BROKER1"),
        sBrokerB := legGetString (pComponent, "IS_BROKER2"),

        bEmptyComDetails := sComName == "" OR sBrokerA == "" OR sBrokerB == "",
        IF bEmptyComDetails AND  ( ( sEvent <> "mxContractEventIPORTFOLIO_ALLOCATION" ) OR ( sEvent <> "mxContractEventIPORTFOLIO_ASSIGNMENT" ) OR ( sEvent <> "mxContractEventIPORTFOLIO_MODIFICATION" ) OR ( sEvent <> "mxContractEventIPORTFOLIO_TRANSFER" ) )THEN
        ThrowError ("Missing Commodity Details","Please fill all details related to Murabaha Commodity before proceeding to book the deal")
    },

        //end

        //BAB addition - Deal booking should be blocked if SAMA Purchase is not made with SAMA and is USD-SAR
        sInstrument := legGetString(pComponent,"Instrument"),
        IF sTypology == "SAMA Purchase" THEN
        {
        IF sCounterparty <> "10000030" THEN
        {
        ThrowError("Deal cannot be booked","Counterparty <> SAMA, CIF 10000030")
        },
        IF sInstrument <> "USD/SAR" THEN
        {
        ThrowError("Deal cannot be booked","Currency pair <> USD/SAR")
        }
        },

        //BAB addition - Deal booking should be blocked if RR SAMA and Repo SAMA is not made with SAMA
        IF sTypology == "Repo SAMA" OR sTypology == "RR SAMA" THEN
        {
        	IF sCounterparty <> "10000030" THEN
        	{
        		ThrowError("Deal cannot be booked","Counterparty <> SAMA, CIF 10000030")
        	}
        },
        //end of BAB addition

        //BAB addition - Error if COunterpart, Portfolio or Price are empty
        IF sFamilyGroup == "EQUIT" THEN
        {
        sCounterparty := legGetString(pComponent,"Counterpart"),
        fPrice := legGetNumeric(pComponent,"Price"),
        sPortfolio := legGetString(pComponent,"Portfolio"),
        sTradePurpose :=legGetString(pComponent,"Trade_purpose"),
        IF sCounterparty == "" THEN
        {
        ThrowError("Deal cannot be booked","Counterparty is empty")
        },
        IF fPrice == 0.0 AND sTradePurpose <> "Corporate action execution" THEN
        {
        ThrowError("Deal cannot be booked","Price is equal to 0")
        },
        IF sPortfolio == "" THEN
        {
        ThrowError("Deal cannot be booked","Portfolio is empty")
        }
        },

        //End of BAB addition

        //BAB addition - Check for Broker A and Broker B in Murabaha Details
         IF  legIsElementValid( pComponent,"IS_BROKER1" ) THEN
            sBrokerA := legGetString(pComponent,"IS_BROKER1"),
         IF  legIsElementValid( pComponent,"IS_BROKER2" ) THEN
            sBrokerB := legGetString(pComponent,"IS_BROKER2"),
         IF sBrokerB <> "" AND sBrokerA <> "" THEN   
         {
            IF sBrokerA == sBrokerB THEN
            {
                ThrowError("Deal cannot be booked","Broker B is equal to Broker A")
            }
         },
         //end of BAB addition

         // Deal Purpose addition - Fady Abdelnour
        IF sTypology =="PRS" THEN 
           {
           sDealPurpose := legGetString (pComponent,"PURPOSE"),
           IF sDealPurpose =="" THEN
           ThrowError ("Missing Deal Purpose","Please fill the Deal Purpose before proceeding to book the deal")
           },
         // End Deal Purpose addition - Fady Abdelnour


	iContract:= iContract + 1	
	}
};

{

    pEvent := This,
    bSplit := TRUE,

    // Stage 1: Check the flows to be Split
                // Get Pointers 
    sAction := properties.Get( "mx.preTrade.action" ),
                sUserGroup := sysGetGroup(),
    pGroupResults := lookupResults("MX.ALL.UserGroupProfile","ALL","USER_GROUP",sUserGroup),
    sGroupType := lookupResultsGetString(pGroupResults,0,0),
    bNo := FALSE,
    IF (sAction <> "CNL" ) THEN

    {

    pEventUDFs := evtGetUserFields(pEvent),    
    sB2BMirrorFees := "Yes",
    dEventDate := evtGetEventDate(pEvent),
    dAccrualDate := dEventDate + shift(dEventDate,"-1od","ALL DAYS"),
    pVBO:= evtGetVersionedBOAt(pEvent,0),

    pOldBO:= evtVersionedBOGetOld(pVBO),
    pNewBO := evtVersionedBOGetNew(pVBO),
    iNumberOfContracts := legGetNumberOfContracts(pNewBO),

    // Get Pointer on first component of first Contract
    pFirstNewComponent := legGetComponentAt(legGetContractAt(pNewBO,0),0),
    pFirstOldComponent := legGetComponentAt(legGetContractAt(pOldBO,0),0),   

    sMainPortfolio := legGetString(pFirstNewComponent,"Portfolio"),
    sMainB2BPortfolio := legGetString(pFirstNewComponent,"Back_to_back_portfolio"),
    bIsMainContractBTB := legGetFOPIsBackToBack(legGetContractAt(pNewBO,0)),
    sMainCounterpart := legGetString(pFirstNewComponent,"Counterpart"),
	sTypology:=legGetTypology(pFirstNewComponent),    

    sTypol := legGetString(pFirstOldComponent,"Typology"),

    //Get Unwind details
	fUnwindRatio := evtGetNumeric(pEvent,"UnwoundRatio")/100.0,

    iFlowCounter := 0, 
    iFlowCounter := evtGetNumberOfFlows(pEvent) - 1,
    iAccrual:= 0,


    	//In the below code we assume the pretrade rule Event.Rules.public.completion.UnwindCapEx has executed successfully and created one CapitalEx flow for the First contract of the package
    	//Total number of flows upon first execution of the below code is therefore assumed to be [NumberOfContracts + 1] except for PRS

            sProductGroup := legGetProductGroup(pFirstNewComponent),


                WHILE (iFlowCounter >= 0) DO 
            {

                dEffectDate := evtGetDate( pEvent,"EffectiveDate" ) ,

                pEventFlow := evtGetFlowAt(pEvent,iFlowCounter),
                pEventFlowUDFs := evtFlowGetUDF(pEventFlow), 
                sFlowSource := evtFlowGetSource(pEventFlow),
                sFlowDestination := evtFlowGetDestination(pEventFlow),

                //Set all Flows' Value date to Unwind Effective date
                evtFlowSetValueDate(pEventFlow,dEffectDate),

                // To Avoid Exception when using ptfGetDisplayedLabel on a counterparty
                bFlowDestinationIsPortfolio := FALSE,
                bFlowDestinationIsMainPortfolio := FALSE,
                bFlowDestinationIsMainB2BPortfolio := FALSE,        
                bFlowDestinationIsPortfolio := evtFlowIsDestinationPortfolio(pEventFlow),

                IF (bFlowDestinationIsPortfolio) THEN
                {        
                    bFlowDestinationIsMainPortfolio := (ptfGetDisplayedLabel(sFlowDestination) == sMainPortfolio),
                    bFlowDestinationIsMainB2BPortfolio := (ptfGetDisplayedLabel(sFlowDestination) == sMainB2BPortfolio)        
                },

                // Get Flow Details
                sUnwindFeeSource := sFlowSource,
                sUnwindFeeDestination := sFlowDestination,
                dUnwindFeeDate := evtFlowGetValueDate(pEventFlow),
                sUnwindFeeCurrency := evtFlowGetCurrency(pEventFlow), 
                fUnwindFeeComponent := evtFlowGetComponentReference(pEventFlow),
                fUnwindFeeAmount := evtFlowGetAmount(pEventFlow),
                sUnwindFeeNature := evtFlowGetNature(pEventFlow),
                sUnwindFeeTypology1 := evtFlowGetTypologyLabelAt(pEventFlow,0),     
                sUnwindFeeTypology2 := evtFlowGetTypologyLabelAt(pEventFlow,1),     
                sUnwindFeeTypology3 := evtFlowGetTypologyLabelAt(pEventFlow,2),     
                sUnwindFeeTypology4 := evtFlowGetTypologyLabelAt(pEventFlow,3),                            
                sUnwindFeeTypology5 := evtFlowGetTypologyLabelAt(pEventFlow,4),
                sUnwindFeePayReceive := evtFlowGetPayReceive(pEventFlow),      



                // Case where flow is with external party
                IF ((iFlowCounter == 0) AND (sFlowSource == sMainPortfolio) AND (sFlowDestination == sMainCounterpart) AND (sUnwindFeeNature == "Capital") AND (sUnwindFeeTypology1 == "CAP") 
                    AND (sUnwindFeeTypology2 == "XIT") AND (sUnwindFeeTypology5 == "INT")) THEN
                {
                    bSplit := TRUE,

                    //Store Original Unwind ratio, value date and fee of trade in event UDFs if it is 0.0 or "", value is taken from first flow of event
                    IF (udfGetNumeric(pEventUDFs,"INT_FEE")==0.0) THEN
                    {
                        udfSetNumeric(pEventUDFs,"INT_FEE",fUnwindFeeAmount),
                        dAccrualDate:= dEffectDate + shift(dEffectDate,"-1od","ALL DAYS")
                    }
                    ELSE
                    {
                        dAccrualDate:= dUnwindFeeDate + shift(dEffectDate,"-1od","ALL DAYS")
                    },

                    fUnwindFeeAmount := udfGetNumeric(pEventUDFs,"INT_FEE") * fUnwindRatio

                },



                iFlowCounter := iFlowCounter - 1             

            },



                    iNumberOfContracts := legGetNumberOfContracts(pNewBO),
                    iNumberOfEventFlows := evtGetNumberOfFlows(pEvent),
                    sUnwindFeeCurrency := evtFlowGetCurrency(evtGetFlowAt(pEvent,0)),
                    fUnwindRatio := evtGetNumeric( pEvent,"UnwoundRatio")/100.0,

                    //Case: Accrual flow not yet created
                    //Create and Define Accrual flow

                    IF (sProductGroup == "IRS") THEN
                    iNbOfEvtFlows := iNumberOfContracts
                    ELSE
                    iNbOfEvtFlows := iNumberOfContracts + 1,


                    IF ( iNumberOfEventFlows <= (iNbOfEvtFlows) ) THEN 						//Event flows initially should be one flow per contract + the Capital flow except for PRS where event flows should be one flow per contract
                    {

                        pAccrualFlow := evtAddFlow(pEvent,fUnwindFeeComponent),

                            //Set Accrual Flow
                            // Create a virtual copy of the trade
                            pContainer := npOpen(TRUE),
                            pClone := npCloneLeg( pContainer,pFirstNewComponent),

                            legOverwrite(pClone,"Evaluation_date",dAccrualDate),            
                            legCompute( pClone,"noWorkflow"),             

                            //System returns the fees in the initial
                            //Get Accrual from Cloned leg
                            fLeg1Accrual := legGetNumeric(pClone,"Accrual") * fUnwindRatio,						 // In Nominal 1 Currency

                            IF ( sProductGroup == "REPO" OR sProductGroup == "IRS" ) THEN						// Repo and PRS have accruals on leg2 that should be retrieved	
                                fLeg2Accrual := legGetNumeric(pClone,"Accrual2") * fUnwindRatio,				// In Nominal 1 Currency as well
                            fTotalAccrual := fLeg1Accrual + fLeg2Accrual,
                            IF (sProductGroup == "REPO") THEN
                                sAccrual1Currency := legGetString(pClone,"Currency")
                            ELSE
                            sAccrual1Currency := legGetString(pClone,"Nominal_unit"), 							// Fee is computed by default in this currency

                            fFxConversionRate := 1.0,
                            IF (sAccrual1Currency == "SAR" AND sUnwindFeeCurrency == "USD") THEN
                            {
                                fFxConversionRate:= 3.75
                            }
                            ELSE IF (sAccrual1Currency == "USD" AND sUnwindFeeCurrency == "SAR") THEN
                            {
                                fFxConversionRate:= 1.0/3.75
                            }            
                            ELSE IF (sAccrual1Currency <> sUnwindFeeCurrency) THEN										
                            {
                                fFxConversionRate := cuGetFxForwardRate(sAccrual1Currency,sUnwindFeeCurrency,dUnwindFeeDate)                    
                            },               

                            // Close Virtual Leg
                            npClose(pContainer),  

                    IF ((fLeg1Accrual <> 0.0) OR (fLeg2Accrual <> 0.0)) THEN
                    {
                        // Update the initial fee from dirty to clean
                        fUnwindFeeCleanSignedAmount := fUnwindFeeAmount - fTotalAccrual / fFxConversionRate,
                     	fAccountingAccrual:= fTotalAccrual / fFxConversionRate,										

                        evtFlowSetAmount(evtGetFlowAt(pEvent,0),fUnwindFeeCleanSignedAmount), 			// The system takes care of pay/receive
                        evtFlowSetComment(evtGetFlowAt(pEvent,0),"Fee"), 


                        //Update Fee of all contracts from Dirty to clean, keep same direction
                        iFeeUpdateCounter := 0,
                        WHILE ( iFeeUpdateCounter < iNumberOfContracts ) DO
                        {

                            fFlowFeeAmount:= evtFlowGetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter)),
                            IF ( fFlowFeeAmount < 0.0 ) THEN 											//Case when Flow is Pay, MV will also be negative
                            {
                                fUnwindFeeCleanSignedAmount := -1.0 * abs( ( abs(fUnwindFeeAmount) - abs(fTotalAccrual/fFxConversionRate)) )
                            }
                            ELSE
                                fUnwindFeeCleanSignedAmount := fUnwindFeeAmount - fTotalAccrual / fFxConversionRate,


                            evtFlowSetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter),fUnwindFeeCleanSignedAmount), 		// The system takes care of pay/receive
                            evtFlowSetComment(evtGetFlowAt(pEvent,iFeeUpdateCounter),"Fee"),

                            iFeeUpdateCounter := iFeeUpdateCounter + 1
                        },

                        //Define Accrual flow details
                        IF (fAccountingAccrual <> 0.0) THEN					
                        {

                            pNewEventFlow := pAccrualFlow,

                            evtFlowSetSource(pNewEventFlow,sUnwindFeeSource),
                            evtFlowSetDestinationParty(pNewEventFlow,sUnwindFeeDestination),    
                            evtFlowSetValueDate(pNewEventFlow,dUnwindFeeDate),
                            evtFlowSetCurrency(pNewEventFlow,sUnwindFeeCurrency),                    
                            evtFlowSetNature(pNewEventFlow,"Revenue"),
                            evtFlowSetTypologyLabelAt(pNewEventFlow,0,sUnwindFeeTypology1),     
                            evtFlowSetTypologyLabelAt(pNewEventFlow,1,"IFEE"),     
                            evtFlowSetTypologyLabelAt(pNewEventFlow,2,sUnwindFeeTypology3),     
                            evtFlowSetTypologyLabelAt(pNewEventFlow,3,sUnwindFeeTypology4),                            
                            evtFlowSetTypologyLabelAt(pNewEventFlow,4,sUnwindFeeTypology5),
                            evtFlowSetComment(pNewEventFlow,"Accruals"),
                            evtFlowOverrideAmount(pNewEventFlow,fAccountingAccrual)      

                        }

                      }//  Close Accrual

                      }//Close create and define Acc flows

                      //Case: Acc flows already defined
                      ELSE
                      {

                      		//Align Accrual flow with Unwind ratio
                            pContainer := npOpen(TRUE),
                            pClone := npCloneLeg( pContainer,pFirstNewComponent),

                            legOverwrite(pClone,"Evaluation_date",dAccrualDate),            
                            legCompute( pClone,"noWorkflow"),             

                            // System returns the fees in the initial
                            //Get Accrual from Cloned leg
                            fLeg1Accrual := legGetNumeric(pClone,"Accrual") * fUnwindRatio, 				// In Nominal 1 Currency

                            IF ( sProductGroup == "REPO" OR sProductGroup == "IRS") THEN					// Repo and PRS have accruals on leg2 that should be retrieved	
                                fLeg2Accrual := legGetNumeric(pClone,"Accrual2") * fUnwindRatio,			// In Nominal 1 Currency as well
                            fTotalAccrual := fLeg1Accrual + fLeg2Accrual,
                            IF (sProductGroup == "REPO") THEN
                                sAccrual1Currency := legGetString(pClone,"Currency")
                            ELSE
                            sAccrual1Currency := legGetString(pClone,"Nominal_unit"),						 // Fee is computed by default in this currency


                            fFxConversionRate := 1.0,
                            IF (sAccrual1Currency == "SAR" AND sUnwindFeeCurrency == "USD") THEN
                            {
                                fFxConversionRate:= 3.75
                            }
                            ELSE IF (sAccrual1Currency == "USD" AND sUnwindFeeCurrency == "SAR") THEN
                            {
                                fFxConversionRate:= 1.0/3.75
                            }            
                            ELSE IF (sAccrual1Currency <> sUnwindFeeCurrency) THEN
                            {
                                fFxConversionRate := cuGetFxForwardRate(sAccrual1Currency,sUnwindFeeCurrency,dUnwindFeeDate)                    
                            },               
                            // Close Virtual Leg
                            npClose(pContainer),


                            IF ((fLeg1Accrual <> 0.0) OR (fLeg2Accrual <> 0.0)) THEN
                            {
                                // Update the initial fee from dirty to clean
                                fUnwindFeeCleanSignedAmount := fUnwindFeeAmount - fTotalAccrual / fFxConversionRate,
                                fAccountingAccrual:= fTotalAccrual / fFxConversionRate,

                            	evtFlowSetAmount(evtGetFlowAt(pEvent,0),fUnwindFeeCleanSignedAmount), 		// The system takes care of pay/receive                              
                            	evtFlowSetComment(evtGetFlowAt(pEvent,0),"Fee"), 


                                IF (fLeg1Accrual <> 0.0) THEN
                                {

                                //Update Fee of all contracts from Dirty to clean, keep same direction
                                iFeeUpdateCounter := 0,
                                WHILE ( iFeeUpdateCounter < iNumberOfContracts ) DO
                                {

                                    fFlowFeeAmount:= evtFlowGetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter)),
                                    IF ( fFlowFeeAmount < 0.0 ) THEN 									//Case when Flow is Pay, MV will also be negative
                                    {
                                        fUnwindFeeCleanSignedAmount := -1.0 * abs( ( abs(fUnwindFeeAmount) - abs(fTotalAccrual/fFxConversionRate)) )
                                    }
                                    ELSE
                                        fUnwindFeeCleanSignedAmount := fUnwindFeeAmount - fTotalAccrual / fFxConversionRate,


                                    evtFlowSetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter),fUnwindFeeCleanSignedAmount), 			// The system takes care of pay/receive

                                    evtFlowSetComment(evtGetFlowAt(pEvent,iFeeUpdateCounter),"Fee"),

                                    //Case: When first Fee is manually customized, reflect customization on all Contracts' Fees
                                    //We compare previous Fee to current fee starting from second fee
                                    iPreviousFeeUpdateCounter := iFeeUpdateCounter - 1,
                                    IF ( iPreviousFeeUpdateCounter >= 0 ) THEN
                                    {
                                        fPreviousUnwindFeeAmount := evtFlowGetAmount(evtGetFlowAt(pEvent,iPreviousFeeUpdateCounter)),
                                        IF ( abs(fPreviousUnwindFeeAmount) <> abs(fUnwindFeeCleanSignedAmount) ) THEN
                                        {
                                            IF fUnwindFeeCleanSignedAmount < 0.0 THEN
                                            {  
                                                evtFlowSetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter), -1.0*abs(fPreviousUnwindFeeAmount)), // The system takes care of pay/receive
                                                evtFlowSetComment(evtGetFlowAt(pEvent,iFeeUpdateCounter),"Fee")
                                            }
                                            ELSE
                                                evtFlowSetAmount(evtGetFlowAt(pEvent,iFeeUpdateCounter), abs(fPreviousUnwindFeeAmount)), // The system takes care of pay/receive
                                                evtFlowSetComment(evtGetFlowAt(pEvent,iFeeUpdateCounter),"Fee")
                                        }
                                    }, //End of Customized Fee

                                    iFeeUpdateCounter := iFeeUpdateCounter + 1
                                },// End of update Fee


                                    //Look for First Accrual flow of first contract
                                    iFlow := 0,
                                    iNbFlows := evtGetNumberOfFlows(pEvent) -1,
                                    iAccrual := 0,
                                    WHILE ( iFlow <= iNbFlows ) DO
                                    {
                                        sComment := evtFlowGetComment(evtGetFlowAt(pEvent,iFlow)),
                                        IF sComment == "Accruals" THEN
                                        {
                                        iAccrual := iFlow,
                                        iFlow := iNbFlows + 1 //Exit the loop once Accrual is found
                                        }
                                        ELSE
                                        iFlow := iFlow +1
                                    },

                                    //Update Accrual flow of first contract
                                    pNewEventFlow := evtGetFlowAt(pEvent,iAccrual),  
                                    evtFlowSetValueDate(pNewEventFlow,dUnwindFeeDate),
                                    evtFlowOverrideAmount(pNewEventFlow,fAccountingAccrual) 
                              }
                      },

                      	iFlows := 0, 
                        iNumberOfFlows:= evtGetNumberOfFlows(pEvent),

                        //Set Flows' Value date to Unwind effective date
                        WHILE (iFlows < iNumberOfFlows) DO 
                        {
                            pEventFlow := evtGetFlowAt(pEvent,iFlows),
                            evtFlowSetValueDate(pEventFlow,evtUnwindGetEffectiveDate (pEvent)),       
                            iFlows := iFlows + 1
                        }

                      },//Close Acc already defined

           IF ((sProductGroup == "IRS") OR (sProductGroup == "LN_BR") OR (sProductGroup == "REPO")) THEN
            {

                //Set Value Date = Effective Date
                iFlows := 0, 
                iNumberOfFlows:= evtGetNumberOfFlows(pEvent),

                WHILE (iFlows < iNumberOfFlows) DO 
                {
                    pEventFlow := evtGetFlowAt(pEvent,iFlows),
                    evtFlowSetValueDate(pEventFlow,evtUnwindGetEffectiveDate (pEvent)),

                    //Set Fee to zero for non IRS
                    IF (sProductGroup <> "IRS") THEN
                    {
                    IF evtFlowGetComment(pEventFlow) == "Fee" THEN
                       evtFlowSetAmount(pEventFlow,0.0) //end of zero                    
                    },
                    iFlows := iFlows + 1
                }  
                },         


            // Stage 4: Mirror the fees Or Update them if already mirrored
            //Fees that will be mirrored/Updated have Types: CapitalEx, Accruals
            //The Fee ot type "Fee" is not updated here, it is already set
            IF (sB2BMirrorFees == "Yes") AND ((sProductGroup == "LN_BR") OR (sProductGroup == "REPO") OR (sProductGroup == "IRS"))   THEN
            {

                //Initialize the Flows array
                pFlowArray := arrayNew(),
                arrayDefinitionSetDate(pFlowArray,"VALUEDATE", FALSE, FALSE),         
                arrayDefinitionSetString(pFlowArray,"CURRENCY", FALSE, FALSE),     
                arrayDefinitionSetNumeric(pFlowArray,"AMOUNT", FALSE, FALSE),         
                arrayDefinitionSetString(pFlowArray,"PAYRECEIVE", FALSE, FALSE),               
                arrayDefinitionSetString(pFlowArray,"NATURE", FALSE, FALSE),           
                arrayDefinitionSetString(pFlowArray,"DESTINATION", FALSE, FALSE),    
                arrayDefinitionSetString(pFlowArray,"SOURCE", FALSE, FALSE),  
                arrayDefinitionSetString(pFlowArray,"FLOWTYPE1", FALSE, FALSE),
                arrayDefinitionSetString(pFlowArray,"FLOWTYPE2", FALSE, FALSE),
                arrayDefinitionSetString(pFlowArray,"FLOWTYPE3", FALSE, FALSE),
                arrayDefinitionSetString(pFlowArray,"FLOWTYPE4", FALSE, FALSE),    
                arrayDefinitionSetString(pFlowArray,"FLOWTYPE5", FALSE, FALSE),    
                arrayDefinitionSetString(pFlowArray,"COMMENT", FALSE, FALSE),   

                iFlows := 0, 
                iNumberOfFlows:= evtGetNumberOfFlows(pEvent),

                //Populate Flows array with the existing flows
                WHILE (iFlows < iNumberOfFlows) DO 
                {
                    pEventFlow := evtGetFlowAt(pEvent,iFlows),
                    sFlowSource := evtFlowGetSource(pEventFlow),
                    sFlowDestination := evtFlowGetDestination(pEventFlow),        

                    IF ((sFlowSource == sMainPortfolio) AND (sFlowDestination == sMainCounterpart)
                        AND ( evtFlowGetComment(pEventFlow) <> "Fee" ) ) THEN 							//Store the External deal flows' details except for Fee
                    {
                        dUnwindFeeDate := evtUnwindGetEffectiveDate (pEvent),
                        pFlowElement := arrayAddElement(pFlowArray),
                        arrayElementSetDate(pFlowElement,"VALUEDATE",evtFlowGetValueDate(pEventFlow)),    
                        arrayElementSetString(pFlowElement,"CURRENCY",evtFlowGetCurrency(pEventFlow)),   
                        arrayElementSetNumeric(pFlowElement,"AMOUNT",abs(evtFlowGetAmount(pEventFlow))),            
                        arrayElementSetString(pFlowElement,"PAYRECEIVE",evtFlowGetPayReceive(pEventFlow)),            
                        arrayElementSetString(pFlowElement,"NATURE",evtFlowGetNature(pEventFlow)),  
                        arrayElementSetString(pFlowElement,"COMMENT",evtFlowGetComment(pEventFlow)),
                        arrayElementSetString(pFlowElement,"DESTINATION",sFlowDestination),               
                        arrayElementSetString(pFlowElement,"SOURCE",sFlowSource),
                        arrayElementSetString(pFlowElement,"FLOWTYPE1",evtFlowGetTypologyLabelAt(pEventFlow,0)),
                        arrayElementSetString(pFlowElement,"FLOWTYPE2",evtFlowGetTypologyLabelAt(pEventFlow,1)),
                        arrayElementSetString(pFlowElement,"FLOWTYPE3",evtFlowGetTypologyLabelAt(pEventFlow,2)),
                        arrayElementSetString(pFlowElement,"FLOWTYPE4",evtFlowGetTypologyLabelAt(pEventFlow,3)),  
                        arrayElementSetString(pFlowElement,"FLOWTYPE5",evtFlowGetTypologyLabelAt(pEventFlow,4))  



                    },

                    iFlows := iFlows + 1
                },

                iFlowsToBeMirrored := arrayGetLenght(pFlowArray),

                IF (iFlowsToBeMirrored > 0  ) THEN
                {
                    // Check if pointer is Contract or Package
                    iContract := 0,
                    iNumberOfContracts := 0,    
                    iNumberOfContracts := legGetNumberOfContracts(pNewBO),

                    WHILE (iContract < iNumberOfContracts ) DO
                    {

                        sPortfolio := "",
                        sCounterpart := "",
                        sInternal := "",
                        sMirror := "",        

                        // Get Pointers on Contracts
                        pOldContract := legGetContractAt(pOldBO,iContract),
                        pNewContract := legGetContractAt(pNewBO,iContract),

                        // We take only the first Component (so STB Contracts with multiple compoments are not looped)
                        pOldComponent:= legGetComponentAt(pOldContract,0),
                        pNewComponent:= legGetComponentAt(pNewContract,0),

                        // Get Trade Info        
                        sPortfolio := legGetString(pNewComponent,"Portfolio"),
                        sCounterpart := legGetString(pNewComponent,"Counterpart"),
                        sInternal := legGetString(pNewComponent,"Internal"),
                        sMirror := "",

                        // Get Mirroring UDF
                        IF ( legIsElementValid( pNewComponent,"MIRROR" ) ) THEN
                        {	
                            sMirror := legGetString(pNewComponent,"MIRROR")                  
                        },

                        // Mirror the flows
                        IF (sCounterpart <> sMainCounterpart) THEN
                        {
                            iFlowsMirror := 0,
                            WHILE (iFlowsMirror < iFlowsToBeMirrored) DO
                            {
                                pMirrorFlow := arrayGetElement(pFlowArray,iFlowsMirror),

                                //Check whether the last flow is Automatic
                                pNewFlowUDFs := evtFlowGetUDF(evtGetFlowAt(pEvent, evtGetNumberOfFlows(pEvent)-1 )),

                                //Case: Flows have not yet been mirrored -> mirror the flows
                                IF udfGetString(pNewFlowUDFs,"AUTOMATIC") <> "Y"  THEN
                                    pNewEventFlow:=evtAddFlow(pEvent,legGetNumeric(pNewComponent,"Trn Number"))

                                    //Case: Flows have already been mirrored -> Update the flows to follow External deal
                                    ELSE
                                    {
                                        //Set iContractShifter to point to the correct Flow, assuming we will have iFlowToBeMirrored = 3
                                        IF iContract == 1 THEN //Second Contract in the package
                                        iContractShifter := 0
                                        ELSE IF iContract == 2 THEN //Third Contract in the package
                                        iContractShifter := 3,

                                    pNewEventFlow := evtGetFlowAt(pEvent, iNumberOfContracts + iFlowsToBeMirrored + iContractShifter + iFlowsMirror ) //To locate Flow that should be updated


                                    },

                                udfSetString(pNewFlowUDFs,"AUTOMATIC","Y"),

                                evtFlowSetValueDate(pNewEventFlow,arrayElementGetDate(pMirrorFlow,"VALUEDATE")),
                                evtFlowSetCurrency(pNewEventFlow,arrayElementGetString(pMirrorFlow,"CURRENCY")),
                                evtFlowSetAmount(pNewEventFlow,arrayElementGetNumeric(pMirrorFlow,"AMOUNT")),
                                evtFlowSetNature(pNewEventFlow,arrayElementGetString(pMirrorFlow,"NATURE")),
                                evtFlowSetTypologyLabelAt(pNewEventFlow,0,arrayElementGetString(pMirrorFlow,"FLOWTYPE1")),     
                                evtFlowSetTypologyLabelAt(pNewEventFlow,1,arrayElementGetString(pMirrorFlow,"FLOWTYPE2")),     
                                evtFlowSetTypologyLabelAt(pNewEventFlow,2,arrayElementGetString(pMirrorFlow,"FLOWTYPE3")),     
                                evtFlowSetTypologyLabelAt(pNewEventFlow,3,arrayElementGetString(pMirrorFlow,"FLOWTYPE4")),                            
                                evtFlowSetTypologyLabelAt(pNewEventFlow,4,arrayElementGetString(pMirrorFlow,"FLOWTYPE5")), 
                                evtFlowSetComment (pNewEventFlow,arrayElementGetString(pMirrorFlow,"COMMENT")),
                                evtFlowSetSource(pNewEventFlow,sPortfolio),

                                // Case: Mainly Sales Deals
                                IF (sInternal == "Yes") THEN
                                {
                                    evtFlowSetPayReceive(pNewEventFlow,arrayElementGetString(pMirrorFlow,"PAYRECEIVE")),                                                                                     
                                    evtFlowSetDestinationPortfolio(pNewEventFlow,sCounterpart),

                                    // change accruals amount
                                    IF evtFlowGetComment(pNewEventFlow) == "Accruals" THEN
                                    {

                                    	// Get Pointer on first component of second Contract
                                        pSecondNewComponent := legGetComponentAt(legGetContractAt(pNewBO,1),0),
                                        pSecondOldComponent := legGetComponentAt(legGetContractAt(pOldBO,1),0),  


                                        //Align Accrual flow with Unwind ratio
                                        pContainer := npOpen(TRUE),
                                        pClone := npCloneLeg( pContainer,pSecondNewComponent),

                                        legOverwrite(pClone,"Evaluation_date",dAccrualDate),            
                                        legCompute( pClone,"noWorkflow"),             

                                        //System returns the fees in the initial
                                        //Get Accrual from Cloned leg
                                        fSecLeg1Accrual := legGetNumeric(pClone,"Accrual") * fUnwindRatio, 					// In Nominal 1 Currency

                                        IF ( sProductGroup == "REPO" OR  sProductGroup == "IRS" ) THEN						// Repo and PRS have accruals on leg2 that should be retrieved	
                                            fSecLeg2Accrual := legGetNumeric(pClone,"Accrual2") * fUnwindRatio,				// In Nominal 1 Currency as well
                                        fSecTotalAccrual := fSecLeg1Accrual + fSecLeg2Accrual,
                                        IF (sProductGroup == "REPO") THEN
                                            sSecAccrual1Currency := legGetString(pClone,"Currency")
                                        ELSE
                                        sSecAccrual1Currency := legGetString(pClone,"Nominal_unit"), 			// Fee is computed by default in this currency

                                        fFxConversionRate := 1.0,
                                        IF (sSecAccrual1Currency == "SAR" AND sUnwindFeeCurrency == "USD") THEN
                                        {
                                            fFxConversionRate:= 3.75
                                        }
                                        ELSE IF (sSecAccrual1Currency == "USD" AND sUnwindFeeCurrency == "SAR") THEN
                                        {
                                            fFxConversionRate:= 1.0/3.75
                                        }            
                                        ELSE IF (sSecAccrual1Currency <> sUnwindFeeCurrency) THEN
                                        {
                                            fFxConversionRate := cuGetFxForwardRate(sSecAccrual1Currency,sUnwindFeeCurrency,dUnwindFeeDate)                    
                                        },               

                                        // Close Virtual Leg
                                        npClose(pContainer),

                                        IF ((fSecLeg1Accrual <> 0.0) OR (fSecLeg2Accrual <> 0.0)) THEN
                                        {
                                    		evtFlowOverrideAmount(pNewEventFlow,fSecTotalAccrual / fFxConversionRate) 

                                  }



                                  }

                                },

                                iFlowsMirror := iFlowsMirror + 1           
                            }  


                        },


                        iContract := iContract + 1
                    }, // Close Loop on Contracts  

                        //Set last Mirrored flow to Automatic
                        pLastFlowUDFs := evtFlowGetUDF(evtGetFlowAt(pEvent,evtGetNumberOfFlows(pEvent)-1)),
                        udfSetString(pLastFlowUDFs,"AUTOMATIC","Y")

                } // Close If Flows To be Mirrored > 0
            }//Close Mirror flows

    }

}; // Close All

//public.completion.ALL.Booking.PreDealChecks

{
	pContract := This,
    sAction := "",
    sSourceClass := "",
    sAction := properties.Get( "mx.preTrade.action" ),
    sSourceClass := properties.Get( "mx.preTrade.BO.source.class" ),
    sPricingSource:= properties.Get( "mx.preTrade.pricing.source"),
    bIsInBookingSequence := strStartsWith( properties.Get( "mx.preTrade.context.namespace" ), "B_" ),

    sGroup := "",
    sGroupType := "",
    sGroupSeniority := "",
    sRegistration := legGetRegistration(pContract),
    sClosingEntity:="",


	sSourceModule := legGetSourceModule(pContract),
    sUser:=sysGetUser(),
	sGroup := sysGetGroup(),


	sPriceOnRequest := "",
    bEvalModeIsOn := FALSE,
	bEvalModeIsOn := (properties.Get("mx.preTrade.evaluation.active") == "YES"),

	pGroupResults := lookupResults("MX.ALL.UserGroupProfile","ALL","USER_GROUP",sGroup),
	sGroupType := lookupResultsGetString(pGroupResults,0,0),
	sGroupSeniority := lookupResultsGetString(pGroupResults,0,1),


	iComponent := 0,
	iNumComponents := legGetNumberOfComponents(pContract),

    //BAB addition for migration trades. Payout direction check
	IF (sRegistration == "Loans/Deposits" OR sRegistration == "Bond Repos") AND sSourceModule == "Migration" THEN
    {
    	WHILE ( iComponent < iNumComponents ) DO
    	{
    		pComponent := legGetComponentAt(pContract,iComponent), 

            //BAB addition - Always re-set Payout to Borrow/Lend if it's set to Lend/Borrow and is protected. This logic is also contained in the rule SanityCheckCommon
            sTypology := legGetTypology(pComponent),
            IF ( sTypology == "Murabaha Borrowing" OR sTypology == "CD Issuance" OR sTypology == "Wakala Borrowing" OR sTypology == "Wakala Borrowing CFC" OR sTypology == "RR Murabaha" OR sTypology == "RR Waad" OR sTypology == "Repo SAMA")  THEN 
            {
                sPayout := legGetString(pComponent,"Payout"),
                IF ( sPayout == "Lend" ) THEN
                {
                    legOverwrite (pComponent,"Payout","Borrow"),
                    ThrowError ( pComponent,"Payout Lend is not allowed for this product, Payout has been reset to Borrow","Payout")
                }  
            }

            ELSE IF ( sTypology == "Murabaha Placement" OR  sTypology == "Wakala Placement CFC" OR sTypology == "Wakala Placement" OR sTypology == "DPM Murabaha" OR sTypology == "Repo Murabaha" OR sTypology == "Repo Waad" OR sTypology == "RR SAMA" 
                   OR sTypology == "LTM" OR sTypology == "LTM Callable" OR sTypology == "LTM Range" OR sTypology == "LTM Range Callable" OR sTypology == "LTM CapFloorCollar")  THEN 
            {
                sPayout := legGetString(pComponent,"Payout"),
                IF ( sPayout == "Borrow" ) THEN
                {
                    legOverwrite (pComponent,"Payout","Lend"),
                    ThrowError ( pComponent,"Payout Borrow is not allowed for this product, Payout has been reset to Lend","Payout")
                }  
        	},
            iComponent := iComponent +1
        }
    },  

    iComponent := 0,

 //  If the context is RFQ and the role is provider (trader) do not apply predeal checks  
bRFQTraderSkipCheck := sysGetRFQRole() <> "PROVIDER" OR properties.Get("mx.preTrade.pricing.context") <> "MAIL" ,

////////////////////////////////////////////////////////////////////////////////////////////

    IF (sGroup <> "SALES_INT" AND sGroup <> "TRADER_INT") THEN 
    {

    //Open loop on components
    WHILE ( iComponent < iNumComponents ) DO
    {

    sCheck := "",
    sCheckType := "",


    pComponent := legGetComponentAt(pContract,iComponent), 
	sComponentSTPStatus := legGetString(pComponent,"Validation_status"),        
	pAllMessages := legGetMessages( pComponent ),     
    sRegistration := legGetRegistration(pComponent),
    sTypology := legGetTypology(pComponent),
    sInternal := legGetString( pComponent,"Internal"),
    sTrader := legGetString(pComponent, "Source trader"),

    //BAB: Only for Reuters deals coming via IDC: FX Spot, FX Waad, Murabaha/Wakala Borrowing/Placement.
    //Roy J: Should consume FX swaps as well, but it was not tested. To be tested
    bIsFXT := bIsInBookingSequence AND sInternal == "No" AND sSourceModule =="FXT",


    bEligible  := (((sAction == "INS" AND sSourceClass == "") 
        					OR (sAction == "INS" AND sSourceClass == "mxContractEventICANCEL_REISSUE") 
	        					OR (sAction == "INS" AND sSourceClass == "mxContractEventIRESTRUCTURE")
		        					OR (sAction == "INS" AND sSourceClass == "mxContractEventRatesIFORWARD_RESTRUCTURE")
                                    	OR (sAction == "MOD" AND sComponentSTPStatus == "Pending") OR (sAction == "MOD" AND sPricingSource =="TRADE"))
    	    	                        	AND sInternal == "No" AND (legIsInitialized(pComponent)) AND (NOT(bIsInBookingSequence)))
                                                    OR bIsFXT
                                                /* OR (bIsInBookingSequence AND (sSourceModule == "dts" OR sSourceModule == "fxgo" OR sSourceModule == "360t" OR sSourceModule == "autobahn" OR (sSourceModule == "rbs" AND strCONTAIN(sTypology,"Outright"))))*/,    

    IF (bEligible) THEN
    {   
    // Get the list of checks needed with the corresponding check types



    		// Retrieve Senior validation level
            pLevelValidationResults := lookupResults("BAB.ALL.ValidationLevel","ALL","Group Seniority" ,sGroupSeniority),
            IF ( NOT isNull(pLevelValidationResults) ) THEN
            {
            	flevelValidation := lookupResultsGetNumeric( pLevelValidationResults, 0, 0),
				flevelBlock:=flevelValidation + 1.00
            }
            //Case for missing validation level assigned, set to 0 to block
            ELSE
            {
            	flevelValidation:=0.00,
    			flevelBlock:=0.00
            },



			pChecksResults := lookupResults("BAB.ALL.PredealChecks","ALL","Registration",sRegistration,"Typology",sTypology),

            pMainContract := legGetContractAt( This,0 ),
            pMainPackage := legGetFatherPackage( pMainContract ),

             IF ( NOT isNull( pMainPackage ) ) THEN 
            	sMainRegistrationLabel := legGetRegistrationLabel(pMainPackage)
            ELSE
            	sMainRegistrationLabel := legGetRegistrationLabel(pMainContract),

      		IF ( sMainRegistrationLabel == "mxContractFxISPLIT" ) THEN
            {                                   
            	sFieldNameBreach := "cross.PRE_RES"
            }   

            // WZ
            ELSE IF (sMainRegistrationLabel == "mxContractFxISPLITSWAP") THEN {
				sFieldNameBreach := "crossswp.nearLeg.PRE_RES"
            // end of WZ
            }
            ELSE IF ( sMainRegistrationLabel == "mxContractFxISWAP" ) THEN
            {
            	sFieldNameBreach := "PRE_RES"
            }
            ELSE
            {                      
				sFieldNameBreach := "PRE_RES"
            },

            //For Reuters FXT deals, default breach reason to "IDC deal Breach". If there is no breach, this pretrade will empty PRE_RES field at the end
            //This pretrade checks if PRE_RES is filled and adds a message only if bValidation is true, so messages will not be added if there is no breach
            IF bIsFXT THEN
            {
                IF legIsElementValid(pComponent,sFieldNameBreach) THEN
                legOverwrite(pComponent,"PRE_RES","IDC deal Breach")

            },//End of Reuters FXT deals


            //added to block loaded trades
            IF sPricingSource =="TRADE" THEN
            {
				IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-TradeLoad-Check") == 0 ) THEN
               legAddMessage( pComponent, "The deal is a previoulsy loaded deal, kindly insert a new one" ,"Type", "Sane-TradeLoad-Check" ,messageSysGetErrorLabel())
	        },


            pArray := arrayNew(),
			arrayDefinitionSetNumeric(pArray,"RANK", TRUE, FALSE),              

	        iResult := 0,  
	        iNbCheckResults := lookupResultsGetNumberOfLines(pChecksResults),

            // Open Loop on Check Types 
            WHILE (iResult < iNbCheckResults) DO
             {

             sCheck := lookupResultsGetString( pChecksResults,iResult,0 ),
			 sCheckType := lookupResultsGetString( pChecksResults,iResult,1 ),

             // Tenor Check
				IF (sCheck == "Tenor") THEN
	            {
             		legOverwrite(pComponent,"PRE_TENOR",""), // Default to Empty
                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Nominal Unit"),
                    sCriteria:=legGetString(pComponent,sCriteriaField),


                    // Get the Limits
					pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check","Tenor","Criteria",sCriteria,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),

                     IF (NOT isNull(pLimitsResults)) THEN
                     {
                     	fTenor := 0.0,
		                sStartDateField := "",
		                sMaturityDateField := "",
                        dTradingDate := legGetDate(pComponent,"Trading_Date"),
		                dStartDate := "00000000",
		                dMaturityDate := "00000000",

                     	// Get e-tradepad fields mappings
	            		sStartDateField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Start"),
		  				sMaturityDateField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Maturity"),


                        // Avoid Computing a Tenor if both Start Date Or Maturity date is not yet filled
                         IF (toString(legGetDate(pComponent,sStartDateField)) <> "00000000") AND (toString(legGetDate(pComponent,sMaturityDateField)) <> "00000000") THEN
	        	        {
                        	dStartDate := legGetDate(pComponent,sStartDateField),
	                		dMaturityDate := legGetDate(pComponent,sMaturityDateField),

                            pTenorArray := arrayNew(),
							arrayDefinitionSetNumeric(pTenorArray,"LIMIT", TRUE, TRUE),
                            arrayDefinitionSetNumeric(pTenorArray,"GROUPRANK", TRUE, TRUE),


                            // Tenor is Computed in Years
                    	    fTenor := convertIToNumeric(toInt(dMaturityDate-dStartDate)) / 365.0,
                        	fTenor := round(fTenor,2),

                            //Fill Array with limit result
                            iNb:=0,
                            iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),

                            WHILE (iNb < iNbResults ) DO
                            {
                           	 	fMaxTenorLimits := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                            	sLUTGroupSeniority:=lookupResultsGetString(pLimitsResults,iNb,0),

                                fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority),

                                fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),

                                pTenorElement := arrayAddElement(pTenorArray),
        						arrayElementSetNumeric(pTenorElement,"LIMIT",fMaxTenorLimits),    
                                arrayElementSetNumeric(pTenorElement,"GROUPRANK",fLUTGroupRank),  
                            iNb:=iNb+1
                            },

                            	bValidation:=FALSE,
                                bBlocking:=FALSE,
                          		//Array scanning
 								iCount := 0,
 								iNumberOfElements := arrayGetLength(pTenorArray),
 								WHILE(iCount< iNumberOfElements)
 								DO
 								{
  								pElement := arrayGetElement(pTenorArray, iCount),
  								fLIMITtenor := arrayElementGetNumeric(pElement,"LIMIT"),
                                fGROUPRANKtenor := arrayElementGetNumeric(pElement,"GROUPRANK"),

                                IF(fGROUPRANKtenor<=(fMyGroupRank+flevelValidation) AND (fGROUPRANKtenor>=fMyGroupRank))THEN
                                {

                                	IF(fTenor>fLIMITtenor) THEN 
                               		 {

                                		bValidation:=TRUE,
                                        fLimitBreached:=fLIMITtenor,
                                        fValSens:=fGROUPRANKtenor

                                	 }

                                },

                                IF(fGROUPRANKtenor>=(fMyGroupRank+flevelBlock))   THEN
                                {

                                	IF(fTenor>fLIMITtenor) THEN 
                               		 {
                                		bValidation:=FALSE,
                                		bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITtenor

                                	 }

                                },

                                iCount := iCount + 1
								},

						IF ((sCheckType == "SeniorValidation")) THEN
                         {
                        IF (bValidation) THEN
                         {

                           legOverwrite(pComponent,"PRE_TENOR","Deal/Limit (" + sTenorUnits + "): " + toString(fTenor, 15, 4, TRUE, 0) + "/" + toString(fLimitBreached, 15, 4, TRUE, 0)),
                           pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                            //To check in the case of FX Swap, get the Near leg PRE_RES value
                        IF sMainRegistrationLabel == "mxContractFxISWAP"  THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES") },


                            IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN

                         {
                           legSetCellColorAsError(pComponent,sFieldNameBreach),
                           legSetCellColorAsError(pContract, sFieldNameBreach),
                           legSetCellColorAsWarning(pComponent,sMaturityDateField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Tenor-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Tenor Breach : Breach Reason is required",sMaturityDateField,"Sane-Tenor-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                         {
                           legSetCellColorAsWarning(pComponent,sMaturityDateField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Tenor-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Tenor Breach : Trade will be sent for FO Validation" ,sMaturityDateField ,"Sane-Tenor-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }

                        },

                        IF (bBlocking) THEN
                         {
                           legSetCellColorAsError(pComponent,sMaturityDateField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Tenor-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Tenor Breach : Trade is blocked due to senior limit breach",sMaturityDateField,"Sane-Tenor-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }

                         },



                         IF((sCheckType == "Blocking") AND ((bBlocking) OR (bValidation)) ) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sMaturityDateField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Tenor-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Tenor Breach : Trade is blocked due to limit breach", sMaturityDateField,"Sane-Tenor-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }






                     }

                    }    


             	}//end of Tenor 

                //NominalFX Check
                ELSE IF (sCheck == "NominalFX") AND bRFQTraderSkipCheck THEN
                {

	            	legOverwrite(pComponent,"PRE_NOM",""),

					// Get the Limits
                    sInstrument:=legGetString(pComponent,"Instrument"),
                    iCurr:=0,
                    iNbCurr:=2,

                     WHILE (iCurr < iNbCurr) DO
                    {
                    	sNominalUnitField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Nominal Unit"),
						sOtherNominalUnitField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Other Nominal Unit"),	
						sNominalUnit:=legGetString(pComponent,sNominalUnitField),
						sOtherNominalUnit:=legGetString(pComponent,sOtherNominalUnitField),
                        bNominal:=FALSE,
                        bOtherNominal:=FALSE,

                    	IF iCurr == 0 THEN
                        {
                        	sCriteriaField:=sNominalUnit,
                            bNominal:=TRUE
                        }    
                        ELSE
                        {
                        	sCriteriaField:=sOtherNominalUnit,
                            bOtherNominal:=TRUE
                        },

                        //BAB addition - To differentiate between SAR and Non SAR currency pairs
                        IF sNominalUnit == "SAR" OR sOtherNominalUnit == "SAR" THEN
                        {
                        	sCriteriaField2 := "SAR"
                        },
                        //end of BAB addition

                    	pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check","NominalFX","Criteria",sCriteriaField,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),

                        IF (isNull(pLimitsResults)) THEN
                        {
                        	sCriteriaField:="Converted",
                            pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check","NominalFX","Criteria",sCriteriaField,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType)
                        },

                        IF ( NOT isNull(pLimitsResults)) THEN
                        {
                        	fNominal := 0.0,
                            fTradedLimit := 0.0,
                            sNominalField := "",
                            sPriceField := "",
                            sNominalUnit := "",

                            // Get e-tradepad fields mappings 
                            sNominalField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Nominal"),
                            sOtherNominalField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Other Nominal"),

                            //FX Swap Far leg NominalFX 
                            IF sRegistration == "Forex-Swap Leg" THEN
                            {
                            	 sNominalFieldFar := "Den_nominal_far_leg",
                                 sOtherNominalFieldFar := "Num_nominal_far_leg"
                            },


                            //Define Nominal Array
                            pFXNominalArray := arrayNew(),
                           	arrayDefinitionSetNumeric(pFXNominalArray,"LIMIT", TRUE, TRUE),
                           	arrayDefinitionSetNumeric(pFXNominalArray,"GROUPRANK", TRUE, TRUE),

                            // Get the Two currency Nominal
                            fNominal := legGetNumeric(pComponent,sNominalField),

                            //Get the FX Swap Far leg Nominal
                            IF sRegistration == "Forex-Swap Leg" THEN
                            {
                            	fNominalFar := legGetNumeric(pComponent,sNominalFieldFar)
                            },



                            IF (sRegistration <> "Flexible Deal") THEN
                            fOtherNominal:= legGetNumeric(pComponent,sOtherNominalField),

                            //Get the FX Swap Far leg Nominal
                            IF sRegistration == "Forex-Swap Leg" THEN
                            {
                            	fOtherNominalFar := legGetNumeric(pComponent,sOtherNominalFieldFar)
                            },




                           IF (fNominal <> 0.0) OR (fNominalFar <> 0.0) THEN //Far leg addition 
                            {

                            iNb:=0,
                            iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),

                             WHILE ( iNb < iNbResults ) DO
                             {
                              // Get Limits 
                               sLUTGroupSeniority := lookupResultsGetString(pLimitsResults,iNb,0),
                               fMaxNominalLimits := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                               sLimitUnit:=lookupResultsGetString(pLimitsResults,iNb,2),  


                               fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority),

                               fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),


                                pNominalElement := arrayAddElement(pFXNominalArray),
                                arrayElementSetNumeric(pNominalElement,"LIMIT",fMaxNominalLimits),
                                arrayElementSetNumeric(pNominalElement,"GROUPRANK",fLUTGroupRank),                                   

                              iNb:=iNb+1      
                              },

                              // Convert to USD for non G6         	
                                        IF (sCriteriaField == "Converted") THEN
                                        {
                                            fRate1 := cuGetFxRate("USD",legGetString(pComponent,sNominalUnitField)),
                                            fRate2 := cuGetFxRate("USD",legGetString(pComponent,sOtherNominalUnitField)),
                                            fNominal:= fNominal * fRate1,
                                            fOtherNominal:= fOtherNominal * fRate2,

                                            //Conversion of the FX Swap Far leg
                                            IF sRegistration == "Forex-Swap Leg" THEN
                                            {
                                            	fNominalFar := fNominalFar * fRate1,
                                                fOtherNominalFar := fOtherNominalFar * fRate2

                                            }


                                        },
                                //Far leg validation and Boolean
                                bValidationFar:=FALSE,
                                bBlockingFar:=FALSE,


                              	bValidation:=FALSE,
                                bBlocking:=FALSE,
                          		//Array scanning
 								iCount := 0,
 								iNumberOfElements := arrayGetLength(pFXNominalArray),


 								WHILE(iCount< iNumberOfElements)
 								DO
 								{
  								pElement := arrayGetElement(pFXNominalArray, iCount),
  								fLIMITfxNom := arrayElementGetNumeric(pElement,"LIMIT"),
                                fGROUPRANKfxNom := arrayElementGetNumeric(pElement,"GROUPRANK"),


                                IF(fGROUPRANKfxNom<=(fMyGroupRank+flevelValidation) AND (fGROUPRANKfxNom>=fMyGroupRank))THEN
                                {

                                        IF bNominal THEN
                                        {
                                            fTradedNominal:= ABS(fNominal),

                                            sNominalField:=sNominalField,

                                            //FX Swap Far leg check
                                            IF sRegistration == "Forex-Swap Leg" THEN
                                            {
                                            	fTradedNominalFar:= ABS(fNominalFar),

                                                sNominalFieldFar:=sNominalFieldFar

                                            }


                                        }    
                                        ELSE IF bOtherNominal THEN
                                        {    
                                            fTradedNominal:= ABS(fOtherNominal),

                                            sNominalField:= sOtherNominalField,

                                            //FX Swap Far leg check
                                            IF sRegistration == "Forex-Swap Leg" THEN
                                            {

                                            	fTradedNominalFar:= ABS(fOtherNominalFar),

                                                sNominalFieldFar:=sOtherNominalFieldFar

                                            }


                                        },

                                	IF(fTradedNominal > fLIMITfxNom) THEN 
                               		 {

                                		bValidation:=TRUE,
                                        fLimitBreached:=fLIMITfxNom,
                                        fValSens:=fGROUPRANKfxNom

                                	 },

                                     //FX Swap Far leg check
                                     IF sRegistration == "Forex-Swap Leg" THEN
                                     {
                                     	IF (fTradedNominalFar > fLIMITfxNom) THEN
                                        {
                                        	bValidationFar:=TRUE,
 											fLimitBreached:=fLIMITfxNom,
                                       		fValSens:=fGROUPRANKfxNom
                                        }

                                     }



                                },

                                IF(fGROUPRANKfxNom>=(fMyGroupRank+flevelBlock))THEN
                                {

                                        IF bNominal THEN
                                        {
                                            fTradedNominal:= ABS(fNominal),

                                            sNominalField:=sNominalField,

                                            //FX Swap Far leg check
                                            IF sRegistration == "Forex-Swap Leg" THEN
                                            {
                                            	fTradedNominalFar:= ABS(fNominalFar),

                                                sNominalFieldFar:=sNominalFieldFar

                                            }




                                        }    

                                        ELSE IF bOtherNominal THEN
                                        {    
                                            fTradedNominal:= ABS(fOtherNominal),

                                            sNominalField:= sOtherNominalField,

                                            //FX Swap Far leg check
                                            IF sRegistration == "Forex-Swap Leg" THEN
                                            {
                                            	fTradedNominalFar:= ABS(fOtherNominalFar),

                                                sNominalFieldFar:=sOtherNominalFieldFar

                                            }


                                        },

                                	IF(fTradedNominal > fLIMITfxNom) THEN 
                               		 {

                                		bValidation:=FALSE,
                                		bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITfxNom

                                	 },
                                     //FX Swap Far leg check
                                     IF sRegistration == "Forex-Swap Leg" THEN
                                     {

                                     	IF (fTradedNominalFar > fLIMITfxNom) THEN
                                        {
                                        	bValidationFar:=FALSE,
                                			bBlockingFar:=TRUE,
                                        	fLimitBreached:=fLIMITfxNom
                                        }

                                     }


                                },
                                iCount := iCount + 1
                                },

                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bValidation) THEN
                         {
                           legOverwrite(pComponent,"PRE_NOM","Deal/Limit: " + strToken(toString(fTradedNominal, 15, 0, TRUE, 0),".",0) + "/" + strToken(toString(fLimitBreached, 15, 0, TRUE, 0),".",0)),
                           pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                           //To check in the case of FX Swap, get the Near leg PRE_RES value
						IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES") },



                            IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN
                         {
                           legSetCellColorAsError(pComponent,sFieldNameBreach),
                           legSetCellColorAsError(pContract, sFieldNameBreach),
                           legSetCellColorAsWarning(pComponent,sNominalField),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Breach Reason is required",sNominalField,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                         {
                           legSetCellColorAsWarning(pComponent,sNominalField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade will be sent for FO Validation",sNominalField ,"Sane-NominalFX-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }
                        },



                        IF (bBlocking) THEN
                         {
                           legSetCellColorAsError(pComponent,sNominalField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to senior limit breach",sNominalField,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }


                         },



                         IF((sCheckType == "Blocking") AND ((bBlocking) OR (bValidation)) ) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sNominalField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to limit breach",sNominalField,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         },

                         //FX Swap Far leg Nominal Breach
                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bValidationFar) THEN
                         {
                           legOverwrite(pComponent,"PRE_NOM","Deal/Limit: " + strToken(toString(fTradedNominalFar, 15, 0, TRUE, 0),".",0) + "/" + strToken(toString(fLimitBreached, 15, 0, TRUE, 0),".",0)),
                           pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                           //To check in the case of FX Swap, get the Near leg PRE_RES value
						IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES") },

                            IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN
                         {
                           legSetCellColorAsError(pComponent,sFieldNameBreach),
                           legSetCellColorAsError(pContract, sFieldNameBreach),
                           legSetCellColorAsWarning(pComponent,sNominalFieldFar),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Breach Reason is required",sNominalFieldFar,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidationFar)) THEN
                         {
                           legSetCellColorAsWarning(pComponent,sNominalFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade will be sent for FO Validation",sNominalFieldFar ,"Sane-NominalFX-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }

                        },

                        IF (bBlockingFar) THEN
                         {
                           legSetCellColorAsError(pComponent,sNominalFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to senior limit breach",sNominalFieldFar,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }
                        },


                         IF((sCheckType == "Blocking") AND ((bBlockingFar) OR (bValidationFar)) ) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sNominalFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-NominalFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to limit breach",sNominalFieldFar,"Sane-NominalFX-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }


                            }// Close if nominal is not 0 
                        },// Close if no limits are set

                         iCurr:= iCurr + 1

                    }//Close Currency Loop

                }// End of NominalFX Check


                //Nominal check for MM trades
                ELSE IF (sCheck == "Nominal") AND bRFQTraderSkipCheck  THEN
                { 


                //default PRE_NOM limit variable to empty
               		legOverwrite(pComponent,"PRE_NOM",""),
                    IF ((sRegistration == "Loans/Deposits") OR (sRegistration == "Interest rate swaps"))  THEN 
                    sCurrency:=legGetString(pComponent,"Nominal_unit")
                    ELSE IF ((sRegistration == "Bonds") OR (sRegistration == "Bond Repos"))  THEN 
                    sCurrency:=legGetString(pComponent,"Currency")
                    ELSE IF ((sRegistration == "Loans/Deposits") AND ((sTypology == "Repo SAMA") OR (sTypology == "RR SAMA"))) THEN
                    sCurrency:=legGetString(pComponent,"Instrument")
                    ELSE IF (sRegistration == "Equities") THEN
                    sCurrency:=legGetString(pComponent, "Other_nominal_unit"),

               		sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField",sCheck),
                    fNominal:=legGetNumeric(pComponent,sCriteriaField),
                    fNominalAbs := ABS(fNominal),


                    pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check",sCheck,"Criteria",sCurrency,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),


                    IF (NOT isNull(pLimitsResults)) THEN
                    {
                        //Define MM Nominal Array
                        pMMNominalArray := arrayNew(),
                        arrayDefinitionSetNumeric(pMMNominalArray,"LIMIT", TRUE, TRUE),
                        arrayDefinitionSetNumeric(pMMNominalArray,"GROUPRANK", TRUE, TRUE), 

                        iNb:=0,
                        iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),

                        WHILE (iNb < iNbResults) DO

                        {
                            fMaxNominal := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                       		sCurrencylimit := lookupResultsGetString (pLimitsResults,iNb,2),
                        	fRate := cuGetFxRate(sCurrency, sCurrencylimit),
                        	fMaxNominalConverted := fMaxNominal * fRate,
                            sLUTGroupSeniority := lookupResultsGetString(pLimitsResults,iNb,0),
                            fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority),
                            fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),


                            pNominalElement := arrayAddElement(pMMNominalArray),
                            arrayElementSetNumeric(pNominalElement,"LIMIT",fMaxNominalConverted),
                            arrayElementSetNumeric(pNominalElement,"GROUPRANK",fLUTGroupRank),


                              iNb:=iNb+1      
                         },

                       			bValidation:=FALSE,
                                bBlocking:=FALSE,
                          		//Array scanning
 								iCount := 0,
 								iNumberOfElements := arrayGetLength(pMMNominalArray),


 								WHILE(iCount< iNumberOfElements)
 								DO
 								{
  								pElement := arrayGetElement(pMMNominalArray, iCount),
  								fLIMITNOM := arrayElementGetNumeric(pElement,"LIMIT"),
                                fGROUPRANKNOM := arrayElementGetNumeric(pElement,"GROUPRANK"),

                                IF((fGROUPRANKNOM<=(fMyGroupRank+flevelValidation)) AND(fGROUPRANKNOM>=fMyGroupRank)) THEN
                                {



                                	IF(fNominalAbs > fLIMITNOM) THEN 
                               		 {

                                		bValidation:=TRUE,
                                        fLimitBreached:=fLIMITNOM,
                                        fValSens:=fGROUPRANKNOM

                                	 }

                                },

                                IF(fGROUPRANKNOM>=(fMyGroupRank+flevelBlock))THEN
                                {


                                	IF(fNominalAbs > fLIMITNOM) THEN 
                               		 {

                                		bValidation:=FALSE,
                                		bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITNOM

                                	 }

                                },
                                iCount := iCount + 1
                                },


                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bValidation) THEN
                         {
                           legOverwrite(pComponent,"PRE_NOM","Deal/Limit: " + strToken(toString(fNominalAbs, 15, 0, TRUE, 0),".",0) + "/" + strToken(toString(fLimitBreached, 15, 0, TRUE, 0),".",0)),
                           pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                           IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (bValidation)) THEN
                         {

                           legSetCellColorAsError(pComponent,sFieldNameBreach),
                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Nominal-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Breach Reason is required",sCriteriaField,"Sane-Nominal-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                         {
                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Nominal-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade will be sent for FO Validation",sCriteriaField ,"Sane-Nominal-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }
                        },

                        IF (bBlocking) THEN
                         {
                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Nominal-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to senior limit breach",sCriteriaField,"Sane-Nominal-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }

                         },

                         IF((sCheckType == "Blocking") AND ((bValidation) OR (bBlocking)) ) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sNominalField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Nominal-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Nominal Breach : Trade is blocked due to limit breach",sCriteriaField,"Sane-Nominal-Breach" ,messageSysGetErrorLabel())                          	
                            }
                         } 
                            } 
                            } //End of Nominal check for MM trades

                           // RateMM Check 
                           ELSE IF (sCheck == "RateMM" AND sGroupType <> "Sales") THEN
               	 			{ 
                			// default PRE_RATE limit variable to empty
                            legOverwrite(pComponent,"PRE_RATE",""),
                            sCurrency:=legGetString(pComponent,"Nominal_unit"),
                            sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField",sCheck),
                            fCriteria:=legGetNumeric(pComponent,sCriteriaField),
                            sCurrency:=legGetString(pComponent,"Nominal_unit"),
                            pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check",sCheck,"Criteria",sCurrency,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),   

                            IF (NOT isNull(pLimitsResults)) THEN
                                {
                                    //Define RateMM Array
                                    pMMRatesArray := arrayNew(),
                                    arrayDefinitionSetNumeric(pMMRatesArray,"LIMIT", TRUE, TRUE),
                                    arrayDefinitionSetNumeric(pMMRatesArray,"GROUPRANK", TRUE, TRUE),
                                    iNb:=0,
                                    iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),


                                     WHILE (iNb < iNbResults) DO 
                                        {
                                        fMaxRate := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                                        sLUTGroupSeniority := lookupResultsGetString(pLimitsResults,iNb,0),
                                        fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority),
                                         fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),

                                        pRatesElement := arrayAddElement(pMMRatesArray),
                                        arrayElementSetNumeric(pRatesElement,"LIMIT",fMaxRate),
                                        arrayElementSetNumeric(pRatesElement,"GROUPRANK",fLUTGroupRank),

                                        iNb:=iNb+1 

                                        },

                                //BAB addition for Price on request check
                                IF legIsElementValid(pComponent,"Price_on_request") THEN
                                sPriceOnRequest := legGetString(pComponent,"Price_on_request"),        
                                IF sPriceOnRequest <> "Yes" THEN
                                {
                                // Create a virtual Copy of the Trade
                                pContainer := npOpen(),
                                pComponent := legGetComponentAt(pContract,iComponent),
                                pClone := npCloneLeg( pContainer,pComponent),
                                pCloneComp:=legGetComponentAt(pClone,0),
                                legOverwrite(pCloneComp,"Price_on_request","No"),
                                legOverwrite( pCloneComp,"Rate_Margin",0.0 ),
                                legOverwrite( pCloneComp,"Sales margin",0.0 ),
                                legOverwrite( pCloneComp,"Corporate Margin",0.0 ),
                                sCurrency:=legGetString(pClone,"Nominal_unit"),
                                legOverwrite( pCloneComp,"Npv",0.0 ),
                                legCompute(pCloneComp,"noWorkflow"),

                                fMktRate :=legGetNumeric(pCloneComp,"Rate_Margin"),
                                npClose( pContainer )
                                },



                                bValidation:=FALSE,
                                bBlocking:=FALSE,

                          		//Array scanning
 								iCount := 0,
 								iNumberOfElements := arrayGetLength(pMMRatesArray),


 								WHILE(iCount< iNumberOfElements)
 								DO
 								{
  								pElement := arrayGetElement(pMMRatesArray, iCount),
  								fLIMITRATE := arrayElementGetNumeric(pElement,"LIMIT"),
                                fGROUPRANKRATE := arrayElementGetNumeric(pElement,"GROUPRANK"),

                                IF ( fMktRate <> 0.0) THEN

                                {

                                fDiff :=  ABS((fCriteria - fMktRate)/fMktRate),

                                 IF((fGROUPRANKRATE<=(fMyGroupRank+flevelValidation)) AND (fGROUPRANKRATE>=fMyGroupRank))THEN
                                {

                                	IF(fDiff >fLIMITRATE) THEN 

                               		 {

                                		bValidation:=TRUE,
                                        fLimitBreached:=fLIMITRATE,
                                        fValSens:=fGROUPRANKRATE

                                	 }

                                },

                                IF(fGROUPRANKRATE>=(fMyGroupRank+flevelBlock))THEN
                                {


                                	IF(fDiff > fLIMITRATE) THEN 

                               		 {

                                		bValidation:=FALSE,
                                		bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITRATE

                                	 }

                                }
                                },
                                iCount := iCount + 1
                                },

                         IF ((sCheckType == "SeniorValidation")) THEN
                         {

                         IF (bValidation) THEN
                         {
                          legOverwrite(pComponent,"PRE_RATE","Deal/Limit: " + toString(fDiff, 15, 4, TRUE, 0) + "/" + toString(fLimitBreached, 15, 4, TRUE, 0)),
                          pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                          IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (bValidation)) THEN
                         {
                          legSetCellColorAsError(pComponent,sFieldNameBreach),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Rate Breach : Breach Reason is required",sCriteriaField,"Sane-MMRate-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Rate Breach : Trade will be sent for FO Validation",sCriteriaField ,"Sane-MMRate-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }
                        },

                        IF (bBlocking) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Rate Breach : Trade is blocked due to senior limit breach",sCriteriaField,"Sane-MMRate-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }

                         },

                         IF((sCheckType == "Blocking") AND ((bValidation) OR (bBlocking))) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sNominalField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Rate Breach : Trade is blocked due to limit breach",sCriteriaField,"Sane-MMRate-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }


                                }

                			} //End of RateMM Check


                 //FX Rate Check                                   
                 ELSE IF (sCheck == "Rate" AND sGroupType <> "Sales" AND sRegistration <> "Bonds") THEN
	             {
                	legOverwrite(pComponent,"PRE_RATE",""), // Default to Empty
            		/*
                    //Below commented out as limit check per currency is not needed

                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Nominal Unit"),
                    sCriteria := legGetString(pComponent,sCriteriaField),

                    sCriteriaField2 := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Other Nominal Unit"),
                    sCriteria2 := legGetString(pComponent,sCriteriaField2),

                    // Get the Limits
					*/
                    //Addition until Bloomberg issue is Fixed for BDT and PHP

                    sCurrAdd := legGetString(pContract,"Num_unit"),
                    IF (sCurrAdd == "BDT") OR (sCurrAdd == "PHP") THEN
                    sCriteriaField2 := "PHP-BDT",
                    //End of Addition
                    iNb :=0,

                    pLimitsResults1 := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check",sCheck,"Criteria",sCriteria,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),
                    //pLimitsResults2 := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check",sCheck,"Criteria",sCriteria2,"User Group Profile",sGroupType),

                    //Take the minimum limit of the two to be applied
                    fMaxRateLimits1 := lookupResultsGetNumeric(pLimitsResults1,iNb,1),
                    //fMaxRateLimits2 := lookupResultsGetNumeric(pLimitsResults2,iNb,1),

                    /*
                    IF MIN(fMaxRateLimits1,fMaxRateLimits2) <> 0.0 THEN
                    {
                    	IF fMaxRateLimits1 > fMaxRateLimits2 THEN
                        pLimitsResults := pLimitsResults2
                        ELSE
                        pLimitsResults := pLimitsResults1
                    }
                    ELSE IF fMaxRateLimits1 == 0.0 THEN
                    pLimitsResults:=pLimitsResults2
                    ELSE */
                    pLimitsResults:=pLimitsResults1,

                    IF (NOT isNull(pLimitsResults)) THEN
					{  
                    	sForwardRate := "",
		                sMarketPrice := "",
						fForwardRate := 0.0000000,
		                fMarketRate := 0.0000000
                    },

                    // Get e-tradepad fields mappings
                    sForwardRate:= lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Rate"),
                    sMarketPrice := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Market Rate"),
                    fForwardRate := legGetNumeric( pComponent,sForwardRate),

                    //For Imported FXT deals in booking sequence, use virtual pricing
                    IF bIsFXT THEN
                    {
                        pContainer := npOpen(),
                        pComponent := legGetComponentAt(pContract,iComponent),
                        pClone := npCloneLeg( pContainer,pComponent),
                        pCloneComp:=legGetComponentAt(pClone,0),
                        legOverwrite(pCloneComp,"Price_on_request","No"),
                        legCompute(pCloneComp,"noWorkflow"),

                        fMarketRate := legGetNumeric( pCloneComp,sMarketPrice),

                        npClose( pContainer )

                    }
                    ELSE // For all other scenarios, non-FXT
                   fMarketRate := legGetNumeric( pComponent,sMarketPrice),

                    //FX Swap far leg Rate
                    IF sRegistration == "Forex-Swap Leg" THEN
                    {
                    sForwardRateFar := "Forward__leg2_",
                    fForwardRateFar := legGetNumeric(pComponent,sForwardRateFar)
                    },


                    //Avoid computing if market rate is Zero
                    IF (fMarketRate <> 0.0) THEN
                	{

                        pFXRateArray := arrayNew(),
                        arrayDefinitionSetNumeric(pFXRateArray,"LIMIT", TRUE, TRUE),
                        arrayDefinitionSetNumeric(pFXRateArray,"GROUPRANK", TRUE, TRUE), 

                        iNb:=0,
                        iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),

                        WHILE (iNb < iNbResults ) DO
                        {
                            fMaxRateLimits := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                            sLUTGroupSeniority:=lookupResultsGetString(pLimitsResults,iNb,0),
                            fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority), 

                            pRateElement := arrayAddElement(pFXRateArray),
                            arrayElementSetNumeric(pRateElement,"LIMIT",fMaxRateLimits),    
                            arrayElementSetNumeric(pRateElement,"GROUPRANK",fLUTGroupRank), 

                            iNb:=iNb+1

                        },

                        //BAB addition for far leg of FX swap
                        bValidationFar:=FALSE,
                        bBlockingFar:=FALSE,
                        //end of BAB addition

                        bValidation:=FALSE,
                        bBlocking:=FALSE,
                        //Array scanning
                        iCount := 0,
                        iNumberOfElements := arrayGetLength(pFXRateArray),


                        //Loop on the Rate array for each group to identify if there is a breach, what is the breach level and validator seniority needed
                        WHILE (iCount < iNumberOfElements )
                        DO
                        {
                            pElement := arrayGetElement(pFXRateArray, iCount),
                            fLIMITRATE := arrayElementGetNumeric(pElement,"LIMIT"),
                            fGROUPRANKRATE := arrayElementGetNumeric(pElement,"GROUPRANK"),
                            fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),

                            IF ( fMarketRate <> 0.0) THEN
                            {

                                //BAB addition for far leg Rate of FX swap
                             	IF (sRegistration <> "Forex-Swap Leg") OR (sRegistration == "Forex-Swap Leg" AND iComponent == 0) THEN
                             	{
                            	fDelta := ABS(fForwardRate - fMarketRate),
                                fDeltaPercentage := fDelta/fMarketRate
                                },


                             	//BAB addition for far leg Rate of FX swap
                             	IF sRegistration == "Forex-Swap Leg" THEN
                             	{
                                	fDeltaFar := ABS(fForwardRateFar - fMarketRate),
                                    fDeltaPercentageFar := fDeltaFar/fMarketRate
                             	},



                             	IF ((fGROUPRANKRATE<=(fMyGroupRank+flevelValidation)) AND (fGROUPRANKRATE>=fMyGroupRank))THEN
                             	{

                                	IF(fDelta >fLIMITRATE*fMarketRate) THEN 
                                 	{
                                    	bValidation:=TRUE,
                                    	fLimitBreached:=fLIMITRATE,
                                    	//fValSens:=fGROUPRANKRATE
                                    	fValSens := fMyGroupRank //Validator of FX Rate breach should always be +1 of my group rank seniority

                                 	},

                             		//BAB addition for far leg Rate
                             		IF sRegistration == "Forex-Swap Leg" THEN
                             		{
                                		IF(fDeltaFar >fLIMITRATE*fMarketRate) THEN 
                                 		{
                                    		bValidationFar:=TRUE,
                                    		fLimitBreached:=fLIMITRATE,
                                    		//fValSens:=fGROUPRANKRATE
                                    		fValSens := fMyGroupRank //Validator of FX Rate breach should always be +1 of my group rank seniority

                                 		}	
                             		}



                         		}

                               /*
                               IF(fGROUPRANKRATE>=(fMyGroupRank+flevelBlock))THEN
                                {

                                    IF(fDelta >fLIMITRATE*fMarketRate) THEN 
                                     {

                                        bValidation:=FALSE,
                                        bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITRATE

                                     },
                                     //BAB addition for far leg Rate
                                     IF sRegistration == "Forex-Swap Leg" THEN
                                     {
                                        IF(fDeltaFar >fLIMITRATE*fMarketRate) THEN 
                                        {
                                        bValidationFar:=FALSE,
                                        bBlockingFar:=TRUE,
                                        fLimitBreached:=fLIMITRATE
                                        }

                                     }

                                } */
                            },



                         	iCount := iCount + 1
                         }, //End of loop on Rate array

                         //Check type Senior validation
                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                             IF (bValidation) THEN
                             {
                                  legOverwrite(pComponent,"PRE_RATE","Deal/Limit: " + toString(fDeltaPercentage, 15, 4, TRUE, 0) + "/" + toString(fLimitBreached, 15, 4, TRUE, 0)),
                                  pElement := arrayAddElement(pArray),
                                  arrayElementSetNumeric(pElement,"RANK",fValSens),

                                  //To check in the case of FX Swap, get the relevant leg PRE_RES value
                                  IF sMainRegistrationLabel == "mxContractFxISWAP" THEN
                                  {
                                      sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES"),
                                      legSetString(legGetComponentAt(pContract,iComponent),"PRE_RES",sFieldNameBreachNearLeg)
                                  },

                                  IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN 
                                  {
                                  	legSetCellColorAsError(pComponent,sFieldNameBreach),
                                  	legSetCellColorAsError(pContract, sFieldNameBreach),


                                   	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                                    {
                                      	legAddMessage( pComponent, "Traded Rate Breach : Breach Reason is required",sForwardRate,"Sane-Rate-Breach" ,messageSysGetErrorLabel())                          	
                                    }
                             	  },

                             	  IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                                  { 
                                  	legSetCellColorAsWarning(pComponent,sForwardRate),

                                   	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Rate-Breach") == 0 ) THEN
                                   	{
                                    	legAddMessage( pComponent, "Traded Rate Breach : Trade will be sent for FO Validation",sForwardRate ,"Sane-Rate-Breach" ,messageSysGetWarningLabel())                          	
                                   	}
                              	  }
                             },

                            //For far leg Rate of FX swap
                             IF (bValidationFar) THEN
                             {
                                legOverwrite(pComponent,"PRE_RATE","Deal/Limit: " + toString(fDeltaPercentageFar, 15, 4, TRUE, 0) + "/" + toString(fLimitBreached, 15, 4, TRUE, 0)),
                                pElement := arrayAddElement(pArray),
                                arrayElementSetNumeric(pElement,"RANK",fValSens),

                                //To check in the case of FX Swap, get the relevant leg PRE_RES value
                                IF sMainRegistrationLabel == "mxContractFxISWAP" THEN
                                {
                                    sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES"),
                                    legSetString(legGetComponentAt(pContract,iComponent),"PRE_RES",sFieldNameBreachNearLeg)
                                },

                                 IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN 
                                  {
                                  	legSetCellColorAsError(pComponent,sFieldNameBreach),
                                  	legSetCellColorAsError(pContract, sFieldNameBreach),


                                   	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                                    {
                                      	legAddMessage( pComponent, "Traded Rate Breach : Breach Reason is required",sForwardRateFar,"Sane-Rate-Breach" ,messageSysGetErrorLabel())                          	
                                    }
                             	  },

                             	  IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidationFar)) THEN
                                  { 
                                  	legSetCellColorAsWarning(pComponent,sForwardRateFar),

                                   	IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Rate-Breach") == 0 ) THEN
                                   	{
                                    	legAddMessage( pComponent, "Traded Rate Breach : Trade will be sent for FO Validation",sForwardRateFar ,"Sane-Rate-Breach" ,messageSysGetWarningLabel())                          	
                                   	}
                              	  }


                            },


                            IF (bBlocking) THEN
                            {

                               legSetCellColorAsWarning(pComponent,sForwardRate),

                               IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                               {
                                  legAddMessage( pComponent, "Traded Rate Breach : Trade is blocked due to senior limit breach",sForwardRate,"Sane-MMRate-Breach" ,messageSysGetErrorLabel())                          	
                               }
                            } 

                         },

                         //Check type Blocking
                         IF((sCheckType == "Blocking") AND ((bValidation) OR (bBlocking))) THEN
                         {

                            legSetCellColorAsWarning(pComponent,sForwardRate),

                            IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-MMRate-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Rate Breach : Trade is blocked due to limit breach",sForwardRate,"Sane-MMRate-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }


            		}           

                }//End of FX Rate Check 

				//Margin Check                
                 ELSE IF (sCheck == "Margin" AND sGroupType == "Sales" AND (sRegistration == "Loans/Deposits" OR sRegistration == "Spot-Forward" OR sRegistration == "Forex-Swap Leg"  )) THEN              
                { 
                   //default PRE_MAR limit variable to empty
               		legOverwrite(pComponent,"PRE_MAR",""),
                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField",sCheck),
                    fMargin:=ABS(legGetNumeric(pComponent,sCriteriaField)),

                    //BAB addition far leg margin
                    IF sRegistration == "Forex-Swap Leg" THEN
                    {
                    	sCriteriaFieldFar := "Sales_margin_2_pips",
                        fMarginFar := ABS(legGetNumeric(pComponent,sCriteriaFieldFar))
                    },


                     pLimitsResults := lookupResults("BAB.ALL.PreDealLimits","ALL","Registration",sRegistration,"Typology",sTypology,"Check",sCheck,"Criteria",sCurrency,"Criteria 2", sCriteriaField2,"User Group Profile",sGroupType),

                    IF (NOT isNull(pLimitsResults)) THEN
                    {
                        //Define MM Nominal Array
                        pMarginArray := arrayNew(),
                        arrayDefinitionSetNumeric(pMarginArray,"LIMIT", TRUE, TRUE),
                        arrayDefinitionSetNumeric(pMarginArray,"GROUPRANK", TRUE, TRUE),

                        iNb:=0,
                        iNbResults:=lookupResultsGetNumberOfLines(pLimitsResults),

                        WHILE (iNb < iNbResults) DO

                        {
                            fMaxMargin := lookupResultsGetNumeric(pLimitsResults,iNb,1),
                            sLUTGroupSeniority:=lookupResultsGetString(pLimitsResults,iNb,0),
                            fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sLUTGroupSeniority), 
                            fMyGroupRank:=lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),

		    	        	pMarginElement := arrayAddElement(pMarginArray),
        					arrayElementSetNumeric(pMarginElement,"LIMIT",fMaxMargin),    
                            arrayElementSetNumeric(pMarginElement,"GROUPRANK",fLUTGroupRank), 

                                iNb:=iNb+1

                           },

                               //BAB addition for far leg
                                bValidationFar:=FALSE,
                                bBlockingFar:=FALSE,
                                //end of BAB addition

                           		bValidation:=FALSE,
                                bBlocking:=FALSE,
                          		//Array scanning
 								iCount := 0,
 								iNumberOfElements := arrayGetLength(pMarginArray),


 								WHILE(iCount< iNumberOfElements)
 								DO
 								{
  								pElement := arrayGetElement(pMarginArray, iCount),
  								fLIMITRATE := arrayElementGetNumeric(pElement,"LIMIT"),
                                fGROUPRANKRATE := arrayElementGetNumeric(pElement,"GROUPRANK"),

                                IF (fMargin <> 0.0) OR (fMarginFar <> 0.0) THEN //far leg
                                {

                                 IF((fGROUPRANKRATE<=(fMyGroupRank+flevelValidation)) AND (fGROUPRANKRATE>=fMyGroupRank))THEN
                                {

                                	IF(fMargin > fLIMITRATE) THEN 
                               		 {

                                		bValidation:=TRUE,
                                        fLimitBreached:=fLIMITRATE,
                                        fValSens:=fGROUPRANKRATE

                                	 },

                                      //BAB addition far leg margin
                                      IF sRegistration == "Forex-Swap Leg" THEN
                                      {
                                      	IF(fMarginFar > fLIMITRATE) THEN 
                               		 	{
                                        	bValidationFar:=TRUE,
                                        	fLimitBreached:=fLIMITRATE,
                                       		fValSens:=fGROUPRANKRATE
                                        }
                                      }  




                                },

                                IF(fGROUPRANKRATE>=(fMyGroupRank+flevelBlock))THEN
                                {


                                	IF(fMargin >fLIMITRATE) THEN  
                               		 {

                                		bValidation:=FALSE,
                                		bBlocking:=TRUE,
                                        fLimitBreached:=fLIMITRATE

                                	 },
                                     //BAB addition far leg margin
                                     IF sRegistration == "Forex-Swap Leg" THEN
                                     {
                                     	IF(fMarginFar > fLIMITRATE) THEN 
                               		 	{
                                        	bValidationFar:=FALSE,
                                			bBlockingFar:=TRUE,
                                        	fLimitBreached:=fLIMITRATE
                                        }
                                     }  

                                }
                                },

                                iCount := iCount + 1
                                },

                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bValidation) THEN
                         {
                          legOverwrite(pComponent,"PRE_MAR","Deal/Limit: " + strToken(toString(fMargin, 15, 0, TRUE, 0),".",0) + "/" + strToken(toString(fLimitBreached, 15, 0, TRUE, 0),".",0)),
                          pElement := arrayAddElement(pArray),
                           arrayElementSetNumeric(pElement,"RANK",fValSens),

                            //To check in the case of FX Swap, get the Near leg PRE_RES value
                        IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES")},



                            IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN

                         {
                          legSetCellColorAsError(pComponent,sFieldNameBreach),
                          legSetCellColorAsError(pContract, sFieldNameBreach),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Breach Reason is required",sCriteriaField,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidation)) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade will be sent for FO Validation",sCriteriaField ,"Sane-Margin-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }
                        },

                        IF (bBlocking) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade is blocked due to senior limit breach",sCriteriaField,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        } 

                         },

                         IF((sCheckType == "Blocking") AND ((bValidation) OR (bBlocking))) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade is blocked due to limit breach",sCriteriaField,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         },

                         //BAB addition for far leg check
                         IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bValidationFar) THEN
                         {
                          legOverwrite(pComponent,"PRE_MAR","Deal/Limit: " + strToken(toString(fMarginFar, 15, 0, TRUE, 0),".",0) + "/" + strToken(toString(fLimitBreached, 15, 0, TRUE, 0),".",0)),
                          pElement := arrayAddElement(pArray),
                          arrayElementSetNumeric(pElement,"RANK",fValSens),

                        //To check in the case of FX Swap, get the Near leg PRE_RES value
                        IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES")},


                         IF ((legGetString(pComponent,sFieldNameBreach) == "") AND (sFieldNameBreachNearLeg == "")) THEN

                         {
                          legSetCellColorAsError(pComponent,sFieldNameBreach),
                          legSetCellColorAsError(pContract, sFieldNameBreach),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Breach Reason is required",sCriteriaFieldFar,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        },

                        IF ((legGetString(pComponent,sFieldNameBreach) <> "") AND (bValidationFar)) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade will be sent for FO Validation",sCriteriaFieldFar ,"Sane-Margin-Breach" ,messageSysGetWarningLabel())                          	
                            }
                        }
                        },

                        IF (bBlockingFar) THEN
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade is blocked due to senior limit breach",sCriteriaFieldFar,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        } 

                         },

                         IF((sCheckType == "Blocking") AND ((bValidationFar) OR (bBlockingFar))) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sCriteriaFieldFar),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded Margin Breach : Trade is blocked due to limit breach",sCriteriaFieldFar,"Sane-Margin-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }



                        }



                }// End of Margin Check

                //FX spread limit Check
                ELSE IF (sCheck == "SpreadFX" AND sGroupType == "Sales") THEN
	            {
                	//legOverwrite(pComponent,"PRE_RATE",""), // Default to Empty

                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Other Nominal Unit"),
                    sCriteria := legGetString(pComponent,sCriteriaField),

                    IF(sCriteria=="USD" OR sCriteria=="SAR") THEN
                    {
                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Nominal Unit"),
                    sCriteria := legGetString(pComponent,sCriteriaField)
                    },

                    // Get the Limits

                    iNb :=0,

                    pLimitsResults := lookupResults("BAB.ALL.PreDealSpreadLimit","ALL","Registration",sRegistration,"Typology",sTypology,"Criteria",sCriteria),

                    fMinRateLimits := lookupResultsGetNumeric(pLimitsResults,iNb,0),
                    fMaxRateLimits := lookupResultsGetNumeric(pLimitsResults,iNb,1),



                    IF (NOT isNull(pLimitsResults)) THEN
					{  
                    	sNetForwardRate := "",
		                sMarketPrice := "",
						fNetForwardRate := 0.0000000,
		                fMarketRate := 0.0000000,
                        bBlocking:=FALSE,
                        sSplitCurrency:=legGetString(pComponent,"Split_currency"),

                        IF(sSplitCurrency=="") THEN
                        {
                            // Get e-tradepad fields mappings
                            sNetForwardRate:= lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Net Rate"),
                            sMarketPrice := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Market Rate"),
                            fNetForwardRate := legGetBidAskOneSide(pComponent,sNetForwardRate),                         
                            sSecondDelivery:=legGetString(pComponent,"Second_delivery"),

                            //For Imported FXT deals in booking sequence, use virtual pricing
                            IF bIsFXT THEN
                            {
                                pContainer := npOpen(),
                                pComponent := legGetComponentAt(pContract,iComponent),
                                pClone := npCloneLeg( pContainer,pComponent),
                                pCloneComp:=legGetComponentAt(pClone,0),
                                legOverwrite(pCloneComp,"Price_on_request","No"),
                                legCompute(pCloneComp,"noWorkflow"),

                                //fMktRate :=legGetNumeric(pCloneComp,"Rate_Margin"),

                            	IF ((sTypology=="Banknotes" OR sTypology == "Banknotes Credit") AND sSecondDelivery=="Yes") THEN
                                {
                                    fMarketRate :=legGetNumeric(pCloneComp,"Local_forward")
                                }
                                ELSE
                                {
                                    fMarketRate := legGetNumeric( pCloneComp,sMarketPrice)
                                },

                                npClose( pContainer )

                            }
                            ELSE // For all other scenarios, non-FXT
                            {
                                IF ((sTypology=="Banknotes" OR sTypology == "Banknotes Credit") AND sSecondDelivery=="Yes") THEN
                                {
                                    fMarketRate :=legGetNumeric(pComponent,"Local_forward") 
                                }
                                ELSE
                                {
                                    fMarketRate := legGetNumeric( pComponent,sMarketPrice)
                                }
                            }
                            ,


                            IF (fMarketRate <> 0.0) THEN
                            {
                            	fUpperBound:= fMarketRate*(1.00+fMaxRateLimits/100.00),
                                fLowerBound:= fMarketRate*(1.00-fMinRateLimits/100.00),
                                IF ( ( fNetForwardRate > fUpperBound ) OR (fNetForwardRate < fLowerBound ) )THEN
                                {
                                	bBlocking:=TRUE
                                }

                            } 
                        }
                        //Case for cross deals split
                        ELSE IF (sSplitCurrency<>"") THEN
                        {
                        sCriteriaPrimary := legGetString(pComponent,"Split_Primary_unit"),

                        IF(sCriteriaPrimary=="USD") THEN
                        {
                        sCriteriaPrimary := legGetString(pComponent,"Split_Primary_other")
                        },

                        sCriteriaSecondary := legGetString(pComponent,"Split_Secondary_unit"),

                        IF(sCriteriaSecondary=="USD") THEN
                        {
                        sCriteriaSecondary := legGetString(pComponent,"Split_Secondary_other")
                        },


                        pLimitsResultsPrimary := lookupResults("BAB.ALL.PreDealSpreadLimit","ALL","Registration",sRegistration,"Typology",sTypology,"Criteria",sCriteriaPrimary),
                   		pLimitsResultsSecondary := lookupResults("BAB.ALL.PreDealSpreadLimit","ALL","Registration",sRegistration,"Typology",sTypology,"Criteria",sCriteriaSecondary),

                    	fMinRateLimitsPrimary := lookupResultsGetNumeric(pLimitsResultsPrimary,iNb,0),
                    	fMaxRateLimitsPrimary := lookupResultsGetNumeric(pLimitsResultsPrimary,iNb,1),

                        fMinRateLimitsSecondary := lookupResultsGetNumeric(pLimitsResultsSecondary,iNb,0),
                    	fMaxRateLimitsSecondary := lookupResultsGetNumeric(pLimitsResultsSecondary,iNb,1),

                        fMinRateLimitsCross:=fMinRateLimitsPrimary+fMinRateLimitsSecondary+(fMinRateLimitsPrimary*fMinRateLimitsSecondary),
                        fMaxRateLimitsCross:=fMaxRateLimitsPrimary+fMaxRateLimitsSecondary+(fMaxRateLimitsPrimary*fMaxRateLimitsSecondary),


                       	sNetForwardRate:= lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Rate"),
                        sMarketPrice := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Market Rate"),
                        sMargin:= lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Margin"),


                        fNetForwardRate := legGetBidAskOneSide(pComponent,sNetForwardRate),

                        //For Imported FXT deals in booking sequence, use virtual pricing
                        IF bIsFXT THEN
                        {
                            pContainer := npOpen(),
                            pComponent := legGetComponentAt(pContract,iComponent),
                            pClone := npCloneLeg( pContainer,pComponent),
                            pCloneComp:=legGetComponentAt(pClone,0),
                            legOverwrite(pCloneComp,"Price_on_request","No"),
                            legCompute(pCloneComp,"noWorkflow"),
                            fMarketRate := legGetNumeric( pCloneComp,sMarketPrice),

                            npClose( pContainer )

                        }
                        ELSE
                        //For all other scenarios, non-FXT
                        fMarketRate := legGetNumeric( pComponent,sMarketPrice), //Enhance for FXT, do virtual pricing to get mktforward in booking sequence

                        fMargin:=legGetNumeric(pComponent,sMargin),
                            IF (fMarketRate <> 0.0) THEN
                            {
                            	fUpperBound:=fMarketRate*(1.00+fMaxRateLimitsCross/100.00),
                                fLowerBound:=fMarketRate*(1.00-fMinRateLimitsCross/100.00),

                                IF ( ( fNetForwardRate > fUpperBound ) OR (fNetForwardRate < fLowerBound ) )THEN
                                {
                                	bBlocking:=TRUE
                                }

                            } 

                        }

                        },


                        IF (bBlocking) THEN
                         {

                           legSetCellColorAsError(pComponent,sNetForwardRate),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-SpreadFX-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "Traded FX spread Breach : Trade is blocked due to FX spread limit breach", sNetForwardRate ,"Sane-SpreadFX-Breach" ,messageSysGetErrorLabel())                          	
                            }
                        }



                }// End of FX spread limit check

                // Holiday Check
                ELSE IF (sCheck == "Holiday") THEN
                {
              		sMaturityDateField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Maturity"),
                	dMaturityDate := legGetDate(pComponent,sMaturityDateField),
                    sInstrument:=legGetString(pComponent,"Instrument"),
                   	sFamilyType := legGetProductFamily(pComponent),

                    // BAB addition for the SAMA Purchase calendar change to check LNB holidays
            		sTypology := legGetString(pComponent,"Typology"),
            	/*	IF sTypology == "SAMA Purchase" THEN 
            		{
                    	sCalendar := "LNBNYBRIB"
                    }, */

                    IF sFamilyType <> "CURR" THEN
                    {
                    	pSecurity := secGetSecurityData(sInstrument),
                    	IF ( NOT isNull(pSecurity) ) THEN
                        {
                            sCalendar := securityGetCalendarLabel(pSecurity)
                        }

             			ELSE IF (legIsElementValid(pComponent,"Payment_calendar")) THEN
             			{
            				sCalendar := legGetString(pComponent,"Payment_calendar")

             			}
                    },

                    IF sFamilyType <> "CURR" THEN
                    {
                        IF (toString(dMaturityDate) <> "00000000") THEN
                            bHoliday := datIsHoliday(dMaturityDate, sCalendar),
                        IF(bHoliday) THEN	
                        {
                            IF( legGetString (pComponent, sMaturityDateField) == "") THEN	
                            {
                                legSetCellColorAsError(pComponent,sMaturityDateField),
                                IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Holiday-Check") == 0 ) THEN
                                legAddMessage( pComponent, "The maturity date is a holiday", sMaturityDateField ,"Sane-Holiday-Check" ,messageSysGetErrorLabel())
                            }
                        }
                    }

                } // End of Holiday Check 


               //Start of Backdated Checks
            	ELSE IF (sCheck == "Backdated") THEN
                {
                    legOverwrite(pComponent,"PRE_BACK",""),
                	bBackValidation:=FALSE,
                	sStartDateField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Deal Start"),
                    dStartDate:=legGetDate(pComponent,sStartDateField),
                    dSystemDate := sysGetFODeskDate(),
		    sPortfolio := legGetString(pComponent,"Portfolio"),
                    dTradingDate := legGetDate(pComponent,"Trading_Date"),
                    fLUTGroupRank:= lookupNumeric("BAB.ALL.GroupRanking","ALL","Group Seniority" ,sGroupSeniority),
                    sCriteriaField := lookupString("BAB.ALL.FieldsMapping","ALL","Registration",sRegistration,"MappingField","Deal Start"),
					IF (toString(dStartDate) <> "00000000") AND (sPortfolio <> "INV_EQ_VLST") AND (sPortfolio <> "INV_EQ_GLST") THEN
                    {
                    	IF (dStartDate < dTradingDate OR dTradingDate < dSystemDate) THEN
                        {
                        bBackValidation:=TRUE,
                       fValSens:=fLUTGroupRank
                        },

                        IF ((sCheckType == "SeniorValidation")) THEN
                         {
                         IF (bBackValidation) THEN
                         {
                         legOverwrite(pComponent,"PRE_BACK","Contract Is Back-Dated"),
                         pElement := arrayAddElement(pArray),
                         arrayElementSetNumeric(pElement,"RANK",fValSens),

                        //To check in the case of FX Swap, get the Near leg PRE_RES value
                        IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
						sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES") },
                        //sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,iComponent),"PRE_RES") },

                        IF ((legGetString(pComponent,sFieldNameBreach) == "") AND sFieldNameBreachNearLeg == "") THEN
                         {

                         	legSetCellColorAsError(pComponent,sFieldNameBreach),
                            legSetCellColorAsError(pContract, sFieldNameBreach),


                            IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-BackValued-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "BackValued : Breach Reason is required",sCriteriaField,"Sane-BackValued-Breach" ,messageSysGetErrorLabel())   
                            }
                		 }

                         ELSE
                         {

                           legSetCellColorAsWarning(pComponent,sCriteriaField),


                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-BackValued-Breach") == 0 ) THEN

                            {
                            legAddMessage(pComponent, "BackValued : Trade will be sent for FO Validation",sCriteriaField, "Sane-BackValued-Breach", messageSysGetWarningLabel())                        	
                            }
                        }
                        }

                         },

                         IF((sCheckType == "Blocking") AND ((bBackValidation))) THEN
                         {

                          legSetCellColorAsWarning(pComponent,sCriteriaField),

                           IF ( messagesGetNbOfMessagesFromCode( pAllMessages,"Sane-Margin-Breach") == 0 ) THEN
                            {
                              legAddMessage( pComponent, "BackValued Breach : Trade is blocked due to limit breach",sCriteriaField,"Sane-BackValued-Breach" ,messageSysGetErrorLabel())                          	
                            }

                         }
                        }

                }, //End of Backdated Checks             

             iResult := iResult + 1
             },// Close Loop on Check Types

             //Choose the highest validation level if several breaches
             iRankArray:=arrayGetLenght(pArray),
             iArraycount:=0,


             IF legIsElementValid(pComponent,"VAL_SEN") OR legIsElementValid(pComponent,"cross.VAL_SEN") THEN
             {
                 IF (iRankArray >= 1) THEN
                 {
                    pFirstElement := arrayGetElement(pArray,0),
                    fMax := arrayElementGetNumeric(pFirstElement,"RANK"),

                    WHILE(iArraycount<iRankArray) DO
                    {
                        pArrayElement:=arrayGetElement(pArray,iArraycount),
                        fArrayElement := arrayElementGetNumeric(pArrayElement,"RANK"),

                        IF(fArrayElement>fMax) THEN
                        fMax:=fArrayElement,

                        iArraycount:= iArraycount + 1
                    },

                   fMaxValidation := fMax + 1.0, // choose +1 level of MyGroup fo validation 
	               legOverwrite(pComponent,"VAL_SEN",fMaxValidation)

                 }

                 ELSE
                 {
                 	//Set VAL_SEN to zero and clear the Breach reason field
                    legOverwrite(pComponent,"VAL_SEN",0.0),
                    legOverwrite(pComponent,"PRE_RES",""), 
                    //To check in the case of FX Swap, get the Near leg PRE_RES value
                    IF sMainRegistrationLabel == "mxContractFxISWAP" THEN {
				    sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,0),"PRE_RES") }
                    //sFieldNameBreachNearLeg := legGetString(legGetComponentAt(pContract,iComponent),"PRE_RES") }

                 }
			}


    },//Close Eligible trades


     iComponent := iComponent + 1                                       
    }//Close loop on components


	}

};

// Retrieves the needed info from the hedged bond trade(s) needed to create the modelled ASWP trade in the workflow

{

		pHedge	:= This,    	

       	fPositionNominal := 0.0,
        fTradeNominalWithoutCap := 0.0,
        sPositionBuySell := "",
        sTradeBuySell := "",
        sBondTypology := "",

        //To initialize
        dPositionDate := "",
        dPositionStartDate := "",
        dIssueDate := "",
        sPositionBuySell := "",
        fCurrentCapFactor := "",
        fASWP := 0,
        dHedgingMaturity:= "",
        dPosStartDate2:="",
        fPositionNominal2:="",
        dHedgingMaturity:="",
        dBondTradeDate:="",
		dCouponDate2:="",
		sIsAmortized:="",
        sSecurityType:="",
        dBondNextCallDate:="",

        sHedgedInstrument := "",
        dIssueDate := "",
    sHedgeType := mx.accounting.hedge.Hedge.GetType(pHedge),
        //Initialize UDFs
        	pHedgeUDFs := mx.accounting.hedge.Hedge.GetUserFields(pHedge),

           IF (sHedgeType == "CASH_FLOW") THEN
			{ 
                udfSetString(pHedgeUDFs, "HDG_CODE", "1080") 
                },

        	IF (sHedgeType == "FAIR_VALUE") THEN
			{ 
             udfSetString(pHedgeUDFs, "HDG_CODE", "1805")  },    

            udfSetDate(pHedgeUDFs,"HDGING_MAT",dHedgingMaturity),
            udfSetNumeric(pHedgeUDFs,"POS_NOM",fPositionNominal2),
           	udfSetDate(pHedgeUDFs,"TRADE_DATE",dBondTradeDate), 
	        udfSetString(pHedgeUDFs,"POS_BS",sPositionBuySell),
            udfSetDate(pHedgeUDFs,"START_DATE",dCouponDate2),
           	udfSetString(pHedgeUDFs, "IS_AMORT", sIsAmortized),


        iHedgedCount := 0,

	    pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge),      
	    iHedgeItem := mx.system.collection.GetLength(pHedgedItems),

		dHedgeStartDate := mx.accounting.hedge.Hedge.GetStartDate(pHedge),

        WHILE (iHedgedCount < iHedgeItem ) DO 
        {

        	pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,iHedgedCount),
			pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt),            
            sHedgedRegistration := legGetRegistration(pHedgedItem),	



            IF ( sHedgedRegistration == "Bonds" 
            		) THEN {

				sTradeBuySell := legGetString(pHedgedItem,"Buy_Sell"),
                //sHedgedInstrument := legGetString(pHedgedItem,"Instrument"),
                        //Get Bond's Issue date
                dIssueDate := legGetDate(pHedgedItem,"Issue_date"),
                dTradeDate := legGetDate(pHedgedItem,"Trading_Date"),

                fTradeNominal := legGetNumeric(pHedgedItem,"Nominal"),
                fTradePercentage := mx.accounting.hedge.Component.GetPercentage(pHedgedElt),                 

            	// Get the Nominal without the cap factor
                fQuantity := legGetNumeric(pHedgedItem,"Quantity"),
                fLotSize := legGetNumeric(pHedgedItem,"Lot_size"),                
                fTradeNominalWithoutCap := fQuantity * fLotSize,  

                // Aggregate the Nominal
                IF (sTradeBuySell == "Buy") THEN
                {
                	fPositionNominal := fPositionNominal + fTradeNominalWithoutCap * fTradePercentage / 100.0
                }
                ELSE IF (sTradeBuySell == "Sell") THEN 
                {
                	fPositionNominal := fPositionNominal - fTradeNominalWithoutCap * fTradePercentage / 100.0
                },


                // Get Minimum Date
                // First Default the value to the first component
                IF (iHedgedCount == 0) THEN 
                {
                	dPositionDate := dTradeDate,
                    dBondTradeDate:=dTradeDate,
                    dPositionStartDate := legGetDate(pHedgedItem,"Settl_Payment_date")
                }
                // Else get smallest date
                ELSE IF (dTradeDate < dPositionDate) THEN
                {
                	dPositionDate := dTradeDate,
                    dBondTradeDate:=dTradeDate,
                    dPositionStartDate := legGetDate(pHedgedItem,"Settl_Payment_date")
                }

            },
        	iHedgedCount := iHedgedCount + 1

        },


       // Just to avoid unnecessary computation
        IF (fPositionNominal <> 0.0) THEN
        {	


        // Current Cap Factor
        	pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,0),
			pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt),
	        pStreams := legGetStreams(pHedgedItem),  // Get cashflow schedule
    	    pStream := streamsGetStream(pStreams,0,0),  // Get 1st cashflow schedule in case the instrument is phased

            //sInstrument:= legGetString(pHedgedItem,"Instrument"),
            //pBond := mx.system.object.PushByLabel("mx.statics.securities.SecurityHeader", sInstrument),  

			//fCoupon:= mx.statics.securities.SecurityHeader.GetCoupon(pBond),
            fCoupon:= legGetNumeric(pHedgedItem,"Coupon"),

	        fInitialNominal := streamGetCapital(pStream),
			fCurrentNominal := fInitialNominal, // Default Value            

	        iPeriodCounter := 0,
	        iNumberOfPeriods := streamGetNumberOfPeriods(pStream),

    	    WHILE (iPeriodCounter < iNumberOfPeriods) DO
	        {
				dPeriodStartDate := streamGetPeriodStartDate(pStream,iPeriodCounter),
				dPeriodEndDate := streamGetPeriodEndDate(pStream,iPeriodCounter),

			//if hedge start date is in the middle of the period
				IF ((dHedgeStartDate >= dPeriodStartDate) AND (dHedgeStartDate < dPeriodEndDate)) THEN
				{
					fCurrentNominal := streamGetPeriodRemainingCapital(pStream,iPeriodCounter),
					dCouponDate := streamGetPeriodStartDate(pStream,iPeriodCounter),
                    //dEndDate:=streamGetPeriodEndDate(pStream,iPeriodCounter),
					iPeriodCounter := iNumberOfPeriods
				},

				iPeriodCounter := iPeriodCounter + 1

			},


          //if hedge start date < settlement date of the bond  

            dPeriodStartDate := streamGetPeriodStartDate(pStream,0),
            dPeriodEndDate := streamGetPeriodEndDate(pStream,0),
            IF ((toString(dCouponDate)== "00000000" AND dHedgeStartDate<dPeriodStartDate)) THEN 
            {
            	dCouponDate:=dHedgeStartDate
            },

            fPositionNominal2 := abs(fPositionNominal),
			fCurrentCapFactor := fCurrentNominal / fInitialNominal,  // Needed in case a partial redemption or the security captial has changed during the period
    	    fPositionNominal := fPositionNominal * fCurrentCapFactor,




	        // Get Buy/Sell
	        IF (fPositionNominal >= 0.0) THEN
	        {
	            sPositionBuySell := "Buy"
	        }
	        ELSE IF (fPositionNominal < 0.0) THEN
	        {
	            sPositionBuySell := "Sell"
	        },

            // Nominal should not be signed
	        fPositionNominal := abs(fPositionNominal),




            // Maturity 
            pHedgingInsts := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge), // Get Hedging Instruments
			iHedgingInst := mx.system.collection.GetLength(pHedgingInsts),	// Number of Hedging Instruments            
            iHedgingCounter := 0,


            WHILE (iHedgingCounter < iHedgingInst) DO
            {
				pHedgingElt := mx.system.collection.GetElementAt(pHedgingInsts,iHedgingCounter),
				pHedgingInst := mx.accounting.hedge.Component.GetPricingLeg(pHedgingElt),



    		dMaturityDate := legGetDate(pHedgingInst,"Maturity"),
                IF (iHedgingCounter == 0) THEN
                {	

                	dHedgingMaturity := dMaturityDate
                }
                ELSE IF (dMaturityDate > dHedgingMaturity) THEN
                {
                	dHedgingMaturity := dMaturityDate
                },


            	iHedgingCounter := iHedgingCounter + 1

            },



             // Get the trade date of the Asset Swap
           	IF (dCouponDate > dHedgeStartDate ) THEN // To avoid inserting a deal with trade date > system date
            {
            	dPositionDate := dHedgeStartDate                
            }
            ELSE 
            {
            	dPositionDate := dCouponDate
            },


            //Set asset swap start date
            IF (dPositionDate==dHedgeStartDate AND dHedgeStartDate<=dPeriodStartDate) THEN
            {
            	dPositionStartDate:=dPeriodStartDate //set ASWP start date equal to bond start date
            }
            ELSE 
            {
            	dPositionStartDate:=dPositionDate //set ASWP start date equal to dPosition date
            },


         //Added to get the New ASWP start date


            pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,0), 
			pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt), // Get the hedged pricing leg

			//dBondTradeDate:=legGetTradingDate(pHedgedItem),


            pStreams := legGetStreams(pHedgedItem),
    	    pStream := streamsGetStream(pStreams,0,0),

	        iPeriodCounter := 0,
	        iNumberOfPeriods := streamGetNumberOfPeriods(pStream),

			 sIsAmortized:="No",

              /*IF(iNumberOfPeriods >1) THEN{
                fPeriodNominal:= streamGetPeriodRemainingCapital(pStream,1),
                fPreviousPeriodNominal:=streamGetPeriodRemainingCapital(pStream,0),

                IF(fPeriodNominal<>fPreviousPeriodNominal) THEN
                sIsAmortized:="Yes"},*/

    	    WHILE (iPeriodCounter < iNumberOfPeriods) DO
	        {
				dPeriodStartDate := streamGetPeriodStartDate(pStream,iPeriodCounter),
				dPeriodEndDate := streamGetPeriodEndDate(pStream,iPeriodCounter),

                IF(iPeriodCounter<>0) THEN {
                    fPeriodNominal:= streamGetPeriodRemainingCapital(pStream,iPeriodCounter),
                	fPreviousPeriodNominal:=streamGetPeriodRemainingCapital(pStream,iPeriodCounter-1),
                    IF(fPeriodNominal<>fPreviousPeriodNominal) THEN
                	sIsAmortized:="Yes"
                    },


			//if bond trade date is in the middle of the period
				IF ((dBondTradeDate >= dPeriodStartDate) AND (dBondTradeDate < dPeriodEndDate)) THEN
				{
					fCurrentNominal2 := streamGetPeriodRemainingCapital(pStream,iPeriodCounter),

					dCouponDate2 := streamGetPeriodStartDate(pStream,iPeriodCounter)

					//iPeriodCounter := iNumberOfPeriods
				},

				iPeriodCounter := iPeriodCounter + 1

			},

            //if bond trade date < settlement date of the bond  

            dPeriodStartDate := streamGetPeriodStartDate(pStream,0),
            dPeriodEndDate := streamGetPeriodEndDate(pStream,0),
            IF ((toString(dCouponDate2)== "00000000" AND dBondTradeDate<dPeriodStartDate)) THEN 
            {dCouponDate2:=dPeriodStartDate,
            fCurrentNominal2 := legGetNumeric(pHedgedItem,"Nominal_amount__cap_factor_"),
            fCurrentNominal2 :=streamGetPeriodRemainingCapital(pStream,0)
            },


            // ADD & TEST CHECK IF START DATE IN PERIOD , TAKE PERIOD START DATE

            fCurrentCapFactor2 := fCurrentNominal2 / fInitialNominal,
    	    fPositionNominal2 := fPositionNominal2 * fCurrentCapFactor2,

            //set the ASWP trade date to -10D of actual bond trade date
            //dBondTradeDate:=dBondTradeDate+shift(dBondTradeDate,"-10od","ALL DAYS"),


	        // Fill the UDFs
			//pHedgeUDFs := mx.accounting.hedge.Hedge.GetUserFields(pHedge),

            udfSetDate(pHedgeUDFs,"HDGING_MAT",dHedgingMaturity),
            udfSetNumeric(pHedgeUDFs,"POS_NOM",fPositionNominal2),
           	udfSetDate(pHedgeUDFs,"TRADE_DATE",dBondTradeDate), 
	        udfSetString(pHedgeUDFs,"POS_BS",sPositionBuySell),
            udfSetDate(pHedgeUDFs,"START_DATE",dCouponDate2),
           	udfSetString(pHedgeUDFs, "IS_AMORT", sIsAmortized),
            udfSetNumeric(pHedgeUDFs,"BD_CPN",fCoupon)

        },


        sHedgedInstrument := legGetString(pHedgedItem,"Instrument"),
        pSecurityData := secGetSecurityData(sHedgedInstrument),
     	pSecurity := mx.system.object.PushByLabel("mx.statics.securities.SecurityHeader", sHedgedInstrument),
        sSecurityType := mx.statics.securities.SecurityHeader.GetType(pSecurity),
        dBondNextCallDate := bondGetNextCallDate(pSecurityData, dSystemDate),

   //   	IF (sSecurityType == "Callable") THEN
		//	{
        //        udfOverwriteString(pHedgeUDFs, "CALLABLE", "Y"),
       //         udfOverwriteDate(pHedgeUDFs,"HDGING_MAT",dBondNextCallDate)              

     //       },


     	pHedgingInsts := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge), 
     	pHedgingElt := mx.system.collection.GetElementAt(pHedgingInsts,0),
	 	pHedgingInst := mx.accounting.hedge.Component.GetPricingLeg(pHedgingElt), // Get the hedging pricing leg


     	    pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge),
        	pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,0),
			pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt),   //Get the hedged pricing leg


          //  Fill the hedging item Profit Center
         sPTF:=legGetString(pHedgingInst,"Portfolio"),
            pPTFUDF:=ptfGetUserFields(sPTF),
            sProfCenter:=udfGetString(pPTFUDF, "SEG_CODE"),

           udfSetString(pHedgeUDFs,"PCEN_HDGIN",sProfCenter),

           // Fill the hedged item Profit Center
            sPTF:=legGetString(pHedgedItem,"Portfolio"),
            pPTFUDF:=ptfGetUserFields(sPTF),
            sProfCenter:=udfGetString(pPTFUDF, "SEG_CODE"),
            udfSetString(pHedgeUDFs,"PCEN_HDGED",sProfCenter),

            //Fill the hedged item settlement date   
            dSettleDate := legGetDate(pHedgedItem,"Settl_Payment_date"),
            udfSetDate(pHedgeUDFs,"BND_STL",dSettleDate),

             //Fill Accounting Section
             sAccSection:=ptfGetAccountingSection(sPTF),
             udfSetString(pHedgeUDFs,"ACC_SEC",sAccSection),

             sBondTypology:= legGetString(pHedgedItem,"Typology"),
             udfSetString(pHedgeUDFs,"BND_TYPO",sBondTypology)

};

//Credit spread retreiver
  {

      pHedge := This,

        // Default values
        sHedgedType := "",
        sHedgingTypeLeg1 := "",
        sHedgingTypeLeg2 := "",
        sHedgeType := "", //JS
        fCreditSpread := 0.0,
        sUDF := "",

        pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge), // Get Hedged Items
        pHedgingInsts := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge), // Get Hedging Instruments

        iHedgedItems := mx.system.collection.GetLength( pHedgedItems ),       // Number of Hedged Items
        iHedgingInst := mx.system.collection.GetLength( pHedgingInsts ),        // Number of Hedging Instruments

        // Just to avoid unnecessary computations
        //  bHedgeInitialized := ((iHedgedItems <> 0) AND (iHedgingInst == 1)),

      bHedgeInitialized := (iHedgedItems <> 0),    

        IF (bHedgeInitialized) THEN
        {
            // Check if credit spread should be retrieved.

               pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,0), 
               pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt), // Get the hedged pricing leg

               pHedgingElt := mx.system.collection.GetElementAt(pHedgingInsts,0),
               pHedgingInst := mx.accounting.hedge.Component.GetPricingLeg(pHedgingElt), // Get the hedging pricing leg

               sHedgedGroup := legGetProductGroup(pHedgedItem), // Get the hedged product group
               sHedgingGroup := legGetProductGroup(pHedgingInst), // Get the hedging product group

            //To update UDFS at the level of the hedge
               pHedgeStrategy := mx.accounting.hedge.Hedge.GetStrategy(pHedge),
               pTheoHedgeStrategy := mx.accounting.hedge.Hedge.GetTheoreticalHedgingComponents(pHedge),
               pTheoHedgeElt := mx.system.collection.GetElementAt(pTheoHedgeStrategy,0),
               pTheoHedgeComponent := mx.accounting.hedge.Component.GetPricingLeg(pTheoHedgeElt), 
               sHedgeType := mx.accounting.hedge.Hedge.GetType(pHedge),
               pHedgeUDFs := mx.accounting.hedge.Hedge.GetUserFields(pHedge),

            sHedgeStrategy := mx.accounting.hedge.config.Strategy.GetLabel(pHedgeStrategy),
            sHedgingRegistration := legGetRegistration(pHedgingInst),
            sHedgingTradePurpose := legGetString(pHedgingInst,"Trade_purpose"),

          // Check if Eligible for Credit Spread
            bCreditSpreadEligible := FALSE,
            bCreditSpreadEligible := (sHedgedGroup == "BOND") AND ((sHedgingGroup == "IRS") ), /* JS uncommented and remove loan */


            IF (bCreditSpreadEligible) THEN
            {

              IF ((sHedgingRegistration == "Interest rate swaps") ) THEN
	    	{

		        pStreams := legGetStreams(pHedgingInst),
	    	    iPhases := streamsGetNumberOfPhases(pStreams),
    	    	iNumberOfLegs := streamsGetNumberOfLegsPerPhase(pStreams),
	        	iLegCounter := 0,

		        IF (iPhases == 1 AND iNumberOfLegs == 2) THEN
	    	    {

		        	WHILE (iLegCounter < iNumberOfLegs) DO
	    	        {

	        	        // Variable for Leg Cell Names    
	            	    IF (iLegCounter == 0) THEN
	                	{
		                	sThisLeg := "", // To retreive the cells of this leg in the e-tradepad
		                    sOtherLeg := "2", // To retreive the cells of other leg in the e-tradepad
        	                sUDF := "1", // To know in which UDF to store
                            sOtherUDF := "2"
	        	        }
	            	    ELSE IF (iLegCounter == 1) THEN
	                	{
	                		sThisLeg := "2", // To retreive the cells of this leg in the e-tradepad
		                    sOtherLeg := "", // To retreive the cells of other leg in the e-tradepad
    	                    sUDF := "2", // To know in which UDF to store
                            sOtherUDF := "1"
	    	            },

	            	    /* Get whether Floating or Fixed
                    		If Leg is Fixed then Credit Free Rate is the ATM Fixed Rate leg where margin is 0 on the otherleg
                        	If Leg is Floating then Credit Free Rate is the ATM margin without changing the margin of the other leg
	                        In case the floating logic is not valid, the IF statement should be removed while keeping legOverwrite(pClone,"Rate_Margin" + sOtherLeg,0.0)
    	                */
	    	            sLegType := legGetString(pHedgingInst,"Leg_type" + sThisLeg), 
						sLegOtherType := legGetString(pHedgingInst,"Leg_type" + sOtherLeg),

                      //   pAddFlow:=legGetAdditionalFlows(pHedgingInst),
                     //    pAddFlowAt:=additionalFlowsGetFlowAt(pAddFlow,0),
                    //     fAmount:=flowGetAmount(pAddFlowAt),

                        IF (sHedgingTradePurpose <> "Hedge theoretical component") THEN
                        {

				    	    // Create the clone
		    		        pContainer :=npOpen(),  
			            	pClone:=legClone(pContainer,pHedgingInst),        

		    		        // Force the Market Data Date to Trading Date    
			    	    //  dTradingDate := legGetDate(pClone,"Trading Date"),
						//	legOverwrite(pClone,"Market Data date",dTradingDate),

                            // Case 1: Fair Flow Hedge
                            IF ((sLegType == "Fixed") AND (sLegOtherType == "Floating")) THEN
                            {                            

                                legCompute(pClone,"noWorkflow"),
                                legSetLocalImplied(pClone,"Rate_Margin" + sThisLeg),
                                legOverwrite(pClone,"Rate_Margin" + sOtherLeg,0.0),

	    	                  //  legOverwrite(pClone,"Npv",fAmount), //overwrite NPV to be equal to Premium
                                legOverwrite(pClone,"Npv",0.0),
    	                        legCompute(pClone,"noWorkflow"),

                            	fRateLeg := legGetNumeric(pHedgingInst,"Rate_Margin" + sThisLeg),
                                fCreditFreeRate := legGetNumeric(pClone,"Rate_Margin" + sThisLeg),
                            	fCreditSpread := fRateLeg - fCreditFreeRate


                            },



                            // Close the Container
                            npClose(pContainer)
                        },


    	        		iLegCounter := iLegCounter + 1
		            } // Close loop on trade legs
    		    } // Close Phase Leg Condition                 	    	 
		    }  // Close Product      

            }              
        },

        udfSetNumeric(pHedgeUDFs, "BND_CRD_SP", fCreditSpread)

};

// Pretrade to check if the same hedged item is used in different hedge relationships. If yes block the insertion or warn the user.

{

pHedge := This, 

	pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge),
	iNbHedgedItems := mx.system.collection.GetLength(pHedgedItems),
	iHedgedItemsCounter := 0,
	iErrorsHedging := 0,

    WHILE (iHedgedItemsCounter < iNbHedgedItems) DO
    {

        pHedgedItem := mx.system.collection.GetElementAt(pHedgedItems,iHedgedItemsCounter),
        fPercentage := mx.accounting.hedge.Component.GetPercentage(pHedgedItem),
        pHedgedTrade := mx.accounting.hedge.Component.GetPricingLeg(pHedgedItem),
        sBuyOrSell := legGetString(pHedgedTrade,"Buy_Sell"),


        fHedgedItemTradeNumber := legGetNumeric(pHedgedTrade,"Trn Number"),
        sHedgedItemTradeNumber := toString(fHedgedItemTradeNumber),

        pOtherComponents := mx.accounting.hedge.Component.GetOtherComponents(pHedgedItem),   
        iNbOtherComponents := mx.system.collection.GetLength(pOtherComponents),
        iOtherComponents := 0,
        fSumPercentage := fPercentage,    

               WHILE (iOtherComponents < iNbOtherComponents) DO
               {
                pOtherComponent :=  mx.system.collection.GetElementAt(pOtherComponents,iOtherComponents),
                fOtherPercentage := mx.accounting.hedge.Component.GetPercentage(pOtherComponent),   
                fSumPercentage :=  fOtherPercentage + fSumPercentage,
                	IF (fSumPercentage > 100.00) THEN
                    {
                              iErrorsHedging := iErrorsHedging + 1,
                              iOtherComponents := iNbOtherComponents
                    }      
                    ELSE IF ((fSumPercentage < 100.00) OR (fSumPercentage == 100.00)) THEN
                    {
                              iErrorsHedging := iErrorsHedging,
                              iOtherComponents := iOtherComponents            
                    },
                    iOtherComponents := iOtherComponents + 1                
               },
        iHedgedItemsCounter := iHedgedItemsCounter + 1
    },

  	 IF iErrorsHedging > 0 THEN
    { 
    sMessage := toString("Hedged Item ") + sHedgedItemTradeNumber + toString(" is overused"),
                             ThrowError("Hedge Compliance",sMessage)
	}   

};

 // Pretrade to check if the same hedging instrument is used in different hedge relationships. If yes block the insertion or warn the user.

{

pHedge := This, 

	pHedgingItems := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge),
	iNbHedgingItems := mx.system.collection.GetLength(pHedgingItems),
	iHedgingItemsCounter := 0,
	iErrorsHedging := 0,

    WHILE (iHedgingItemsCounter < iNbHedgingItems) DO
    {

        pHedgingItem := mx.system.collection.GetElementAt(pHedgingItems,iHedgingItemsCounter),
        fPercentage := mx.accounting.hedge.Component.GetPercentage(pHedgingItem),
        pHedgingTrade := mx.accounting.hedge.Component.GetPricingLeg(pHedgingItem),
       // sBuyOrSell := legGetString(pHedgingTrade,"Buy_Sell"),


        fHedgingItemTradeNumber := legGetNumeric(pHedgingTrade,"Trn Number"),
        sHedgingItemTradeNumber := toString(fHedgingItemTradeNumber),

        pOtherComponents := mx.accounting.hedge.Component.GetOtherComponents(pHedgingItem),   
        iNbOtherComponents := mx.system.collection.GetLength(pOtherComponents),
        iOtherComponents := 0,
        fSumPercentage := fPercentage,    

               WHILE (iOtherComponents < iNbOtherComponents) DO
               {
                pOtherComponent :=  mx.system.collection.GetElementAt(pOtherComponents,iOtherComponents),
                fOtherPercentage := mx.accounting.hedge.Component.GetPercentage(pOtherComponent),   
                fSumPercentage :=  fOtherPercentage + fSumPercentage,
                	IF (fSumPercentage > 100.00) THEN
                    {
                              iErrorsHedging := iErrorsHedging + 1,
                              iOtherComponents := iNbOtherComponents
                    }      
                    ELSE IF ((fSumPercentage < 100.00) OR (fSumPercentage == 100.00)) THEN
                    {
                              iErrorsHedging := iErrorsHedging,
                              iOtherComponents := iOtherComponents            
                    },
                    iOtherComponents := iOtherComponents + 1                
               },
        iHedgingItemsCounter := iHedgingItemsCounter + 1
    },

	IF iErrorsHedging > 0 THEN
   { 
    sMessage := toString("Hedging Item ") + sHedgingItemTradeNumber + toString(" is overused"),
                               ThrowError("Hedge Compliance",sMessage)
	}   

};

// Needed to know which leg of the Hedging trade (IRS or CS) is the floating leg to use to compute the credit spread

{

	pHedge := This,

	pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge), // Get pointer on Hedged Component
    pHedgingInsts := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge), // Get Pointer on Hedging Component

	iHedgedItems := mx.system.collection.GetLength(pHedgedItems), // Number of Hedged Items
	iHedgingInst := mx.system.collection.GetLength(pHedgingInsts),// Number of Hedging Instruments

    IF ((iHedgedItems >0) AND (iHedgingInst>0)) THEN
    {
    	// Get a pointer on the first hedged item
	    pHedgedElt := mx.system.collection.GetElementAt(pHedgedItems,0),
		pHedgedItem := mx.accounting.hedge.Component.GetPricingLeg(pHedgedElt), 

        // Check if Hedged is Fixed or Floating
	    pHedgedStreams := legGetStreams(pHedgedItem),
	    pHedgedStream := streamsGetStream(pHedgedStreams,0,0),
	    pHedgedIndex := streamGetIndex(pHedgedStream), // Get a Pointer on the Index

		IF (isNull(pHedgedIndex)) THEN // Check if Fixed or Floating
		{
			sHedgedType := "Fixed"
		}
	    ELSE 
		{
			sHedgedType := "Floating",
			sHedgedIndexCurrency := indexGetCurrency(pHedgedIndex) 
		},        

    	// Get a pointer on the first hedging instrument
	    pHedgingElt := mx.system.collection.GetElementAt(pHedgingInsts,0),	
		pHedgingInst := mx.accounting.hedge.Component.GetPricingLeg(pHedgingElt),    	

        // Check the type of Legs of the hedging instrument
	    pHedgingStreams := legGetStreams(pHedgingInst),

        // Leg 1
	    pHedgingStreamLeg1 := streamsGetStream(pHedgingStreams,0,0),
		pHedgingIndexLeg1 := streamGetIndex(pHedgingStreamLeg1), // Get a Pointer on the Index

		// Check if Fixed or Floating
	    IF (isNull(pHedgingIndexLeg1)) THEN 
    	{
	    	sHedgingTypeLeg1 := "Fixed"
	    }
	    ELSE 
	    {
		    sHedgingTypeLeg1 := "Floating",
	    	sHedgingIndexCurrency1 := indexGetCurrency(pHedgingIndexLeg1)

	    },

	    // Leg 2
	    pHedgingStreamLeg2 := streamsGetStream(pHedgingStreams,0,1),
		pHedgingIndexLeg2 := streamGetIndex(pHedgingStreamLeg2), // Get a Pointer on the Index

	    IF (isNull(pHedgingIndexLeg2)) THEN // Check if Fixed or Floating
	    {
	    	sHedgingTypeLeg2 := "Fixed"
	    }
	    ELSE 
	    {
		    sHedgingTypeLeg2 := "Floating",
	    	sHedgingIndexCurrency2 := indexGetCurrency(pHedgingIndexLeg2)	        
	    },   

		// Case where the hedged item is Fixed
	    IF (sHedgedType == "Fixed") THEN 
	    {
	    	// Case where the leg 1 of the hedging is fixed
	    	IF (sHedgingTypeLeg1 == "Fixed" AND sHedgingTypeLeg2 == "Floating") THEN 
	        {
	        	iHedgingStream := 0 
	        }
			// Case where the leg 2 of the hedging is fixed
	        ELSE IF (sHedgingTypeLeg1 == "Floating" AND sHedgingTypeLeg2 == "Fixed") THEN 
	        {
	        	iHedgingStream := 1 
	        }   
	    }
	    // Case where the hedged item is Floating and Cross-Currency Swap  
	    ELSE IF (sHedgingGroup == "CS") THEN 
	    {
	    	// Case where the hedged margin is equal to Leg 1 Margin
	    	IF (sHedgedIndexCurrency == sHedgingIndexCurrency1) THEN
	        {
	        	iHedgingStream := 0 
	        }
	        ELSE IF (sHedgedIndexCurrency == sHedgingIndexCurrency2) THEN
	        {
	    		iHedgingStream := 1
	    	}  
	    }
        // Case IRS hedging a Floating Bond
	    ELSE IF (sHedgedType == "Floating") THEN
        {
	    	// Case where the leg 1 of the hedging is fixed
	    	IF (sHedgingTypeLeg1 == "Fixed" AND sHedgingTypeLeg2 == "Floating") THEN 
	        {
	        	iHedgingStream := 1 
	        }
			// Case where the leg 2 of the hedging is fixed
	        ELSE IF (sHedgingTypeLeg1 == "Floating" AND sHedgingTypeLeg2 == "Fixed") THEN 
	        {
	        	iHedgingStream := 0 
	        }          	
        },


    	pHedgeUDFs := mx.accounting.hedge.Hedge.GetUserFields(pHedge),
	    udfSetInteger(pHedgeUDFs,"HDGING_LEG",iHedgingStream)       

    }


};

  {

		pHedge	:= This,    	
		bBlockInsertion := FALSE,
        sMessage := "",


        sHedgeType := mx.accounting.hedge.Hedge.GetType(pHedge),

    //    pHedgeUDFs := mx.accounting.hedge.Hedge.GetUserFields(pHedge),


        sAccountingMethod := mx.accounting.hedge.Hedge.GetAccountingMethod(pHedge), // HYPO_DERIV

        pHedgedItems := mx.accounting.hedge.Hedge.GetHedgedComponents(pHedge),
	    iHedgeItems := mx.system.collection.GetLength(pHedgedItems),        

        pHedgingInstruments := mx.accounting.hedge.Hedge.GetHedgingComponents(pHedge),
	    iHedgingInstruments := mx.system.collection.GetLength(pHedgingInstruments),        

        pHypotheticalDerivatives := mx.accounting.hedge.Hedge.GetTheoreticalHedgedComponents(pHedge),        
	    iHypotheticalDerivatives := mx.system.collection.GetLength(pHypotheticalDerivatives),
		pHypotheticalElt := mx.system.collection.GetElementAt(pHypotheticalDerivatives,0),
		pHypotheticalItem := mx.accounting.hedge.Component.GetPricingLeg(pHypotheticalElt),        


        // Compliance checks for Cash Flow Hedge
        IF (sHedgeType == "CASH_FLOW") THEN
        {
        	// Check whether hypothetical derivative is the accounting method
        	IF (sAccountingMethod <> "HYPO_DERIV") THEN
            {
            	bBlockInsertion := TRUE,
                sMessage := sMessage + "Accounting method should be Hypothetical Derivative for a cash flow hedge" + endline()

            },

            // Check that a hedging instrument is selected
        	IF (iHedgingInstruments == 0) THEN
            {
            	bBlockInsertion := TRUE,
                sMessage := sMessage + "No hedging instrument selected" + endline()

            }            
            // Check whether the hypothetical was created
            ELSE IF (iHypotheticalDerivatives <> iHedgingInstruments) THEN
            {
            	bBlockInsertion := TRUE,
                sMessage := sMessage + "Hypothetical derivative not created" + endline()

            }





        }, // Close Cash flow hedge type


        // Throw Error
        IF (bBlockInsertion) THEN
        {
        	ThrowError("Wrong Input",sMessage)

        }
};

{

	pLeg := This,

    sAction := properties.Get("mx.preTrade.action"),
    sSourceClass := properties.Get("mx.preTrade.BO.source.class"),

    iComponent := 0,
    iNumberOfComponents := legGetNumberOfComponents(pLeg),


    WHILE (iComponent < iNumberOfComponents) DO
    {

    	pComponent := legGetComponentAt(pLeg,iComponent),
        iComponentVersion := legGetVersion(pComponent),
        sProductGroup := legGetProductGroup(pComponent),
        bBlock := FALSE,

        IF (sProductGroup == "BOND") THEN
        {
	        sPortfolio := legGetString(pComponent,"Portfolio"),
    	    sPortfolioAccountingSection := ptfGetAccountingSection(sPortfolio),
	        sBuySell := legGetString(pComponent,"Buy_Sell"),

            sInstrumentCurrency := legGetString(pComponent,"Currency"),
            fInitialCleanPrice := legGetNumeric(pComponent,"Settlement_price"),
            fInitialNominal := legGetNumeric(pComponent,"Nominal"),          
            dDealValueDate := legGetDate(pComponent,"Settl_Payment_date"),	                        
            pAllFees := legGetBrokerFlows(pComponent),

            //Set the UDF to contain the Initial Clean Price
            legOverwrite(pComponent,"LIQ_CP",fInitialCleanPrice),

    	    // Eligibility for Cost Amortization
	        IF (sPortfolioAccountingSection == "Issuance" AND sBuySell == "Sell" )
         //   AND (sSourceClass == "" OR sSourceClass == "mxContractEventICANCEL_REISSUE") AND sAction == "INS")
         THEN
	        {
                pInitialData := legGetInitialDatas(pComponent),

                // Audit CP
                initialdatasSetNumeric(pInitialData,"v" + toString(iComponentVersion) + " Initial CP", fInitialCleanPrice),

	            iFee := 0,
	            iNumberOfFees := brkFlowsGetNumberOfFlows(pAllFees),   

				fBrokerageFees := 0.0,

				IF (iNumberOfFees <> 0) THEN 
	            {

					WHILE ( iFee < iNumberOfFees ) DO 
	                {

		                // Get info on the fee
						pFee := brkFlowsGetAt(pAllFees,iFee),
						sFeeCode := brkFlowGetCode(pFee),
						sFeeType := brkFlowGetType(pFee),
						sFeeCurrency := brkFlowGetCurrency(pFee),
						sFeeSource := brkFlowGetSource(pFee),
						sFeeDestination := brkFlowGetDestination(pFee),
						fFeeAmount := brkFlowGetFee(pFee),
						dFeeValueDate := brkFlowGetValueDate(pFee),

                        // If Fee Payment date is greater than Bond Settlement Date, Block the insertion of the trade
                        IF (dFeeValueDate > dDealValueDate) THEN
                        {
                        	bBlock := TRUE
							//ThrowError("Issuance Fees","The value date of the issuances fees should not be greater than the settlement date of the bond")
                        },

	                    fFxRate := 0,

	                    // Force the Brokerafe Fees code to Pre-Issue
						//brkFlowSetCode(pFee,"Pre-Issue"),

				         // Exclude Fee if its Source Portfolio is different from portfolio of the trade
						IF (sFeeSource == sPortfolio) THEN
	                    {
							// Adjustment of fees having Fee Currency different than Instrument Currency
							IF ( sFeeCurrency <> sInstrumentCurrency) THEN
	                        {			
								cuGetFxRate (sInstrumentCurrency,sFeeCurrency),                                                                
								fFxRate := cuGetFxRate (sInstrumentCurrency,sFeeCurrency),
	                            fNativeAmount := fFeeAmount,
								fFeeAmount := fFeeAmount * fFxRate
							}                 
			            },	                                        

	                    // Audit Fees
						initialdatasSetNumeric(pInitialData,"v" + toString(iComponentVersion) + " Fee " + toString(iFee + 1) + " Amount in " + sInstrumentCurrency,fFeeAmount),
	                    initialdatasSetDate(pInitialData,"v" + toString(iComponentVersion) + " Fee " + toString(iFee + 1) + " Insertion Date",sysGetDate()),

	                    IF (fFxRate <> 0.0) THEN
	                    {
	                    	initialdatasSetNumeric(pInitialData,"v" + toString(iComponentVersion) + " Fee " + toString(iFee + 1) + " " + sInstrumentCurrency + "/" + sFeeCurrency,fFxRate),
							initialdatasSetNumeric(pInitialData,"v" + toString(iComponentVersion) + " Fee " + toString(iFee + 1) + " Amount in " + sFeeCurrency,fNativeAmount)
	                   	},                                        

	                    // Aggregate the Fees
						fBrokerageFees := fBrokerageFees + fFeeAmount,

                        iFee := iFee + 1

		        	}, // Close While loop on the Fees

                        fNewCleanCost := fInitialCleanPrice / 100.0 * fInitialNominal - fBrokerageFees,
					    fNewCleanPrice := (fNewCleanCost / fInitialNominal *100.0),
						legOverwrite(pComponent,"LIQ_CP",fNewCleanPrice)


                    }
                    ELSE
                    {
		                legOverwrite(pComponent,"LIQ_CP",fNewCleanPrice)
                    }

				}//  Close IF fees <> 0                  

        	},//  Close IF ISSUANCE Sell
                  iComponent := iComponent + 1
            }

            };

{
    pPackage := This,
    pFlows   := mx.deliverable.Package.GetFlows(pPackage),

    iFlows     := mx.system.collection.GetLength(pFlows),
    iRemovedFlows := 0,
    iFlow     := 0,
    sUser := sysGetUser(),
               dSystemDate := sysGetDate(),

    WHILE (iFlow < iFlows) DO {
        bBlockTrade := FALSE,
     bTransfer  := FALSE,   
        bCash  := FALSE,
        bSec  := FALSE,
        bPos  := FALSE,
        bPhys := FALSE,
        bIRDlb  := FALSE,
        bBlockTrade := FALSE,
     bTransfer  := FALSE,
     bIsInt := FALSE,   
     pFlow := mx.system.collection.GetElementAt(pFlows,(iFlow-iRemovedFlows)),
     bKilledFlow:=FALSE,


        //Get the component depending on the nature of the flow
        bCash := mx.system.object.IsInstanceOf(pFlow, "mx.deliverable.Cash"),
        bSec  := mx.system.object.IsInstanceOf(pFlow, "mx.deliverable.Security"),
        bPos  := mx.system.object.IsInstanceOf(pFlow, "mx.deliverable.Position"),
        bPhys := mx.system.object.IsInstanceOf(pFlow, "mx.deliverable.PhysicalFlow"),

        IF bCash THEN {pComponent := mx.deliverable.Cash.GetComponent(pFlow)},
        IF bSec  THEN {pComponent := mx.deliverable.Security.GetComponent(pFlow)},
        IF bPos  THEN {pComponent := mx.deliverable.Position.GetComponent(pFlow)},
        IF bPhys THEN {pComponent := mx.deliverable.PhysicalFlow.GetComponent(pFlow)},



    sRegistration := legGetRegistration( pComponent ),
        pFlowTypology := mx.deliverable.Cash.GetTypology(pFlow),
        sFlowType0:=mx.deliverable.Typology.GetFlowType0(pFlowTypology),  
        sFlowType1:=mx.deliverable.Typology.GetFlowType1(pFlowTypology),  
        sFlowType2:=mx.deliverable.Typology.GetFlowType2(pFlowTypology), 
        sFlowType3:=mx.deliverable.Typology.GetFlowType3(pFlowTypology),
		sFlowType4:=mx.deliverable.Typology.GetFlowType4(pFlowTypology),
        pStlMethod := mx.deliverable.Security.GetSettlementMethod(pFlow),
        pCurrency := mx.deliverable.Cash.GetCurrency(pFlow),
        sDeliverableCurrency:= mx.statics.fx.CurrencyDefinition.GetCurrencyLabel(mx.deliverable.Cash.GetCurrency(pFlow)),




    //

        // for MURABAHA Com Paper

    sIsMurCOM := legGetTypology(pComponent),

    IF (sIsMurCOM == "Murabaha Com Paper" AND bKilledFlow == FALSE) THEN
    {
              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    
    },
    // end of MURABAHA COM

   // For CD
      sIsCD := legGetTypology(pComponent),
    IF (sIsCD == "CD Issuance" AND sFlowType0 == "CAP" AND sFlowType1 == "IPAY" AND sFlowType2 == "" AND sFlowType3 == "" AND sFlowType4 == "ADD") THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },

   // for BankNotes
    /*
    sTypology := legGetTypology(pComponent),
    IF (sTypology == "Banknotes" AND sFlowType0 <> "BRK" AND bKilledFlow == FALSE AND bCash) THEN
    {
        sBankNoteCurrency := legGetString(pComponent,"BANK_NOTE"),
        IF(sBankNoteCurrency == sDeliverableCurrency) THEN {
              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    
        }
    },	
    */
   	// remove interface delivererables T24.FX ,T24.MM, Migration

          sSourceModule := legGetSourceModule(pComponent),
                                  sSourceModuleTypology := legGetTypology(pComponent),

                                dValueDate := mx.deliverable.Cash.GetValueDate( pFlow ),

	IF ((sSourceModule == "T24.FX" OR sSourceModule == "T24.MM" OR (sSourceModule == "Migration" AND toString(dValueDate) <= "20220804" ) )AND bKilledFlow == FALSE AND bCash) THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE

    },
    //End of interfaces

    // for sukuk coupons

    sTypology := legGetTypology(pComponent),
    IF (sTypology == "Sukuk" AND sFlowType0 <> "CAP" AND sFlowType1 <> "NOM" AND sFlowType2 <> "INIT" AND bKilledFlow == FALSE AND bCash) THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },
    IF (sTypology == "Sukuk Issuance" AND sFlowType0 <> "CAP" AND sFlowType1 <> "NOM" AND sFlowType2 <> "INIT" AND bKilledFlow == FALSE AND bCash) THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },

    //end coupon 

        // for repo waad

    // for fixed leg coupon 
    sTypology := legGetTypology(pComponent),
    IF (sTypology == "Repo Waad" AND sFlowType0 == "REV" AND sFlowType1 == "CPN" AND sFlowType2 == "FIX" AND sFlowType3 == "FIX" AND sFlowType4 == "UND") THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },

    //for floating leg coupon
    sTypology := legGetTypology(pComponent),
    IF (sTypology == "Repo Waad" AND sFlowType0 == "REV" AND sFlowType1 == "CPN" AND sFlowType2 == "VAR" AND sFlowType3 == "FIX" AND sFlowType4 == "UND") THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },
    //end repo waad

    // for rev repo waad

    // for fixed leg coupon 
    sTypology := legGetTypology(pComponent),
    IF (sTypology == "RR Waad" AND sFlowType0 == "REV" AND sFlowType1 == "CPN" AND sFlowType2 == "FIX" AND sFlowType3 == "FIX" AND sFlowType4 == "UND") THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },

    //for floating leg coupon
    sTypology := legGetTypology(pComponent),
    IF (sTypology == "RR Waad" AND sFlowType0 == "REV" AND sFlowType1 == "CPN" AND sFlowType2 == "VAR" AND sFlowType3 == "FIX" AND sFlowType4 == "UND") THEN
    {

              mx.system.collection.RemoveElement(pFlows, pFlow),
              mx.system.object.Destroy(pFlow),
              iRemovedFlows := iRemovedFlows + 1,
              bKilledFlow:=TRUE    

    },
    //end rev repo waad

            iFlow := iFlow + 1     
 }
};

// mx.preTrade.routing.FXMM.Pricing.Rout-RFQ

/*
Router for RFQ (Pre-pricing)

The aim is to do a pre-pricing in the context of RFQ
*/

{
	pLeg := This,
	//Field Initialization
	sOutput := "noRFQ",
	fRFQId := legGetRFQId(pLeg),

	// To know if the context is RFQ
	IF ( fRFQId <> 0.0 ) THEN
    {
    	sOutput := "RFQ"
    },
    setReturnValue( sOutput )  
};
